window.OFFICIAL_EXAMS = [
{
  id:"o-n1-1", lvl:"N1", title:"Examen oficial N1 · 1", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙・文法）・読解", minutes:110, questions:[
      {sec:"問題1　漢字読み",q:"次の　下線の　言葉の　読み方として　最も　よいものを、1・2・3・4から　一つ　選びなさい。　彼の　主張は　説得力に　<u>乏しい</u>。",o:["むなしい","あやしい","とぼしい","まずしい"],a:2,exp:"<b>乏しい→とぼしい</b>「escaso, carente de」。"},
      {q:"次の　下線の　言葉の　読み方として　最も　よいものを、1・2・3・4から　一つ　選びなさい。　その　計画は　早くも　<u>頓挫</u>した。",o:["とんそ","とんさ","どんざ","とんざ"],a:3,exp:"<b>頓挫→とんざ</b>「estancamiento repentino」。"},
      {q:"次の　下線の　言葉の　読み方として　最も　よいものを、1・2・3・4から　一つ　選びなさい。　彼女の　態度は　<u>一貫</u>している。",o:["いつかん","いっかん","いちかん","いっかんせい"],a:1,exp:"<b>一貫→いっかん</b>「coherencia」。"},
      {q:"次の　下線の　言葉の　読み方として　最も　よいものを、1・2・3・4から　一つ　選びなさい。　両国の　関係は　<u>緊張</u>している。",o:["きんじょう","きんちょう","こんちょう","きんきょう"],a:1,exp:"<b>緊張→きんちょう</b>「tensión」。"},
      {q:"次の　下線の　言葉の　読み方として　最も　よいものを、1・2・3・4から　一つ　選びなさい。　彼の　業績は　<u>顕著</u>な　成果を　上げた。",o:["けんちゃく","けんちょ","げんちょ","けんじょ"],a:1,exp:"<b>顕著→けんちょ</b>「notable」。"},
      {q:"次の　下線の　言葉の　読み方として　最も　よいものを、1・2・3・4から　一つ　選びなさい。　交渉は　<u>暗礁</u>に　乗り上げた。",o:["あんじょう","くらいわ","やみいわ","あんしょう"],a:3,exp:"<b>暗礁→あんしょう</b>「escollo」、暗礁に乗り上げる＝estancarse."},
      {sec:"問題2　文脈規定",q:"（　）に　入れるのに　最も　よいものを、1・2・3・4から　一つ　選びなさい。　彼の　説明は　（　）を　得ず、聞いていて　疲れる。",o:["要求","要因","要素","要領"],a:3,exp:"<b>要領を得ない</b>「no ir al grano」。"},
      {q:"（　）に　入れるのに　最も　よいものを、1・2・3・4から　一つ　選びなさい。　彼女の　演技は　素人（　）本格的だった。",o:["にしては","にかけては","につき","にとって"],a:0,exp:"<b>〜にしては</b>「para ser (algo)」。"},
      {q:"（　）に　入れるのに　最も　よいものを、1・2・3・4から　一つ　選びなさい。　彼は　反対派の　説得に　（　）を　尽くした。",o:["手","方法","力","知恵"],a:0,exp:"<b>手を尽くす</b>「agotar todos los medios」。"},
      {q:"（　）に　入れるのに　最も　よいものを、1・2・3・4から　一つ　選びなさい。　彼の　態度は　（　）を　投じた。",o:["波動","反響","波紋","衝撃"],a:2,exp:"<b>波紋を投じる</b>「causar revuelo」（連語）。"},
      {q:"（　）に　入れるのに　最も　よいものを、1・2・3・4から　一つ　選びなさい。　この　計画には　（　）が　ある。",o:["難所","難儀","難関","難点"],a:3,exp:"<b>難点</b>「punto problemático」。"},
      {q:"（　）に　入れるのに　最も　よいものを、1・2・3・4から　一つ　選びなさい。　規則を　破った（　）、罰せられるのは　当然だ。",o:["上に","かたわら","うちに","以上"],a:3,exp:"<b>〜以上</b>「dado que (es un hecho)」。"},
      {q:"（　）に　入れるのに　最も　よいものを、1・2・3・4から　一つ　選びなさい。　彼女の　才能（　）、成功は　時間の　問題だった。",o:["はおろか","にひきかえ","をもってすれば","ときたら"],a:2,exp:"<b>〜をもってすれば</b>「con (tal capacidad)」。"},
      {sec:"問題3　言い換え類義",q:"　　の　言葉に　意味が　最も　近いものを、1・2・3・4から　一つ　選びなさい。　彼の　説明は　<u>簡潔</u>だった。",o:["長く詳しい","短く要点をまとめている","感情的である","曖昧である"],a:1,exp:"<b>簡潔</b>≒「conciso」。"},
      {q:"　　の　言葉に　意味が　最も　近いものを、1・2・3・4から　一つ　選びなさい。　彼は　<u>あくまで</u>　反対した。",o:["仕方なく","最後まで、徹底的に","一時的に","少しだけ"],a:1,exp:"<b>あくまで</b>≒「hasta el final」。"},
      {q:"　　の　言葉に　意味が　最も　近いものを、1・2・3・4から　一つ　選びなさい。　彼は　状況を　<u>的確に</u>　判断した。",o:["遅れて","おおざっぱに","感情的に","正確に、適切に"],a:3,exp:"<b>的確に</b>≒「con precisión」。"},
      {q:"　　の　言葉に　意味が　最も　近いものを、1・2・3・4から　一つ　選びなさい。　彼の　意見は　<u>もっともだ</u>。",o:["理にかなっている","曖昧だ","間違っている","おかしい"],a:0,exp:"<b>もっともだ</b>≒「razonable」。"},
      {q:"　　の　言葉に　意味が　最も　近いものを、1・2・3・4から　一つ　選びなさい。　彼は　<u>やんわりと</u>　断った。",o:["穏やかに、遠回しに","急に","強く、はっきりと","何も言わずに"],a:0,exp:"<b>やんわりと</b>≒「con suavidad」。"},
      {q:"　　の　言葉に　意味が　最も　近いものを、1・2・3・4から　一つ　選びなさい。　彼女は　<u>したたかに</u>　交渉を　進めた。",o:["無計画に","率直に","巧妙に、抜け目なく","乱暴に"],a:2,exp:"<b>したたかに</b>≒「de forma astuta」。"},
      {sec:"問題4　用法",q:"次の　言葉の　使い方として　最も　よいものを、1・2・3・4から　一つ　選びなさい。「おもむろに」",o:["おもむろに走って逃げた。","おもむろに驚いて叫んだ。","彼はおもむろに立ち上がり、話し始めた。","おもむろに怒って机を叩いた。"],a:2,exp:"<b>おもむろに</b>＝「con calma」、動作が急でない文脈に合う。"},
      {q:"次の　言葉の　使い方として　最も　よいものを、1・2・3・4から　一つ　選びなさい。「いたって」",o:["いたって時々怒る。","いたって少し休んだ。","いたって急いで走った。","彼はいたって冷静だった。"],a:3,exp:"<b>いたって</b>＝「sumamente」、程度を強める副詞。"},
      {q:"次の　言葉の　使い方として　最も　よいものを、1・2・3・4から　一つ　選びなさい。「もはや」",o:["もはや後戻りはできない。","もはや明日また来る。","もはやまだ間に合う。","もはやこれから始まる。"],a:0,exp:"<b>もはや</b>＝「ya (irreversible)」、後戻りできない文脈に合う。"},
      {q:"次の　言葉の　使い方として　最も　よいものを、1・2・3・4から　一つ　選びなさい。「あたかも」",o:["彼はあたかも専門家であるかのように話した。","あたかも明日雨が降る。","あたかも早く終わった。","あたかも三時に会議がある。"],a:0,exp:"<b>あたかも〜かのように</b>＝「como si」の比喩表現。"},
      {q:"次の　言葉の　使い方として　最も　よいものを、1・2・3・4から　一つ　選びなさい。「ひとしお」",o:["合格の喜びはひとしおだった。","ひとしお三つ買った。","ひとしお静かな部屋だ。","ひとしお早く起きた。"],a:0,exp:"<b>ひとしお</b>＝「más aún, especialmente」感情の強調に使う。"},
      {q:"次の　言葉の　使い方として　最も　よいものを、1・2・3・4から　一つ　選びなさい。「なおさら」",o:["なおさら駅の近くだ。","なおさら明日晴れるだろう。","体調が悪いなら、なおさら休むべきだ。","なおさら三人来た。"],a:2,exp:"<b>なおさら</b>＝「con más razón todavía」。"},
      {sec:"問題5　文法1（文法形式の判断）",q:"次の文の（　）に　入れるのに　最も　よいものを、1・2・3・4から　一つ　選びなさい。　彼の　実力（　）、この　結果は　当然だ。",o:["をものともせず","からすれば","にひきかえ","はさておき"],a:1,exp:"<b>〜からすれば</b>「desde el punto de vista de」。"},
      {q:"次の文の（　）に　入れるのに　最も　よいものを、1・2・3・4から　一つ　選びなさい。　周囲の　反対（　）、彼は　計画を　実行した。",o:["といえども","にひきかえ","を押し切って","にもまして"],a:2,exp:"<b>〜を押し切って</b>「haciendo caso omiso de la oposición」。"},
      {q:"次の文の（　）に　入れるのに　最も　よいものを、1・2・3・4から　一つ　選びなさい。　彼の　業績は　賞賛（　）ものだ。",o:["に至る","に値する","にかかわる","にとどまる"],a:1,exp:"<b>〜に値する</b>「ser digno de」。"},
      {q:"次の文の（　）に　入れるのに　最も　よいものを、1・2・3・4から　一つ　選びなさい。　あの　選手は　若い（　）、驚くべき　精神力を　持っている。",o:["ながらも","こととて","なりに","とばかりに"],a:0,exp:"<b>〜ながらも</b>「aunque, si bien」。"},
      {q:"次の文の（　）に　入れるのに　最も　よいものを、1・2・3・4から　一つ　選びなさい。　失敗を　重ねた（　）、彼は　ようやく　成功を　つかんだ。",o:["なくして","すえに","かたわら","ところで"],a:1,exp:"<b>〜すえに</b>「tras (un largo proceso)」。"},
      {q:"次の文の（　）に　入れるのに　最も　よいものを、1・2・3・4から　一つ　選びなさい。　彼の　態度は　傲慢（　）ほかならない。",o:["に","と","の","で"],a:0,exp:"<b>〜にほかならない</b>「no es sino」。"},
      {q:"次の文の（　）に　入れるのに　最も　よいものを、1・2・3・4から　一つ　選びなさい。　この　問題は　議論すれば　する（　）、複雑さを　増す　ばかりだ。",o:["くらい","ほど","のみ","だけ"],a:1,exp:"<b>〜ば〜ほど</b>「cuanto más...más」。"},
      {q:"次の文の（　）に　入れるのに　最も　よいものを、1・2・3・4から　一つ　選びなさい。　彼は　疲れていた（　）、最後まで　やり遂げた。",o:["かたわら","ゆえに","とあって","にもかかわらず"],a:3,exp:"<b>〜にもかかわらず</b>「a pesar de」。"},
      {q:"次の文の（　）に　入れるのに　最も　よいものを、1・2・3・4から　一つ　選びなさい。　規模の　大小（　）、この　問題は　軽視できない。",o:["につき","を問わず","にそくして","にわたって"],a:1,exp:"<b>〜を問わず</b>「independientemente de」。"},
      {q:"次の文の（　）に　入れるのに　最も　よいものを、1・2・3・4から　一つ　選びなさい。　彼の　貢献（　）、この　プロジェクトは　成功しなかっただろう。",o:["はおろか","にひきかえ","ときたら","なくして"],a:3,exp:"<b>〜なくして（は）</b>「sin (algo), no habría sido posible」。"},
      {sec:"問題6　文法2（文の組み立て）",q:"次の文の　★　に　入る　最も　よいものを、1・2・3・4から　一つ　選びなさい。　彼女は　　___　___　★　___　　新記録を出した。（1 甲斐が　2 あって　3 何度も　4 練習した）",o:["甲斐が","練習した","何度も","あって"],a:0,exp:"正しい順序：3何度も→4練習した→1甲斐が→2あって「何度も練習した甲斐があって」。★の位置には<b>1「甲斐が」</b>が入る。"},
      {q:"次の文の　★　に　入る　最も　よいものを、1・2・3・4から　一つ　選びなさい。　彼の提案は　　___　___　★　___　　と思う。（1 実現可能性が　2 斬新である　3 低い　4 ものの）",o:["ものの","斬新である","低い","実現可能性が"],a:3,exp:"正しい順序：2斬新である→4ものの→1実現可能性が→3低い「斬新であるものの実現可能性が低い」。★の位置には<b>1「実現可能性が」</b>が入る。"},
      {q:"次の文の　★　に　入る　最も　よいものを、1・2・3・4から　一つ　選びなさい。　彼は　　___　___　★　___　　諦めなかった。（1 あっても　2 どんな　3 決して　4 逆境に）",o:["あっても","逆境に","どんな","決して"],a:0,exp:"正しい順序：2どんな→4逆境に→1あっても→3決して「どんな逆境にあっても決して」。★の位置には<b>1「あっても」</b>が入る。"},
      {q:"次の文の　★　に　入る　最も　よいものを、1・2・3・4から　一つ　選びなさい。　この結果は　　___　___　★　___　　産物だ。（1 より　2 偶然　3 必然の　4 という）",o:["という","偶然","より","必然の"],a:2,exp:"正しい順序：2偶然→4という→1より→3必然の「偶然というより必然の」。★の位置には<b>1「より」</b>が入る。"},
      {q:"次の文の　★　に　入る　最も　よいものを、1・2・3・4から　一つ　選びなさい。　　___　___　★　___　　プロジェクトの成功はなかった。（1 貢献　2 彼　3 なくして　4 の）",o:["の","なくして","彼","貢献"],a:3,exp:"正しい順序：2彼→4の→1貢献→3なくして「彼の貢献なくして」。★の位置には<b>1「貢献」</b>が入る。"},
      {sec:"問題7　文章文法",passage:"次の文章を読んで、文章全体の趣旨を踏まえて、（1）から（5）の中に入る最もよいものを、1・2・3・4から一つ選びなさい。<br><br>近年、リモートワークの普及（1）、働き方に対する人々の意識は大きく変化した。従来は「会社に行くこと」が当然とされてきたが、今では場所を（2）成果を出すことが重視されるようになっている。（3）、この変化にはよい面ばかりではない。同僚との偶発的な会話が減り、（4）連携が難しくなったという声も聞かれる。今後は、対面とリモートの利点を（5）働き方が模索されていくだろう。",q:"（1）",o:["にもまして","に伴い","にひきかえ","にとどまらず"],a:1,exp:"<b>〜に伴い</b>「conforme a、debido a」変化の原因を導く。"},
      {q:"（2）",o:["問われ","問い","問うと","問わず"],a:3,exp:"<b>〜を問わず</b>「independientemente de」。"},
      {q:"（3）",o:["しかし","そのうえ","ゆえに","したがって"],a:0,exp:"逆接の接続詞<b>しかし</b>が文脈に合う（よい面ばかりではない、という転換）。"},
      {q:"（4）",o:["部門間へ","部門間を","部門間の","部門間で"],a:2,exp:"「連携」を修飾する連体修飾語には<b>の</b>が適切。"},
      {q:"（5）",o:["生かして","生かした","生かせば","生かすなら"],a:1,exp:"「生かした働き方」＝両方の利点を取り入れた働き方、連体修飾として自然。"},
      {sec:"問題8　内容理解（短文）",passage:"近年、企業の意思決定にデータ分析を活用する動きが加速している。ただし、データに過度に依存するあまり、現場の経験や直感に基づく判断が軽視される傾向も見られ、両者のバランスが課題となっている。",q:"筆者が課題として指摘していることは何か。",o:["経験や直感の完全な排除","意思決定の遅さ","データ分析の技術不足","データと経験・直感のバランス"],a:3,exp:"「両者のバランスが課題」がそのまま答え。"},
      {passage:"言葉は常に変化し続けるものである。新しい表現の誕生を「乱れ」と断じるのは早計であり、むしろ言語の生命力の証と見るべきだろう。",q:"筆者の考えに最も近いものはどれか。",o:["言葉は変化すべきではない","言葉の乱れは深刻な問題だ","新しい表現は言語の生命力の証だ","新しい表現は正すべき誤りだ"],a:2,exp:"「言語の生命力の証と見るべきだろう」が筆者の主張。"},
      {passage:"組織におけるリーダーシップとは、単に指示を出す能力ではなく、メンバーそれぞれの強みを引き出し、全体としての成果を最大化する力を指すと言えよう。",q:"筆者が定義するリーダーシップとは何か。",o:["権威を持って統率する力","メンバーの強みを引き出し成果を最大化する力","指示を的確に出す能力","失敗を許さない厳格さ"],a:1,exp:"「メンバーそれぞれの強みを引き出し…最大化する力」が定義。"},
      {passage:"効率のみを追求する社会は、一見合理的に見えるが、そこから零れ落ちるものの大きさに気づくべきである。数値化できない価値にこそ、目を向ける必要があるのではないか。",q:"筆者の主張として最も適切なものはどれか。",o:["数値化できない価値にも目を向けるべきだ","合理性を否定すべきだ","効率の追求こそが最も重要だ","数値化は無意味である"],a:0,exp:"「数値化できない価値にこそ、目を向ける必要がある」が主張。"},
      {sec:"問題9　内容理解（中文）",passage:"匿名性がもたらす自由と、それに伴う責任の所在の曖昧さは、表裏一体の関係にある。インターネット社会においてこの均衡をどう保つかが、今後一層重要な課題となるだろう。一方で、匿名性を完全に排除することは、自由な言論の萎縮を招く危険もはらんでいる。要は、両者のバランスをいかに設計するかという、制度上の工夫が問われているのである。",q:"筆者が指摘する課題は何か。",o:["責任の所在を明確にする法整備のみ","匿名性を完全に排除すること","インターネットの利用を制限すること","自由と責任のバランスをどう保つか"],a:3,exp:"「この均衡をどう保つかが…重要な課題」がそのまま答え。"},
      {q:"匿名性を完全に排除することについて、筆者はどう考えているか。",o:["積極的に進めるべきだ","自由な言論を萎縮させる危険がある","何の問題もない","既に実現されている"],a:1,exp:"「自由な言論の萎縮を招く危険もはらんでいる」がそのまま答え。"},
      {q:"筆者が最終的に求めているものは何か。",o:["法律による一律の規制","匿名性の完全な廃止","匿名性の完全な保証","バランスを設計する制度上の工夫"],a:3,exp:"「両者のバランスをいかに設計するかという、制度上の工夫が問われている」が結論。"},
      {passage:"伝統を守ることと、時代に合わせて変化すること。この二つは一見相反するようでいて、実は共存しうるものである。表面的な形は変わっても、その核となる精神が受け継がれていれば、それは立派な継承と呼べよう。逆に、形式だけを頑なに守り続け、本質的な精神を見失ってしまえば、それはもはや形骸化した儀式にすぎない。",q:"筆者は伝統の継承をどう捉えているか。",o:["形が変わっても精神が受け継がれれば継承と呼べる","形を絶対に変えてはならない","伝統は時代とともに消えるべきだ","精神より形式を重視すべきだ"],a:0,exp:"「その核となる精神が受け継がれていれば…継承と呼べよう」が主張。"},
      {q:"筆者が「形骸化した儀式」と呼ぶのはどのような状態か。",o:["伝統が完全に消えた状態","形式だけを守り精神を見失った状態","新しい伝統が生まれた状態","精神だけを重視し形式を捨てた状態"],a:1,exp:"「形式だけを頑なに守り続け、本質的な精神を見失ってしまえば」がそのまま該当。"},
      {q:"この文章全体の要旨として最も適切なものはどれか。",o:["時代の変化を伝統より優先すべきだ","伝統は一切変えるべきではない","伝統の継承には形式よりも精神の連続性が重要だ","形式と精神は無関係である"],a:2,exp:"文章全体を通して「核となる精神」の重要性を訴えている。"},
      {passage:"議論において重要なのは、相手を論破することではなく、互いの前提の違いを明らかにし、そこから建設的な合意点を探ることである。勝敗にこだわる姿勢からは、実りある対話は生まれない。むしろ、自分の意見が変わることを恐れず、相手の主張の妥当な部分を認める柔軟さこそが、質の高い議論を支える土台となる。",q:"筆者が重要だと述べていることは何か。",o:["前提の違いを明らかにし合意点を探ること","議論に勝つこと","自分の意見を貫くこと","相手を論破すること"],a:0,exp:"「互いの前提の違いを明らかにし、そこから建設的な合意点を探る こと」が重要だと述べている。"},
      {q:"筆者が「質の高い議論」を支える土台としているものは何か。",o:["相手の主張の妥当な部分を認める柔軟さ","勝敗にこだわる姿勢","自分の意見を変えない強さ","相手を論破する技術"],a:0,exp:"「相手の主張の妥当な部分を認める柔軟さこそが…土台となる」がそのまま答え。"},
      {q:"筆者は「勝敗にこだわる姿勢」についてどう述べているか。",o:["質の高い議論に不可欠だ","対話の基本条件だ","時には必要である","実りある対話を生まない"],a:3,exp:"「勝敗にこだわる姿勢からは、実りある対話は生まれない」がそのまま答え。"},
      {sec:"問題10　内容理解（長文）",passage:"科学技術の進歩は人類に多大な恩恵をもたらしてきたが、同時に新たな倫理的課題も生み出してきた。遺伝子操作技術の発展により、病気の予防や治療の可能性は大きく広がった。しかし、その一方で、どこまでの操作が許容されるのか、生命そのものをどう扱うべきかという根本的な問いが突きつけられている。<br><br>技術的に可能であることと、倫理的に許容されることは、必ずしも一致しない。この乖離をどう埋めるかは、科学者だけの問題ではなく、社会全体で議論すべき課題である。専門家の知見に基づきつつも、一般市民が議論に参加できる仕組みづくりが求められている。<br><br>技術の可能性と社会が許容すべき範囲との線引きを、我々は常に問い続ける必要がある。それは、答えが一度出れば終わる問いではなく、技術が進歩し続ける限り、絶えず更新されていくべき問いなのである。",q:"筆者が指摘する根本的な問いとは何か。",o:["遺伝子操作の技術的な難しさ","科学者の倫理観の欠如","病気の治療法の開発速度","生命をどこまで操作してよいかという問い"],a:3,exp:"「どこまでの操作が許容されるのか、生命そのものをどう扱うべきかという根本的な問い」がそのまま答え。"},
      {q:"「技術的に可能であることと、倫理的に許容されることは、必ずしも一致しない」とはどういうことか。",o:["両者は完全に一致している","倫理は技術の発展を妨げるだけだ","技術でできることが常に倫理的に正しいとは限らない","技術は常に倫理を超えて発展すべきだ"],a:2,exp:"技術的可能性と倫理的許容性の乖離を指摘した文。"},
      {q:"筆者が求めている仕組みとはどのようなものか。",o:["技術開発を止める仕組み","一般市民が議論に参加できる仕組み","法律で一律に禁止する仕組み","専門家だけで完結する仕組み"],a:1,exp:"「一般市民が議論に参加できる仕組みづくりが求められている」がそのまま答え。"},
      {q:"筆者が訴えていることは何か。",o:["科学技術の発展を止めるべきだということ","技術の恩恵のみを重視すべきこと","倫理的課題は存在しないということ","技術の可能性と社会的許容の線引きを問い続ける必要性"],a:3,exp:"「線引きを、我々は常に問い続ける必要がある」が結論。"},
      {sec:"問題11　統合理解",passage:"【A】在宅勤務の普及は、通勤時間の削減や柔軟な働き方を可能にし、多くの労働者から歓迎されている。特に育児や介護と仕事の両立を目指す人々にとって、その恩恵は大きい。企業側もオフィスコストの削減という利点を享受しており、双方にとって望ましい変化と言えるだろう。<br><br>【B】しかし、在宅勤務には見過ごせない課題もある。同僚との偶発的な交流が失われることで、新しいアイデアが生まれにくくなったという指摘や、若手社員が先輩の仕事ぶりを間近で観察する機会が減り、育成が滞っているという声も聞かれる。効率だけでは測れない価値が、静かに失われているのかもしれない。",q:"Aの筆者が在宅勤務について述べていることは何か。",o:["企業のコストが増加している","労働者にも企業にも恩恵がある望ましい変化だ","従来の働き方に戻すべきだ","育児や介護との両立は不可能だ"],a:1,exp:"Aは「双方にとって望ましい変化」と肯定的に評価している。"},
      {q:"Bの筆者が懸念していることは何か。",o:["通勤時間の増加","企業コストの増加","偶発的な交流の減少による弊害","労働時間の増加"],a:2,exp:"Bは「偶発的な交流が失われる」ことによる弊害を懸念している。"},
      {q:"AとBの筆者に共通する視点は何か。",o:["在宅勤務は完全に否定すべきだ","企業は在宅勤務を禁止すべきだ","在宅勤務に課題は存在しない","在宅勤務には利点と課題の両面がある"],a:3,exp:"Aは利点、Bは課題を強調しているが、両者とも在宅勤務がもたらす変化の両面性を扱っている。"},
      {sec:"問題12　主張理解（長文）",passage:"教育の目的は、知識の詰め込みではなく、自ら考え、判断する力を養うことにあると言えよう。試験の点数のみで学びの成果を測ろうとする姿勢は、この本質を見誤らせる危険をはらんでいる。<br><br>もちろん、基礎知識の習得は不可欠であり、それなしには思考の材料そのものが不足してしまう。しかし、知識を「持っていること」と、それを「使いこなせること」の間には大きな隔たりがある。教育現場では、この二つを混同し、前者のみを評価する傾向が根強く残っているのではないか。<br><br>真に求められているのは、既知の知識を新しい状況に応用し、未知の問題に対して自分なりの答えを導き出す力である。そのためには、正解が一つに定まらない問いに向き合う経験を、教育の中により多く取り入れていく必要があるだろう。",q:"筆者が危惧していることは何か。",o:["試験制度そのものの廃止","知識の詰め込みが不十分であること","基礎知識の習得が不要になること","試験の点数のみで学びを測ることが本質を見誤らせること"],a:3,exp:"「試験の点数のみで…測ろうとする姿勢は…本質を見誤らせる危険」がそのまま答え。"},
      {q:"筆者は基礎知識の習得についてどう考えているか。",o:["試験でのみ評価すべきだ","思考の材料として不可欠である","知識より応用力のほうが先に必要だ","不要であり廃止すべきだ"],a:1,exp:"「基礎知識の習得は不可欠であり、それなしには思考の材料そのものが不足してしまう」と述べている。"},
      {q:"筆者が「大きな隔たりがある」と述べているのは何と何の間か。",o:["基礎教育と応用教育","教師と生徒","知識を持っていることと使いこなせること","試験の点数と実際の能力"],a:2,exp:"「知識を『持っていること』と、それを『使いこなせること』の間には大きな隔たりがある」がそのまま答え。"},
      {q:"筆者が教育に取り入れるべきだと述べているのはどのような経験か。",o:["正解が一つに定まらない問いに向き合う経験","試験で高得点を取る経験","知識を暗記する経験","教師の話を聞くだけの経験"],a:0,exp:"「正解が一つに定まらない問いに向き合う経験を…取り入れていく必要がある」がそのまま答え。"},
      {sec:"問題13　情報検索",passage:"【日本語スピーチコンテスト　参加案内】<br>・対象：日本語を学習する外国人（国籍不問、レベル制限なし）<br>・部門：初級の部（学習歴1年未満）／中上級の部（学習歴1年以上）<br>・持ち時間：各部門とも3分以内（超過した場合、減点対象）<br>・申込方法：ウェブサイトの申込フォームより、10月15日（水）までに登録。学習歴の証明は不要。<br>・当日の流れ：受付は開始30分前から。初級の部から開始し、その後、休憩を挟んで中上級の部を行う。<br>・表彰：各部門、上位3名に賞状と副賞を贈呈。参加者全員に参加証を発行。<br>・注意事項：原稿の持ち込みは可。ただし、原稿を読み上げるだけのスピーチは減点対象となる場合がある。",q:"学習歴8か月の人が参加する場合、当てはまるのはどれか。",o:["両方の部門に申し込める","初級の部に申し込み、学習歴の証明書類は不要","中上級の部に申し込み、証明書類が必要","参加資格がない"],a:1,exp:"学習歴1年未満は初級の部。「学習歴の証明は不要」なので証明書類は不要。"},
      {q:"この案内から分かることとして正しいものはどれか。",o:["参加者は上位者しか参加証をもらえない","中上級の部が先に行われる","持ち時間を超過すると減点される可能性がある","原稿を見ながら話すことは一切禁止されている"],a:2,exp:"「超過した場合、減点対象」がそのまま該当。原稿持ち込みは可、初級が先、参加証は全員分発行。"}
    ]},
    {id:"b", title:"聴解", minutes:55, questions:[
      {sec:"問題1　課題理解",audio:"女：来週の会議室の予約なんですが、金曜日の午後はもう埋まっていますね。木曜日の午後なら空いていますが、いかがですか。　男：じゃあ、木曜日でお願いします。あ、資料の印刷もお願いできますか。十部お願いします。　女：分かりました。",q:"女の人はこのあと、まず何をしますか。",o:["資料を十部印刷する","会議の議題を考える","会議室を金曜日に予約する","参加者に連絡する"],a:0,exp:"男性が最後に頼んだのは「資料の印刷、十部」。会議室は木曜に決定済みで、次にすべき行動は印刷。"},
      {audio:"男：すみません、この荷物、宅配便で送りたいんですが。　女：サイズと重さを測りますので、少々お待ちください。あと、伝票にご住所とお名前をご記入ください。　男：はい、分かりました。",q:"男の人はこのあと、まず何をしますか。",o:["荷物のサイズを測る","伝票に住所と名前を書く","料金を支払う","荷物を持ち帰る"],a:1,exp:"店員が「伝票にご住所とお名前をご記入ください」と依頼しており、客が次にすべき行動はそれ。サイズ測定は店員側の作業。"},
      {audio:"女：来週の出張ですが、飛行機と新幹線、どちらがいいですか。　男：時間がないので、飛行機にしましょう。あ、それと、ホテルの予約もお願いできますか。　女：かしこまりました。",q:"女の人はこのあと、まず何をしますか。",o:["新幹線の切符を買う","飛行機を予約する","出張の日程を決める","ホテルを予約する"],a:3,exp:"最後に依頼されたのは「ホテルの予約」。飛行機はすでに決定済みで、次の行動はホテル予約。"},
      {audio:"男：新入社員の研修ですが、三日間の予定でよろしいですか。　女：ええ、それでお願いします。あ、初日の午前中は会社説明にして、午後から工場見学にしてもらえますか。　男：承知しました。",q:"男の人はこのあと、まず何をしますか。",o:["三日間の研修を中止する","工場見学を中止する","研修初日の予定を組み直す","会社説明を省略する"],a:2,exp:"女性の依頼「初日の午前を会社説明、午後を工場見学に」を受けて、男性が予定を組み直す必要がある。"},
      {audio:"女：この資料、明日の会議までに仕上げないといけないんですが、手伝ってもらえますか。　男：いいですよ。どこまで進んでいますか。　女：グラフはできているので、あとは文章の部分をお願いできますか。",q:"男の人はこのあと、何をしますか。",o:["資料を印刷する","資料の文章の部分を書く","グラフを作成する","会議の日程を確認する"],a:1,exp:"「文章の部分をお願いできますか」と頼まれているので、男性は文章部分を担当する。"},
      {sec:"問題2　ポイント理解",audio:"男：今回のプロジェクト、予定より遅れていますね。原因は何だと思いますか。　女：人手不足も一因ですが、一番大きいのは仕様変更が何度もあったことだと思います。最初の設計をやり直す必要が出てしまって。",q:"女の人は、プロジェクトが遅れている一番の原因は何だと言っていますか。",o:["予算が足りないこと","設計者が交代したこと","仕様変更が何度もあったこと","人手が不足していること"],a:2,exp:"「一番大きいのは仕様変更が何度もあったこと」がそのまま答え。人手不足は一因に過ぎない。"},
      {audio:"女：新しい店舗の場所、駅前と郊外のショッピングモール、どちらにしますか。　男：家賃は駅前の方が高いですが、集客力を考えると駅前の一択でしょう。長い目で見れば、その方が採算が取れると思います。",q:"男の人が駅前を選ぶ一番の理由は何ですか。",o:["面積が広いから","駅から近く通勤が楽だから","集客力が高く長期的に採算が取れるから","家賃が安いから"],a:2,exp:"「集客力を考えると…長い目で見れば、その方が採算が取れる」が理由。家賃は逆に駅前の方が高いと述べている。"},
      {audio:"男：今度の講演会、参加者が少なかったですね。　女：告知の時期が遅かったのが一番の問題だったと思います。会場や講師には問題なかったんですが。",q:"女の人は、参加者が少なかった一番の原因は何だと言っていますか。",o:["講師の話がつまらなかったこと","告知の時期が遅かったこと","日程が悪かったこと","会場が悪かったこと"],a:1,exp:"「告知の時期が遅かったのが一番の問題」がそのまま答え。"},
      {audio:"女：新商品の売り上げ、思ったほど伸びていませんね。　男：価格設定は問題ないと思うんですが、広告の打ち方が弱かったんじゃないかと。ターゲット層にうまく届いていない気がします。",q:"男の人は、売り上げが伸びない一番の原因は何だと考えていますか。",o:["競合が多いこと","価格が高すぎること","商品の品質が悪いこと","広告がターゲット層に届いていないこと"],a:3,exp:"「広告の打ち方が弱かった…ターゲット層にうまく届いていない」が原因として挙げられている。"},
      {audio:"男：来期の予算案、営業部からの要望が通らなかったようですね。　女：全社的にコスト削減の方針が出ていて、どの部署も一律で減らされることになったみたいです。営業部だけの問題ではないようです。",q:"営業部の要望が通らなかった一番の理由は何ですか。",o:["営業部の実績が悪かったから","予算案の書き方が悪かったから","全社的なコスト削減方針があったから","他部署の予算が優先されたから"],a:2,exp:"「全社的にコスト削減の方針が出ていて…一律で減らされる」がそのまま理由。"},
      {audio:"女：この機械、最近よく故障しますね。　男：使用年数もありますが、それより湿度の高い環境で使い続けたことが大きいと思います。想定されていた使用環境と違ったんでしょう。",q:"男の人は、機械が故障する一番の原因は何だと考えていますか。",o:["使用年数が長いこと","湿度の高い環境で使い続けたこと","部品の品質が悪いこと","操作方法が間違っていたこと"],a:1,exp:"「それより湿度の高い環境で使い続けたことが大きい」が原因として挙げられている。"},
      {sec:"問題3　概要理解",audio:"最近、企業の間で、従業員の副業を認める動きが広がっている。従業員のスキルアップにつながるという期待がある一方、本業への影響を懸念する声も根強い。人事担当者たちは、両者のバランスをどう取るか、模索を続けている。",q:"この話は、主に何について述べていますか。",o:["副業を完全に禁止する企業が増えていること","従業員の給料が下がっていること","企業が副業解禁のバランスに悩んでいること","企業の人事制度が廃止されたこと"],a:2,exp:"副業を認める動きと、その影響への懸念、バランスの模索が主題。"},
      {audio:"言葉というものは、時代とともに変化していくものである。若者の間で生まれる新しい表現を「乱れ」だと批判する声もあるが、それもまた言語が生きている証だと捉えることもできるのではないだろうか。",q:"この話は、主に何について述べていますか。",o:["言葉の変化についての一つの見方","若者言葉の具体的な例","正しい日本語の使い方の解説","言語教育の方法"],a:0,exp:"言葉の変化を肯定的に捉える視点についての話。"},
      {audio:"睡眠不足は、集中力の低下だけでなく、長期的には健康にも悪影響を及ぼすとされる。忙しい現代人にとって睡眠時間を確保することは簡単ではないが、その重要性が改めて見直されている。",q:"この話は、主に何について述べていますか。",o:["忙しさの原因","睡眠の重要性が見直されていること","健康診断の必要性","効率的な仕事の進め方"],a:1,exp:"睡眠不足の悪影響と、その重要性の見直しが主題。"},
      {audio:"地方都市では、若者の人口流出が長年の課題となってきた。しかし近年、リモートワークの普及により、都市部の仕事を続けながら地方に移住するという新しい選択肢を選ぶ人が増えているという。",q:"この話は、主に何について述べていますか。",o:["若者の就職難","リモートワークによる地方移住という新しい動き","地方都市の人口減少の原因","都市部の住宅事情"],a:1,exp:"リモートワークをきっかけとした地方移住という新しい選択肢についての話。"},
      {audio:"効率を追い求めるあまり、余白や無駄とされてきたものの中にあった価値まで失われつつあるのではないか、という指摘がある。適度な余裕こそが、新しい発想を生む土壌になるという考え方も広がっている。",q:"この話は、主に何について述べていますか。",o:["効率化の技術的な方法","過度な効率化が創造性を損なう可能性","余暇時間の過ごし方","労働時間の短縮策"],a:1,exp:"効率化の行き過ぎが創造性を損なう恐れについての話。"},
      {sec:"問題4　即時応答",audio:"この件について、少し確認させていただけますか。",q:"最もよい返答はどれですか。",o:["はい、どうぞ。","もう終わりました。","それは残念ですね。","いいえ、まだです。"],a:0,exp:"確認の申し出に対して自然な返答は「はい、どうぞ」。"},
      {audio:"申し訳ございませんが、本日中の対応は難しい状況です。",q:"最もよい返答はどれですか。",o:["では、いつ頃なら可能でしょうか。","おめでとうございます。","はい、すぐやります。","それは良かったです。"],a:0,exp:"対応が難しいという連絡への自然な返答は、代替案を尋ねる「では、いつ頃なら可能でしょうか」。"},
      {audio:"この資料、ちょっと目を通していただけますか。",q:"最もよい返答はどれですか。",o:["もう捨てました。","いいえ、要りません。","それはおめでとうございます。","はい、拝見します。"],a:3,exp:"資料を確認してほしいという依頼への自然な返答は「はい、拝見します」。"},
      {audio:"恐れ入りますが、少々お待ちいただけますでしょうか。",q:"最もよい返答はどれですか。",o:["それはすごいですね。","はい、かしこまりました。","いいえ、待てません。","もう終わりです。"],a:1,exp:"待ってほしいという依頼への自然な返答は「はい、かしこまりました」。"},
      {audio:"この度は大変ご迷惑をおかけし、申し訳ございませんでした。",q:"最もよい返答はどれですか。",o:["もっとやってください。","おめでとうございます。","それは嬉しいです。","いえ、こちらこそ確認不足がありました。"],a:3,exp:"謝罪への自然な返答として、相手を責めずに応じる「いえ、こちらこそ」が適切。"},
      {audio:"来週の予定、変更になる可能性があります。",q:"最もよい返答はどれですか。",o:["分かりました。決まり次第教えてください。","おめでとうございます。","それは羨ましいです。","もう変更しました。"],a:0,exp:"予定変更の可能性を知らされた自然な返答は「決まり次第教えてください」。"},
      {audio:"この企画、正直あまり自信がないんです。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","どの部分が気になりますか。一緒に考えましょう。","もうやめましょう。","それはよかったですね。"],a:1,exp:"不安を打ち明けられた際の自然な返答は、具体的に寄り添う「どの部分が気になりますか」。"},
      {audio:"この書類、ハンコを押していただけますか。",q:"最もよい返答はどれですか。",o:["はい、こちらに押しますね。","それは大変ですね。","もう押されています。","いいえ、書きません。"],a:0,exp:"押印の依頼への自然な返答は「はい、こちらに押しますね」。"},
      {audio:"すみません、少し声が小さくて聞き取れませんでした。",q:"最もよい返答はどれですか。",o:["もう聞こえています。","おめでとうございます。","それは残念ですね。","失礼しました。もう一度お伝えします。"],a:3,exp:"聞き取れなかったという指摘への自然な返答は「もう一度お伝えします」。"},
      {audio:"この案で進めてもよろしいでしょうか。",q:"最もよい返答はどれですか。",o:["はい、それでお願いします。","もう終わった話です。","それはすごいですね。","いいえ、まだ始まっていません。"],a:0,exp:"承認を求められた際の自然な返答は「はい、それでお願いします」。"},
      {audio:"何かお手伝いできることがあれば言ってください。",q:"最もよい返答はどれですか。",o:["それは大変でしたね。","もう大丈夫だったんです。","ありがとうございます。では、これをお願いできますか。","おめでとうございます。"],a:2,exp:"手伝いの申し出への自然な返答は、感謝したうえで具体的に依頼する流れ。"},
      {sec:"問題5　統合理解",audio:"司会：新しいオフィスのレイアウトについて、三つの案が出ています。それぞれの意見を聞きましょう。<br>男性A：私はオープンスペース案がいいと思います。部署間のコミュニケーションが活発になりますし、コストも抑えられます。<br>女性：私は個室中心の案を推します。集中して作業したいという社員の声も多いですし、機密情報を扱う部署もありますから。<br>男性B：私はその中間の、半個室のブース形式がいいと思います。ある程度の集中力も保てますし、コストもオープン案ほどではないですが、個室案よりは抑えられます。<br>司会：なるほど。それでは、コストと集中力のバランスを重視して、ブース形式で進めることにしましょう。",q:"最終的にどの案で進めることになりましたか。",o:["ブース形式の案","三つの案を組み合わせた新しい案","個室中心の案","オープンスペース案"],a:0,exp:"司会が最後に「ブース形式で進めることにしましょう」と決定している。"},
      {q:"女性が個室中心の案を推した理由は何ですか。",o:["コストが最も安いから","部署間の交流を増やすため","男性Aの意見に賛成だったから","集中したい社員の声や機密情報への配慮"],a:3,exp:"「集中して作業したいという社員の声…機密情報を扱う部署もある」が理由。"},
      {audio:"司会：来年の新入社員研修について、三つの案があります。<br>男性A：私は座学中心の研修がいいと思います。基礎知識をしっかり身につけさせるべきです。<br>女性：私は実地研修を増やすべきだと思います。現場での経験がないと、座学だけでは実践力が身につきません。<br>男性B：両方を組み合わせて、午前は座学、午後は実地という形にするのはどうでしょうか。バランスが取れると思います。<br>司会：それでは、午前座学・午後実地の組み合わせ案で進めましょう。",q:"最終的にどの案で進めることになりましたか。",o:["案がまとまらなかった","座学中心の案","実地研修中心の案","午前座学・午後実地の組み合わせ案"],a:3,exp:"司会が「午前座学・午後実地の組み合わせ案で進めましょう」と決定している。"}
    ]}
  ]
},
{
  id:"o-n1-2", lvl:"N1", title:"Examen oficial N1 · 2", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙・文法）・読解", minutes:110, questions:[
      {sec:"問題1　漢字読み",q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　彼の意見は極めて<u>妥当</u>だ。",o:["だとう","だどう","たとう","たどう"],a:0,exp:"妥当→だとう「razonable」。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　両者の主張は<u>相反</u>している。",o:["あいはん","あいそう","そうへん","そうはん"],a:0,exp:"相反→あいはん「mutuamente contradictorio」。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　彼女は冷静さを<u>失わず</u>に対応した。",o:["うしないず","しっしず","しつわず","うしなわず"],a:3,exp:"失わず→うしなわず「sin perder」。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　彼の発言は<u>波紋</u>を呼んだ。",o:["はもん","なみもん","はぶん","はんもん"],a:0,exp:"波紋→はもん「onda expansiva、repercusión」。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　この提案には<u>難点</u>がある。",o:["なんてん","なんでん","なんてい","かたてん"],a:0,exp:"難点→なんてん「punto problemático」。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　新しい制度が<u>導入</u>された。",o:["どうにゅう","どうい","どうにゅ","とうにゅう"],a:0,exp:"導入→どうにゅう「introducción」。"},
      {sec:"問題2　文脈規定",q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼の話は具体性に（　）、説得力に欠ける。",o:["欠け","欠く","欠かず","欠いて"],a:0,exp:"連用中止形「欠け」で文をつなぐ。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　規則に反する（　）、罰則が科される。",o:["次第では","場合には","ものは","につれ"],a:1,exp:"〜場合には「en caso de」。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼は部長（　）、部下からの信頼も厚い。",o:["にしたら","というより","でありながら","にとって"],a:2,exp:"〜でありながら「siendo, a pesar de ser」。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　予算の都合（　）、計画の一部を見直した。",o:["上は","上で","上に","上"],a:3,exp:"〜上「desde el punto de vista de」。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼女は若手（　）、堂々とした態度で発表した。",o:["にひきかえ","ときたら","でありながら","はおろか"],a:2,exp:"〜でありながら「a pesar de ser」。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼の実績（　）、この昇進は妥当だろう。",o:["にひきかえ","をよそに","に照らせば","はおろか"],a:2,exp:"〜に照らせば「a la luz de」。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼は反対意見（　）、自説を曲げなかった。",o:["にひきかえ","をよそに","といえども","にもまして"],a:1,exp:"〜をよそに「haciendo caso omiso de」。"},
      {sec:"問題3　言い換え類義",q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　彼の主張は説得力に<u>乏しい</u>。",o:["一貫している","豊富だ","少ない、欠けている","極端だ"],a:2,exp:"乏しい≒「escaso」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　その計画は早くも<u>頓挫</u>した。",o:["縮小された","行き詰まった","成功した","延期された"],a:1,exp:"頓挫する≒「estancarse」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　彼女の意見は<u>的を射て</u>いる。",o:["曖昧である","間違っている","要点を突いている","感情的である"],a:2,exp:"的を射る≒「dar en el clavo」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　彼は<u>いたって</u>冷静だった。",o:["時々","少し","非常に","急に"],a:2,exp:"いたって≒「sumamente」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　彼は<u>もはや</u>若くない。",o:["すでに、今となっては","決して","まだ","たぶん"],a:0,exp:"もはや≒「ya (irreversible)」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　彼女は<u>あくまで</u>反対した。",o:["最後まで、徹底的に","仕方なく","少しだけ","一時的に"],a:0,exp:"あくまで≒「hasta el final」。"},
      {sec:"問題4　用法",q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「ひとしお」",o:["ひとしお三つ買った。","ひとしお静かな部屋だ。","ひとしお早く起きた。","合格の喜びはひとしおだった。"],a:3,exp:"ひとしお＝「más aún、especialmente」感情の強調。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「なおさら」",o:["なおさら三人来た。","なおさら明日晴れるだろう。","体調が悪いなら、なおさら休むべきだ。","なおさら駅の近くだ。"],a:2,exp:"なおさら＝「con más razón」。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「あたかも」",o:["あたかも早く終わった。","彼はあたかも専門家であるかのように話した。","あたかも三時に会議がある。","あたかも明日雨が降る。"],a:1,exp:"あたかも〜かのように＝「como si」。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「おのずから」",o:["結果は努力次第でおのずから明らかになる。","おのずから走って逃げた。","おのずから三時に来た。","おのずから怒って叫んだ。"],a:0,exp:"おのずから＝「por sí solo, de forma natural」。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「いわんや」",o:["大人でも難しいのだから、いわんや子供にはできない。","いわんや三時に会議がある。","いわんや早く終わった。","いわんや明日晴れるだろう。"],a:0,exp:"いわんや＝「y ni qué decir de」より極端な例を導く。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「よもや」",o:["よもや彼が裏切るとは思わなかった。","よもや早く終わった。","よもや明日雨が降る。","よもや三時に会議がある。"],a:0,exp:"よもや〜ないだろう＝「no creo que… (con sorpresa)」。"},
      {sec:"問題5　文法1（文法形式の判断）",q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　社員の声を反映する（　）、制度を見直した。",o:["かねて","べく","がてら","もかまわず"],a:1,exp:"〜べく「con el fin de」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　周囲の反対を（　）、彼は計画を実行した。",o:["めぐって","かねて","押し切って","もとに"],a:2,exp:"〜を押し切って「haciendo caso omiso de」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　経験の有無に（　）、誰でも参加できる。",o:["わたって","かかわらず","こたえて","そって"],a:1,exp:"〜にかかわらず「independientemente de」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　失敗を重ねた（　）、彼はようやく成功をつかんだ。",o:["なくして","かたわら","すえに","ところで"],a:2,exp:"〜すえに「tras un largo proceso」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　規則を破った（　）、罰せられるのは当然だ。",o:["かたわら","上に","うちに","以上"],a:3,exp:"〜以上「dado que」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼女の才能（　）、成功は時間の問題だった。",o:["ときたら","をもってすれば","にひきかえ","はおろか"],a:1,exp:"〜をもってすれば「con tal capacidad」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　この結果は偶然（　）必然の産物だ。",o:["というもの","といえども","というより","というのに"],a:2,exp:"〜というより「más que」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼の貢献（　）、この成功はなかっただろう。",o:["なくして","はおろか","ときたら","にひきかえ"],a:0,exp:"〜なくして（は）「sin (algo)、no habría sido posible」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　規模の大小（　）、この問題は軽視できない。",o:["につき","にそくして","にわたって","を問わず"],a:3,exp:"〜を問わず「independientemente de」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼は逆境（　）、決して諦めなかった。",o:["ときたら","はおろか","にあっても","にひきかえ"],a:2,exp:"〜にあっても「incluso estando en (situación adversa)」。"},
      {sec:"問題6　文法2（文の組み立て）",q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　彼は　___　___　★　___　最後までやり遂げた。（1 にもかかわらず　2 疲れて　3 いた　4 も）",o:["いた","疲れて","も","にもかかわらず"],a:3,exp:"正しい順序：2疲れて→3いた→4も→1にもかかわらず「疲れていたにもかかわらず」。★の位置には1「にもかかわらず」が入る。"},
      {q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　この問題は　___　___　★　___　複雑さを増すばかりだ。（1 する　2 議論すれば　3 ほど　4 だけ）",o:["だけ","議論すれば","ほど","する"],a:2,exp:"正しい順序：2議論すれば→1する→3ほど「議論すればするほど」。★の位置には3「ほど」が入る。"},
      {q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　彼女は　___　___　★　___　見事な対応を見せた。（1 経験の　2 をものともせず　3 乏しさ　4 も）",o:["乏しさ","経験の","をものともせず","も"],a:2,exp:"正しい順序：1経験の→3乏しさ→2をものともせず「経験の乏しさをものともせず」。★の位置には2「をものともせず」が入る。"},
      {q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　彼の　___　★　___　___　この成功はなかっただろう。（1 貢献　2 なくして　3 も　4 は）",o:["なくして","貢献","も","は"],a:0,exp:"正しい順序：1貢献→2なくして「彼の貢献なくして」。★の位置には2「なくして」が入る。"},
      {q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　この結果は　___　___　★　___　産物だ。（1 という　2 偶然　3 より　4 必然の）",o:["必然の","より","偶然","という"],a:1,exp:"正しい順序：2偶然→1という→3より→4必然の「偶然というより必然の」。★の位置には3「より」が入る。"},
      {sec:"問題7　文章文法",passage:"次の文章を読んで、文章全体の趣旨を踏まえて、（1）から（5）の中に入る最もよいものを、1・2・3・4から一つ選びなさい。<br><br>効率化が叫ばれる現代社会において、あらゆる無駄が排除されるべきだという風潮が強まっている。しかし、この考え方（1）、見落とされているものがあるのではないか。一見無駄に見える雑談や余白（2）、新しいアイデアが生まれることも少なくない。（3）、効率を追求するあまり、こうした偶発的な創造性の芽まで摘み取ってしまう危険がある。もちろん、無駄を完全に肯定するわけではない。（4）、適度な余裕を持つことの価値を、改めて見直す必要があるということだ。効率と余白、この両者の（5）こそが、これからの時代に求められているのだろう。",q:"（1）",o:["でも","には","なら","とは"],a:1,exp:"〜には「en (esta idea)」、対象を示す助詞。"},
      {q:"（2）",o:["ばかり","まで","から","ゆえ"],a:2,exp:"〜から「a partir de」、原因・出発点を示す。"},
      {q:"（3）",o:["ところが","つまり","したがって","ゆえに"],a:0,exp:"逆接の接続詞「ところが」が文脈に合う。"},
      {q:"（4）",o:["言われてみれば","言われるとおり","言うまでもなく","言いたいのは"],a:3,exp:"「言いたいのは〜ということだ」筆者の主張をまとめる定型表現。"},
      {q:"（5）",o:["バランス","分離","対立","優劣"],a:0,exp:"文脈上、両者の「バランス」が求められているという結論が自然。"},
      {sec:"問題8　内容理解（短文）",passage:"再生可能エネルギーの普及が進む一方、天候に左右される発電量の不安定さが課題として指摘されている。蓄電技術の進歩が解決の鍵とされる。",q:"再生可能エネルギーの課題は何か。",o:["発電量が天候に左右される不安定さ","コストが高すぎること","法律で禁止されていること","設置場所がないこと"],a:0,exp:"「天候に左右される発電量の不安定さが課題」がそのまま答え。"},
      {passage:"この病院では、待ち時間の長さが患者の不満の原因となっていた。予約システムを改善した結果、待ち時間が大幅に短縮された。",q:"待ち時間が短縮された理由は何か。",o:["医師の増員","予約システムの改善","患者数の減少","診療時間の延長"],a:1,exp:"「予約システムを改善した結果、待ち時間が大幅に短縮された」がそのまま答え。"},
      {passage:"若者の政治への関心の低さが長年指摘されてきたが、SNSを通じた情報発信により、若い世代の投票率が改善しつつある地域もある。",q:"若者の投票率改善に貢献しているものは何か。",o:["学校教育の変化","SNSを通じた情報発信","法律の改正","選挙制度の変更"],a:1,exp:"「SNSを通じた情報発信により…投票率が改善しつつある」がそのまま答え。"},
      {passage:"この企業では、社員のメンタルヘルスケアの一環として、専門カウンセラーへの相談窓口を設置した。利用は匿名で行えるため、利用者数は着実に増えている。",q:"相談窓口の利用者数が増えている理由は何か。",o:["評判が良いから","料金が無料だから","匿名で利用できるから","強制されているから"],a:2,exp:"「利用は匿名で行えるため、利用者数は着実に増えている」がそのまま答え。"},
      {sec:"問題9　内容理解（中文）",passage:"組織における意思決定の遅さは、しばしば責任の所在の不明確さに起因する。誰もが責任を負いたがらない風土からは、迅速で大胆な決断は生まれにくい。それを打開するには、権限と責任を明確に紐づける制度設計が不可欠である。とはいえ、責任の所在を明確にしすぎると、今度は挑戦を避ける萎縮した組織風土を生みかねないという逆説もはらんでいる。",q:"意思決定が遅くなる原因として筆者が挙げていることは何か。",o:["情報不足","予算の制約","人材の不足","責任の所在が不明確な組織風土"],a:3,exp:"「責任の所在の不明確さに起因する」がそのまま答え。"},
      {q:"筆者が指摘する打開策は何か。",o:["責任を誰にも負わせない制度","権限と責任を明確に紐づける制度設計","決断を先送りにする仕組み","人材を増やすこと"],a:1,exp:"「権限と責任を明確に紐づける制度設計が不可欠」がそのまま答え。"},
      {q:"筆者が指摘する「逆説」とは何か。",o:["責任があいまいなほうが効率的なこと","権限が多いほど責任も軽くなること","責任を明確にしすぎると挑戦を避ける風土を生みかねないこと","制度設計は不要だということ"],a:2,exp:"「責任の所在を明確にしすぎると…萎縮した組織風土を生みかねない」がそのまま答え。"},
      {passage:"言語習得において、母語の影響を完全に排除することは不可能である。むしろ母語との違いを意識的に比較することこそが、効率的な学習につながると考えられる。学習者が自らの母語の癖に自覚的であればあるほど、誤りのパターンを予測し、対策を立てやすくなるからだ。",q:"筆者の考えに近いものはどれか。",o:["母語は学習の妨げにしかならない","母語の影響は完全に排除すべきだ","比較は学習効果を下げる","母語との違いを意識的に比較することが効率的な学習につながる"],a:3,exp:"「母語との違いを意識的に比較することこそが…学習につながる」が主張。"},
      {q:"母語の癖に自覚的であることの利点は何か。",o:["誤りのパターンを予測し対策を立てやすくなる","文法を暗記しやすくなる","母語を完全に忘れられる","発音が自然に良くなる"],a:0,exp:"「誤りのパターンを予測し、対策を立てやすくなる」がそのまま答え。"},
      {q:"この文章全体の要旨として最も適切なものはどれか。",o:["学習効果は母語と無関係だ","母語は学習において無視すべきだ","母語との対比を意識することが効果的な言語学習につながる","誤りを気にすべきではない"],a:2,exp:"文章全体を通して母語比較の有用性を訴えている。"},
      {passage:"批判的思考とは、単に他者の意見を否定することではない。自らの前提をも疑い、多角的な視点から物事を検証する姿勢を指すのである。この姿勢は一朝一夕に身につくものではなく、日々の小さな問いかけの積み重ねによって、徐々に養われていくものだ。",q:"筆者が定義する批判的思考とは何か。",o:["自分の意見を主張すること","議論に勝つための技術","自らの前提も疑い多角的に検証する姿勢","他者の意見を否定すること"],a:2,exp:"「自らの前提をも疑い、多角的な視点から…検証する姿勢」が定義。"},
      {q:"筆者は批判的思考がどのように養われると述べているか。",o:["他者から教えられるだけで身につく","一度の訓練で完成する","生まれつきの才能による","日々の小さな問いかけの積み重ねによって"],a:3,exp:"「日々の小さな問いかけの積み重ねによって、徐々に養われていく」がそのまま答え。"},
      {q:"この文章で筆者が最も伝えたいことは何か。",o:["批判的思考は日々の積み重ねで徐々に養われる姿勢だ","批判的思考は生まれつきの才能だ","批判的思考は短期間で完成する","他者の意見への反論こそが批判的思考だ"],a:0,exp:"文章全体を通して「日々の積み重ねで養われる姿勢」であることを強調している。"},
      {sec:"問題10　内容理解（長文）",passage:"歴史を学ぶ意義は、単なる過去の出来事の暗記にあるのではなく、現在を相対化し、未来への教訓を引き出す視座を得ることにある。過去の事例を知ることで、現在直面している問題が、実は人類が繰り返し経験してきた普遍的な課題の一形態にすぎないと気づくことがある。<br><br>この視座は、目の前の出来事に対して過剰に一喜一憂することを防ぎ、より長期的で冷静な判断を可能にする。同時に、過去の失敗から学ばずに同じ過ちを繰り返すことの愚かさを、具体的な事例を通して実感させてくれる。<br><br>もっとも、歴史から学ぶことは、過去を単純に現在に当てはめることではない。時代背景や社会構造の違いを踏まえたうえで、慎重に類推する必要がある。安易な歴史の教訓化は、かえって誤った判断を導きかねないという点にも、注意を払うべきだろう。",q:"筆者が述べる歴史を学ぶ意義は何か。",o:["年号を覚えること","過去を美化すること","現在を相対化し未来への教訓を得る視座","過去の出来事を正確に暗記すること"],a:2,exp:"「現在を相対化し、未来への教訓を引き出す視座を得ること」が意義。"},
      {q:"この視座がもたらす効果として述べられていることは何か。",o:["感情的な判断を促すこと","長期的で冷静な判断を可能にすること","過去をすべて忘れさせること","現在の問題を軽視させること"],a:1,exp:"「より長期的で冷静な判断を可能にする」がそのまま答え。"},
      {q:"筆者が注意を促していることは何か。",o:["過去の事例をそのまま現在に適用すべきこと","時代背景を無視してよいこと","安易な歴史の教訓化がかえって誤った判断を導く危険","歴史を学ぶこと自体が無意味であること"],a:2,exp:"「安易な歴史の教訓化は…誤った判断を導きかねない」がそのまま答え。"},
      {q:"この文章全体を通して筆者が伝えたいことは何か。",o:["歴史は暗記科目として学ぶべきだ","歴史から学ぶには慎重な類推と視座の両方が必要だ","過去の失敗はもう繰り返されない","歴史学は現代社会に無関係だ"],a:1,exp:"意義と注意点の両方を述べたうえでのバランスの取れた結論。"},
      {sec:"問題11　統合理解",passage:"【A】人工知能の発達により、これまで人間にしかできないと思われていた仕事の一部が自動化されつつある。単純作業だけでなく、データ分析や翻訳といった知的業務にも及んでおり、今後多くの職種が影響を受けると予想される。この変化を前向きに捉え、人間はより創造的な業務にシフトしていくべきだという声もある。<br><br>【B】しかし、この楽観的な見方には慎重であるべきだ。新たに生まれる「創造的な仕事」の数が、失われる仕事の数を上回る保証はどこにもない。歴史的に技術革新が新しい雇用を生んできたのは事実だが、今回のAIによる変化は、これまでの技術革新とは異質で急速な側面を持つ。楽観論だけで対策を怠れば、社会的な混乱を招きかねない。",q:"Aの筆者が主張していることは何か。",o:["単純作業のみが自動化される","人間はより創造的な業務にシフトすべきだ","AIの発展はすぐに止めるべきだ","知的業務は自動化されない"],a:1,exp:"Aは「人間はより創造的な業務にシフトしていくべき」と前向きに捉えている。"},
      {q:"Bの筆者が懸念していることは何か。",o:["新しい仕事が失われる仕事を上回る保証がないこと","単純作業が残り続けること","技術革新自体が起きないこと","AIが全く発展しないこと"],a:0,exp:"「新たに生まれる…仕事の数が、失われる仕事の数を上回る保証はどこにもない」が懸念。"},
      {q:"AとBの筆者に共通する認識は何か。",o:["AIの発達をすぐ止めるべきだということ","AIの発達が雇用に大きな影響を与えるということ","AIの発達は雇用に無関係だということ","AIは知的業務に及ばないということ"],a:1,exp:"両者ともAIが雇用に大きな影響を与えるという前提を共有し、その評価が分かれている。"},
      {sec:"問題12　主張理解（長文）",passage:"多様性を尊重する社会とは、異なる意見を単に許容するだけでなく、それらが交わることで新たな価値が生まれることを積極的に歓迎する社会である。対立を恐れず、そこから学ぶ姿勢こそが求められる。<br><br>ただし、ここで注意すべきは、「多様性の尊重」という言葉が、時に思考停止の言い訳として使われてしまう危険性である。あらゆる意見を無批判に等価値として扱うことは、真の多様性の尊重とは言えない。時には、明らかに誤った主張や、他者を傷つける言説に対しては、毅然と反論する必要がある。<br><br>真の多様性の尊重とは、あらゆる意見を無条件に受け入れることではなく、異なる意見と真摯に向き合い、対話を通じて互いを理解しようと努め続けるプロセスそのものを指すのだろう。",q:"筆者が定義する多様性を尊重する社会とは何か。",o:["異なる意見の交わりから新たな価値を歓迎する社会","一つの意見に統一される社会","対立を完全に避ける社会","異なる意見を無視する社会"],a:0,exp:"「異なる意見…交わることで新たな価値が生まれることを積極的に歓迎する社会」が定義。"},
      {q:"筆者が危険性として指摘していることは何か。",o:["多様性の尊重が思考停止の言い訳に使われること","多様性を重視しすぎること","対立が全く起きないこと","異なる意見が少ないこと"],a:0,exp:"「『多様性の尊重』という言葉が、時に思考停止の言い訳として使われてしまう危険性」がそのまま答え。"},
      {q:"筆者は誤った主張に対してどうすべきだと述べているか。",o:["無視すべきだ","議論を避けるべきだ","無条件に受け入れるべきだ","毅然と反論する必要がある"],a:3,exp:"「明らかに誤った主張…に対しては、毅然と反論する必要がある」がそのまま答え。"},
      {q:"筆者が考える真の多様性の尊重とは何か。",o:["あらゆる意見を無条件に受け入れること","対話を通じて互いを理解しようと努め続けるプロセス","一つの正解を見つけること","対立を完全になくすこと"],a:1,exp:"「対話を通じて互いを理解しようと努め続けるプロセスそのもの」が定義。"},
      {sec:"問題13　情報検索",passage:"【市民オンライン講座　参加案内】<br>・対象：市内在住・在勤・在学の18歳以上（学生は学生証提示で受講料半額）<br>・講座：Ａ「防災の基礎」（全2回）／Ｂ「地域経済入門」（全4回）／Ｃ「日本語ボランティア養成」（全6回、修了者は登録ボランティアとして活動可）<br>・受講料：1講座につき2,000円（学生1,000円）。複数講座の同時申込みで500円割引（1講座あたり）。<br>・申込方法：市の公式サイトから、開講日の1週間前までに登録。定員に達し次第、締め切り。<br>・注意事項：全回数の3分の2以上出席しないと、修了証は発行されない。Ｃ講座のみ、修了証がボランティア登録の条件となる。",q:"市内在住の大学生が、AとB講座を同時に申し込む場合の受講料はいくらか。",o:["2,000円","1,500円","3,000円","4,000円"],a:1,exp:"学生価格1,000円×2講座＝2,000円から、同時申込割引500円を差し引いて1,500円。"},
      {q:"Ｃ講座を修了した人ができることは何か。",o:["受講料の返金を受けること","無料で他の講座を受けること","講師になること","登録ボランティアとして活動すること"],a:3,exp:"「Ｃ講座のみ、修了証がボランティア登録の条件となる」がそのまま答え。"}
    ]},
    {id:"b", title:"聴解", minutes:55, questions:[
      {sec:"問題1　課題理解",audio:"男：来週の展示会の準備、順調ですか。　女：はい、ほぼ予定通りですが、パンフレットの印刷だけ少し遅れています。今日中に印刷会社に確認の連絡を入れます。",q:"女の人はこのあと、まず何をしますか。",o:["印刷会社に連絡する","展示会を延期する","会場を変更する","パンフレットを作り直す"],a:0,exp:"「今日中に印刷会社に確認の連絡を入れます」がそのまま答え。"},
      {audio:"女：この契約書、サインする前にもう一度内容を確認したいのですが。　男：もちろんです。念のため、法務部にも目を通してもらいましょうか。　女：お願いします。",q:"男の人はこのあと、まず何をしますか。",o:["契約を解除する","契約書にサインする","法務部に確認を依頼する","新しい契約書を作る"],a:2,exp:"「法務部にも目を通してもらいましょうか」「お願いします」から、次の行動は法務部への依頼。"},
      {audio:"男：来月のセミナー、会場の候補が二つあるんですが。　女：それぞれの収容人数と料金を比較した資料を作ってもらえますか。　男：分かりました、今日中に準備します。",q:"男の人はこのあと、何をしますか。",o:["会場の比較資料を作る","会場を予約する","セミナーを中止する","参加者を募集する"],a:0,exp:"「比較した資料を作ってもらえますか」への返答「今日中に準備します」が答え。"},
      {audio:"女：新商品のパッケージデザイン、三案ありますが、どれがいいと思いますか。　男：正直迷いますね。マーケティング部の意見も聞いてから決めませんか。　女：そうしましょう。",q:"この後、まず何をしますか。",o:["デザインをすぐに決める","三案とも採用する","マーケティング部の意見を聞く","デザインをやり直す"],a:2,exp:"「マーケティング部の意見も聞いてから決めませんか」「そうしましょう」が答え。"},
      {audio:"男：来週の出張の交通手段、まだ決めていませんでした。　女：新幹線の方が早いですが、予算的には高速バスの方が安いです。上司に確認してから決めましょう。",q:"この後、まず何をしますか。",o:["新幹線を予約する","バスを予約する","出張を中止する","上司に確認する"],a:3,exp:"「上司に確認してから決めましょう」がそのまま答え。"},
      {sec:"問題2　ポイント理解",audio:"女：今回のキャンペーン、思ったより反響がありませんでしたね。　男：広告のタイミングが悪かったのが一番の原因だと思います。競合他社が同時期に大型キャンペーンを打っていたので。",q:"男の人は、反響が少なかった一番の原因は何だと言っていますか。",o:["広告のデザインが悪かったこと","商品の質が悪かったこと","予算が少なかったこと","広告のタイミングが競合と重なったこと"],a:3,exp:"「広告のタイミングが悪かったのが一番の原因…競合他社が同時期に」がそのまま答え。"},
      {audio:"男：この地域、若い世代の人口流出が続いていますね。　女：働き口の少なさも一因ですが、一番大きいのは、進学のために都市部に出た若者がそのまま戻ってこないことだと思います。",q:"女の人は、人口流出の一番大きい原因は何だと考えていますか。",o:["交通の便が悪いこと","進学で都市部に出た若者が戻らないこと","家賃が高いこと","働き口が少ないこと"],a:1,exp:"「一番大きいのは、進学のために都市部に出た若者がそのまま戻ってこないこと」がそのまま答え。"},
      {audio:"女：この機械、修理してもすぐまた同じ箇所が壊れますね。　男：部品自体の耐久性に問題があるんだと思います。使い方の問題ではなさそうです。",q:"男の人は、故障の一番の原因は何だと考えていますか。",o:["使い方の間違い","設置場所の悪さ","部品自体の耐久性","使用頻度の多さ"],a:2,exp:"「部品自体の耐久性に問題がある…使い方の問題ではなさそう」がそのまま答え。"},
      {audio:"男：今回のアンケート、回答率が低かったですね。　女：質問数が多すぎたのが一番の原因じゃないかと思います。回答に時間がかかりすぎたんでしょう。",q:"女の人は、回答率が低かった一番の原因は何だと言っていますか。",o:["対象者が少なかったこと","質問数が多すぎたこと","質問内容が難しかったこと","締め切りが早すぎたこと"],a:1,exp:"「質問数が多すぎたのが一番の原因」がそのまま答え。"},
      {audio:"女：この店、最近お客さんが減っていますね。　男：近くに大型スーパーができたことが一番大きいと思います。価格でとても太刀打ちできません。",q:"男の人は、客が減った一番の原因は何だと考えていますか。",o:["営業時間が短くなったこと","商品の質が落ちたこと","近くに大型スーパーができたこと","スタッフが減ったこと"],a:2,exp:"「近くに大型スーパーができたことが一番大きい」がそのまま答え。"},
      {audio:"男：新しいシステム、導入後もトラブルが多いですね。　女：社員への研修が不十分だったことが一番の原因だと思います。システム自体の問題ではないようです。",q:"女の人は、トラブルの一番の原因は何だと考えていますか。",o:["社員への研修が不十分だったこと","システム自体の欠陥","導入の時期が悪かったこと","予算不足"],a:0,exp:"「社員への研修が不十分だったことが一番の原因…システム自体の問題ではない」がそのまま答え。"},
      {sec:"問題3　概要理解",audio:"再生可能エネルギーの普及に伴い、電力供給の安定性をどう確保するかが新たな課題として浮上している。天候による発電量の変動を補うため、蓄電技術への投資が急速に進められている。",q:"この話は、主に何について述べていますか。",o:["電気料金の値上げ","再生可能エネルギー普及に伴う課題と対策","発電所の建設計画","停電の原因"],a:1,exp:"再生可能エネルギー普及に伴う電力安定性の課題と、蓄電技術による対策についての話。"},
      {audio:"歴史を学ぶ意義は、単なる暗記にあるのではなく、現在を相対化し、未来への教訓を得ることにあるとされる。過去の事例から学ぶことで、同じ過ちを繰り返さずに済むという考え方である。",q:"この話は、主に何について述べていますか。",o:["歴史の年号の覚え方","過去の戦争の原因","歴史学者の役割","歴史を学ぶ意義についての一つの考え方"],a:3,exp:"歴史を学ぶ意義についての考察が主題。"},
      {audio:"多様性を尊重する社会とは、あらゆる意見を無条件に受け入れることではなく、対話を通じて互いを理解しようと努め続けるプロセスそのものだという指摘がある。",q:"この話は、主に何について述べていますか。",o:["多様性を測る指標","法律による多様性の保護","多様性の尊重の本質についての考え方","対立を避ける方法"],a:2,exp:"多様性の尊重とは何かについての考察が主題。"},
      {audio:"人工知能の発達によって、多くの仕事が自動化されつつある一方、新しい仕事が失われる仕事の数を上回るかどうかは不確かであり、楽観的な見方には慎重であるべきだという意見がある。",q:"この話は、主に何について述べていますか。",o:["AIの開発費用","AIによる雇用への影響への懸念","AIの技術的な仕組み","AI規制の法律"],a:1,exp:"AIによる雇用への影響とその不確実性についての話。"},
      {audio:"効率化ばかりを追求する風潮に対し、雑談や余白といった一見無駄に見えるものの中にこそ、新しい発想の種があるのではないかという指摘がなされている。",q:"この話は、主に何について述べていますか。",o:["雑談の内容の分析","効率的な仕事の進め方","職場のルール作り","効率化の行き過ぎがもたらす弊害への懸念"],a:3,exp:"効率化偏重への懸念と、余白の価値についての話。"},
      {sec:"問題4　即時応答",audio:"この案件、少しお時間をいただけますか。",q:"最もよい返答はどれですか。",o:["もう終わりました。","おめでとうございます。","それは残念です。","はい、大丈夫です。"],a:3,exp:"時間の猶予を求める依頼への自然な返答は「はい、大丈夫です」。"},
      {audio:"恐縮ですが、この件は一旦白紙に戻させていただきたく。",q:"最もよい返答はどれですか。",o:["承知しました。理由を伺ってもよろしいですか。","それは嬉しいです。","おめでとうございます。","もう決まったことです。"],a:0,exp:"白紙撤回の申し出への自然な返答は、承諾しつつ理由を尋ねる形。"},
      {audio:"このデータ、念のためもう一度確認していただけますか。",q:"最もよい返答はどれですか。",o:["もう確認済みです、以上です。","承知しました。すぐ確認します。","それはすごいですね。","おめでとうございます。"],a:1,exp:"確認依頼への自然な返答は「承知しました。すぐ確認します」。"},
      {audio:"この提案、少々厳しいというのが正直な感想です。",q:"最もよい返答はどれですか。",o:["具体的にどの点が厳しいでしょうか。","おめでとうございます。","もう決まりました。","それは嬉しいです。"],a:0,exp:"否定的な感想への自然な返答は、具体的な理由を尋ねる形。"},
      {audio:"恐れ入りますが、担当が変わりまして。",q:"最もよい返答はどれですか。",o:["もう変わっていません。","おめでとうございます。","それは残念すぎます。","承知しました。新しいご担当者様をご紹介いただけますか。"],a:3,exp:"担当変更の連絡への自然な返答は、新担当者を確認する形。"},
      {audio:"この件、来週まで持ち越しということでよろしいでしょうか。",q:"最もよい返答はどれですか。",o:["いいえ、もう終わっています。","もう来週です。","それはおめでとうございます。","はい、それで結構です。"],a:3,exp:"持ち越しの確認への自然な返答は「はい、それで結構です」。"},
      {audio:"念のため伺いますが、この内容で間違いないでしょうか。",q:"最もよい返答はどれですか。",o:["それはすごいですね。","いいえ、まだ始まっていません。","はい、間違いありません。","もう終わった話です。"],a:2,exp:"内容確認への自然な返答は「はい、間違いありません」。"},
      {audio:"申し訳ございませんが、少々お時間をいただいております。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","それは嬉しいです。","もう終わったんですね。","承知しました。どのくらいかかりそうですか。"],a:3,exp:"時間を要するという連絡への自然な返答は、目安を尋ねる形。"},
      {audio:"この度は貴重なご意見をありがとうございました。",q:"最もよい返答はどれですか。",o:["いえ、お役に立てて何よりです。","それは残念ですね。","もう終わりです。","おめでとうございます。"],a:0,exp:"感謝の言葉への自然な返答は「お役に立てて何よりです」。"},
      {audio:"恐縮ですが、こちらの内容、少々お待ちいただけますか。",q:"最もよい返答はどれですか。",o:["いいえ、待てません。","はい、ゆっくりで構いません。","それはすごいですね。","もう終わりました。"],a:1,exp:"待ってほしいという依頼への自然な返答は「ゆっくりで構いません」。"},
      {audio:"この件、正式に決定する前に一度社内で共有していただけますか。",q:"最もよい返答はどれですか。",o:["承知しました。共有の場を設けます。","もう共有しました、以上です。","おめでとうございます。","それは大変ですね。"],a:0,exp:"共有依頼への自然な返答は「承知しました。共有の場を設けます」。"},
      {sec:"問題5　統合理解",audio:"司会：来年度の社員旅行、行き先の候補が三つ出ています。<br>男性A：私は温泉地がいいと思います。日頃の疲れを癒せますし、幅広い年代に喜ばれると思います。<br>女性：私は海外がいいと思います。非日常感がありますし、若手社員のモチベーションにもつながるのではないでしょうか。<br>男性B：予算とスケジュールを考えると、近場の観光地が現実的だと思います。一泊二日で行けますし、費用も抑えられます。<br>司会：予算の制約もありますし、今回は近場の観光地案で進めましょう。",q:"最終的にどの案で進めることになりましたか。",o:["近場の観光地案","三つを組み合わせた案","海外案","温泉地案"],a:0,exp:"司会が最後に「近場の観光地案で進めましょう」と決定している。"},
      {q:"男性Aが温泉地を推した理由は何ですか。",o:["若手のモチベーションが上がるから","予算が最も安いから","スケジュールが組みやすいから","疲れを癒せて幅広い年代に喜ばれるから"],a:3,exp:"「日頃の疲れを癒せますし、幅広い年代に喜ばれる」が理由。"},
      {audio:"司会：新しい社内報のテーマについて、三つ案があります。<br>男性A：社員紹介を中心にした企画がいいと思います。社内の交流が深まります。<br>女性：業界の最新動向を扱う専門的な内容にすべきだと思います。社員の知識向上につながります。<br>男性B：両方を組み合わせて、前半に社員紹介、後半に業界動向を載せるのはどうでしょうか。<br>司会：それでは、前半に社員紹介、後半に業界動向という組み合わせ案で進めましょう。",q:"最終的にどの案で進めることになりましたか。",o:["社員紹介と業界動向を組み合わせた案","業界動向のみの案","案がまとまらなかった","社員紹介のみの案"],a:0,exp:"司会が「前半に社員紹介、後半に業界動向という組み合わせ案で進めましょう」と決定している。"}
    ]}
  ]
},
{
  id:"o-n1-3", lvl:"N1", title:"Examen oficial N1 · 3", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙・文法）・読解", minutes:110, questions:[
      {sec:"問題1　漢字読み",q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　彼の主張は<u>一理</u>ある。",o:["いちりん","いつり","ひとり","いちり"],a:3,exp:"一理→いちり「parte de razón」。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　その事実は<u>顕在</u>化しつつある。",o:["けんさい","けんぜん","けんざい","げんざい"],a:2,exp:"顕在→けんざい「manifiesto、evidente」。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　彼女は<u>寛容</u>な人だ。",o:["かんよ","かんよん","かんいよう","かんよう"],a:3,exp:"寛容→かんよう「tolerante」。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　その説明は<u>釈然</u>としない。",o:["せきぜん","しゃくねん","しゃくぜん","せきねん"],a:2,exp:"釈然→しゃくぜん（釈然としない＝no quedar convencido）。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　彼は<u>謙虚</u>な姿勢を崩さない。",o:["げんきょ","けんぎょ","けんきょ","けんこ"],a:2,exp:"謙虚→けんきょ「humilde」。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　この事業は<u>採算</u>が取れない。",o:["さいさく","さいそん","さいさん","さいざん"],a:2,exp:"採算→さいさん「rentabilidad」。"},
      {sec:"問題2　文脈規定",q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼の説明は（　）を得ず、腑に落ちない。",o:["納得","承知","理解","了承"],a:0,exp:"納得を得ない「no resultar convincente」。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼は反対派の説得に（　）を尽くした。",o:["手","方法","知恵","力"],a:0,exp:"手を尽くす「agotar todos los medios」。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　その提案は物議を（　）。",o:["呼んだ","起こした","招いた","醸した"],a:3,exp:"物議を醸す「causar controversia」。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼女は（　）交渉を進めた。",o:["率直に","乱暴に","無計画に","したたかに"],a:3,exp:"したたかに「con astucia」。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　この結果には（　）の余地がない。",o:["疑問","不審","懐疑","疑い"],a:0,exp:"疑問の余地がない「no hay lugar a dudas」。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼は難局を（　）乗り切った。",o:["急激に","過剰に","巧みに","強引に"],a:2,exp:"巧みに「hábilmente」。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼女の指摘は（　）を突いていた。",o:["核心","本心","中心","内心"],a:0,exp:"核心を突く「dar en el meollo」。"},
      {sec:"問題3　言い換え類義",q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　彼の話は<u>釈然</u>としなかった。",o:["面白かった","納得できなかった","分かりやすかった","感動した"],a:1,exp:"釈然としない≒「no quedar convencido」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　彼は<u>謙虚</u>な態度を保っている。",o:["傲慢な","無関心な","控えめで礼儀正しい","積極的な"],a:2,exp:"謙虚≒「humilde」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　この計画は<u>採算</u>が取れない。",o:["時間がかかる","利益が出ない","人気がない","評判が悪い"],a:1,exp:"採算が取れない≒「no ser rentable」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　彼は<u>巧みに</u>危機を乗り越えた。",o:["仕方なく","無理やり","偶然に","うまく、器用に"],a:3,exp:"巧みに≒「hábilmente」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　彼女の意見は<u>核心</u>を突いていた。",o:["過去の部分","最も重要な部分","表面的な部分","不必要な部分"],a:1,exp:"核心≒「lo esencial」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　その事実は<u>顕在化</u>しつつある。",o:["誇張されている","隠されている","忘れられている","表面化してきている"],a:3,exp:"顕在化≒「manifestarse」。"},
      {sec:"問題4　用法",q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「せめて」",o:["全部は無理でも、せめて半分だけでも終わらせたい。","せめて怒って叫んだ。","せめて三人来た。","せめて明日晴れるだろう。"],a:0,exp:"せめて＝「al menos」。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「案の定」",o:["案の定、明日雨が降るだろう。","案の定、三時に会議がある。","案の定、早く終わった。","案の定、彼は約束の時間に遅れた。"],a:3,exp:"案の定＝「tal como se esperaba」。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「にわかに」",o:["にわかに早く終わった。","にわかに明日会議がある。","にわかに三時に来た。","空がにわかにかき曇り、雨が降り出した。"],a:3,exp:"にわかに＝「de repente」。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「あえて」",o:["あえて三人来た。","あえて明日晴れるだろう。","彼はあえて厳しい道を選んだ。","あえて怒って叫んだ。"],a:2,exp:"あえて＝「a propósito, deliberadamente」。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「もっぱら」",o:["最近はもっぱら在宅で仕事をしている。","もっぱら三時に会議がある。","もっぱら早く終わった。","もっぱら明日雨が降る。"],a:0,exp:"もっぱら＝「exclusivamente」。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「あわよくば」",o:["あわよくば、優勝も狙えるかもしれない。","あわよくば早く終わった。","あわよくば明日会議がある。","あわよくば三時に来た。"],a:0,exp:"あわよくば＝「con suerte」。"},
      {sec:"問題5　文法1（文法形式の判断）",q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　この提案は斬新である（　）、実現には課題が多い。",o:["べく","反面","あまり","つつ"],a:1,exp:"〜反面「por otro lado」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼女は若手（　）、堂々とした態度で発表した。",o:["にとって","というより","でありながら","にしたら"],a:2,exp:"〜でありながら「a pesar de ser」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼は反対意見（　）、自説を曲げなかった。",o:["をよそに","にもまして","にひきかえ","といえども"],a:0,exp:"〜をよそに「haciendo caso omiso de」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼の実績（　）、この昇進は妥当だろう。",o:["にひきかえ","に照らせば","をよそに","はおろか"],a:1,exp:"〜に照らせば「a la luz de」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　規則に反する（　）、罰則が科される。",o:["場合には","次第では","ものは","につれ"],a:0,exp:"〜場合には「en caso de」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼女は経験の乏しさ（　）、見事な対応を見せた。",o:["はおろか","にひきかえ","ときたら","をものともせず"],a:3,exp:"〜をものともせず「sin dejarse afectar por」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　この問題は議論すればする（　）、複雑さを増すばかりだ。",o:["だけ","のみ","くらい","ほど"],a:3,exp:"〜ば〜ほど「cuanto más...más」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼は疲れていた（　）、最後までやり遂げた。",o:["とあって","かたわら","ゆえに","にもかかわらず"],a:3,exp:"〜にもかかわらず「a pesar de」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼の貢献（　）、この成功はなかっただろう。",o:["ときたら","なくして","はおろか","にひきかえ"],a:1,exp:"〜なくして（は）「sin (algo)」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼は逆境（　）、決して諦めなかった。",o:["にあっても","ときたら","はおろか","にひきかえ"],a:0,exp:"〜にあっても「incluso en (adversidad)」。"},
      {sec:"問題6　文法2（文の組み立て）",q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　彼女は　___　___　★　___　周囲を驚かせた。（1 実力　2 その　3 で　4 圧倒的な）",o:["圧倒的な","で","その","実力"],a:1,exp:"正しい順序：2その→4圧倒的な→1実力→3で「その圧倒的な実力で」。★の位置には3「で」が入る。"},
      {q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　彼の提案は　___　___　★　___　考えられる。（1 に　2 値する　3 検討　4 十分）",o:["値する","検討","に","十分"],a:0,exp:"正しい順序：4十分→3検討→1に→2値する「十分検討に値する」。★の位置には2「値する」が入る。"},
      {q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　この決定は　___　___　★　___　下されたものだ。（1 熟慮の　2 うえで　3 十分な　4 を）",o:["熟慮の","うえで","十分な","を"],a:1,exp:"正しい順序：3十分な→1熟慮の→4を→2うえで「十分な熟慮のうえで」。★の位置には2「うえで」が入る。"},
      {q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　彼は　___　★　___　___　最後までやり遂げた。（1 苦境　2 に　3 立たされ　4 ながらも）",o:["に","立たされ","ながらも","苦境"],a:0,exp:"正しい順序：1苦境→2に→3立たされ→4ながらも「苦境に立たされながらも」。★の位置には2「に」が入る。"},
      {q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　この会社は　___　___　★　___　成長を続けている。（1 業界の　2 動向　3 を　4 見極めつつ）",o:["業界の","見極めつつ","を","動向"],a:2,exp:"正しい順序：1業界の→2動向→3を→4見極めつつ「業界の動向を見極めつつ」。★の位置には3「を」が入る。"},
      {sec:"問題7　文章文法",passage:"次の文章を読んで、文章全体の趣旨を踏まえて、（1）から（5）の中に入る最もよいものを、1・2・3・4から一つ選びなさい。<br><br>近年、地方創生というキーワードのもと、様々な政策が打ち出されている。しかし、一律の施策を全国に（1）だけでは、各地域固有の課題に対応しきれないという指摘がある。地域（2）異なる歴史や産業構造を無視した画一的な支援策は、（3）効果を上げにくい。真に求められているのは、それぞれの地域の実情を踏まえた、きめ細やかな支援である。（4）、地域住民自身が主体となって課題解決に取り組む姿勢も、同様に重要だと言えよう。行政と住民、双方の（5）が、地方創生の鍵を握っているのである。",q:"（1）",o:["適用され","適用して","適用した","適用する"],a:3,exp:"「〜だけでは」に続く辞書形「適用する」が自然。"},
      {q:"（2）",o:["に対して","によって","にとって","において"],a:1,exp:"〜によって「según, dependiendo de」。"},
      {q:"（3）",o:["必ずしも","むしろ","いっそう","かえって"],a:0,exp:"「必ずしも〜にくい」で部分否定を導く。"},
      {q:"（4）",o:["つまり","ただし","ところが","同時に"],a:3,exp:"追加の論点を導く「同時に」が文脈に合う。"},
      {q:"（5）",o:["分離","競争","対立","協働"],a:3,exp:"行政と住民の「協働」が鍵になるという結論が自然。"},
      {sec:"問題8　内容理解（短文）",passage:"この企業は環境負荷の軽減を経営方針の柱に据え、生産工程の見直しを進めている。短期的なコスト増加は避けられないが、長期的な企業価値の向上を見込んでいる。",q:"この企業が見込んでいることは何か。",o:["短期的な利益の拡大","長期的な企業価値の向上","海外進出の拡大","従業員数の削減"],a:1,exp:"「長期的な企業価値の向上を見込んでいる」がそのまま答え。"},
      {passage:"この地域では、伝統工芸品の後継者不足が深刻化しており、行政と民間が連携した育成プログラムが開始された。若い世代への技術継承が急務とされている。",q:"育成プログラムの目的は何か。",o:["輸出の拡大","若い世代への技術継承","観光客の誘致","価格の引き上げ"],a:1,exp:"「若い世代への技術継承が急務」がそのまま答え。"},
      {passage:"この調査によれば、リモートワークの普及により、地方への移住を検討する都市部の若者が増加している。働く場所の制約が減ったことが背景にある。",q:"地方移住の増加の背景は何か。",o:["交通網の発達","都市部の家賃高騰","地方の経済成長","働く場所の制約が減ったこと"],a:3,exp:"「働く場所の制約が減ったことが背景」がそのまま答え。"},
      {passage:"この病院では、電子カルテの導入により、医師間の情報共有が円滑になり、診断の精度が向上したと報告されている。",q:"電子カルテ導入の効果は何か。",o:["医療費の削減","患者数の増加","診断の精度向上","診療時間の短縮"],a:2,exp:"「情報共有が円滑になり、診断の精度が向上した」がそのまま答え。"},
      {sec:"問題9　内容理解（中文）",passage:"少子高齢化が進む日本では、労働力不足を補うため、外国人労働者の受け入れ拡大が議論されている。一方で、言語や文化の違いによる職場での摩擦を懸念する声も根強い。受け入れ企業側には、単なる労働力としてではなく、共に働く仲間としての意識改革が求められている。",q:"外国人労働者の受け入れに関して懸念されていることは何か。",o:["治安の悪化","住居不足","賃金の高騰","言語や文化の違いによる摩擦"],a:3,exp:"「言語や文化の違いによる職場での摩擦を懸念する声も根強い」がそのまま答え。"},
      {q:"受け入れ企業側に求められていることは何か。",o:["共に働く仲間としての意識改革","受け入れの完全な停止","賃金の引き下げ","労働力としてのみ扱うこと"],a:0,exp:"「共に働く仲間としての意識改革が求められている」がそのまま答え。"},
      {q:"この文章の要旨として最も適切なものはどれか。",o:["外国人労働者の受け入れは不要である","賃金さえ上げれば全て解決する","言語の違いは全く問題にならない","外国人労働者受け入れには制度と意識の両面の変化が必要だ"],a:3,exp:"制度的な議論と意識改革の両方に言及している。"},
      {passage:"人工知能の発達により、これまで人間にしかできないと思われていた仕事の一部が自動化されつつある。ただし、創造性や対人関係を要する分野では、人間の役割は依然として大きい。技術が進歩するほど、逆に人間ならではの資質の価値が際立つという逆説的な現象が起きている。",q:"人間の役割が依然として大きい分野はどこか。",o:["データ入力の分野","単純作業の分野","計算処理の分野","創造性や対人関係を要する分野"],a:3,exp:"「創造性や対人関係を要する分野では、人間の役割は依然として大きい」がそのまま答え。"},
      {q:"筆者が指摘する「逆説的な現象」とは何か。",o:["人間の資質が失われつつあること","技術が退化していること","技術が進歩するほど人間らしい資質の価値が際立つこと","技術が進歩するほど人間の仕事が増えること"],a:2,exp:"「技術が進歩するほど、逆に人間ならではの資質の価値が際立つ」がそのまま答え。"},
      {q:"この文章の要旨として最も適切なものはどれか。",o:["人間の仕事は今後完全になくなる","AIの発達により人間ならではの資質の価値が再評価されている","AIはすべての仕事を代替する","創造性はAIにも備わっている"],a:1,exp:"文章全体を通して人間的資質の再評価を論じている。"},
      {passage:"効率化ばかりを追求する現代社会において、雑談や余白といった一見無駄に見えるものの中にこそ、新しい発想の種が潜んでいるのではないかという指摘がある。無駄を一律に排除する姿勢は、かえって組織の創造性を損なう危険をはらんでいる。",q:"筆者が指摘する危険は何か。",o:["無駄を一律に排除することが創造性を損なうこと","効率化が全く進まないこと","雑談を推奨しすぎること","余白が多すぎること"],a:0,exp:"「無駄を一律に排除する姿勢は、かえって組織の創造性を損なう危険」がそのまま答え。"},
      {q:"筆者は雑談や余白をどう捉えているか。",o:["完全に無駄なもの","業務効率を下げるだけのもの","時間の浪費でしかないもの","新しい発想の種になりうるもの"],a:3,exp:"「新しい発想の種が潜んでいるのではないか」と肯定的に捉えている。"},
      {q:"この文章の要旨として最も適切なものはどれか。",o:["余白は完全に排除すべきだ","雑談は業務の妨げにしかならない","効率偏重の姿勢が組織の創造性を損なう危険がある","効率化はすべて推進すべきだ"],a:2,exp:"効率偏重への警鐘が文章全体の要旨。"},
      {sec:"問題10　内容理解（長文）",passage:"言葉というものは、常に変化し続けるものである。新しい表現の誕生を「言葉の乱れ」と断じて批判する声は、いつの時代にも存在してきた。しかし、こうした変化を単純に否定的に捉えることは、言語という生きたシステムの本質を見誤っているのではないだろうか。<br><br>言語は、話者たちの日々のコミュニケーションの中で、絶えず磨かれ、作り替えられていくものである。新しい語彙や言い回しが生まれるのは、既存の表現では言い表せない微妙なニュアンスを、話者たちが必要としているからにほかならない。この意味で、言語の変化とは、話者集団の創造性の表れと見ることもできる。<br><br>もちろん、あらゆる変化を無条件に肯定すべきだというわけではない。コミュニケーションの円滑さを著しく損なうような変化については、一定の抑制も必要だろう。重要なのは、変化そのものを一律に「乱れ」として排斥するのではなく、その変化が言語コミュニティにとってどのような意味を持つのかを、丁寧に見極めていく姿勢である。",q:"筆者が「言葉の乱れ」という捉え方についてどう考えているか。",o:["正しい捉え方であり支持すべきだ","古い言葉のみに当てはまる捉え方だ","言語学的に証明された事実だ","言語という生きたシステムの本質を見誤った捉え方だ"],a:3,exp:"「言語という生きたシステムの本質を見誤っているのではないか」がそのまま答え。"},
      {q:"筆者は新しい語彙が生まれる理由をどう説明しているか。",o:["既存の表現では言い表せないニュアンスを話者が必要とするから","若者が年配者に反抗したいから","偶然生まれるだけで理由はない","言語学者が意図的に作るから"],a:0,exp:"「既存の表現では言い表せない微妙なニュアンスを、話者たちが必要としているから」がそのまま答え。"},
      {q:"筆者はすべての言語変化を肯定すべきだと考えているか。",o:["分からない、と述べている","いいえ、言語は一切変化すべきではないと考えている","はい、無条件にすべて肯定すべきだと考えている","いいえ、コミュニケーションを損なう変化には抑制も必要だと考えている"],a:3,exp:"「コミュニケーションの円滑さを著しく損なうような変化については、一定の抑制も必要」と述べている。"},
      {q:"この文章全体を通して筆者が最も伝えたいことは何か。",o:["言葉の乱れはすべて排除すべきだ","言語は変化させてはならない","言語変化の意味を丁寧に見極める姿勢が重要だ","若者言葉は正しい日本語ではない"],a:2,exp:"「変化が言語コミュニティにとってどのような意味を持つのかを、丁寧に見極めていく姿勢」が結論。"},
      {sec:"問題11　統合理解",passage:"【A】終身雇用制度は、従業員に安定と忠誠心をもたらし、長期的な人材育成を可能にしてきた。企業にとっても、離職率の低さは大きなメリットであり、この制度を安易に手放すべきではないという意見がある。<br><br>【B】しかし、終身雇用制度は、変化の激しい現代のビジネス環境には適していないという指摘もある。年功序列と結びついたこの制度は、若手の意欲的な挑戦を阻害し、企業の新陳代謝を妨げる要因にもなりかねない。今後は、より流動的な雇用形態への移行が求められるだろう。",q:"Aの筆者が主張していることは何か。",o:["若手の挑戦を阻害すべきだ","終身雇用制度を安易に手放すべきではない","終身雇用制度をすぐに廃止すべきだ","離職率は高い方がよい"],a:1,exp:"Aは終身雇用制度の維持を支持している。"},
      {q:"Bの筆者が懸念していることは何か。",o:["雇用が流動的すぎること","終身雇用制度が若手の挑戦を阻害すること","離職率が低すぎること","終身雇用制度がすぐになくなること"],a:1,exp:"「若手の意欲的な挑戦を阻害し…新陳代謝を妨げる要因」が懸念。"},
      {q:"AとBの筆者に共通する視点は何か。",o:["終身雇用制度に問題は全くないということ","雇用制度自体が不要だということ","終身雇用制度は完全に無意味だということ","終身雇用制度には利点と課題の両面があるということ"],a:3,exp:"両者とも終身雇用制度の効果と限界の両面を扱っている。"},
      {sec:"問題12　主張理解（長文）",passage:"組織におけるリーダーシップとは、単に指示を出す能力ではなく、メンバーそれぞれの強みを引き出し、全体としての成果を最大化する力を指すと言えよう。優れたリーダーは、自らが前面に立って主導するだけでなく、時にはあえて一歩引き、メンバーが自律的に判断し行動できる環境を整えることに長けている。<br><br>この考え方に立てば、リーダーシップの評価基準も見直す必要が出てくる。従来は、決断力やカリスマ性が重視されがちであったが、それだけでは組織全体の持続的な成長を支えることは難しい。むしろ、メンバーの成長を辛抱強く見守り、失敗から学ぶ機会を与える度量こそが、真に評価されるべき資質ではないだろうか。<br><br>もちろん、時には迅速で強力なリーダーシップが求められる局面もある。重要なのは、状況に応じてリーダーシップのあり方を柔軟に使い分ける、いわば「適応力」であるように思われる。",q:"筆者が定義するリーダーシップとは何か。",o:["指示を的確に出す能力","失敗を許さない厳格さ","権威を持って統率する力","メンバーの強みを引き出し成果を最大化する力"],a:3,exp:"「メンバーそれぞれの強みを引き出し…最大化する力」が定義。"},
      {q:"筆者が評価されるべきだと述べている資質は何か。",o:["常に前面に立ち主導する姿勢","決断力とカリスマ性のみ","メンバーに一切任せない厳格さ","メンバーの成長を見守り失敗から学ぶ機会を与える度量"],a:3,exp:"「メンバーの成長を辛抱強く見守り、失敗から学ぶ機会を与える度量」がそのまま答え。"},
      {q:"筆者が重要だと考えているものは何か。",o:["常に強力なリーダーシップを発揮すること","常にメンバーに任せること","状況に応じてリーダーシップのあり方を使い分ける適応力","決断力を完全に捨てること"],a:2,exp:"「状況に応じてリーダーシップのあり方を柔軟に使い分ける…適応力」がそのまま答え。"},
      {q:"この文章全体を通して筆者が伝えたいことは何か。",o:["リーダーは常に前面に立つべきだ","リーダーシップは状況に応じた柔軟な使い分けが重要だ","リーダーシップに正解は存在しない","カリスマ性こそが唯一の評価基準だ"],a:1,exp:"柔軟な「適応力」の重要性を結論としている。"},
      {sec:"問題13　情報検索",passage:"【地域図書館　貸出サービス案内】<br>・利用登録：市内在住・在勤・在学者は無料。市外在住者は年間登録料1,000円。<br>・貸出冊数：一般書10冊、雑誌・DVD各2点まで、貸出期間は2週間。<br>・延長：予約が入っていない資料に限り、1回だけ2週間延長可能。手続きはウェブサイトまたは電話で。<br>・予約サービス：他の利用者が借りている資料の予約が可能。準備ができ次第、メールで通知（登録者のみ）。<br>・返却：休館日でも館外の返却ポストを利用可能。ただし、CD・DVDは破損防止のため窓口でのみ返却可。<br>・注意：延滞が続いた場合、新規の貸出および予約サービスの利用が一時停止される。",q:"市外在住のAさんが本を借りたい場合、まず何をする必要があるか。",o:["市内に転居する","無料で登録する","図書館に問い合わせるだけでよい","年間登録料1,000円を払って利用登録をする"],a:3,exp:"「市外在住者は年間登録料1,000円」を払って登録する必要がある。"},
      {q:"この案内から分かることとして正しいものはどれか。",o:["延滞しても罰則は一切ない","CD・DVDは窓口でのみ返却できる","延長は何回でもできる","予約は登録者以外も利用できる"],a:1,exp:"「CD・DVDは破損防止のため窓口でのみ返却可」がそのまま該当。"}
    ]},
    {id:"b", title:"聴解", minutes:55, questions:[
      {sec:"問題1　課題理解",audio:"女：来月の株主総会の準備、進んでいますか。　男：資料の作成はほぼ終わりましたが、会場の最終確認がまだです。今日中に会場に電話して確認します。",q:"男の人はこのあと、まず何をしますか。",o:["株主総会を延期する","司会者を決める","資料を作り直す","会場に電話して確認する"],a:3,exp:"「今日中に会場に電話して確認します」がそのまま答え。"},
      {audio:"男：新商品の発売日、来月の10日でよろしいですか。　女：はい、それで進めてください。あと、プレスリリースの原稿も確認をお願いできますか。　男：分かりました。",q:"男の人はこのあと、まず何をしますか。",o:["プレスリリースの原稿を確認する","会議を開く","商品を回収する","発売日を変更する"],a:0,exp:"「プレスリリースの原稿も確認をお願いできますか」「分かりました」が答え。"},
      {audio:"女：来週の面接、履歴書の確認は済んでいますか。　男：まだです。今日の午後、全員分に目を通します。あと、面接会場の準備もお願いできますか。　女：分かりました。",q:"女の人はこのあと、まず何をしますか。",o:["面接会場を準備する","履歴書を確認する","面接を延期する","候補者に連絡する"],a:0,exp:"男性から依頼された「面接会場の準備」に女性が「分かりました」と応じている。"},
      {audio:"男：来月のイベント、出演者のスケジュール調整はどうなっていますか。　女：ほぼ固まりましたが、一人だけ返事待ちです。今日中に確認の連絡を入れます。",q:"女の人はこのあと、まず何をしますか。",o:["イベントを中止する","会場を変更する","出演者に確認の連絡を入れる","出演者を増やす"],a:2,exp:"「今日中に確認の連絡を入れます」がそのまま答え。"},
      {audio:"女：この報告書、来週の会議までに仕上げないといけないんですが。　男：手伝いますよ。どこまで進んでいますか。　女：データはまとまっているので、あとは考察の部分をお願いできますか。",q:"男の人はこのあと、何をしますか。",o:["データをまとめる","報告書の考察の部分を書く","会議の日程を変更する","報告書を印刷する"],a:1,exp:"「考察の部分をお願いできますか」への流れから、男性は考察部分を担当する。"},
      {sec:"問題2　ポイント理解",audio:"男：この製品、返品が多いですね。　女：説明書が分かりにくいのが一番の原因だと思います。使い方を誤解しているお客様が多いようです。",q:"女の人は、返品が多い一番の原因は何だと言っていますか。",o:["説明書が分かりにくいこと","製品自体の欠陥","価格が高すぎること","配送が遅いこと"],a:0,exp:"「説明書が分かりにくいのが一番の原因」がそのまま答え。"},
      {audio:"女：この工場、事故が続いていますね。　男：老朽化した設備もありますが、一番の問題は安全確認の手順が形骸化していたことだと思います。",q:"男の人は、事故が続く一番の原因は何だと考えていますか。",o:["天候の悪さ","作業員の不注意","安全確認の手順が形骸化していたこと","設備の老朽化"],a:2,exp:"「一番の問題は安全確認の手順が形骸化していたこと」がそのまま答え。"},
      {audio:"男：今回の新人研修、評判が良くなかったですね。　女：内容よりも、日程が詰め込みすぎだったことが一番の問題だったと思います。",q:"女の人は、評判が悪かった一番の原因は何だと言っていますか。",o:["講師が不足していたこと","内容が悪かったこと","会場が狭かったこと","日程が詰め込みすぎだったこと"],a:3,exp:"「内容よりも、日程が詰め込みすぎだったことが一番の問題」がそのまま答え。"},
      {audio:"女：このアプリ、ダウンロード数が伸び悩んでいますね。　男：機能自体はいいんですが、広告が届いていないのが一番の原因だと思います。",q:"男の人は、ダウンロード数が伸び悩む一番の原因は何だと考えていますか。",o:["広告が届いていないこと","価格が高いこと","デザインが古いこと","機能が悪いこと"],a:0,exp:"「機能自体はいいんですが、広告が届いていないのが一番の原因」がそのまま答え。"},
      {audio:"男：この店舗、離職率が高いですね。　女：シフトの融通が利かないことが一番の原因だと聞いています。給料自体には不満は少ないようです。",q:"女の人は、離職率が高い一番の原因は何だと言っていますか。",o:["人間関係が悪いこと","シフトの融通が利かないこと","給料が安いこと","仕事がきついこと"],a:1,exp:"「シフトの融通が利かないことが一番の原因…給料自体には不満は少ない」がそのまま答え。"},
      {audio:"男：このプロジェクト、予算オーバーしていますね。　女：初期の見積もりが甘かったことが一番の原因だと思います。追加の要望への対応にも影響しているようです。",q:"女の人は、予算オーバーの一番の原因は何だと考えていますか。",o:["為替の変動","人件費の高騰","初期の見積もりが甘かったこと","追加要望が多すぎたこと"],a:2,exp:"「初期の見積もりが甘かったことが一番の原因」がそのまま答え。"},
      {sec:"問題3　概要理解",audio:"終身雇用制度は、従業員に安定をもたらしてきた一方、変化の激しい現代のビジネス環境には適さないという指摘もある。今後、より流動的な雇用形態への移行が求められるかもしれない。",q:"この話は、主に何について述べていますか。",o:["終身雇用制度の課題と今後の展望","採用面接の方法","給料の計算方法","退職金の制度"],a:0,exp:"終身雇用制度の課題と今後の雇用のあり方についての話。"},
      {audio:"組織のリーダーシップとは、指示を出す能力ではなく、メンバーの強みを引き出し成果を最大化する力だという考え方が広まりつつある。状況に応じた柔軟な対応力も重要視されている。",q:"この話は、主に何について述べていますか。",o:["組織図の作り方","給与制度の設計","リーダーシップのあり方についての一つの考え方","会議の進め方"],a:2,exp:"リーダーシップの本質についての考察が主題。"},
      {audio:"言葉は時代とともに常に変化するものであり、新しい表現の誕生を単純に「乱れ」と否定するのではなく、その意味を丁寧に見極める姿勢が重要だという指摘がある。",q:"この話は、主に何について述べていますか。",o:["正しい敬語の使い方","方言の分類","言語変化を捉える姿勢についての考え方","外来語の増加"],a:2,exp:"言語変化への向き合い方についての話。"},
      {audio:"外国人労働者の受け入れが議論される中、受け入れ企業側には単なる労働力としてではなく、共に働く仲間としての意識改革が求められているという指摘がある。",q:"この話は、主に何について述べていますか。",o:["外国人労働者受け入れに必要な企業の意識改革","労働ビザの種類","外国人労働者の給与水準","入国管理の手続き"],a:0,exp:"受け入れ企業側の意識改革の必要性についての話。"},
      {audio:"人工知能の発達で多くの仕事が自動化される一方、創造性や対人関係を要する分野では人間の役割が依然として大きく、人間らしい資質の価値が再評価されつつあるという指摘がある。",q:"この話は、主に何について述べていますか。",o:["AIの規制に関する法律","AIの技術的な仕組み","AI時代における人間的資質の再評価","AIの開発費用"],a:2,exp:"AI時代における人間的資質の価値の再評価についての話。"},
      {sec:"問題4　即時応答",audio:"この件、少し検討させていただきたいのですが。",q:"最もよい返答はどれですか。",o:["それは残念ですね。","おめでとうございます。","承知しました。いつ頃までにお返事いただけますか。","もう決まりました。"],a:2,exp:"検討を求められた際の自然な返答は、期限を確認する形。"},
      {audio:"恐れ入りますが、この日程では難しそうです。",q:"最もよい返答はどれですか。",o:["では、ご都合のよい日程を教えていただけますか。","それは嬉しいです。","もう決まったことです。","おめでとうございます。"],a:0,exp:"日程が難しいという連絡への自然な返答は、代替日を尋ねる形。"},
      {audio:"この資料、少し修正した方がいいと思います。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","それはすごいですね。","もう修正済みです、以上です。","ありがとうございます。具体的に教えていただけますか。"],a:3,exp:"修正の指摘への自然な返答は、感謝しつつ詳細を尋ねる形。"},
      {audio:"正直、この案には懐疑的です。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","もう決まりました。","それは嬉しいです。","どのあたりが気になりますか。"],a:3,exp:"懐疑的な意見への自然な返答は、理由を尋ねる形。"},
      {audio:"急なお願いで恐縮ですが、明日までにお願いできますか。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","それは残念ですね。","承知しました。やってみます。","もう終わりました。"],a:2,exp:"急な依頼への自然な返答は「承知しました。やってみます」。"},
      {audio:"この件について、率直なご意見を伺えますか。",q:"最もよい返答はどれですか。",o:["もう終わった話です。","はい、正直に申し上げますと。","それはすごいですね。","おめでとうございます。"],a:1,exp:"率直な意見を求められた際の自然な返答は「正直に申し上げますと」。"},
      {audio:"恐縮ですが、こちらのミスでご迷惑をおかけしました。",q:"最もよい返答はどれですか。",o:["もっとやってください。","おめでとうございます。","それは嬉しいです。","いえ、こちらこそ確認が足りませんでした。"],a:3,exp:"謝罪への自然な返答は、相手を責めずに応じる形。"},
      {audio:"この案件、優先順位を上げていただけますか。",q:"最もよい返答はどれですか。",o:["もう終わりました。","おめでとうございます。","それは残念ですね。","承知しました。他の作業と調整します。"],a:3,exp:"優先順位を上げてほしいという依頼への自然な返答。"},
      {audio:"この度は多大なご協力をいただき、感謝申し上げます。",q:"最もよい返答はどれですか。",o:["いえ、こちらこそ良い経験になりました。","それは残念ですね。","おめでとうございます。","もう終わりです。"],a:0,exp:"感謝の言葉への自然な返答。"},
      {audio:"念のため確認ですが、この内容で公開してよろしいでしょうか。",q:"最もよい返答はどれですか。",o:["いいえ、まだ始まっていません。","それはすごいですね。","はい、問題ありません。","もう公開済みです。"],a:2,exp:"公開前の最終確認への自然な返答は「はい、問題ありません」。"},
      {audio:"この提案、社内で共有してもよろしいでしょうか。",q:"最もよい返答はどれですか。",o:["はい、ぜひ共有してください。","それは大変ですね。","もう共有済みです。","おめでとうございます。"],a:0,exp:"共有の許可を求められた際の自然な返答。"},
      {sec:"問題5　統合理解",audio:"司会：来年度の広報戦略について、三つの案が出ています。<br>男性A：SNSを中心にした広報がいいと思います。若年層に効果的にリーチできます。<br>女性：私は従来通り、テレビCMを中心にすべきだと思います。幅広い年代への浸透力があります。<br>男性B：両方を組み合わせて、SNSとテレビCMを連動させる案はどうでしょうか。相乗効果が期待できます。<br>司会：予算の制約もありますが、相乗効果を狙って、SNSとテレビCMを連動させる案で進めましょう。",q:"最終的にどの案で進めることになりましたか。",o:["SNSとテレビCMを連動させる案","SNS中心の案","テレビCM中心の案","案がまとまらなかった"],a:0,exp:"司会が最後に「SNSとテレビCMを連動させる案で進めましょう」と決定している。"},
      {q:"女性がテレビCMを推した理由は何ですか。",o:["若年層に人気があるから","制作が簡単だから","幅広い年代への浸透力があるから","予算が最も安いから"],a:2,exp:"「幅広い年代への浸透力があります」が理由。"},
      {audio:"司会：来年度の福利厚生制度の見直しについて、三つ案があります。<br>男性A：住宅手当を増やすべきだと思います。特に若手社員の負担が大きいです。<br>女性：私は育児支援制度を充実させるべきだと思います。出産後の離職を防げます。<br>男性B：両方に少しずつ予算を配分するのはどうでしょうか。<br>司会：それでは、住宅手当と育児支援の両方に予算を配分する案で進めましょう。",q:"最終的にどの案で進めることになりましたか。",o:["住宅手当のみを増やす案","現状維持の案","育児支援のみを充実させる案","住宅手当と育児支援の両方に予算を配分する案"],a:3,exp:"司会が「住宅手当と育児支援の両方に予算を配分する案で進めましょう」と決定している。"}
    ]}
  ]
},
{
  id:"o-n1-4", lvl:"N1", title:"Examen oficial N1 · 4", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙・文法）・読解", minutes:110, questions:[
      {sec:"問題1　漢字読み",q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　彼の話には<u>矛盾</u>がある。",o:["ぼうじゅん","むそん","むじゅん","むしゅん"],a:2,exp:"矛盾→むじゅん「contradicción」。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　彼は<u>斬新</u>な発想を持っている。",o:["ざんしん","ざんせい","ざんじん","ぜんしん"],a:0,exp:"斬新→ざんしん「innovador」。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　この措置は<u>適宜</u>見直される。",o:["てっき","てきぎ","てきよう","てきい"],a:1,exp:"適宜→てきぎ「según convenga、oportunamente」。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　彼女の<u>洞察</u>力には驚かされる。",o:["どうさく","どうかん","どうさつ","とうさつ"],a:2,exp:"洞察→どうさつ「perspicacia」。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　規則の<u>抜け穴</u>を利用した。",o:["ぬけあな","ばつあな","ぬけけつ","ぬきあな"],a:0,exp:"抜け穴→ぬけあな「resquicio、laguna」。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　この決定は<u>覆す</u>ことができない。",o:["くつす","ふくす","おおいかえす","くつがえす"],a:3,exp:"覆す→くつがえす「revocar、dar la vuelta」。"},
      {sec:"問題2　文脈規定",q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼は自らの信念を（　）貫いた。",o:["漠然と","漫然と","悠然と","頑として"],a:3,exp:"頑として「obstinadamente、firmemente」。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼の主張には（　）の余地がある。",o:["検討","納得","賛同","了承"],a:0,exp:"検討の余地がある「hay margen para reconsiderar」。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼女は（　）として動じなかった。",o:["唖然","超然","泰然","漠然"],a:2,exp:"泰然としている「permanecer sereno」。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　この問題は（　）を要する。",o:["慎重対応","慎重さ対応","慎重に対応","慎重な対応"],a:3,exp:"「慎重な対応」が名詞句として自然な形。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼の提案は（　）に値する。",o:["一考","一挙","一見","一目"],a:0,exp:"一考に値する「digno de una consideración」（連語）。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼女は（　）として研究に打ち込んでいる。",o:["黙々","超然","漫然","悠然"],a:0,exp:"黙々として「en silencio, dedicándose sin quejas」。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼の話は（　）を得ない支離滅裂なものだった。",o:["要求","要素","要領","要因"],a:2,exp:"要領を得ない「no ir al grano」。"},
      {sec:"問題3　言い換え類義",q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　彼は自らの信念を<u>頑として</u>貫いた。",o:["一時的に","柔軟に","頑固に、譲らずに","消極的に"],a:2,exp:"頑として≒「obstinadamente」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　彼女は<u>泰然</u>として構えていた。",o:["怒っている様子","焦っている様子","落ち着いて動じない様子","不安そうな様子"],a:2,exp:"泰然≒「sereno, imperturbable」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　彼は<u>抜け穴</u>を利用した。",o:["規則の目的","規則の全体","規則の隙間","規則の中心"],a:2,exp:"抜け穴≒「resquicio, laguna」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　彼の<u>洞察力</u>には驚かされる。",o:["記憶する力","物事を深く見抜く力","計算する力","説得する力"],a:1,exp:"洞察力≒「capacidad de perspicacia」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　この決定を<u>覆す</u>のは難しい。",o:["ひっくり返す","支持する","延期する","公表する"],a:0,exp:"覆す≒「revocar, dar la vuelta」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　彼は<u>黙々と</u>作業を続けた。",o:["急いで","不満を言いながら","何も言わずに黙々と","楽しそうに"],a:2,exp:"黙々と≒「en silencio, sin quejas」。"},
      {sec:"問題4　用法",q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「たとえ」",o:["たとえ明日雨が降る。","たとえ失敗しても、また挑戦すればいい。","たとえ三時に会議がある。","たとえ早く終わった。"],a:1,exp:"たとえ〜ても「aunque, incluso si」仮定的譲歩を表す。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「よしんば」",o:["よしんば明日晴れるだろう。","よしんば早く終わった。","よしんば失敗したとしても、後悔はしない。","よしんば三時に来た。"],a:2,exp:"よしんば〜としても「incluso suponiendo que」（あくまで仮定の譲歩）。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「かろうじて」",o:["かろうじて三時に会議がある。","かろうじて明日雨が降る。","終電にかろうじて間に合った。","かろうじて早く終わった。"],a:2,exp:"かろうじて「a duras penas, por poco」。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「言わずもがな」",o:["彼の実力は言わずもがな、誰もが認めるところだ。","言わずもがな早く終わった。","言わずもがな明日晴れるだろう。","言わずもがな三時に来た。"],a:0,exp:"言わずもがな＝「ni que decir tiene」自明のことを表す。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「なまじ」",o:["なまじ知識があるばかりに、かえって迷うことがある。","なまじ明日雨が降る。","なまじ早く終わった。","なまじ三時に会議がある。"],a:0,exp:"なまじ「a medias、precisamente porque (algo) resulta contraproducente」。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「ひいては」",o:["ひいては三時に来た。","ひいては明日雨が降る。","個人の成長は、ひいては組織全体の発展につながる。","ひいては早く終わった。"],a:2,exp:"ひいては「y por extensión, y en última instancia」。"},
      {sec:"問題5　文法1（文法形式の判断）",q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼の発言（　）、社内に動揺が広がった。",o:["を受けて","にわたって","にかけて","につけて"],a:0,exp:"〜を受けて「en respuesta a」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　この結果は努力（　）ほかならない。",o:["に","で","が","の"],a:0,exp:"〜にほかならない「no es sino」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　予算が限られている（　）、できることは限られる。",o:["以上","反面","上に","ものなら"],a:0,exp:"〜以上「dado que」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼女の演技は素人（　）本格的だった。",o:["につき","にとって","にしては","にかけては"],a:2,exp:"〜にしては「para ser (algo)」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　苦労した（　）、成功の喜びは大きい。",o:["のみか","だけに","だけで","ばかりに"],a:1,exp:"〜だけに「precisamente porque」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　規則に反する（　）、罰則が科される。",o:["場合には","次第では","につれ","ものは"],a:0,exp:"〜場合には「en caso de」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼は部長（　）、部下からの信頼も厚い。",o:["でありながら","にとって","というより","にしたら"],a:0,exp:"〜でありながら「a pesar de ser」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　予算の都合（　）、計画の一部を見直した。",o:["上","上で","上に","上は"],a:0,exp:"〜上「desde el punto de vista de」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼の実力（　）、この結果は当然だ。",o:["からすれば","をものともせず","はさておき","にひきかえ"],a:0,exp:"〜からすれば「desde el punto de vista de」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　周囲の反対（　）、彼は計画を実行した。",o:["にもまして","にひきかえ","といえども","を押し切って"],a:3,exp:"〜を押し切って「haciendo caso omiso de」。"},
      {sec:"問題6　文法2（文の組み立て）",q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　彼女は　___　___　★　___　新しい市場を切り開いた。（1 を　2 独自の　3 発想　4 活かして）",o:["独自の","を","発想","活かして"],a:1,exp:"正しい順序：2独自の→3発想→1を→4活かして「独自の発想を活かして」。★の位置には1「を」が入る。"},
      {q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　この案は　___　___　★　___　実行に移された。（1 のうえで　2 十分な　3 検討　4 を経て）",o:["を経て","のうえで","十分な","検討"],a:2,exp:"正しい順序：2十分な→3検討→4を経て→1のうえで「十分な検討を経てのうえで」。★の位置には1「のうえで」が入る。"},
      {q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　彼は　___　★　___　___　最後までやり通した。（1 周囲の　2 懸念　3 をよそに　4 も）",o:["懸念","周囲の","も","をよそに"],a:0,exp:"正しい順序：1周囲の→2懸念→4も→3をよそに「周囲の懸念をよそに」。★の位置には2「懸念」が入る。"},
      {q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　この改革は　___　___　★　___　実現しなかっただろう。（1 なくして　2 は　3 首相の　4 決断）",o:["は","首相の","なくして","決断"],a:3,exp:"正しい順序：3首相の→4決断→1なくして→2は「首相の決断なくしては」。★の位置には4「決断」が入る。"},
      {q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　彼女は　___　___　★　___　冷静に対応した。（1 パニック　2 に　3 陥る　4 ことなく）",o:["に","パニック","陥る","ことなく"],a:2,exp:"正しい順序：1パニック→2に→3陥る→4ことなく「パニックに陥ることなく」。★の位置には3「陥る」が入る。"},
      {sec:"問題7　文章文法",passage:"次の文章を読んで、文章全体の趣旨を踏まえて、（1）から（5）の中に入る最もよいものを、1・2・3・4から一つ選びなさい。<br><br>科学研究の世界では、失敗は避けるべきものというより、むしろ新たな発見への（1）と捉えられることが多い。仮説が誤っていたと分かること自体が、次の仮説を（2）ための貴重な手がかりとなるからだ。しかし、成果主義が強まる昨今、失敗を許容しない風潮も同時に強まっている（3）指摘される。研究者が失敗を恐れるあまり、確実に成果の出る安全な研究テーマばかりを選ぶようになれば、（4）画期的な発見の芽は摘まれてしまいかねない。真に創造的な研究を育むには、失敗を（5）評価する文化の醸成が不可欠だと言えよう。",q:"（1）",o:["義務","終着点","結果","布石"],a:3,exp:"布石「preparación para el futuro」比喩的に次への一歩を表す。"},
      {q:"（2）",o:["立てた","立てられ","立てて","立てる"],a:3,exp:"「〜ための」に続く動詞は辞書形「立てる」。"},
      {q:"（3）",o:["を","に","と","が"],a:2,exp:"「〜と指摘される」引用・内容を示す助詞。"},
      {q:"（4）",o:["つまり","かえって","したがって","むしろ"],a:1,exp:"逆説的な結果を導く「かえって」が文脈に合う。"},
      {q:"（5）",o:["否定的に","消極的に","前向きに","一切"],a:2,exp:"文脈上、失敗を「前向きに」評価する文化が求められているという結論が自然。"},
      {sec:"問題8　内容理解（短文）",passage:"この自治体では、子育て世帯への支援策として、保育料の無償化を実施した。その結果、若い世帯の転入が増加している。",q:"保育料無償化の結果、何が起きたか。",o:["若い世帯の転入増加","保育士の不足","税収の減少","人口の減少"],a:0,exp:"「若い世帯の転入が増加している」がそのまま答え。"},
      {passage:"この大学では、留学生と日本人学生が共同で生活する寮を新設した。異文化交流を通じた相互理解の促進が狙いだ。",q:"新しい寮の目的は何か。",o:["留学生数の制限","施設の老朽化対策","家賃収入の増加","異文化交流を通じた相互理解の促進"],a:3,exp:"「異文化交流を通じた相互理解の促進が狙い」がそのまま答え。"},
      {passage:"この業界では、人材の流動性が高まっており、転職を経験することが一般的になっている。企業側も中途採用に力を入れざるを得ない状況だ。",q:"企業はなぜ中途採用に力を入れているか。",o:["法律で義務付けられているから","業績が悪化したから","人材の流動性が高まっているから","新卒採用を廃止したから"],a:2,exp:"「人材の流動性が高まっており…中途採用に力を入れざるを得ない」がそのまま答え。"},
      {passage:"インターネット広告市場は急速に拡大しており、従来のテレビや新聞広告の市場規模を上回りつつある。企業側も広告戦略の見直しを迫られている。",q:"企業が迫られていることは何か。",o:["テレビ広告の増加","新聞購読の促進","広告費の削減","広告戦略の見直し"],a:3,exp:"「企業側も広告戦略の見直しを迫られている」がそのまま答え。"},
      {sec:"問題9　内容理解（中文）",passage:"教育の目的は、知識の詰め込みではなく、自ら考え、判断する力を養うことにあると言えよう。試験の点数のみで学びの成果を測ろうとする姿勢は、この本質を見誤らせる危険をはらんでいる。もちろん、基礎知識の習得は不可欠であり、それなしには思考の材料そのものが不足してしまう。",q:"筆者が危惧していることは何か。",o:["試験の点数のみで学びを測ることが本質を見誤らせること","試験制度そのものの廃止","基礎知識の習得が不要になること","知識の詰め込みが不十分であること"],a:0,exp:"「試験の点数のみで…測ろうとする姿勢は…本質を見誤らせる危険」がそのまま答え。"},
      {q:"筆者は基礎知識の習得についてどう考えているか。",o:["試験でのみ評価すべきだ","知識より応用力のほうが先に必要だ","思考の材料として不可欠である","不要であり廃止すべきだ"],a:2,exp:"「基礎知識の習得は不可欠であり、それなしには思考の材料そのものが不足してしまう」と述べている。"},
      {q:"この文章全体の趣旨として最も適切なものはどれか。",o:["基礎知識は不要である","試験の点数偏重が教育の本質を見誤らせる危険がある","試験は教育に不可欠な唯一の指標だ","思考力は生まれつきのものだ"],a:1,exp:"試験偏重への警鐘が文章全体の趣旨。"},
      {passage:"研究者にとって最も重要な資質は、既存の常識を疑う姿勢である。定説を鵜呑みにせず、あえて問い直すことから、新たな発見は生まれる。もっとも、根拠なく何でも疑えばよいというものではなく、疑いには相応の論理的な裏付けが必要である。",q:"筆者が述べる研究者にとって重要な資質は何か。",o:["定説を忠実に守る姿勢","論文を多く書く能力","既存の常識を疑う姿勢","効率よく実験を行う能力"],a:2,exp:"「既存の常識を疑う姿勢」が最重要資質とされている。"},
      {q:"筆者が付け加えている条件は何か。",o:["疑うこと自体が目的だということ","何でも疑ってよいということ","定説は常に正しいということ","疑いには論理的な裏付けが必要であること"],a:3,exp:"「疑いには相応の論理的な裏付けが必要である」がそのまま答え。"},
      {q:"この文章全体の趣旨として最も適切なものはどれか。",o:["常識は疑うべきではない","定説を守ることが研究者の使命だ","何でも疑うことが研究の本質だ","論理的根拠に基づいて常識を疑う姿勢が研究者に重要だ"],a:3,exp:"根拠ある懐疑の姿勢の重要性が文章全体の趣旨。"},
      {passage:"組織の持続的な成長には、既存事業の深化と新規事業の探索、この二つを同時に追求する経営姿勢が求められるという考え方がある。片方に偏ると、短期的な効率は上がっても、長期的な変化への対応力を失いかねない。",q:"筆者が求めている経営姿勢は何か。",o:["新規事業のみに集中する姿勢","既存事業の深化と新規事業の探索を同時に追求する姿勢","既存事業のみに集中する姿勢","変化を避ける姿勢"],a:1,exp:"「深化と探索、この二つを同時に追求する経営姿勢が求められる」がそのまま答え。"},
      {q:"片方の事業に偏るとどうなると述べられているか。",o:["長期的な変化への対応力を失いかねない","必ず倒産する","短期的な効率も下がる","従業員が全員離職する"],a:0,exp:"「片方に偏ると…長期的な変化への対応力を失いかねない」がそのまま答え。"},
      {q:"この文章全体の趣旨として最も適切なものはどれか。",o:["新規事業だけに集中すべきだ","短期的な効率のみを重視すべきだ","既存事業だけに集中すべきだ","深化と探索の両立が組織の持続的成長に不可欠だ"],a:3,exp:"深化と探索の両立の重要性が文章全体の趣旨。"},
      {sec:"問題10　内容理解（長文）",passage:"組織における意思決定の遅さは、しばしば責任の所在の不明確さに起因すると言われる。誰もが責任を負いたがらない風土からは、迅速で大胆な決断は生まれにくい。この課題を打開するには、権限と責任を明確に紐づける制度設計が不可欠だとされる。<br><br>しかし、ここで注意すべき逆説がある。責任の所在を明確にしすぎると、今度は失敗を過度に恐れる萎縮した組織風土を生みかねないという点である。誰が責任者かが明確であればあるほど、その人物は挑戦的な決断を避け、無難な選択に流れやすくなる可能性がある。<br><br>したがって、真に求められているのは、単純な責任の明確化ではなく、挑戦の結果としての失敗を許容する文化と、責任の所在の明確化を両立させる、繊細なバランス感覚なのかもしれない。制度と文化、この両輪がかみ合って初めて、組織は迅速かつ大胆な意思決定を行えるようになるのだろう。",q:"筆者が指摘する意思決定の遅さの原因は何か。",o:["人材の不足","情報不足","予算の制約","責任の所在の不明確さ"],a:3,exp:"「責任の所在の不明確さに起因する」がそのまま答え。"},
      {q:"筆者が指摘する「逆説」とは何か。",o:["権限が多いほど責任も軽くなること","責任があいまいなほうが効率的なこと","制度設計は不要だということ","責任を明確にしすぎると挑戦を避ける風土を生みかねないこと"],a:3,exp:"「責任の所在を明確にしすぎると…萎縮した組織風土を生みかねない」がそのまま答え。"},
      {q:"筆者が真に求めているものは何か。",o:["失敗を許容する文化と責任明確化のバランス","責任の所在を徹底的に明確にすること","責任の所在を完全に曖昧にすること","制度設計を放棄すること"],a:0,exp:"「失敗を許容する文化と、責任の所在の明確化を両立させる…バランス感覚」がそのまま答え。"},
      {q:"この文章全体を通して筆者が伝えたいことは何か。",o:["失敗は絶対に許容すべきではない","組織の意思決定は常に遅いものだ","制度と文化の両輪がかみ合うことで迅速な意思決定が可能になる","責任は明確にしないほうがよい"],a:2,exp:"「制度と文化、この両輪がかみ合って初めて…迅速かつ大胆な意思決定を行える」が結論。"},
      {sec:"問題11　統合理解",passage:"【A】副業を認める企業が増えている。従業員が新たなスキルを身につけ、収入源を分散できることは、労働者にとって大きなメリットだ。企業にとっても、社外で得た知見が本業に還元される可能性があり、双方にとって有益な制度だと言えよう。<br><br>【B】しかし、副業解禁には慎重であるべきだという意見も根強い。本業への集中力が削がれ、長時間労働による健康被害のリスクが高まるという懸念がある。また、情報漏洩など、管理上の課題も無視できない。制度を導入する際は、労働時間の適切な管理体制が前提となるべきだ。",q:"Aの筆者が主張していることは何か。",o:["副業は労働者にのみ利益がある","副業は禁止すべきだ","副業は企業にのみ利益がある","副業は労働者にも企業にも有益な制度だ"],a:3,exp:"Aは「双方にとって有益な制度」と述べている。"},
      {q:"Bの筆者が懸念していることは何か。",o:["労働時間が短くなりすぎること","健康被害のリスクや情報漏洩などの課題","副業がすぐになくなること","副業を行う人がいなくなること"],a:1,exp:"「長時間労働による健康被害のリスク…情報漏洩など、管理上の課題」が懸念。"},
      {q:"AとBの筆者に共通する前提は何か。",o:["副業は絶対に禁止すべきだということ","副業には利点と課題の両面があるということ","副業は労働者にとって無意味だということ","副業には全く問題がないということ"],a:1,exp:"両者とも副業の効果と課題の両面を扱っている。"},
      {sec:"問題12　主張理解（長文）",passage:"効率化ばかりを追求する現代社会において、雑談や余白といった一見無駄に見えるものの中にこそ、新しい発想の種が潜んでいるのではないかという指摘がある。効率を過度に重視するあまり、こうした偶発的な創造性の芽まで摘み取ってしまう危険がある。<br><br>もちろん、無駄を無制限に許容すべきだというわけではない。しかし、あらゆる業務プロセスから「無駄」とされるものを徹底的に排除しようとする姿勢は、短期的な生産性を高める一方で、長期的にはイノベーションの種を枯渇させる恐れがある。<br><br>組織が真に持続的な成長を遂げるためには、効率と余白、この一見矛盾する二つの要素を、意図的に共存させる工夫が求められるのではないだろうか。",q:"筆者が指摘する危険は何か。",o:["効率化が全く進まないこと","雑談を推奨しすぎること","過度な効率化が創造性の芽を摘み取ること","余白が多すぎること"],a:2,exp:"「効率を過度に重視するあまり…創造性の芽まで摘み取ってしまう危険」がそのまま答え。"},
      {q:"筆者は無駄の扱いについてどう考えているか。",o:["無制限に許容すべきではないが徹底的な排除にも問題がある","無駄について特に意見はない","無駄はすべて許容すべきだ","無駄は完全に排除すべきだ"],a:0,exp:"「無駄を無制限に許容すべきだというわけではない」「徹底的に排除しようとする姿勢は…恐れがある」の両面から述べている。"},
      {q:"筆者が組織に求めていることは何か。",o:["効率のみを追求すること","効率と余白を意図的に共存させる工夫","余白のみを重視すること","無駄を完全に排除する仕組み"],a:1,exp:"「効率と余白…この一見矛盾する二つの要素を、意図的に共存させる工夫が求められる」がそのまま答え。"},
      {q:"この文章全体を通して筆者が伝えたいことは何か。",o:["効率と余白の共存が持続的な成長につながる","効率化こそが唯一の正解だ","イノベーションは効率化から生まれる","余白は不要である"],a:0,exp:"効率と余白の共存を提案する結論。"},
      {sec:"問題13　情報検索",passage:"【企業向け研修プログラム　案内】<br>・コース：Ａ「新人研修」（1日）／Ｂ「管理職研修」（2日）／Ｃ「グローバル人材育成」（3日、英語での実施）<br>・料金：1名につきＡ 30,000円、Ｂ 60,000円、Ｃ 100,000円（税別）。同一企業から5名以上の同時申込みで全体の10％割引。<br>・開催形式：対面またはオンライン、企業ごとに選択可能。ただし、Ｃコースは対面のみ。<br>・申込締切：開催日の3週間前まで。締切後のキャンセルは料金の50％を申し受ける。<br>・注意事項：Ｃコースの受講には、事前の英語力診断テスト（無料）の受験が必須。基準に満たない場合は受講をお断りする場合がある。",q:"ある企業がＣコースをオンラインで受講したい場合、どうなるか。",o:["問題なくオンラインで受講できる","Ｃコースはオンラインでは受講できない","追加料金を払えばオンラインで受講できる","事前診断テストなしで受講できる"],a:1,exp:"「Ｃコースは対面のみ」とあるため、オンラインでは受講できない。"},
      {q:"この案内から分かることとして正しいものはどれか。",o:["キャンセルには一切料金がかからない","すべてのコースはオンラインのみで実施される","5名未満でも割引が適用される","Ｃコース受講には事前の英語力診断テストが必須である"],a:3,exp:"「事前の英語力診断テスト…の受験が必須」がそのまま該当。"}
    ]},
    {id:"b", title:"聴解", minutes:55, questions:[
      {sec:"問題1　課題理解",audio:"男：来週の取締役会の資料、準備は進んでいますか。　女：ほぼ終わりましたが、財務データの最終確認がまだです。今日中に経理部に確認を取ります。",q:"女の人はこのあと、まず何をしますか。",o:["財務データを削除する","取締役会を延期する","資料を作り直す","経理部に確認を取る"],a:3,exp:"「今日中に経理部に確認を取ります」がそのまま答え。"},
      {audio:"女：新しいオフィスの内装、業者は決まりましたか。　男：まだ二社に絞った段階です。今日の午後、見積もりを比較します。　女：分かったら教えてください。",q:"男の人はこのあと、まず何をしますか。",o:["オフィスを移転する","見積もりを比較する","業者と契約する","内装工事を始める"],a:1,exp:"「今日の午後、見積もりを比較します」がそのまま答え。"},
      {audio:"男：来月の展示会、ブースのデザイン案は決まりましたか。　女：三案の中から、社内アンケートで人気だったものに決めようと思っています。今日結果を集計します。",q:"女の人はこのあと、まず何をしますか。",o:["デザインをやり直す","アンケート結果を集計する","展示会を中止する","業者に発注する"],a:1,exp:"「今日結果を集計します」がそのまま答え。"},
      {audio:"女：来週の海外出張、ホテルの予約はできていますか。　男：まだです。今日中に、会社指定の旅行代理店に連絡します。",q:"男の人はこのあと、まず何をしますか。",o:["航空券を購入する","現地の会社に連絡する","旅行代理店に連絡する","出張を中止する"],a:2,exp:"「今日中に、会社指定の旅行代理店に連絡します」がそのまま答え。"},
      {audio:"女：この提案書、来週のプレゼンまでに仕上げないといけないんですが。　男：手伝いますよ。どこまで進んでいますか。　女：構成はできているので、あとはグラフの作成をお願いできますか。",q:"男の人はこのあと、何をしますか。",o:["提案書のグラフを作成する","プレゼンの日程を変更する","構成を作り直す","提案書を印刷する"],a:0,exp:"「グラフの作成をお願いできますか」への流れから、男性はグラフ作成を担当する。"},
      {sec:"問題2　ポイント理解",audio:"男：このソフトウェア、なかなか普及しませんね。　女：価格の高さも一因ですが、一番の問題は操作が複雑すぎることだと思います。",q:"女の人は、普及しない一番の原因は何だと言っていますか。",o:["広告が少ないこと","価格が高いこと","競合が多いこと","操作が複雑すぎること"],a:3,exp:"「一番の問題は操作が複雑すぎること」がそのまま答え。"},
      {audio:"女：この地域、観光客が減っていますね。　男：交通の便もありますが、一番大きいのは、SNSでの発信が他の観光地に比べて弱いことだと思います。",q:"男の人は、観光客が減った一番の原因は何だと考えていますか。",o:["交通の便が悪いこと","天候が悪いこと","SNSでの発信が弱いこと","宿泊施設が少ないこと"],a:2,exp:"「一番大きいのは、SNSでの発信が…弱いこと」がそのまま答え。"},
      {audio:"男：この製品、クレームが増えていますね。　女：品質自体よりも、説明書の翻訳が不自然なことが一番の原因だと聞いています。",q:"女の人は、クレームが増えた一番の原因は何だと言っていますか。",o:["製品の品質が悪いこと","配送が遅いこと","説明書の翻訳が不自然なこと","価格が高すぎること"],a:2,exp:"「説明書の翻訳が不自然なことが一番の原因」がそのまま答え。"},
      {audio:"女：この学校、退学者が増えていますね。　男：経済的な理由もありますが、一番の原因は、入学前と実際の授業内容のギャップだと言われています。",q:"男の人は、退学者が増えた一番の原因は何だと考えていますか。",o:["教師の質","経済的な理由","入学前と実際の授業内容のギャップ","施設の古さ"],a:2,exp:"「一番の原因は、入学前と実際の授業内容のギャップ」がそのまま答え。"},
      {audio:"男：この工場、生産効率が落ちていますね。　女：設備の老朽化もありますが、一番の原因は、作業手順の見直しが長年されていないことだと思います。",q:"女の人は、生産効率低下の一番の原因は何だと考えていますか。",o:["作業手順の見直しがされていないこと","人員の不足","設備の老朽化","原材料の不足"],a:0,exp:"「一番の原因は、作業手順の見直しが長年されていないこと」がそのまま答え。"},
      {audio:"女：この飲食店、客の回転率が悪いですね。　男：メニューの品数もありますが、一番の問題は、会計システムに時間がかかりすぎることだと思います。",q:"男の人は、回転率が悪い一番の原因は何だと考えていますか。",o:["会計システムに時間がかかること","席の配置が悪いこと","メニューの品数が多いこと","スタッフが少ないこと"],a:0,exp:"「一番の問題は、会計システムに時間がかかりすぎること」がそのまま答え。"},
      {sec:"問題3　概要理解",audio:"組織の意思決定の遅さは、責任の所在の不明確さに起因すると言われる一方、責任を明確にしすぎると挑戦を避ける風土を生むという逆説もある。制度と文化のバランスが求められている。",q:"この話は、主に何について述べていますか。",o:["給与制度の設計","組織の意思決定における責任と挑戦のバランス","会議の効率的な進め方","人事評価の方法"],a:1,exp:"責任の明確化と挑戦を許容する文化のバランスについての話。"},
      {audio:"副業を認める企業が増える中、労働者にも企業にもメリットがあるという意見がある一方、健康被害や情報漏洩を懸念する声もあり、労働時間の管理体制が課題となっている。",q:"この話は、主に何について述べていますか。",o:["副業禁止の歴史","副業の税制上の扱い","副業の探し方","副業解禁のメリットと課題"],a:3,exp:"副業解禁の利点と課題についての話。"},
      {audio:"効率化を追求するあまり、雑談や余白といった一見無駄に見えるものの中にある創造性の芽まで失われつつあるのではないかという指摘があり、効率と余白の共存が求められている。",q:"この話は、主に何について述べていますか。",o:["労働時間の短縮策","職場のルール作り","効率的な会議の進め方","過度な効率化が創造性を損なう可能性への懸念"],a:3,exp:"効率偏重への懸念と、余白の価値についての話。"},
      {audio:"研究者にとって重要な資質は既存の常識を疑う姿勢だが、根拠のない懐疑は意味がなく、疑いには論理的な裏付けが必要だという指摘がある。",q:"この話は、主に何について述べていますか。",o:["研究者に必要な批判的思考のあり方","論文の書き方","研究費の獲得方法","学会発表の準備"],a:0,exp:"研究者に求められる思考態度についての話。"},
      {audio:"教育の目的は知識の詰め込みではなく自ら考え判断する力を養うことにあるとされるが、基礎知識の習得もまた不可欠だという指摘がある。",q:"この話は、主に何について述べていますか。",o:["学校の設備投資","教員の待遇改善","教育における基礎知識と思考力の関係","入試制度の改革"],a:2,exp:"教育の目的と基礎知識の重要性についての話。"},
      {sec:"問題4　即時応答",audio:"この案件、少々お時間をいただいてもよろしいでしょうか。",q:"最もよい返答はどれですか。",o:["はい、構いません。","それは残念です。","もう終わりました。","おめでとうございます。"],a:0,exp:"時間の猶予を求める依頼への自然な返答は「はい、構いません」。"},
      {audio:"申し訳ございませんが、この価格ではお引き受けしかねます。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","では、どのくらいの価格であれば可能でしょうか。","それは嬉しいです。","もう決まったことです。"],a:1,exp:"価格を理由に断られた際の自然な返答は、条件を尋ねる形。"},
      {audio:"この企画、正直な感想をお聞かせいただけますか。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","もう決まりました。","それはすごいですね。","率直に申し上げますと、少し懸念があります。"],a:3,exp:"率直な感想を求められた際の自然な返答。"},
      {audio:"恐縮ですが、少々検討にお時間をいただいております。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","承知しました。目安を教えていただけますか。","もう終わったんですね。","それは嬉しいです。"],a:1,exp:"時間を要するという連絡への自然な返答は、目安を尋ねる形。"},
      {audio:"この件、上層部の承認が必要になりそうです。",q:"最もよい返答はどれですか。",o:["もう承認されています。","おめでとうございます。","それは残念すぎます。","承知しました。どのくらいで結果が分かりますか。"],a:3,exp:"承認プロセスの連絡への自然な返答は、期間を確認する形。"},
      {audio:"念のため、この認識で相違ないか確認させてください。",q:"最もよい返答はどれですか。",o:["もう終わった話です。","はい、その認識で間違いありません。","それはすごいですね。","いいえ、まだ始まっていません。"],a:1,exp:"認識確認への自然な返答は「はい、その認識で間違いありません」。"},
      {audio:"この度は多大なご迷惑をおかけし、深くお詫び申し上げます。",q:"最もよい返答はどれですか。",o:["いえ、こちらこそ配慮が足りませんでした。","もっとやってください。","それは嬉しいです。","おめでとうございます。"],a:0,exp:"謝罪への自然な返答は、相手を責めずに応じる形。"},
      {audio:"この提案、社内での反応はいかがでしょうか。",q:"最もよい返答はどれですか。",o:["それは残念ですね。","概ね好評ですが、一部懸念の声もあります。","もう終わりました。","おめでとうございます。"],a:1,exp:"社内の反応を尋ねられた際の自然な返答。"},
      {audio:"この度はご丁寧なご説明をいただき、恐縮です。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","もう終わりです。","それは残念ですね。","いえ、お役に立てば幸いです。"],a:3,exp:"感謝の言葉への自然な返答。"},
      {audio:"恐れ入りますが、こちらの資料、少々古い可能性がございます。",q:"最もよい返答はどれですか。",o:["承知しました。最新版を確認いたします。","もう最新版です、以上です。","おめでとうございます。","それはすごいですね。"],a:0,exp:"資料が古い可能性を指摘された際の自然な返答。"},
      {audio:"この件、事前に社内で共有しておいていただけますか。",q:"最もよい返答はどれですか。",o:["もう共有済みです。","承知しました。明日までに共有します。","それは大変ですね。","おめでとうございます。"],a:1,exp:"共有依頼への自然な返答。"},
      {sec:"問題5　統合理解",audio:"司会：新しい社員食堂のメニュー方針について、三つ案があります。<br>男性A：健康志向のメニューを中心にすべきだと思います。低カロリーで栄養バランスの取れたものを増やすべきです。<br>女性：私はボリューム重視のメニューがいいと思います。特に体力仕事の社員には量が大事です。<br>男性B：両方のニーズに応えるため、日替わりで健康メニューとボリュームメニューを両方用意するのはどうでしょうか。<br>司会：それでは、日替わりで両方のメニューを用意する案で進めましょう。",q:"最終的にどの案で進めることになりましたか。",o:["日替わりで両方のメニューを用意する案","ボリューム重視メニューのみの案","現状維持の案","健康志向メニューのみの案"],a:0,exp:"司会が「日替わりで両方のメニューを用意する案で進めましょう」と決定している。"},
      {q:"女性がボリューム重視のメニューを推した理由は何ですか。",o:["健康志向の社員が少ないから","予算が最も安いから","体力仕事の社員には量が大事だから","調理が簡単だから"],a:2,exp:"「特に体力仕事の社員には量が大事です」が理由。"},
      {audio:"司会：新入社員のメンター制度について、三つ案があります。<br>男性A：ベテラン社員一人につき新人一人のマンツーマン方式がいいと思います。<br>女性：私はチーム全体でサポートする方式がいいと思います。特定の人に負担が偏りません。<br>男性B：両方を組み合わせて、メインのメンターを一人決めつつ、チーム全体でもサポートする形はどうでしょうか。<br>司会：それでは、メインメンターとチームサポートを組み合わせる案で進めましょう。",q:"最終的にどの案で進めることになりましたか。",o:["メインメンターとチームサポートを組み合わせる案","チーム全体でサポートする案のみ","マンツーマン方式のみの案","制度自体を導入しない案"],a:0,exp:"司会が「メインメンターとチームサポートを組み合わせる案で進めましょう」と決定している。"}
    ]}
  ]
},
{
  id:"o-n1-5", lvl:"N1", title:"Examen oficial N1 · 5", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙・文法）・読解", minutes:110, questions:[
      {sec:"問題1　漢字読み",q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　彼の意見は<u>示唆</u>に富んでいる。",o:["じさ","しさ","しし","じし"],a:1,exp:"示唆→しさ「sugerencia、insinuación」。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　その主張は<u>牽強付会</u>だ。",o:["けんごうふかい","けんきょうふえ","けんごうふえ","けんきょうふかい"],a:3,exp:"牽強付会→けんきょうふかい「argumento forzado, retorcido」。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　彼は<u>寡黙</u>な人だ。",o:["がもく","かもく","かぼく","かもつ"],a:1,exp:"寡黙→かもく「taciturno、poco hablador」。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　彼女の対応は<u>秀逸</u>だった。",o:["しゅうえつ","ひでおつ","しゅういつ","ひでいつ"],a:2,exp:"秀逸→しゅういつ「excelente、sobresaliente」。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　その決定は<u>拙速</u>だった。",o:["せっそく","せっすみ","せつそく","せつすみ"],a:0,exp:"拙速→せっそく「apresurado、precipitado」。"},
      {q:"次の下線の言葉の読み方として最もよいものを、1・2・3・4から一つ選びなさい。　彼は<u>執着</u>を捨てられなかった。",o:["しゅうじゃく","しゅうちゃく","しつちゃく","しっちゃく"],a:1,exp:"執着→しゅうちゃく「apego, obsesión」。"},
      {sec:"問題2　文脈規定",q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼は事態を（　）に受け止めた。",o:["真剣","深刻","本気","真面目"],a:1,exp:"深刻に受け止める「tomarse en serio (una situación grave)」。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼の発言は（　）を招いた。",o:["評判","話題","注目","物議"],a:3,exp:"物議を招く「causar controversia」（連語）。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼女は（　）として批判に耐えた。",o:["漠然","茫然","超然","毅然"],a:3,exp:"毅然として「con firmeza, sin flaquear」。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　この問題は（　）を要する。",o:["慎重検討","慎重な検討","慎重に検討","慎重さ検討"],a:1,exp:"「慎重な検討」が名詞句として自然。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼の説明には（　）がある。",o:["説得力","説得質","説得感","説得性"],a:0,exp:"説得力「poder de convicción」が正しい語形。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼女は（　）として動じなかった。",o:["超然","泰然","唖然","漠然"],a:1,exp:"泰然としている「permanecer sereno」。"},
      {q:"（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼は難局を（　）乗り切った。",o:["急激に","巧みに","過剰に","強引に"],a:1,exp:"巧みに「hábilmente」。"},
      {sec:"問題3　言い換え類義",q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　彼の意見は<u>示唆</u>に富んでいる。",o:["理解しにくい","反論しにくい","結論をはっきり述べる","ヒントや気づきを与える"],a:3,exp:"示唆に富む≒「rico en sugerencias」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　その決定は<u>拙速</u>だった。",o:["的確だった","遅すぎた","慎重すぎた","急ぎすぎて不十分だった"],a:3,exp:"拙速≒「apresurado y descuidado」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　彼は<u>寡黙</u>な人だ。",o:["口数が少ない","おしゃべりな","陽気な","感情的な"],a:0,exp:"寡黙≒「taciturno、reservado」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　彼女の対応は<u>秀逸</u>だった。",o:["遅かった","不十分だった","普通だった","非常に優れていた"],a:3,exp:"秀逸≒「sobresaliente」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　彼は<u>執着</u>を捨てられなかった。",o:["無関心","柔軟さ","強いこだわり","冷静さ"],a:2,exp:"執着≒「apego、obsesión」。"},
      {q:"　　の言葉に意味が最も近いものを、1・2・3・4から一つ選びなさい。　彼は<u>毅然</u>として批判に耐えた。",o:["不安そうに","態度を崩さず堂々と","諦めて","焦って"],a:1,exp:"毅然として≒「con firmeza, sin flaquear」。"},
      {sec:"問題4　用法",q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「よそに」",o:["よそに早く終わった。","よそに三時に会議がある。","周囲の心配をよそに、彼は平然としていた。","よそに明日雨が降る。"],a:2,exp:"〜をよそに「haciendo caso omiso de」。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「かたわら」",o:["かたわら三時に来た。","かたわら明日雨が降る。","かたわら早く終わった。","彼は仕事のかたわら、大学院で学んでいる。"],a:3,exp:"〜かたわら「mientras (hace otra cosa en paralelo)」。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「すべからく」",o:["すべからく早く終わった。","すべからく三時に会議がある。","リーダーはすべからく謙虚であるべきだ。","すべからく明日晴れるだろう。"],a:2,exp:"すべからく〜べきだ「por naturaleza / necesariamente se debe」規範的な当為を表す。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「いみじくも」",o:["彼はいみじくも真実を言い当てた。","いみじくも早く終わった。","いみじくも三時に来た。","いみじくも明日雨が降る。"],a:0,exp:"いみじくも「acertadamente, con precisión sorprendente」。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「あながち」",o:["あながち明日会議がある。","彼の意見もあながち間違いとは言えない。","あながち三時に来た。","あながち早く終わった。"],a:1,exp:"あながち〜とは言えない「no del todo, no necesariamente」部分否定。"},
      {q:"次の言葉の使い方として最もよいものを、1・2・3・4から一つ選びなさい。「つゆほども」",o:["つゆほども明日雨が降る。","つゆほども三時に来た。","彼は失敗をつゆほども後悔していない。","つゆほども早く終わった。"],a:2,exp:"つゆほども〜ない「en absoluto, ni una pizca」強い否定を表す。"},
      {sec:"問題5　文法1（文法形式の判断）",q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　この提案は斬新である（　）、実現には課題が多い。",o:["つつ","反面","あまり","べく"],a:1,exp:"〜反面「por otro lado」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼は疲れていた（　）、最後までやり遂げた。",o:["かたわら","ゆえに","にもかかわらず","とあって"],a:2,exp:"〜にもかかわらず「a pesar de」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼の貢献（　）、この成功はなかっただろう。",o:["ときたら","なくして","にひきかえ","はおろか"],a:1,exp:"〜なくして（は）「sin (algo)」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　規模の大小（　）、この問題は軽視できない。",o:["にわたって","につき","を問わず","にそくして"],a:2,exp:"〜を問わず「independientemente de」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼は逆境（　）、決して諦めなかった。",o:["ときたら","にあっても","はおろか","にひきかえ"],a:1,exp:"〜にあっても「incluso en (adversidad)」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　この結果は偶然（　）必然の産物だ。",o:["というもの","というのに","といえども","というより"],a:3,exp:"〜というより「más que」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　彼女は経験の乏しさ（　）、見事な対応を見せた。",o:["をものともせず","はおろか","にひきかえ","ときたら"],a:0,exp:"〜をものともせず「sin dejarse afectar por」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　社員の声を反映する（　）、制度を見直した。",o:["かねて","もかまわず","がてら","べく"],a:3,exp:"〜べく「con el fin de」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　周囲の反対を（　）、彼は計画を実行した。",o:["かねて","もとに","めぐって","押し切って"],a:3,exp:"〜を押し切って「haciendo caso omiso de」。"},
      {q:"次の文の（　）に入れるのに最もよいものを、1・2・3・4から一つ選びなさい。　経験の有無に（　）、誰でも参加できる。",o:["かかわらず","そって","わたって","こたえて"],a:0,exp:"〜にかかわらず「independientemente de」。"},
      {sec:"問題6　文法2（文の組み立て）",q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　彼は　___　___　★　___　批判に耐えた。（1 として　2 毅然　3 なおも　4 続く）",o:["毅然","として","なおも","続く"],a:1,exp:"正しい順序：4続く→3なおも→2毅然→1として「続くなおも毅然として」の語順を整理すると「なおも続く批判に毅然として耐えた」。★の位置には1「として」が入る。"},
      {q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　この結論は　___　___　★　___　導き出されたものだ。（1 データ　2 分析　3 の　4 綿密な）",o:["分析","の","データ","綿密な"],a:1,exp:"正しい順序：4綿密な→1データ→2分析→3の「綿密なデータ分析の」。★の位置には3「の」が入る。"},
      {q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　彼女は　___　★　___　___　冷静さを失わなかった。（1 直面し　2 困難に　3 ながらも　4 大きな）",o:["大きな","直面し","ながらも","困難に"],a:1,exp:"正しい順序：4大きな→2困難に→1直面し→3ながらも「大きな困難に直面しながらも」。★の位置には1「直面し」が入る。"},
      {q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　彼の　___　___　★　___　この事業は成功しなかった。（1 なかったら　2 尽力　3 が　4 献身的な）",o:["が","なかったら","献身的な","尽力"],a:0,exp:"正しい順序：4献身的な→2尽力→3が→1なかったら「献身的な尽力がなかったら」。★の位置には3「が」が入る。"},
      {q:"次の文の　★　に入る最もよいものを、1・2・3・4から一つ選びなさい。　この制度は　___　___　★　___　導入された。（1 声を　2 現場の　3 反映して　4 も）",o:["声を","も","反映して","現場の"],a:2,exp:"正しい順序：2現場の→1声を→3反映して「現場の声を反映して」。★の位置には3「反映して」が入る。"},
      {sec:"問題7　文章文法",passage:"次の文章を読んで、文章全体の趣旨を踏まえて、（1）から（5）の中に入る最もよいものを、1・2・3・4から一つ選びなさい。<br><br>組織における心理的安全性という概念が、近年注目を集めている。これは、率直な意見や懸念を口にしても、罰せられたり恥をかかされたりしない（1）確信を、メンバーが共有している状態を指す。この安全性が低い組織では、メンバーは失敗を恐れるあまり本音を言わなくなり、（2）問題の早期発見が遅れがちになる。<br><br>ただし、心理的安全性とは、単に居心地の良い、ぬるま湯的な環境を意味するわけではない（3）。むしろ、率直な指摘や建設的な対立を歓迎する土壌があってこそ、真の心理的安全性は成立する。（4）、心地よさだけを追求する組織は、かえって成長の機会を逃しかねない。<br><br>心理的安全性を高めることは、決して簡単な取り組みではない。しかし、その（5）は、組織の長期的な競争力に直結する重要な課題だと言えるだろう。",q:"（1）",o:["とばかりの","という","ときたる","といった"],a:1,exp:"〜という確信「la convicción de que」内容を示す。"},
      {q:"（2）",o:["それゆえ","ところが","ともあれ","結果として"],a:3,exp:"結果として「como resultado」因果関係を導く。"},
      {q:"（3）",o:["ということは間違いない","ということはあり得ない","ということに注意が必要だ","というのは誤解だ"],a:2,exp:"文脈上、誤解されやすい点への注意喚起として自然。"},
      {q:"（4）",o:["したがって","ところで","つまり","むしろ"],a:3,exp:"逆説的な補足を導く「むしろ」が文脈に合う。"},
      {q:"（5）",o:["放棄","否定","構築","消滅"],a:2,exp:"文脈上、心理的安全性の「構築」が競争力に直結するという結論が自然。"},
      {sec:"問題8　内容理解（短文）",passage:"この会社では、社員の提案から生まれた新商品が好調な売れ行きを見せている。社員のアイデアを大切にする社風が実を結んだ形だ。",q:"新商品の好調な売れ行きは何の結果か。",o:["社員のアイデアを大切にする社風","競合の撤退","値下げ","広告の効果"],a:0,exp:"「社員のアイデアを大切にする社風が実を結んだ」がそのまま答え。"},
      {passage:"この地域では、空き店舗を利用したイベントが定期的に開かれており、地域の活性化につながっている。",q:"空き店舗の利用は何につながっているか。",o:["犯罪の増加","地域の活性化","家賃の上昇","人口の減少"],a:1,exp:"「地域の活性化につながっている」がそのまま答え。"},
      {passage:"この地域は昔から農業が盛んで、特に米作りで知られている。しかし近年、若い世代の農業離れが進み、後継者不足が深刻な問題となっている。",q:"この地域の問題は何か。",o:["観光客が少ないこと","米の生産量が多すぎること","後継者不足","土地が狭いこと"],a:2,exp:"「後継者不足が深刻な問題」がそのまま答え。"},
      {passage:"この病院では、待ち時間の長さが患者の不満の原因となっていた。予約システムを改善した結果、待ち時間が大幅に短縮された。",q:"待ち時間が短縮された理由は何か。",o:["患者数の減少","予約システムの改善","医師の増員","診療時間の延長"],a:1,exp:"「予約システムを改善した結果、待ち時間が大幅に短縮された」がそのまま答え。"},
      {sec:"問題9　内容理解（中文）",passage:"組織における心理的安全性という概念が、近年注目を集めている。率直な意見を言っても罰せられないという確信をメンバーが共有している状態を指すが、これは単に居心地のよい環境を意味するわけではない。むしろ、建設的な対立を歓迎する土壌があってこそ成立するものである。",q:"筆者が定義する心理的安全性とは何か。",o:["上司にのみ意見が許される環境","率直な意見を言っても罰せられないという確信の共有","対立を一切避ける環境","居心地のよいぬるま湯的な環境"],a:1,exp:"「率直な意見や懸念を口にしても…罰せられたりしない確信を、メンバーが共有している状態」が定義。"},
      {q:"筆者は心理的安全性についてどのような誤解を指摘しているか。",o:["測定不可能だという誤解","効果がないという誤解","単に居心地のよい環境だという誤解","上司にのみ必要だという誤解"],a:2,exp:"「単に居心地の良い、ぬるま湯的な環境を意味するわけではない」がそのまま答え。"},
      {q:"この文章全体の趣旨として最も適切なものはどれか。",o:["心理的安全性は建設的な対立があってこそ成立する","心理的安全性は上司だけが持つべきものだ","心理的安全性は不要な概念だ","心理的安全性は対立を避けることで成立する"],a:0,exp:"「建設的な対立を歓迎する土壌があってこそ、真の心理的安全性は成立する」が趣旨。"},
      {passage:"少子高齢化が進む日本では、労働力不足を補うため、外国人労働者の受け入れ拡大が議論されている。一方で、言語や文化の違いによる職場での摩擦を懸念する声も根強い。",q:"外国人労働者の受け入れに関して懸念されていることは何か。",o:["治安の悪化","住居不足","言語や文化の違いによる摩擦","賃金の高騰"],a:2,exp:"「言語や文化の違いによる職場での摩擦を懸念する声も根強い」がそのまま答え。"},
      {q:"この文章が扱っている論点は何か。",o:["賃金体系の見直し","治安対策の強化","移民法の改正手続き","労働力不足対策としての外国人労働者受け入れとその課題"],a:3,exp:"労働力不足対策とその懸念点の両方を扱っている。"},
      {q:"この文章の要旨として最も適切なものはどれか。",o:["言語の違いは全く問題にならない","外国人労働者の受け入れは不要である","外国人労働者受け入れには制度と意識の両面の変化が必要だ","賃金さえ上げれば全て解決する"],a:2,exp:"制度的な議論と意識改革の両方に言及している。"},
      {passage:"効率化ばかりを追求する現代社会において、雑談や余白といった一見無駄に見えるものの中にこそ、新しい発想の種が潜んでいるのではないかという指摘がある。無駄を一律に排除する姿勢は、かえって組織の創造性を損なう危険をはらんでいる。",q:"筆者が指摘する危険は何か。",o:["雑談を推奨しすぎること","余白が多すぎること","無駄を一律に排除することが創造性を損なうこと","効率化が全く進まないこと"],a:2,exp:"「無駄を一律に排除する姿勢は、かえって組織の創造性を損なう危険」がそのまま答え。"},
      {q:"筆者は雑談や余白をどう捉えているか。",o:["新しい発想の種になりうるもの","完全に無駄なもの","時間の浪費でしかないもの","業務効率を下げるだけのもの"],a:0,exp:"「新しい発想の種が潜んでいるのではないか」と肯定的に捉えている。"},
      {q:"この文章全体の趣旨として最も適切なものはどれか。",o:["効率偏重の姿勢が組織の創造性を損なう危険がある","効率化はすべて推進すべきだ","雑談は業務の妨げにしかならない","余白は完全に排除すべきだ"],a:0,exp:"効率偏重への警鐘が文章全体の趣旨。"},
      {sec:"問題10　内容理解（長文）",passage:"教育の目的は、知識の詰め込みではなく、自ら考え、判断する力を養うことにあると言えよう。試験の点数のみで学びの成果を測ろうとする姿勢は、この本質を見誤らせる危険をはらんでいる。<br><br>もちろん、基礎知識の習得は不可欠であり、それなしには思考の材料そのものが不足してしまう。しかし、知識を「持っていること」と、それを「使いこなせること」の間には大きな隔たりがある。教育現場では、この二つを混同し、前者のみを評価する傾向が根強く残っているのではないか。<br><br>真に求められているのは、既知の知識を新しい状況に応用し、未知の問題に対して自分なりの答えを導き出す力である。そのためには、正解が一つに定まらない問いに向き合う経験を、教育の中により多く取り入れていく必要があるだろう。",q:"筆者が危惧していることは何か。",o:["試験の点数のみで学びを測ることが本質を見誤らせること","知識の詰め込みが不十分であること","基礎知識の習得が不要になること","試験制度そのものの廃止"],a:0,exp:"「試験の点数のみで…測ろうとする姿勢は…本質を見誤らせる危険」がそのまま答え。"},
      {q:"筆者が「大きな隔たりがある」と述べているのは何と何の間か。",o:["知識を持っていることと使いこなせること","教師と生徒","基礎教育と応用教育","試験の点数と実際の能力"],a:0,exp:"「知識を『持っていること』と、それを『使いこなせること』の間には大きな隔たりがある」がそのまま答え。"},
      {q:"筆者が教育に取り入れるべきだと述べているのはどのような経験か。",o:["知識を暗記する経験","教師の話を聞くだけの経験","正解が一つに定まらない問いに向き合う経験","試験で高得点を取る経験"],a:2,exp:"「正解が一つに定まらない問いに向き合う経験を…取り入れていく必要がある」がそのまま答え。"},
      {q:"この文章全体を通して筆者が最も伝えたいことは何か。",o:["思考力は教育では養えない","知識の応用力を養う教育への転換が必要だ","基礎知識の習得は不要だ","試験は教育に不可欠な唯一の指標だ"],a:1,exp:"応用力を養う教育への転換の必要性が全体の結論。"},
      {sec:"問題11　統合理解",passage:"【A】終身雇用制度は、従業員に安定と忠誠心をもたらし、長期的な人材育成を可能にしてきた。この制度を安易に手放すべきではないという意見がある。<br><br>【B】しかし、終身雇用制度は、変化の激しい現代のビジネス環境には適していないという指摘もある。年功序列と結びついたこの制度は、若手の意欲的な挑戦を阻害しかねない。今後は、より流動的な雇用形態への移行が求められるだろう。",q:"Aの筆者が主張していることは何か。",o:["若手の挑戦を阻害すべきだ","離職率は高い方がよい","終身雇用制度をすぐに廃止すべきだ","終身雇用制度を安易に手放すべきではない"],a:3,exp:"Aは終身雇用制度の維持を支持している。"},
      {q:"Bの筆者が懸念していることは何か。",o:["雇用が流動的すぎること","終身雇用制度が若手の挑戦を阻害すること","終身雇用制度がすぐになくなること","離職率が低すぎること"],a:1,exp:"「若手の意欲的な挑戦を阻害しかねない」が懸念。"},
      {q:"AとBの筆者に共通する視点は何か。",o:["終身雇用制度は完全に無意味だということ","雇用制度自体が不要だということ","終身雇用制度に問題は全くないということ","終身雇用制度には利点と課題の両面があるということ"],a:3,exp:"両者とも終身雇用制度の効果と限界の両面を扱っている。"},
      {sec:"問題12　主張理解（長文）",passage:"組織における心理的安全性という概念が、近年ますます重視されている。率直な意見や懸念を口にしても、罰せられたり恥をかかされたりしないという確信をメンバーが共有している状態を指す。<br><br>この安全性が低い組織では、メンバーは失敗を恐れるあまり本音を言わなくなり、結果として問題の早期発見が遅れがちになる。小さな懸念が共有されないまま放置され、後に取り返しのつかない大きな問題へと発展するケースも少なくない。<br><br>ただし、心理的安全性とは、単に居心地の良い、ぬるま湯的な環境を意味するわけではない。むしろ、率直な指摘や建設的な対立を歓迎する土壌があってこそ、真の心理的安全性は成立するのである。心地よさだけを追求する組織は、かえって成長の機会を逃しかねない。<br><br>心理的安全性を高めることは、決して簡単な取り組みではない。しかし、その構築は、組織の長期的な競争力に直結する重要な課題だと言えるだろう。",q:"筆者が定義する心理的安全性とは何か。",o:["居心地のよいぬるま湯的な環境","上司にのみ意見が許される環境","対立を一切避ける環境","率直な意見を言っても罰せられないという確信の共有"],a:3,exp:"「率直な意見や懸念を口にしても…罰せられたりしない確信を、メンバーが共有している状態」が定義。"},
      {q:"心理的安全性が低い組織で起きることとして述べられているのは何か。",o:["離職率が必ず下がること","問題の早期発見が遅れがちになること","給料が必ず上がること","業績が必ず向上すること"],a:1,exp:"「本音を言わなくなり、結果として問題の早期発見が遅れがちになる」がそのまま答え。"},
      {q:"筆者が指摘する誤解は何か。",o:["心理的安全性は単に居心地のよい環境だという誤解","心理的安全性は不要だという誤解","心理的安全性は上司にのみ必要だという誤解","心理的安全性は測定できないという誤解"],a:0,exp:"「単に居心地の良い、ぬるま湯的な環境を意味するわけではない」がそのまま答え。"},
      {q:"この文章全体を通して筆者が伝えたいことは何か。",o:["心理的安全性は簡単に構築できる","居心地のよさこそが最も重要だ","対立は組織にとって常に有害である","建設的な対立を伴う心理的安全性の構築が組織の競争力に直結する"],a:3,exp:"「その構築は、組織の長期的な競争力に直結する重要な課題」が結論。"},
      {sec:"問題13　情報検索",passage:"【オンライン日本語検定　受験案内】<br>・レベル：初級／中級／上級の3レベル。レベルは事前診断テスト（無料、所要15分）の結果に基づき自動判定。<br>・受験料：初級3,000円、中級4,000円、上級5,000円。学生証提示で全レベル一律1,000円引き。<br>・受験方法：自宅のパソコンから受験可能。カメラでの本人確認とオンライン監督が必須。<br>・結果発表：受験後、即日で仮結果を通知。正式な証明書は2週間後に発行。<br>・再受験：不合格の場合、1か月後から再受験可能。再受験時の受験料は半額。<br>・注意事項：診断テストで判定されたレベルより下のレベルでの受験は認められない。",q:"学生が診断テストで中級と判定された場合、受験料はいくらか。",o:["3,000円","4,000円","5,000円","2,000円"],a:0,exp:"中級4,000円から学生割引1,000円引きで3,000円。"},
      {q:"この案内から分かることとして正しいものはどれか。",o:["本人確認は不要である","結果は受験当日には一切分からない","診断テストで判定されたレベルより下では受験できない","再受験の受験料は変わらない"],a:2,exp:"「診断テストで判定されたレベルより下のレベルでの受験は認められない」がそのまま該当。"}
    ]},
    {id:"b", title:"聴解", minutes:55, questions:[
      {sec:"問題1　課題理解",audio:"女：来月の株主総会、招集通知の発送はいつですか。　男：来週中に発送する予定です。今日中に最終的な文面の確認をお願いできますか。",q:"女の人はこのあと、まず何をしますか。",o:["招集通知を発送する","株主総会を延期する","会場を予約する","招集通知の文面を確認する"],a:3,exp:"「今日中に最終的な文面の確認をお願いできますか」への依頼が答え。"},
      {audio:"男：新製品の発表会、来賓リストの確認は済んでいますか。　女：まだです。今日の午後、広報部と一緒に確認します。",q:"女の人はこのあと、まず何をしますか。",o:["広報部と来賓リストを確認する","来賓を追加する","会場を変更する","発表会を中止する"],a:0,exp:"「今日の午後、広報部と一緒に確認します」がそのまま答え。"},
      {audio:"女：来週の監査、必要な書類はそろっていますか。　男：ほとんどそろっていますが、一部の領収書がまだです。今日中に経理に確認します。",q:"男の人はこのあと、まず何をしますか。",o:["書類をすべて破棄する","監査を延期する","経理に確認する","新しい書類を作成する"],a:2,exp:"「今日中に経理に確認します」がそのまま答え。"},
      {audio:"男：来月のシステム移行、テストの日程は決まりましたか。　女：来週の水曜日に決まりました。今日中に関係部署に連絡します。",q:"女の人はこのあと、まず何をしますか。",o:["関係部署に連絡する","システムを移行する","テストを中止する","日程を再調整する"],a:0,exp:"「今日中に関係部署に連絡します」がそのまま答え。"},
      {audio:"女：この報告書、来週の役員会議までに仕上げないといけないんですが。　男：手伝いますよ。どこまで進んでいますか。　女：本文はできているので、あとは要約の部分をお願いできますか。",q:"男の人はこのあと、何をしますか。",o:["報告書の要約部分を書く","本文を書き直す","会議の日程を変更する","報告書を印刷する"],a:0,exp:"「要約の部分をお願いできますか」への流れから、男性は要約部分を担当する。"},
      {sec:"問題2　ポイント理解",audio:"男：この新サービス、思ったより契約が伸びませんね。　女：料金プランが分かりにくいのが一番の原因だと思います。比較検討に時間がかかりすぎているようです。",q:"女の人は、契約が伸びない一番の原因は何だと言っていますか。",o:["料金プランが分かりにくいこと","サービス自体の質が悪いこと","広告が少ないこと","競合が多いこと"],a:0,exp:"「料金プランが分かりにくいのが一番の原因」がそのまま答え。"},
      {audio:"女：このチーム、最近ミスが増えていますね。　男：業務量の増加もありますが、一番の原因は、確認作業を一人に頼りすぎていることだと思います。",q:"男の人は、ミスが増えた一番の原因は何だと考えていますか。",o:["メンバーが未熟なこと","業務量が増加したこと","確認作業を一人に頼りすぎていること","締め切りが厳しいこと"],a:2,exp:"「一番の原因は、確認作業を一人に頼りすぎていること」がそのまま答え。"},
      {audio:"男：この店舗、リピーターが少ないですね。　女：接客の質もありますが、一番の問題は、ポイントカードの特典が魅力的でないことだと思います。",q:"女の人は、リピーターが少ない一番の原因は何だと考えていますか。",o:["ポイントカードの特典が魅力的でないこと","立地が悪いこと","接客の質が悪いこと","価格が高いこと"],a:0,exp:"「一番の問題は、ポイントカードの特典が魅力的でないこと」がそのまま答え。"},
      {audio:"女：このアプリ、評価が低いですね。　男：デザインの問題もありますが、一番の原因は、動作が重く頻繁に落ちることだと思います。",q:"男の人は、評価が低い一番の原因は何だと考えていますか。",o:["機能が少ないこと","価格が高いこと","動作が重く頻繁に落ちること","デザインが悪いこと"],a:2,exp:"「一番の原因は、動作が重く頻繁に落ちること」がそのまま答え。"},
      {audio:"男：この学部、志願者が減っていますね。　女：立地の問題もありますが、一番大きいのは、就職実績の情報発信が弱いことだと思います。",q:"女の人は、志願者が減った一番の原因は何だと考えていますか。",o:["就職実績の情報発信が弱いこと","定員が少ないこと","学費が高いこと","立地が悪いこと"],a:0,exp:"「一番大きいのは、就職実績の情報発信が弱いこと」がそのまま答え。"},
      {audio:"女：この地域、空き家が増えていますね。　男：高齢化もありますが、一番の原因は、若い世代の働き口が少ないことだと思います。",q:"男の人は、空き家が増えた一番の原因は何だと考えていますか。",o:["交通の便が悪いこと","家賃が高いこと","高齢化が進んでいること","若い世代の働き口が少ないこと"],a:3,exp:"「一番の原因は、若い世代の働き口が少ないこと」がそのまま答え。"},
      {sec:"問題3　概要理解",audio:"組織における心理的安全性が注目される中、これは単に居心地のよい環境を意味するのではなく、建設的な対立を歓迎する土壌があってこそ成立するという指摘がある。",q:"この話は、主に何について述べていますか。",o:["心理的安全性の本質についての考え方","会議の司会の進め方","人事評価の基準","給与制度の設計"],a:0,exp:"心理的安全性とは何かについての考察が主題。"},
      {audio:"教育の目的は知識の詰め込みではなく自ら考え判断する力を養うことにあるとされ、正解が一つに定まらない問いに向き合う経験の重要性が指摘されている。",q:"この話は、主に何について述べていますか。",o:["教育における思考力育成の重要性","入試制度の改革案","学校施設の整備","教員採用の基準"],a:0,exp:"教育の目的と思考力育成についての話。"},
      {audio:"終身雇用制度は安定をもたらす一方、変化の激しい現代には適さないという指摘もあり、より流動的な雇用形態への移行が求められるという意見がある。",q:"この話は、主に何について述べていますか。",o:["労働組合の役割","採用面接の進め方","退職金の計算方法","終身雇用制度の課題と今後の展望"],a:3,exp:"終身雇用制度の課題と今後の雇用のあり方についての話。"},
      {audio:"少子高齢化が進む中、外国人労働者の受け入れが議論されているが、言語や文化の違いによる摩擦を懸念する声もあり、企業側の意識改革が求められている。",q:"この話は、主に何について述べていますか。",o:["入国管理の手続き","外国人労働者の給与水準","労働ビザの種類","外国人労働者受け入れに必要な企業の意識改革"],a:3,exp:"受け入れ企業側の意識改革の必要性についての話。"},
      {audio:"効率化ばかりを追求する風潮に対し、雑談や余白の中にこそ新しい発想の種があるのではないかという指摘がなされ、効率と余白の共存が求められている。",q:"この話は、主に何について述べていますか。",o:["効率的な仕事の進め方","雑談の内容の分析","効率化の行き過ぎがもたらす弊害への懸念","職場のルール作り"],a:2,exp:"効率化偏重への懸念と、余白の価値についての話。"},
      {sec:"問題4　即時応答",audio:"この件、少々お時間をいただければと存じます。",q:"最もよい返答はどれですか。",o:["それは残念です。","はい、承知しました。","おめでとうございます。","もう終わりました。"],a:1,exp:"時間の猶予を求める依頼への自然な返答は「はい、承知しました」。"},
      {audio:"恐縮ですが、この日程では対応が難しそうです。",q:"最もよい返答はどれですか。",o:["それは嬉しいです。","もう決まったことです。","では、ご都合のよい日をお知らせいただけますか。","おめでとうございます。"],a:2,exp:"日程が難しいという連絡への自然な返答は、代替日を尋ねる形。"},
      {audio:"この資料、もう少し具体性を持たせたほうがいいと思います。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","ありがとうございます。どの部分でしょうか。","それはすごいですね。","もう直しました、以上です。"],a:1,exp:"修正の指摘への自然な返答は、感謝しつつ詳細を尋ねる形。"},
      {audio:"正直、この案には少し不安があります。",q:"最もよい返答はどれですか。",o:["もう決まりました。","おめでとうございます。","それは嬉しいです。","どのあたりが不安でしょうか、詳しく伺えますか。"],a:3,exp:"不安を打ち明けられた際の自然な返答は、具体的に寄り添う形。"},
      {audio:"急なお願いで恐縮ですが、今週中にお願いできますか。",q:"最もよい返答はどれですか。",o:["もう終わりました。","それは残念ですね。","承知しました。調整してみます。","おめでとうございます。"],a:2,exp:"急な依頼への自然な返答は「承知しました。調整してみます」。"},
      {audio:"念のため確認させてください。この方向性でよろしいでしょうか。",q:"最もよい返答はどれですか。",o:["はい、その方向性で結構です。","もう終わった話です。","いいえ、まだ始まっていません。","それはすごいですね。"],a:0,exp:"方向性の確認への自然な返答は「はい、その方向性で結構です」。"},
      {audio:"この度はこちらの不手際でご迷惑をおかけしました。",q:"最もよい返答はどれですか。",o:["いえ、こちらこそ説明が不十分でした。","おめでとうございます。","それは嬉しいです。","もっとやってください。"],a:0,exp:"謝罪への自然な返答は、相手を責めずに応じる形。"},
      {audio:"この案件、優先的に対応していただけますか。",q:"最もよい返答はどれですか。",o:["それは残念ですね。","承知しました。他の予定と調整します。","おめでとうございます。","もう終わりました。"],a:1,exp:"優先対応の依頼への自然な返答。"},
      {audio:"この度は温かいお言葉をありがとうございます。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","いえ、こちらこそ励みになりました。","もう終わりです。","それは残念ですね。"],a:1,exp:"感謝の言葉への自然な返答。"},
      {audio:"念のため伺いますが、この内容で先方にお送りしてよろしいでしょうか。",q:"最もよい返答はどれですか。",o:["もう送信済みです。","はい、問題ありません。","それはすごいですね。","いいえ、まだ始まっていません。"],a:1,exp:"送信前の最終確認への自然な返答は「はい、問題ありません」。"},
      {audio:"この提案、まずは部内で共有してもよろしいでしょうか。",q:"最もよい返答はどれですか。",o:["もう共有済みです。","はい、ぜひお願いします。","それは大変ですね。","おめでとうございます。"],a:1,exp:"共有の許可を求められた際の自然な返答。"},
      {sec:"問題5　統合理解",audio:"司会：来年度の新人研修プログラムについて、三つ案があります。<br>男性A：座学中心の研修がいいと思います。基礎をしっかり固めるべきです。<br>女性：私は現場でのOJT中心にすべきだと思います。実践を通じて学ぶことが多いです。<br>男性B：両方を組み合わせて、前半に座学、後半にOJTを行うのはどうでしょうか。<br>司会：それでは、前半座学・後半OJTの組み合わせ案で進めましょう。",q:"最終的にどの案で進めることになりましたか。",o:["案がまとまらなかった","OJT中心の案","座学中心の案","前半座学・後半OJTの組み合わせ案"],a:3,exp:"司会が「前半座学・後半OJTの組み合わせ案で進めましょう」と決定している。"},
      {q:"女性がOJT中心の研修を推した理由は何ですか。",o:["講師が不足しているから","座学が退屈だから","予算が最も安いから","実践を通じて学ぶことが多いから"],a:3,exp:"「実践を通じて学ぶことが多いです」が理由。"},
      {audio:"司会：来年度の顧客対応の改善策について、三つ案があります。<br>男性A：問い合わせ窓口の人員を増やすべきだと思います。<br>女性：私はチャットボットの導入を進めるべきだと思います。24時間対応が可能になります。<br>男性B：両方を組み合わせて、簡単な質問はチャットボット、複雑な質問は人員対応にするのはどうでしょうか。<br>司会：それでは、チャットボットと人員対応を組み合わせる案で進めましょう。",q:"最終的にどの案で進めることになりましたか。",o:["チャットボットと人員対応を組み合わせる案","チャットボット導入のみの案","人員増強のみの案","現状維持の案"],a:0,exp:"司会が「チャットボットと人員対応を組み合わせる案で進めましょう」と決定している。"}
    ]}
  ]
},
{
  id:"o-n5-1", lvl:"N5", title:"Examen oficial N5 · 1", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙）", minutes:20, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　あした 学校へ 行きます。",o:["がくこう","がくこ","がっこう","がっこ"],a:2,exp:"学校→がっこう「escuela」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　毎朝 六時に おきます。",o:["まいあさ","まいばん","まいにち","まいちょう"],a:0,exp:"毎朝→まいあさ「cada mañana」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　この 川は きれいです。",o:["がわ","かわ","かゎ","かは"],a:1,exp:"川→かわ「río」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　兄は だいがくせいです。",o:["あね","あに","おとうと","ちち"],a:1,exp:"兄→あに「hermano mayor」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　雨が ふって います。",o:["ゆき","あめ","かぜ","そら"],a:1,exp:"雨→あめ「lluvia」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　本を 三さつ かいました。",o:["ぽん","ほん","もと","ぼん"],a:1,exp:"本→ほん「libro」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　電車で かいしゃへ 行きます。",o:["でんちゃ","でんくるま","てんしゃ","でんしゃ"],a:3,exp:"電車→でんしゃ「tren」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　わたしの　いえは　おおきいです。",o:["家","室","宅","屋"],a:0,exp:"いえ→家「casa」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　あの　やまは　たかいです。",o:["山","森","田","川"],a:0,exp:"やま→山「montaña」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　まいにち　でんわを　します。",o:["毎日","毎週","毎年","毎月"],a:0,exp:"まいにち→毎日「cada día」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　この　みずは　つめたいです。",o:["水","氷","湯","池"],a:0,exp:"みず→水「agua」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　あの　ひとは　せんせいです。",o:["人","九","入","八"],a:0,exp:"ひと→人「persona」。"},
      {sec:"問題3　文脈規定",q:"（　）に なにを いれますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　のどが かわいたので、水を （　）。",o:["かいます","たべます","のみます","つくります"],a:2,exp:"水は「のみます」（beber）。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　この かばんは とても （　）です。",o:["からい","おもい","あまい","つめたい"],a:1,exp:"かばんが重い「pesado」。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　でんきを （　）、へやを 出ました。",o:["けして","あけて","つけて","しめて"],a:0,exp:"出る前は電気を「けす」（apagar）。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　わたしは まいにち にほんごを （　）。",o:["あそびます","うたいます","べんきょうします","やすみます"],a:2,exp:"にほんごは「べんきょうします」（estudiar）。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　あさ はやく （　）ました。",o:["はたらき","おき","ね","たべ"],a:1,exp:"朝にすることは「おきる」（levantarse）。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　この もんだいは （　）です。",o:["きれい","かんたん","にぎやか","しずか"],a:1,exp:"問題が「かんたん」（fácil）。"},
      {sec:"問題4　言い換え類義",q:"＿＿の ぶんと だいたい おなじ いみの ぶんが あります。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　きょうしつには　だれも　いません。",o:["きょうしつは からです。","きょうしつは きれいです。","きょうしつは にぎやかです。","きょうしつは ひろいです。"],a:0,exp:"「だれもいない」＝「から」（vacío）。"},
      {q:"＿＿の ぶんと だいたい おなじ いみの ぶんが あります。1・2・3・4から ひとつ えらんで ください。　この みちは せまいです。",o:["この みちは きれいです。","この みちは ながいです。","この みちは ひろくないです。","この みちは あんぜんです。"],a:2,exp:"「せまい」＝「ひろくない」（estrecho）。"},
      {q:"＿＿の ぶんと だいたい おなじ いみの ぶんが あります。1・2・3・4から ひとつ えらんで ください。　この りょうりは からいです。",o:["この りょうりは あまくないです。","この りょうりは おおきいです。","この りょうりは つめたいです。","この りょうりは やすいです。"],a:0,exp:"「からい」の最も近い言い換えは「あまくない」。"}
    ]},
    {id:"b", title:"言語知識（文法）・読解", minutes:40, questions:[
      {sec:"問題1　文法1",q:"（　）に なにを いれますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　わたしは がっこう（　）行きます。",o:["の","を","が","へ"],a:3,exp:"「へ」は方向を示す（e）。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　これは わたし（　）ほんです。",o:["に","が","の","を"],a:2,exp:"「の」は所有を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　きょうしつに がくせいが 五人 （　）。",o:["でした","あります","います","します"],a:2,exp:"人は「います」。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　あした パーティー（　）行きますか。",o:["を","で","に","と"],a:2,exp:"「に」は行き先を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　わたしは コーヒー（　）のみます。",o:["を","で","へ","と"],a:0,exp:"「を」は目的語を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　としょかん（　）ほんを よみます。",o:["が","を","で","へ"],a:2,exp:"「で」は動作の場所を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　きのう ともだち（　）あいました。",o:["に","を","で","へ"],a:0,exp:"「に」は会う相手を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　この ケーキは とても （　）です。",o:["おいしいい","おいしいだ","おいしい","おいしくて"],a:2,exp:"い形容詞＋です。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　あには わたし（　）せが たかいです。",o:["でも","より","にも","とも"],a:1,exp:"比較の「より」。"},
      {sec:"問題2　文法2（文の組み立て）",q:"　★　に はいる ものは どれですか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　わたしは　___　___　★　___　います。（1 まいにち　2 に　3 学校　4 かよって）",o:["まいにち","に","学校","かよって"],a:1,exp:"正しい順序：1まいにち→3学校→2に→4かよって「まいにち学校にかよって」。★の位置には2「に」が入る。"},
      {q:"　★　に はいる ものは どれですか。1・2・3・4から ひとつ えらんで ください。　あの　___　___　★　___　です。（1 とても　2 は　3 建物　4 大きい）",o:["は","大きい","建物","とても"],a:1,exp:"正しい順序：3建物→2は→1とても→4大きい「建物はとても大きい」。★の位置には4「大きい」が入る。"},
      {q:"　★　に はいる ものは どれですか。1・2・3・4から ひとつ えらんで ください。　きのう　___　★　___　___　みました。（1 えいがを　2 ともだちと　3 おもしろい　4 いっしょに）",o:["ともだちと","いっしょに","おもしろい","えいがを"],a:2,exp:"正しい順序：2ともだちと→4いっしょに→3おもしろい→1えいがを。★の位置には3「おもしろい」が入る。"},
      {q:"　★　に はいる ものは どれですか。1・2・3・4から ひとつ えらんで ください。　この　みせの　りょうりは　___　___　★　___　です。（1 やすい　2 とても　3 おいしくて　4 も）",o:["おいしくて","も","とても","やすい"],a:3,exp:"正しい順序：3おいしくて→2とても→1やすい「おいしくてとても安い」の並びを整える と3おいしくて→4も→2とても→1やすい。★の位置には1「やすい」が入る。"},
      {sec:"問題3　文章の文法",passage:"わたしは 毎週 日曜日に 図書館へ 行きます。図書館は 家（1）近く、歩いて 十五分ぐらいです。図書館には たくさんの 本が あります。わたしは いつも 三さつ（2）本を かります。（3）、静かな 図書館で 本を 読むのが すきです。図書館の 人は みんな （4）です。これからも 毎週 （5）と 思います。",q:"（1）",o:["まで","へ","から","より"],a:2,exp:"「家から近く」出発点を示す「から」。"},
      {q:"（2）",o:["しか","ぐらい","だけ","ばかり"],a:1,exp:"「三さつぐらい」おおよその数量。"},
      {q:"（3）",o:["または","それに","でも","だから"],a:1,exp:"「それに」＝追加の理由を導く。"},
      {q:"（4）",o:["にぎやか","こわい","うるさい","しんせつ"],a:3,exp:"図書館の人は「しんせつ」（amable）が自然。"},
      {q:"（5）",o:["行きたい","行った","行かない","行きません"],a:0,exp:"「これからも〜たいと思う」希望を表す文型。"},
      {sec:"問題4　内容理解（短文）",passage:"わたしは まいあさ 六時に おきます。それから、朝ごはんを 食べて、七時半に いえを 出ます。",q:"この 人は 何時に いえを 出ますか。",o:["八時","七時半","七時","六時"],a:1,exp:"「七時半にいえを出ます」がそのまま答え。"},
      {passage:"きょうは あめです。かさを もって がっこうへ いきました。でも、ひるから はれました。",q:"きょうの てんきは どうでしたか。",o:["ゆきが ふった","あめから はれに なった","はじめから はれだった","いちにちじゅう あめだった"],a:1,exp:"「あめです…ひるから はれました」→ empezó lloviendo y luego se despejó。"},
      {passage:"わたしの がっこうは えきから ちかいです。あるいて 五ふんです。",q:"がっこうまで どうやって いきますか。",o:["でんしゃで","バスで","あるいて","じてんしゃで"],a:2,exp:"「あるいて五ふんです」→ se va andando。"},
      {sec:"問題5　内容理解（中文）",passage:"わたしの かぞくは 四人です。ちちと ははと いもうとと わたしです。にちようびは みんなで こうえんへ いきます。こうえんには おおきい きが たくさん あります。いもうとは こうえんで あそぶのが すきです。",q:"にちようびに どこへ いきますか。",o:["かいしゃ","こうえん","がっこう","びょういん"],a:1,exp:"「にちようびは みんなで こうえんへ いきます」→ el domingo van al parque。"},
      {q:"いもうとは こうえんで なにを するのが すきですか。",o:["たべること","べんきょうすること","ねること","あそぶこと"],a:3,exp:"「いもうとは こうえんで あそぶのが すきです」がそのまま答え。"},
      {passage:"わたしは にほんごの がっこうに かよっています。まいにち かんじを べんきょうします。むずかしいですが、たのしいです。せんせいは いつも やさしく おしえて くれます。",q:"まいにち なにを べんきょうしますか。",o:["おんがく","かんじ","えいご","すうがく"],a:1,exp:"「まいにち かんじを べんきょうします」がそのまま答え。"},
      {q:"せんせいは どんな 人ですか。",o:["やさしい 人","わかい 人","いそがしい 人","こわい 人"],a:0,exp:"「せんせいは いつも やさしく おしえて くれます」がそのまま答え。"},
      {sec:"問題6　情報検索",passage:"【えいがかんの りょうきん あんない】<br>・おとな：1,800円<br>・がくせい（学生証が ひつよう）：1,200円<br>・こども（6さいから12さいまで）：900円<br>・毎週 水曜日は「レディースデー」で、女性は 全員 1,300円<br>・午前10時までの じょうえいは、だれでも 1,000円",q:"学生証を もっている 20さいの 女性が、水曜日の 午後に 見に 行く 場合、りょうきんは いくらですか。",o:["1,200円","1,000円","1,300円","1,800円"],a:0,exp:"学生証があれば学生料金1,200円が適用される（学割はレディースデー料金より優先）。"}
    ]},
    {id:"c", title:"聴解", minutes:30, questions:[
      {sec:"問題1　課題理解",audio:"女：すみません、この しゅくだいは いつまでですか。　男：あさってまでです。わすれないで くださいね。",q:"しゅくだいは いつまでに 出しますか。",o:["らいしゅう","きょう","あした","あさって"],a:3,exp:"「あさってまでです」がそのまま答え。"},
      {audio:"男：すみません、としょかんは どこですか。　女：この みちを まっすぐ 行って、二つ目の かどを 左に まがって ください。",q:"としょかんは どこに ありますか。",o:["まっすぐ 行った ところ","この みちの 右","駅の 前","二つ目の かどを 左に まがった ところ"],a:3,exp:"「二つ目の かどを 左に まがって ください」がそのまま答え。"},
      {audio:"女：すみません、この かばんは いくらですか。　男：それは 三千円です。",q:"かばんは いくらですか。",o:["三千五百円","三千円","三百円","三万円"],a:1,exp:"「三千円です」がそのまま答え。"},
      {audio:"男：もしもし、田中です。今日の 会議は 何時からですか。　女：二時からです。",q:"会議は 何時から ですか。",o:["三時","二時","一時","四時"],a:1,exp:"「二時からです」がそのまま答え。"},
      {audio:"女：すみません、この にもつを おくりたいです。　男：はい、じゅうしょを かいて ください。",q:"にもつを おくる ために まず なにを しますか。",o:["はこを かう","おかねを はらう","じゅうしょを かく","でんわを する"],a:2,exp:"「じゅうしょを かいて ください」がそのまま答え。"},
      {audio:"男：あしたの てんきよほうは？　女：あさは くもりで、ごごから あめが ふるでしょう。",q:"ごごの てんきは どうですか。",o:["あめ","はれ","ゆき","くもり"],a:0,exp:"「ごごから あめが ふるでしょう」がそのまま答え。"},
      {audio:"女：きょうの しゅくだいは なんページですか。　男：三十ページから 三十五ページまでです。",q:"しゅくだいは どこから どこまでですか。",o:["一ページから 十ページ","二十ページから 三十ページ","三十ページから 三十五ページ","わからない"],a:2,exp:"「三十ページから 三十五ページまでです」がそのまま答え。"},
      {sec:"問題2　ポイント理解",audio:"男：この みせで カードは つかえますか。　女：もうしわけ ございません、げんきんのみです。",q:"この みせで カードは つかえますか。",o:["わからない","つかえない","つかえる","来週から つかえる"],a:1,exp:"「げんきんのみです」＝solo efectivo。"},
      {audio:"女：えきまで あるいて どのくらい かかりますか。　男：じゅっぷんぐらいです。",q:"えきまで どのくらい かかりますか。",o:["じゅっぷんぐらい","いちじかんぐらい","ごふんぐらい","にじゅっぷんぐらい"],a:0,exp:"「じゅっぷんぐらいです」がそのまま答え。"},
      {audio:"男：ゆうびんきょくは なんじまで あいていますか。　女：午後 五時までです。",q:"ゆうびんきょくは なんじまで あいていますか。",o:["午前 五時","午後 五時","午後 三時","午後 六時"],a:1,exp:"「午後 五時までです」がそのまま答え。"},
      {audio:"女：きょうの ばんごはんは なんですか。　男：カレーライスです。",q:"きょうの ばんごはんは なんですか。",o:["すし","カレーライス","ラーメン","ぎょうざ"],a:1,exp:"「カレーライスです」がそのまま答え。"},
      {audio:"男：あさごはんは なにを たべましたか。　女：パンと たまごを たべました。",q:"あさごはんに なにを たべましたか。",o:["パンと たまご","くだものだけ","めんと ぎょうざ","ごはんと みそしる"],a:0,exp:"「パンと たまごを たべました」がそのまま答え。"},
      {audio:"女：かいぎしつは どこですか。　男：二かいの いちばん おくの へやです。",q:"かいぎしつは どこに ありますか。",o:["地下","三かいの となり","一かいの いりぐち","二かいの いちばん おく"],a:3,exp:"「二かいの いちばん おくの へやです」がそのまま答え。"},
      {sec:"問題3　発話表現",audio:"（え：ともだちが てを けがして いる）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["いただきます。","だいじょうぶですか。","おめでとうございます。","おやすみなさい。"],a:1,exp:"けがをした人には「だいじょうぶですか」と聞くのが自然。"},
      {audio:"（え：ともだちの たんじょうびだ）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["いってきます。","おだいじに。","おたんじょうび おめでとう。","ごめんなさい。"],a:2,exp:"誕生日には「おめでとう」と祝う。"},
      {audio:"（え：しごとを おわって かえる とき、まだ のこって いる ひとに いう）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["おはようございます。","ただいま。","いただきます。","お先に しつれいします。"],a:3,exp:"先に帰る時は「お先に失礼します」。"},
      {audio:"（え：レストランで りょうりが きた）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["しつれいします。","ごちそうさまでした。","いただきます。","おじゃまします。"],a:2,exp:"食べる前には「いただきます」。"},
      {audio:"（え：ひとの いえに はいる とき）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["ただいま。","いただきます。","おかえりなさい。","おじゃまします。"],a:3,exp:"人の家に入る時は「おじゃまします」。"},
      {sec:"問題4　即時応答",audio:"すみません、いま なんじですか。",q:"いちばん いい へんじは どれですか。",o:["はい、どうぞ。","三時です。","いいえ、けっこうです。","ありがとう。"],a:1,exp:"時間を聞かれたら時刻を答える。"},
      {audio:"きのう どこへ 行きましたか。",q:"いちばん いい へんじは どれですか。",o:["デパートへ 行きました。","元気です。","はじめまして。","三時です。"],a:0,exp:"「どこへ」には場所を答える。"},
      {audio:"この ペン、つかっても いいですか。",q:"いちばん いい へんじは どれですか。",o:["はい、どうぞ。","ありがとう。","はい、げんきです。","いいえ、三時です。"],a:0,exp:"許可を求められたら「はい、どうぞ」。"},
      {audio:"にほんごは むずかしいですか。",q:"いちばん いい へんじは どれですか。",o:["ありがとうございます。","いいえ、三人です。","はい、あそこです。","はい、すこし むずかしいです。"],a:3,exp:"難易度を聞かれたら感想を答える。"},
      {audio:"おげんきですか。",q:"いちばん いい へんじは どれですか。",o:["はい、三時です。","どういたしまして。","いいえ、けっこうです。","はい、げんきです。"],a:3,exp:"「おげんきですか」には「げんきです」と答える。"},
      {audio:"どうぞ こちらへ。",q:"いちばん いい へんじは どれですか。",o:["ありがとうございます。","いいえ、けっこうです。","はじめまして。","おやすみなさい。"],a:0,exp:"案内されたら「ありがとうございます」。"}
    ]}
  ]
},
{
  id:"o-n5-2", lvl:"N5", title:"Examen oficial N5 · 2", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙）", minutes:20, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　来週 りょこうします。",o:["らいねん","こんしゅう","せんしゅう","らいしゅう"],a:3,exp:"来週→らいしゅう「la semana que viene」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　図書館で べんきょうします。",o:["としょかん","ずしょかん","としょがん","ちしょかん"],a:0,exp:"図書館→としょかん「biblioteca」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　肉より さかなが すきです。",o:["たまご","にく","さかな","やさい"],a:1,exp:"肉→にく「carne」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　病院へ 行きます。",o:["びよういん","びょういん","びょうき","はくいん"],a:1,exp:"病院→びょういん「hospital」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　会社まで バスで いきます。",o:["かいじゃ","かえしゃ","かいしゃ","がいしゃ"],a:2,exp:"会社→かいしゃ「empresa」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　友達と あそびました。",o:["なかま","かぞく","ゆうじん","ともだち"],a:3,exp:"友達→ともだち「amigo」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　先週 やまへ いきました。",o:["せんしゅう","まいしゅう","こんしゅう","らいしゅう"],a:0,exp:"先週→せんしゅう「la semana pasada」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　あめが ふって います。",o:["空","雪","風","雨"],a:3,exp:"あめ→雨「lluvia」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　くるまで いきます。",o:["車","道","電","駅"],a:0,exp:"くるま→車「coche」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　そらが きれいです。",o:["空","風","雨","雲"],a:0,exp:"そら→空「cielo」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　あにが います。",o:["兄","妹","弟","姉"],a:0,exp:"あに→兄「hermano mayor」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　てで もちます。",o:["目","手","口","足"],a:1,exp:"て→手「mano」。"},
      {sec:"問題3　文脈規定",q:"（　）に なにを いれますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　あついので、まどを （　）。",o:["しめます","あけます","けします","つけます"],a:1,exp:"暑い時は窓を「あけます」（abrir）。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　まいにち にほんごを （　）。",o:["やすみます","うたいます","れんしゅうします","あそびます"],a:2,exp:"にほんごの上達には「れんしゅうします」（practicar）。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　でんきを （　）、ねました。",o:["つけて","あけて","しめて","けして"],a:3,exp:"寝る前は電気を「けして」（apagar）。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　この みちを まっすぐ （　）ください。",o:["いき","いった","いく","いって"],a:3,exp:"依頼の「て形」＋ください。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　きょうは あめ（　）でした。",o:["が ふり","ふりて","ふって","が ふった"],a:3,exp:"過去形「雨がふった」。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　わたしは あさごはん（　）たべませんでした。",o:["を","で","へ","が"],a:0,exp:"「を」は目的語を示す。"},
      {sec:"問題4　言い換え類義",q:"＿＿の ぶんと だいたい おなじ いみの ぶんが あります。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　この へやは あかるいです。",o:["この へやは せまいです。","この へやは さむいです。","この へやは きれいです。","この へやは くらくないです。"],a:3,exp:"「あかるい」＝「くらくない」（luminoso ＝ no oscuro）。"},
      {q:"＿＿の ぶんと だいたい おなじ いみの ぶんが あります。1・2・3・4から ひとつ えらんで ください。　この もんだいは むずかしいです。",o:["この もんだいは たのしいです。","この もんだいは みじかいです。","この もんだいは やさしいです。","この もんだいは かんたんじゃないです。"],a:3,exp:"「むずかしい」＝「かんたんじゃない」（difícil ＝ no fácil）。"},
      {q:"＿＿の ぶんと だいたい おなじ いみの ぶんが あります。1・2・3・4から ひとつ えらんで ください。　きょうしつは しずかです。",o:["きょうしつは きれいです。","きょうしつは にぎやかじゃないです。","きょうしつは ひろいです。","きょうしつは あついです。"],a:1,exp:"「しずか」＝「にぎやかじゃない」（tranquilo ＝ no bullicioso）。"}
    ]},
    {id:"b", title:"言語知識（文法）・読解", minutes:40, questions:[
      {sec:"問題1　文法1",q:"（　）に なにを いれますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　としょかん（　）ほんを よみます。",o:["で","を","へ","が"],a:0,exp:"「で」は動作の場所を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　これは わたしが かいた え（　）。",o:["ます","ました","です","でした"],a:2,exp:"名詞文の現在形は「です」。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　きのう ともだち（　）あいました。",o:["に","へ","を","で"],a:0,exp:"「に」は会う相手を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　この ケーキは とても （　）です。",o:["おいしいだ","おいしい","おいしくて","おいしいい"],a:1,exp:"い形容詞＋です。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　わたしは にほんご（　）べんきょうしています。",o:["へ","が","に","を"],a:3,exp:"「を」は目的語を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　あの ひと（　）せんせいです。",o:["に","で","を","は"],a:3,exp:"「は」は文のテーマを示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　にちようびは がっこう（　）やすみです。",o:["に","を","が","は"],a:3,exp:"「は」対比を含むテーマ。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　この りんごは あの りんご（　）おおきいです。",o:["にも","より","とも","でも"],a:1,exp:"比較の「より」。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　わたしは まいにち にほんご（　）はなします。",o:["で","に","が","を"],a:0,exp:"「で」は手段・言語を示す。"},
      {sec:"問題2　文法2（文の組み立て）",q:"　★　に はいる ものは どれですか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　わたしは　___　___　★　___　を　します。（1 にほんごの　2 まいばん　3 べんきょう　4 で）",o:["で","まいばん","べんきょう","にほんごの"],a:2,exp:"正しい順序：2まいばん→1にほんごの→3べんきょう→（を）「まいばんにほんごのべんきょうをします」。★の位置には3「べんきょう」が入る。"},
      {q:"　★　に はいる ものは どれですか。1・2・3・4から ひとつ えらんで ください。　この　___　___　★　___　です。（1 とても　2 は　3 みせ　4 やすい）",o:["とても","は","みせ","やすい"],a:3,exp:"正しい順序：3みせ→2は→1とても→4やすい「みせはとてもやすい」。★の位置には4「やすい」が入る。"},
      {q:"　★　に はいる ものは どれですか。1・2・3・4から ひとつ えらんで ください。　あさ　___　★　___　___　でかけます。（1 はやく　2 おきて　3 を　4 顔）",o:["顔","おきて","を","はやく"],a:1,exp:"正しい順序：1はやく→2おきて→4顔→3を（洗って）「はやくおきて顔を洗って」の簡略形。★の位置には2「おきて」が入る。"},
      {q:"　★　に はいる ものは どれですか。1・2・3・4から ひとつ えらんで ください。　わたしの　___　___　★　___　います。（1 に　2 東京　3 兄は　4 すんで）",o:["東京","に","すんで","兄は"],a:2,exp:"正しい順序：3兄は→2東京→1に→4すんで「兄は東京にすんで」。★の位置には4「すんで」が入る。"},
      {sec:"問題3　文章の文法",passage:"わたしの しゅみは りょうりです。まいしゅう にちようびに あたらしい りょうりを（1）ちょうせんします。せんしゅうは カレーを つくりました。（2）、おいしく できました。りょうりを つくる とき、（3）おんがくを ききます。りょうりが（4）とき、いえのなかが とても いい におい（5）します。",q:"（1）",o:["で","が","に","を"],a:2,exp:"「〜に挑戦する」対象を示す助詞。"},
      {q:"（2）",o:["ぜんぜん","とても","あまり","すこしも"],a:1,exp:"「とても」＋肯定＝muy。"},
      {q:"（3）",o:["いつも","あまり","たまに","ぜんぜん"],a:0,exp:"習慣を表す「いつも」。"},
      {q:"（4）",o:["できなかった","できない","できません","できた"],a:3,exp:"「できたとき」料理ができた時。"},
      {q:"（5）",o:["で","に","を","が"],a:3,exp:"「においがする」における「が」。"},
      {sec:"問題4　内容理解（短文）",passage:"きょうは わたしの たんじょうびです。ともだちが パーティーを ひらいて くれました。とても うれしかったです。",q:"きょうは どんな日ですか。",o:["にゅうがくしき","クリスマス","そつぎょうしき","たんじょうび"],a:3,exp:"「きょうは わたしの たんじょうびです」がそのまま答え。"},
      {passage:"デパートで シャツを かいました。あかい シャツと あおい シャツが ありましたが、あおいのを かいました。",q:"どんな シャツを かいましたか。",o:["あおい シャツ","しろい シャツ","あかい シャツ","くろい シャツ"],a:0,exp:"「あおいのを かいました」がそのまま答え。"},
      {passage:"あしたは しゅくだいが あるので、きょうは はやく うちへ かえります。",q:"きょう なぜ はやく かえりますか。",o:["つかれたから","びょうきだから","しゅくだいが あるから","やくそくが あるから"],a:2,exp:"「しゅくだいが あるので」＝porque tiene deberes。"},
      {sec:"問題5　内容理解（中文）",passage:"わたしは まいしゅう どようびに テニスを します。ともだちと いっしょに します。とても たのしいです。テニスの あとは、いつも みんなで しょくじに いきます。",q:"いつ テニスを しますか。",o:["きんようび","どようび","まいにち","にちようび"],a:1,exp:"「まいしゅう どようびに テニスを します」がそのまま答え。"},
      {q:"テニスの あとに なにを しますか。",o:["うちへ かえる","ねる","べんきょうする","しょくじに いく"],a:3,exp:"「テニスの あとは、いつも みんなで しょくじに いきます」がそのまま答え。"},
      {passage:"ちちは ぎんこうで はたらいています。ははは がっこうで えいごを おしえています。あには だいがくせいで、いもうとは ちゅうがくせいです。",q:"ははの しごとは なんですか。",o:["かいしゃいん","いしゃ","えいごの きょうし","ぎんこういん"],a:2,exp:"「がっこうで えいごを おしえています」＝profesora de inglés。"},
      {q:"あには なにを していますか。",o:["ぎんこうで はたらいている","だいがくで べんきょうしている","がっこうで おしえている","かいしゃで はたらいている"],a:1,exp:"「あには だいがくせいで」がそのまま答え。"},
      {sec:"問題6　情報検索",passage:"【スイミングスクール りょうきん あんない】<br>・こども（3さいから12さいまで）：げつ 5,000円<br>・おとな：げつ 7,000円<br>・入会金：3,000円（きょうだいで 入会する ばあい、二人目から 入会金 むりょう）<br>・体験レッスン：初回のみ 無料（要予約）",q:"9さいと 7さいの きょうだいが いっしょに 入会する ばあい、入会金は ぜんぶで いくらですか。",o:["3,000円","10,000円","6,000円","0円"],a:0,exp:"きょうだいの場合、二人目から入会金無料なので、1人分の3,000円のみ。"}
    ]},
    {id:"c", title:"聴解", minutes:30, questions:[
      {sec:"問題1　課題理解",audio:"男：すみません、駅まで どうやって 行きますか。　女：この バスに 乗って ください。三つ目の バス停です。",q:"駅まで どう 行きますか。",o:["タクシーに 乗る","じてんしゃで 行く","バスに 乗る","あるいて 行く"],a:2,exp:"「この バスに 乗って ください」がそのまま答え。"},
      {audio:"女：あしたの てんきは どうですか。　男：あしたは いちにちじゅう はれるでしょう。",q:"あしたの てんきは どうですか。",o:["くもり","はれ","ゆき","あめ"],a:1,exp:"「いちにちじゅう はれるでしょう」がそのまま答え。"},
      {audio:"男：すみません、この みせで カードは つかえますか。　女：もうしわけ ございません、げんきんのみです。",q:"この みせで カードは つかえますか。",o:["つかえる","わからない","つかえない","来週から つかえる"],a:2,exp:"「げんきんのみです」＝solo efectivo。"},
      {audio:"女：すみません、この でんしゃは しんじゅくへ 行きますか。　男：いいえ、この でんしゃは しぶや行きです。",q:"この でんしゃは どこへ 行きますか。",o:["しぶや","うえの","しんじゅく","とうきょう"],a:0,exp:"「しぶや行きです」がそのまま答え。"},
      {audio:"男：あさごはんは なにを たべましたか。　女：パンと たまごを たべました。",q:"あさごはんに なにを たべましたか。",o:["くだものだけ","パンと たまご","めんと ぎょうざ","ごはんと みそしる"],a:1,exp:"「パンと たまごを たべました」がそのまま答え。"},
      {audio:"女：かいぎしつは どこですか。　男：二かいの いちばん おくの へやです。",q:"かいぎしつは どこに ありますか。",o:["地下","三かいの となり","二かいの いちばん おく","一かいの いりぐち"],a:2,exp:"「二かいの いちばん おくの へやです」がそのまま答え。"},
      {audio:"男：きょうの しゅくだいは なんページですか。　女：三十ページから 三十五ページまでです。",q:"しゅくだいは どこから どこまでですか。",o:["わからない","一ページから 十ページ","三十ページから 三十五ページ","二十ページから 三十ページ"],a:2,exp:"「三十ページから 三十五ページまでです」がそのまま答え。"},
      {sec:"問題2　ポイント理解",audio:"女：きょうは なんようびですか。　男：すいようびです。",q:"きょうは なんようびですか。",o:["すいようび","かようび","もくようび","げつようび"],a:0,exp:"「すいようびです」がそのまま答え。"},
      {audio:"男：えきまで あるいて どのくらい かかりますか。　女：じゅっぷんぐらいです。",q:"えきまで どのくらい かかりますか。",o:["じゅっぷんぐらい","にじゅっぷんぐらい","いちじかんぐらい","ごふんぐらい"],a:0,exp:"「じゅっぷんぐらいです」がそのまま答え。"},
      {audio:"女：あしたの てんきよほうは？　男：あさは くもりで、ごごから ゆきが ふるでしょう。",q:"ごごの てんきは どうですか。",o:["はれ","ゆき","あめ","くもり"],a:1,exp:"「ごごから ゆきが ふるでしょう」がそのまま答え。"},
      {audio:"男：すみません、トイレを かして ください。　女：あちらです。どうぞ。",q:"なにを たのみましたか。",o:["トイレを つかう こと","水を のむ こと","でんわを かける こと","いすを つかう こと"],a:0,exp:"「トイレを かして ください」＝pedir usar el baño。"},
      {audio:"女：きょうしつには つくえが いくつ ありますか。　男：二十こ あります。",q:"つくえは いくつ ありますか。",o:["十八こ","二十こ","十こ","三十こ"],a:1,exp:"「二十こ あります」がそのまま答え。"},
      {audio:"男：びょういんは なんじから あいていますか。　女：くじからです。",q:"びょういんは なんじから あいていますか。",o:["じゅうじ","じゅういちじ","くじ","はちじ"],a:2,exp:"「くじからです」がそのまま答え。"},
      {sec:"問題3　発話表現",audio:"（え：ともだちが かぜを ひいて いる）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["おやすみなさい。","おめでとうございます。","おだいじに。","いただきます。"],a:2,exp:"病気の人には「おだいじに」と気遣う。"},
      {audio:"（え：あさ、がっこうで せんせいに あった）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["こんばんは。","さようなら。","おやすみなさい。","おはようございます。"],a:3,exp:"朝の挨拶は「おはようございます」。"},
      {audio:"（え：しゅくだいを わすれて、せんせいに あやまる）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["いただきます。","ありがとうございます。","すみません、わすれました。","おめでとうございます。"],a:2,exp:"謝罪の際は「すみません」。"},
      {audio:"（え：でんしゃの なかで、ひとの あしを ふんで しまった）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["おめでとうございます。","いただきます。","すみません。","おやすみなさい。"],a:2,exp:"迷惑をかけたら「すみません」と謝る。"},
      {audio:"（え：ともだちの いえを でる とき）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["おかえりなさい。","おじゃまします。","おじゃましました。","ただいま。"],a:2,exp:"帰る時は「おじゃましました」（過去形で挨拶）。"},
      {sec:"問題4　即時応答",audio:"おなまえは？",q:"いちばん いい へんじは どれですか。",o:["三時です。","元気です。","田中です。","ありがとう。"],a:2,exp:"名前を聞かれたら名前を答える。"},
      {audio:"どこから きましたか。",q:"いちばん いい へんじは どれですか。",o:["スペインから きました。","はじめまして。","元気です。","三時です。"],a:0,exp:"出身を聞かれたら国や場所を答える。"},
      {audio:"この ざっしを かりても いいですか。",q:"いちばん いい へんじは どれですか。",o:["いいえ、三時です。","はい、げんきです。","ありがとう。","はい、どうぞ。"],a:3,exp:"許可を求められたら「はい、どうぞ」。"},
      {audio:"にほんの たべものは すきですか。",q:"いちばん いい へんじは どれですか。",o:["ありがとうございます。","はい、大好きです。","はい、あそこです。","いいえ、三人です。"],a:1,exp:"好みを聞かれたら感想を答える。"},
      {audio:"いってきます。",q:"いちばん いい へんじは どれですか。",o:["ただいま。","おかえりなさい。","おやすみなさい。","いってらっしゃい。"],a:3,exp:"「いってきます」には「いってらっしゃい」と返す。"},
      {audio:"ごちそうさまでした。",q:"いちばん いい へんじは どれですか。",o:["いただきます。","おじゃまします。","おそまつさまでした。","しつれいします。"],a:2,exp:"「ごちそうさまでした」には「おそまつさまでした」と返す。"}
    ]}
  ]
},
{
  id:"o-n5-3", lvl:"N5", title:"Examen oficial N5 · 3", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙）", minutes:20, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　火曜日に あいましょう。",o:["びようび","かようび","ひようび","かようひ"],a:1,exp:"火曜日→かようび「martes」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　今日は あついです。",o:["いま","こんじつ","きょう","こんにち"],a:2,exp:"今日→きょう「hoy」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　水を のみます。",o:["ひ","つち","き","みず"],a:3,exp:"水→みず「agua」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　あには かいしゃいんです。",o:["ちち","あに","おとうと","あね"],a:1,exp:"兄→あに「hermano mayor」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　えきの ちかくに すんで います。",o:["こうえん","びょういん","えき","みせ"],a:2,exp:"駅→えき「estación」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　あさ はやく おきます。",o:["よる","ひる","あさ","ゆう"],a:2,exp:"朝→あさ「mañana」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　白い いぬが すきです。",o:["しろい","くろい","あかい","あおい"],a:0,exp:"白い→しろい「blanco」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　あめが ふります。",o:["空","風","雪","雨"],a:3,exp:"あめ→雨「lluvia」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　きょう がっこうへ いきます。",o:["毎日","明日","昨日","今日"],a:3,exp:"きょう→今日「hoy」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　やまに のぼります。",o:["山","川","森","田"],a:0,exp:"やま→山「montaña」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　このみせで かいます。",o:["家","室","屋","店"],a:3,exp:"みせ→店「tienda」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　あしが いたいです。",o:["目","口","足","手"],a:2,exp:"あし→足「pie」。"},
      {sec:"問題3　文脈規定",q:"（　）に なにを いれますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　まいあさ コーヒーを （　）。",o:["のみます","かいます","たべます","つくります"],a:0,exp:"コーヒーは「のみます」。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　この ほんは とても （　）です。",o:["あまい","からい","おもしろい","つめたい"],a:2,exp:"本は「おもしろい」（interesante）。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　まどを （　）、そとを みました。",o:["しめて","あけて","つけて","けして"],a:1,exp:"外を見るためには窓を「あけて」。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　あしたは テスト（　）あります。",o:["へ","を","に","が"],a:3,exp:"「が」は存在の主体を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　この かばんは わたし（　）です。",o:["が","を","の","に"],a:2,exp:"「の」は所有を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　きょうは （　）から、はやく ねます。",o:["うれしい","げんき","つかれた","たのしい"],a:2,exp:"「つかれたから」寝る理由になる。"},
      {sec:"問題4　言い換え類義",q:"＿＿の ぶんと だいたい おなじ いみの ぶんが あります。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　この こうえんは ひろいです。",o:["この こうえんは せまいです。","この こうえんは せまくないです。","この こうえんは きたないです。","この こうえんは ちいさいです。"],a:1,exp:"「ひろい」＝「せまくない」（amplio）。"},
      {q:"＿＿の ぶんと だいたい おなじ いみの ぶんが あります。1・2・3・4から ひとつ えらんで ください。　あの みせは やすいです。",o:["あの みせは とおいです。","あの みせは たかいです。","あの みせは たかくないです。","あの みせは きたないです。"],a:2,exp:"「やすい」＝「たかくない」（barato）。"},
      {q:"＿＿の ぶんと だいたい おなじ いみの ぶんが あります。1・2・3・4から ひとつ えらんで ください。　この へやは きたないです。",o:["この へやは しずかです。","この へやは きれいじゃないです。","この へやは ひろいです。","この へやは あかるいです。"],a:1,exp:"「きたない」＝「きれいじゃない」（sucio）。"}
    ]},
    {id:"b", title:"言語知識（文法）・読解", minutes:40, questions:[
      {sec:"問題1　文法1",q:"（　）に なにを いれますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　わたしは にほんご（　）べんきょうしています。",o:["へ","が","を","に"],a:2,exp:"「を」は目的語を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　あの ひと（　）せんせいです。",o:["は","で","を","に"],a:0,exp:"「は」は文のテーマを示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　にちようびは がっこう（　）やすみです。",o:["が","は","を","に"],a:1,exp:"「は」対比を含むテーマ。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　この りんごは あの りんご（　）おおきいです。",o:["とも","にも","でも","より"],a:3,exp:"比較の「より」。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　すみませんが、まど（　）あけて ください。",o:["で","が","を","に"],a:2,exp:"「を」は目的語を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　きょうは あめが ふって（　）。",o:["います","です","した","あります"],a:0,exp:"「〜ています」進行・継続。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　わたしは まいにち にほんご（　）はなします。",o:["が","を","に","で"],a:3,exp:"「で」は手段・言語を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　この みちを まっすぐ （　）ください。",o:["いった","いき","いく","いって"],a:3,exp:"依頼の「て形」＋ください。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　あには わたし（　）せが たかいです。",o:["でも","にも","とも","より"],a:3,exp:"比較の「より」。"},
      {sec:"問題2　文法2（文の組み立て）",q:"　★　に はいる ものは どれですか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　あさ　___　___　★　___　でかけます。（1 て　2 かおを　3 あらっ　4 から）",o:["かおを","て","あらっ","から"],a:3,exp:"正しい順序：2かおを→3あらっ→1て→4から「かおをあらってから」。★の位置には4「から」が入る。"},
      {q:"　★　に はいる ものは どれですか。1・2・3・4から ひとつ えらんで ください。　この　___　___　★　___　です。（1 とても　2 は　3 パン　4 おいしい）",o:["パン","おいしい","は","とても"],a:1,exp:"正しい順序：3パン→2は→1とても→4おいしい「パンはとてもおいしい」。★の位置には4「おいしい」が入る。"},
      {q:"　★　に はいる ものは どれですか。1・2・3・4から ひとつ えらんで ください。　わたしは　___　★　___　___　います。（1 まいにち　2 に　3 学校　4 かよって）",o:["まいにち","かよって","学校","に"],a:3,exp:"正しい順序：1まいにち→3学校→2に→4かよって「まいにち学校にかよって」。★の位置には2「に」が入る。"},
      {q:"　★　に はいる ものは どれですか。1・2・3・4から ひとつ えらんで ください。　きのう　___　___　★　___　かいました。（1 で　2 くつを　3 あたらしい　4 デパート）",o:["あたらしい","で","デパート","くつを"],a:3,exp:"正しい順序：4デパート→1で→3あたらしい→2くつを「デパートであたらしいくつを」。★の位置には2「くつを」が入る。"},
      {sec:"問題3　文章の文法",passage:"わたしの アパートは えきから ちかいです。あるいて 五ふん（1）。まいあさ、アパートを 出て、コンビニで あさごはんを かいます。それ（2）、えきまで あるきます。でんしゃは いつも こんで いますが、（3）まんいんでは ありません。会社（4）着くのは 九時ごろです。しごとが おわったら、ともだちと しょくじに 行く（5）あります。",q:"（1）",o:["ですか","です","でしょう","でした"],a:1,exp:"現在の状態を表す「です」。"},
      {q:"（2）",o:["より","へ","から","まで"],a:2,exp:"「それから」時間的順序を示す。"},
      {q:"（3）",o:["あまり","ぜんぜん","たまに","いつも"],a:2,exp:"「たまに」＝時々。文脈上「いつも満員というわけではない」ことを表す。"},
      {q:"（4）",o:["を","が","で","に"],a:3,exp:"「〜に着く」到着点を示す助詞。"},
      {q:"（5）",o:["ことは","もの","ことも","はず"],a:2,exp:"「〜こともある」時々そういうことがある、という表現。"},
      {sec:"問題4　内容理解（短文）",passage:"わたしは まいにち じてんしゃで がっこうへ いきます。がっこうまで 十五ふん かかります。",q:"がっこうまで なんぷん かかりますか。",o:["一じかん","五ふん","三十ぷん","十五ふん"],a:3,exp:"「十五ふん かかります」がそのまま答え。"},
      {passage:"スーパーで やさいを かいました。トマトと たまねぎと にんじんを かいました。",q:"なにを かいましたか。",o:["さかな","にく","くだもの","やさい"],a:3,exp:"「やさいを かいました」＋具体例。"},
      {passage:"としょかんは げつようびが やすみです。かようびから にちようびまで あいています。",q:"としょかんが やすみの ひは いつですか。",o:["どようび","げつようび","かようび","にちようび"],a:1,exp:"「げつようびが やすみです」がそのまま答え。"},
      {sec:"問題5　内容理解（中文）",passage:"きょねん、わたしは にほんへ りょこうに いきました。とうきょうと きょうとを みました。とうきょうでは たかい たてものが たくさん ありました。きょうとでは ふるい おてらが たくさん ありました。",q:"どこへ りょこうに いきましたか。",o:["とうきょうだけ","とうきょうと きょうと","ほっかいどうと おきなわ","おおさかと なごや"],a:1,exp:"「とうきょうと きょうとを みました」がそのまま答え。"},
      {q:"きょうとには なにが ありましたか。",o:["ふるい おてら","おおきい やま","うみ","たかい たてもの"],a:0,exp:"「きょうとでは ふるい おてらが たくさん ありました」がそのまま答え。"},
      {passage:"わたしの かいしゃは えきから ちかいです。まいにち 八時に かいしゃに つきます。しごとは 五時に おわります。",q:"かいしゃは なんじに おわりますか。",o:["八時","十時","九時","五時"],a:3,exp:"「しごとは 五時に おわります」がそのまま答え。"},
      {q:"かいしゃまで どうですか。",o:["えきから ちかい","うみの ちかく","やまの なか","えきから とおい"],a:0,exp:"「わたしの かいしゃは えきから ちかいです」がそのまま答え。"},
      {sec:"問題6　情報検索",passage:"【レストランの えいぎょうじかん】<br>・月〜金：11:00〜15:00（ランチ）、17:00〜22:00（ディナー）<br>・土・日・しゅくじつ：11:00〜22:00（休憩なし）<br>・毎週 火曜日は 定休日<br>・ランチタイムは セットメニューが 500円 引き",q:"火曜日の 午後2時に この レストランへ 行くと どう なりますか。",o:["ディナーが 食べられる","ランチが 食べられる","セットメニューが 割引に なる","休みで 入れない"],a:3,exp:"「毎週 火曜日は 定休日」なので入れない。"}
    ]},
    {id:"c", title:"聴解", minutes:30, questions:[
      {sec:"問題1　課題理解",audio:"女：すみません、この にもつを おくりたいんですが。　男：はい、じゃあ サイズと おもさを はかりますね。",q:"店の人は まず なにを しますか。",o:["おかねを うけとる","サイズと おもさを はかる","じゅうしょを きく","はこを さがす"],a:1,exp:"「サイズと おもさを はかりますね」がそのまま答え。"},
      {audio:"男：すみません、この セーター、もう少し 大きい サイズは ありますか。　女：少々 お待ちください。確認いたします。",q:"お客さんは なにを たのみましたか。",o:["ねだんを さげる こと","へんぴんする こと","いろを かえる こと","大きい サイズを かくにんする こと"],a:3,exp:"「もう少し 大きい サイズは ありますか」がそのまま答え。"},
      {audio:"女：来週の 面接ですが、何を 準備すれば いいですか。　男：履歴書と 写真を 持って来て ください。",q:"面接に なにを 持って行きますか。",o:["パソコン","何も 要らない","印鑑だけ","履歴書と 写真"],a:3,exp:"「履歴書と 写真を 持って来て ください」がそのまま答え。"},
      {audio:"男：あの、この 近くに コインランドリーは ありますか。　女：ええ、この 道を まっすぐ 行くと、右側に ありますよ。",q:"コインランドリーは どこに ありますか。",o:["まっすぐ 行った 右側","この 建物の 中","まっすぐ 行った 左側","駅の 前"],a:0,exp:"「まっすぐ 行くと、右側に あります」がそのまま答え。"},
      {audio:"女：荷物を 送りたいのですが、いつ 届きますか。　男：今日 送ると、あさって 届きます。",q:"今日 荷物を 送ると、いつ 届きますか。",o:["明日","あさって","一週間後","今日中"],a:1,exp:"「あさって 届きます」がそのまま答え。"},
      {audio:"男：すみません、この 靴、履いて みても いいですか。　女：もちろんです。サイズは おいくつですか。",q:"お客さんは 何を したいと 言いましたか。",o:["靴を 買いたい","靴を 返品したい","サイズを 知りたい","靴を 履いて みたい"],a:3,exp:"「履いて みても いいですか」がそのまま答え。"},
      {sec:"問題2　ポイント理解",audio:"女：来週の 出張ですが、飛行機と 新幹線、どちらが いいですか。　男：時間が ないので、飛行機に しましょう。",q:"出張には 何を 使いますか。",o:["バス","飛行機","車","新幹線"],a:1,exp:"「飛行機に しましょう」がそのまま答え。"},
      {audio:"男：すみません、レポートの 締め切りは いつまでですか。　女：今週の 金曜日までに 提出して ください。",q:"レポートは いつまでに 出しますか。",o:["今日中","来月","今週の 金曜日","来週の 月曜日"],a:2,exp:"「今週の 金曜日までに 提出して ください」がそのまま答え。"},
      {audio:"女：あの、注文した 商品なんですが、色を 変更したいのですが。　男：かしこまりました。ご希望の 色を 教えて ください。",q:"お客さんは 何を したいですか。",o:["注文を 取り消す","値段を 聞く","注文した 商品の 色を 変える","返品する"],a:2,exp:"「色を 変更したい」がそのまま答え。"},
      {audio:"男：この 電車、次の 駅で 特急に 乗り換えられますか。　女：はい、次の 駅の 二番線から 特急が 出ますよ。",q:"特急は どこから 出ますか。",o:["今の 駅","次の 駅の 二番線","終点","次の 駅の 一番線"],a:1,exp:"「次の 駅の 二番線から 特急が 出ます」がそのまま答え。"},
      {audio:"女：この 商品、色違いは ありますか。　男：申し訳ございません、現在は この 色のみと なって おります。",q:"この 商品には 何色が ありますか。",o:["色は 選べない","三色以上","一色のみ","二色"],a:2,exp:"「現在は この 色のみ」＝solo hay un color。"},
      {audio:"男：すみません、この コンサートの チケット、まだ 買えますか。　女：残り 少しですが、まだ 大丈夫ですよ。",q:"チケットは まだ 買えますか。",o:["来月から 買える","わからない","買える","もう 売り切れた"],a:2,exp:"「残り 少しですが、まだ 大丈夫ですよ」がそのまま答え。"},
      {sec:"問題3　発話表現",audio:"（え：ともだちが しあいに かった）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["おだいじに。","おめでとう。","ざんねんでしたね。","がんばって。"],a:1,exp:"勝った時は「おめでとう」と祝う。"},
      {audio:"（え：これから でかける ともだちに いう）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["いってきます。","いってらっしゃい。","ただいま。","おかえりなさい。"],a:1,exp:"出かける人には「いってらっしゃい」。"},
      {audio:"（え：ともだちに はじめて あった）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["おやすみなさい。","おかえりなさい。","ごちそうさま。","はじめまして。"],a:3,exp:"初対面の挨拶は「はじめまして」。"},
      {audio:"（え：よるねる まえに かぞくに いう）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["おやすみなさい。","ただいま。","こんにちは。","おはようございます。"],a:0,exp:"寝る前の挨拶は「おやすみなさい」。"},
      {audio:"（え：しょくじが おわった）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["いただきます。","ごちそうさまでした。","しつれいします。","おじゃまします。"],a:1,exp:"食後には「ごちそうさまでした」。"},
      {sec:"問題4　即時応答",audio:"おしごとは なんですか。",q:"いちばん いい へんじは どれですか。",o:["はじめまして。","三時です。","がっこうの せんせいです。","元気です。"],a:2,exp:"仕事を聞かれたら職業を答える。"},
      {audio:"にほんに いつから いますか。",q:"いちばん いい へんじは どれですか。",o:["一年前から います。","元気です。","三時です。","ありがとう。"],a:0,exp:"期間を聞かれたら期間を答える。"},
      {audio:"この でんわを つかっても いいですか。",q:"いちばん いい へんじは どれですか。",o:["はい、げんきです。","いいえ、三時です。","ありがとう。","はい、どうぞ。"],a:3,exp:"許可を求められたら「はい、どうぞ」。"},
      {audio:"にほんごの べんきょうは たのしいですか。",q:"いちばん いい へんじは どれですか。",o:["いいえ、三人です。","はい、とても たのしいです。","はい、あそこです。","ありがとうございます。"],a:1,exp:"感想を聞かれたら感想を答える。"},
      {audio:"ただいま。",q:"いちばん いい へんじは どれですか。",o:["いってらっしゃい。","おやすみなさい。","いってきます。","おかえりなさい。"],a:3,exp:"「ただいま」には「おかえりなさい」と返す。"},
      {audio:"どうも ありがとうございました。",q:"いちばん いい へんじは どれですか。",o:["はじめまして。","どういたしまして。","しつれいします。","おじゃまします。"],a:1,exp:"感謝には「どういたしまして」と返す。"}
    ]}
  ]
},
{
  id:"o-n5-4", lvl:"N5", title:"Examen oficial N5 · 4", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙）", minutes:20, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　弟は まだ 小学生です。",o:["あに","おとうと","ちち","あね"],a:1,exp:"弟→おとうと「hermano menor」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　今月は いそがしいです。",o:["らいげつ","こんしゅう","せんげつ","こんげつ"],a:3,exp:"今月→こんげつ「este mes」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　木の したで やすみます。",o:["もり","くさ","はな","き"],a:3,exp:"木→き「árbol」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　母は りょうりが じょうずです。",o:["ちち","あね","はは","いもうと"],a:2,exp:"母→はは「madre」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　空が あおいです。",o:["やま","そら","かわ","うみ"],a:1,exp:"空→そら「cielo」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　新しい くつを かいました。",o:["たかい","あたらしい","ふるい","やすい"],a:1,exp:"新しい→あたらしい「nuevo」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　毎年 なつに りょこうします。",o:["まいしゅう","まいつき","まいにち","まいとし"],a:3,exp:"毎年→まいとし「cada año」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　あしたは やすみです。",o:["木み","体み","休","休み"],a:3,exp:"やすみ→休み「descanso」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　でんしゃに のります。",o:["電池","電話","電車","電気"],a:2,exp:"でんしゃ→電車「tren」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　あたらしい くるまを かいました。",o:["新しい","安い","古い","高い"],a:0,exp:"あたらしい→新しい「nuevo」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　この みちは ながいです。",o:["狭い","広い","短い","長い"],a:3,exp:"ながい→長い「largo」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　あさごはんを たべます。",o:["作ります","買います","食べます","飲みます"],a:2,exp:"たべます→食べます「comer」。"},
      {sec:"問題3　文脈規定",q:"（　）に なにを いれますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　えいがを みて、とても （　）。",o:["はずかしいでした","かんどうしました","いそがしいでした","つかれました"],a:1,exp:"映画を見て「かんどうしました」（emocionarse）。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　この もんだいは （　）です。",o:["むずかしい","にぎやか","きれい","しずか"],a:0,exp:"問題が「むずかしい」（difícil）。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　でんきを （　）、へやが あかるく なりました。",o:["けして","しめて","つけて","あけて"],a:2,exp:"明るくするには電気を「つけて」（encender）。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　あの　みせは　いつも　（　）です。",o:["くらい","しずか","こんで いる","すいて いる"],a:2,exp:"「こんでいる」＝lleno de gente。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　わたしは まいばん 十時に （　）。",o:["たべます","はたらきます","おきます","ねます"],a:3,exp:"夜には「ねます」（acostarse）。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　この みずは とても （　）です。",o:["あつい","つめたい","からい","あまい"],a:1,exp:"水は「つめたい」（frío）。"},
      {sec:"問題4　言い換え類義",q:"＿＿の ぶんと だいたい おなじ いみの ぶんが あります。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　この へやは あついです。",o:["この へやは くらいです。","この へやは さむくないです。","この へやは せまいです。","この へやは さむいです。"],a:1,exp:"「あつい」＝「さむくない」（caliente）。"},
      {q:"＿＿の ぶんと だいたい おなじ いみの ぶんが あります。1・2・3・4から ひとつ えらんで ください。　あの ひとは わかいです。",o:["あの ひとは としを とって いません。","あの ひとは せが たかいです。","あの ひとは げんきじゃないです。","あの ひとは としを とって います。"],a:0,exp:"「わかい」＝「としをとっていない」（joven）。"},
      {q:"＿＿の ぶんと だいたい おなじ いみの ぶんが あります。1・2・3・4から ひとつ えらんで ください。　この にもつは かるいです。",o:["この にもつは おもくないです。","この にもつは おもいです。","この にもつは ちいさいです。","この にもつは おおきいです。"],a:0,exp:"「かるい」＝「おもくない」（ligero）。"}
    ]},
    {id:"b", title:"言語知識（文法）・読解", minutes:40, questions:[
      {sec:"問題1　文法1",q:"（　）に なにを いれますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　わたしは まいにち にほんご（　）べんきょうしています。",o:["を","が","へ","に"],a:0,exp:"「を」は目的語を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　としょかん（　）ほんを よみます。",o:["が","で","を","へ"],a:1,exp:"「で」は動作の場所を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　きのう ともだち（　）あいました。",o:["へ","を","に","で"],a:2,exp:"「に」は会う相手を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　この ケーキは とても （　）です。",o:["おいしいだ","おいしいい","おいしい","おいしくて"],a:2,exp:"い形容詞＋です。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　あには わたし（　）せが たかいです。",o:["でも","とも","にも","より"],a:3,exp:"比較の「より」。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　この りょうりは あそこの りょうり（　）おいしいです。",o:["へも","でも","にも","より"],a:3,exp:"比較の「より」。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　あした パーティー（　）行きますか。",o:["を","と","で","に"],a:3,exp:"「に」は行き先を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　わたしは コーヒー（　）のみます。",o:["へ","と","で","を"],a:3,exp:"「を」は目的語を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　きょうしつに がくせいが 五人 （　）。",o:["います","でした","します","あります"],a:0,exp:"人は「います」。"},
      {sec:"問題2　文法2（文の組み立て）",q:"　★　に はいる ものは どれですか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　あの　___　___　★　___　です。（1 は　2 とても　3 建物　4 大きい）",o:["は","大きい","とても","建物"],a:1,exp:"正しい順序：3建物→1は→2とても→4大きい「建物はとても大きい」。★の位置には4「大きい」が入る。"},
      {q:"　★　に はいる ものは どれですか。1・2・3・4から ひとつ えらんで ください。　わたしは　___　___　★　___　います。（1 まいあさ　2 を　3 コーヒー　4 のんで）",o:["まいあさ","を","コーヒー","のんで"],a:1,exp:"正しい順序：1まいあさ→3コーヒー→2を→4のんで「まいあさコーヒーをのんで」。★の位置には2「を」が入る。"},
      {q:"　★　に はいる ものは どれですか。1・2・3・4から ひとつ えらんで ください。　きのう　___　★　___　___　みました。（1 えいがを　2 おもしろい　3 ともだちと　4 いっしょに）",o:["おもしろい","いっしょに","えいがを","ともだちと"],a:0,exp:"正しい順序：3ともだちと→4いっしょに→2おもしろい→1えいがを「ともだちといっしょにおもしろいえいがを」。★の位置には2「おもしろい」が入る。"},
      {q:"　★　に はいる ものは どれですか。1・2・3・4から ひとつ えらんで ください。　わたしの　___　___　★　___　います。（1 東京　2 に　3 兄は　4 すんで）",o:["兄は","すんで","に","東京"],a:1,exp:"正しい順序：3兄は→1東京→2に→4すんで「兄は東京にすんで」。★の位置には4「すんで」が入る。"},
      {sec:"問題3　文章の文法",passage:"わたしは まいばん、日記を（1）。きょうの できごとや かんがえた ことを かきます。日記を かく（2）、その日の ことを よく おぼえて いられます。ときどき、むかしの 日記を よみかえします。（3）、いろいろな ことを おもいだして、たのしいです。日記は わたしに（4）、とても たいせつな しゅうかんです。これからも つづけたい（5）。",q:"（1）",o:["かきます","おくります","よみます","つくります"],a:0,exp:"日記は「かきます」（escribir）。"},
      {q:"（2）",o:["と","なら","たら","ば"],a:0,exp:"「〜と」で一般的な結果を導く。"},
      {q:"（3）",o:["それで","すると","しかし","または"],a:1,exp:"「すると」＝順接の展開。"},
      {q:"（4）",o:["にして","にとって","として","とって"],a:3,exp:"「〜にとって」＝立場から見て。"},
      {q:"（5）",o:["でしょう","と 思います","と 思いません","かもしれません"],a:1,exp:"「〜たいと思います」希望を表す文型。"},
      {sec:"問題4　内容理解（短文）",passage:"わたしは まいしゅう どようびに テニスを します。ともだちと いっしょに します。",q:"いつ テニスを しますか。",o:["どようび","にちようび","まいにち","きんようび"],a:0,exp:"「まいしゅう どようびに テニスを します」がそのまま答え。"},
      {passage:"きのう ともだちと えいがを みました。それから、レストランで しょくじを しました。",q:"レストランの まえに なにを しましたか。",o:["べんきょうした","うちへ かえった","えいがを みた","かいものを した"],a:2,exp:"「えいがを みました。それから、レストランで」→ el cine fue antes。"},
      {passage:"ちちは ぎんこうで はたらいています。ははは がっこうで えいごを おしえています。",q:"ちちの しごとは なんですか。",o:["きょうし","いしゃ","ぎんこういん","かいしゃいん"],a:2,exp:"「ちちは ぎんこうで はたらいています」がそのまま答え。"},
      {sec:"問題5　内容理解（中文）",passage:"わたしの がっこうは えきから とおいです。まいあさ、バスに のって がっこうへ いきます。バスは 三十ぷんに いっぽん あります。ときどき バスが おくれるので、はやく いえを でます。",q:"がっこうまで なにで いきますか。",o:["バスで","でんしゃで","じてんしゃで","あるいて"],a:0,exp:"「バスに のって がっこうへ いきます」がそのまま答え。"},
      {q:"なぜ はやく いえを でますか。",o:["あさが すきだから","バスが おくれる ことが あるから","バスが すくないから","がっこうが とおいから"],a:1,exp:"「ときどき バスが おくれるので、はやく いえを でます」がそのまま答え。"},
      {passage:"わたしは にほんの おんがくが すきです。まいばん、ねる まえに おんがくを ききます。すきな かしゅの コンサートに いった ことも あります。",q:"いつ おんがくを ききますか。",o:["ねる まえ","あさ おきた とき","がっこうに いる とき","はたらいて いる とき"],a:0,exp:"「まいばん、ねる まえに おんがくを ききます」がそのまま答え。"},
      {q:"この人は なにを した ことが ありますか。",o:["コンサートに いった こと","がいこくに いった こと","うたを つくった こと","がっきを ならった こと"],a:0,exp:"「すきな かしゅの コンサートに いった ことも あります」がそのまま答え。"},
      {sec:"問題6　情報検索",passage:"【市民プールの りようあんない】<br>・りようじかん：午前9時〜午後8時<br>・きゅうかんび：毎週 月曜日<br>・りようりょう：おとな 500円、こども（3さいから15さいまで）300円<br>・回数券：11回分の りょうきんで 12回 りようできる（おとなのみ）",q:"おとなが 回数券を つかって 12回 プールを りようすると、1回あたりの りょうきんは いくらに なりますか。",o:["500円","約417円","300円","約458円"],a:3,exp:"11回分の料金（500円×11＝5,500円）で12回利用できるので、5,500÷12≒458円。"}
    ]},
    {id:"c", title:"聴解", minutes:30, questions:[
      {sec:"問題1　課題理解",audio:"男：来週の 出張の 件ですが、飛行機の 予約は できていますか。　女：まだです。今日中に、旅行代理店に 連絡します。",q:"女の人は このあと、まず 何を しますか。",o:["出張を 中止する","ホテルを 予約する","飛行機に 乗る","旅行代理店に 連絡する"],a:3,exp:"「今日中に、旅行代理店に 連絡します」がそのまま答え。"},
      {audio:"女：この 資料、何部 印刷すれば いいですか。　男：会議の 参加者は 十人なので、十部 お願いします。",q:"何部 印刷しますか。",o:["十五部","十部","二十部","五部"],a:1,exp:"「十部 お願いします」がそのまま答え。"},
      {audio:"男：すみません、電車が おくれて いて、少し 遅刻します。　女：わかりました。気を つけて 来て ください。",q:"この 人は なぜ 電話しましたか。",o:["道が わからないから","病気に なったから","会議を 忘れたから","電車が おくれて 遅刻するから"],a:3,exp:"「電車が おくれて いて、少し 遅刻します」がそのまま答え。"},
      {audio:"女：明日の 会議、場所が 変わりました。三階の 会議室から 五階に 変わったので、気を つけて ください。",q:"明日の 会議は どこで ありますか。",o:["五階","地下","三階","一階"],a:0,exp:"「五階に 変わった」がそのまま答え。"},
      {audio:"男：すみません、この コピー機の 使い方が わかりません。　女：ここの ボタンを 押せば、すぐに コピーが できますよ。",q:"コピー機の 使い方は どうすれば いいですか。",o:["係員を 呼ぶ","ボタンを 押す","紙を 変える","電源を 入れ直す"],a:1,exp:"「ここの ボタンを 押せば…できますよ」がそのまま答え。"},
      {audio:"女：来週の 旅行ですが、天気は どうですか。　男：天気予報に よると、晴れる 日が 多いそうです。",q:"来週の 天気は どうだと 言っていますか。",o:["ずっと くもり","雨の 日が 多い","雪が ふる","晴れる 日が 多い"],a:3,exp:"「晴れる 日が 多いそうです」がそのまま答え。"},
      {sec:"問題2　ポイント理解",audio:"男：すみません、この 薬は どうやって 飲みますか。　女：一日 三回、食事の あとに 飲んで ください。",q:"薬は いつ 飲みますか。",o:["寝る 前だけ","食事の 前","朝だけ","食事の あと"],a:3,exp:"「食事の あとに 飲んで ください」がそのまま答え。"},
      {audio:"女：この 荷物、宅配便で 送りたいんですが。　男：サイズと 重さを 測りますので、少々 お待ちください。",q:"店の 人は まず 何を しますか。",o:["料金を 計算する","サイズと 重さを 測る","住所を 聞く","箱を 探す"],a:1,exp:"「サイズと 重さを 測りますので」がそのまま答え。"},
      {audio:"男：来週の 面接、履歴書の 確認は 済んでいますか。　女：まだです。今日の 午後、全員分に 目を通します。",q:"履歴書の 確認は いつ しますか。",o:["明日の 朝","今日の 午後","もう 済んでいる","来週の 月曜日"],a:1,exp:"「今日の 午後、全員分に 目を通します」がそのまま答え。"},
      {audio:"女：すみません、この 商品、まだ 在庫は ありますか。　男：申し訳ございません、こちらの色は 売り切れです。",q:"この商品は どうなっていますか。",o:["値段が 変わった","売り切れている","在庫が たくさん ある","来月 入荷する"],a:1,exp:"「こちらの色は 売り切れです」がそのまま答え。"},
      {audio:"男：来月の セミナー、定員は 何人ですか。　女：五十人までです。もう 三十人 申し込みが ありました。",q:"あと 何人 申し込めますか。",o:["三十人","二十人","五十人","十人"],a:1,exp:"定員50人のうち30人が申し込み済みなので、残り20人。"},
      {audio:"女：すみません、この レストラン、予約は 必要ですか。　男：週末は 必要ですが、平日は 予約なしでも 大丈夫です。",q:"平日に 行く場合、どうですか。",o:["休みで 入れない","予約は 必要ない","週末しか 開いていない","予約が 必ず 必要"],a:1,exp:"「平日は 予約なしでも 大丈夫です」がそのまま答え。"},
      {sec:"問題3　発話表現",audio:"（え：えきで、みちが わからない 人に あった）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["どうかしましたか。","いただきます。","おやすみなさい。","おめでとうございます。"],a:0,exp:"困っている人には「どうかしましたか」と声をかける。"},
      {audio:"（え：かいぎしつに はいる とき）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["ただいま。","おやすみなさい。","しつれいします。","おかえりなさい。"],a:2,exp:"部屋に入る時は「しつれいします」。"},
      {audio:"（え：でんわで はなしを おわる とき）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["いただきます。","はじめまして。","しつれいします。","おじゃまします。"],a:2,exp:"電話を切る時は「しつれいします」。"},
      {audio:"（え：ともだちに プレゼントを もらった）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["おだいじに。","ごめんなさい。","おめでとうございます。","ありがとうございます。"],a:3,exp:"プレゼントには「ありがとうございます」。"},
      {audio:"（え：しごとの めんせつで、へやに はいる まえ）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["しつれいします。","いってきます。","ただいま。","おかえりなさい。"],a:0,exp:"面接室に入る時も「しつれいします」。"},
      {sec:"問題4　即時応答",audio:"しゅみは なんですか。",q:"いちばん いい へんじは どれですか。",o:["はじめまして。","りょうりです。","三時です。","元気です。"],a:1,exp:"趣味を聞かれたら趣味を答える。"},
      {audio:"なんにん かぞくですか。",q:"いちばん いい へんじは どれですか。",o:["元気です。","三時です。","ありがとう。","四人です。"],a:3,exp:"人数を聞かれたら人数を答える。"},
      {audio:"この いすに すわっても いいですか。",q:"いちばん いい へんじは どれですか。",o:["はい、どうぞ。","ありがとう。","いいえ、三時です。","はい、げんきです。"],a:0,exp:"許可を求められたら「はい、どうぞ」。"},
      {audio:"にほんの てんきは どうですか。",q:"いちばん いい へんじは どれですか。",o:["いいえ、三人です。","はい、あそこです。","ありがとうございます。","今日は あついです。"],a:3,exp:"天気を聞かれたら天気の様子を答える。"},
      {audio:"おさきに しつれいします。",q:"いちばん いい へんじは どれですか。",o:["おやすみなさい。","おかえりなさい。","おつかれさまでした。","ただいま。"],a:2,exp:"先に帰る人には「おつかれさまでした」。"},
      {audio:"すみません、ちょっと いいですか。",q:"いちばん いい へんじは どれですか。",o:["はい、なんですか。","はい、げんきです。","ありがとう。","いいえ、三時です。"],a:0,exp:"話しかけられたら「はい、なんですか」と応じる。"}
    ]}
  ]
},
{
  id:"o-n5-5", lvl:"N5", title:"Examen oficial N5 · 5", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙）", minutes:20, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　姉は びょういんで はたらいて います。",o:["あね","おとうと","あに","いもうと"],a:0,exp:"姉→あね「hermana mayor」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　来年 にほんへ いきます。",o:["せんねん","らいしゅう","らいねん","こんねん"],a:2,exp:"来年→らいねん「el año que viene」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　外は さむいです。",o:["なか","うえ","した","そと"],a:3,exp:"外→そと「fuera」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　父は かいしゃいんです。",o:["はは","ちち","あね","あに"],a:1,exp:"父→ちち「padre」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　目が いたいです。",o:["め","はな","みみ","くち"],a:0,exp:"目→め「ojo」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　安い みせを さがして います。",o:["おおきい","やすい","ちいさい","たかい"],a:1,exp:"安い→やすい「barato」。"},
      {q:"＿＿の ことばは ひらがなで どう かきますか。1・2・3・4から ひとつ えらんで ください。　毎週 にほんごを ならって います。",o:["まいにち","まいつき","まいとし","まいしゅう"],a:3,exp:"毎週→まいしゅう「cada semana」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　あしたは やすみです。",o:["休","体み","木み","休み"],a:3,exp:"やすみ→休み「descanso」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　ちいさい こどもが います。",o:["子供","小子","小供","子ども"],a:0,exp:"こども→子供「niño」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　みぎに まがって ください。",o:["上","下","右","左"],a:2,exp:"みぎ→右「derecha」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　あかい はなが すきです。",o:["黒い","白い","赤い","青い"],a:2,exp:"あかい→赤い「rojo」。"},
      {q:"＿＿の ことばは かんじで どう かきますか。1・2・3・4から ひとつ えらんで ください。　きょうは げつようびです。",o:["火曜日","木曜日","水曜日","月曜日"],a:3,exp:"げつようび→月曜日「lunes」。"},
      {sec:"問題3　文脈規定",q:"（　）に なにを いれますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　この りょうりは とても （　）です。",o:["からい","しずか","つめたい","きれい"],a:0,exp:"料理は「からい」（picante）。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　まいばん、テレビを （　）から ねます。",o:["みて","たべて","つくって","かって"],a:0,exp:"テレビは「みる」（ver）。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　この へやは （　）ので、あついです。",o:["きれいだ","くらい","ひろい","まどが ない"],a:3,exp:"窓がないと暑くなる、という文脈。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　わたしは あさ シャワーを （　）。",o:["たべます","のみます","あびます","かいます"],a:2,exp:"シャワーは「あびます」（ducharse）。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　この もんだいは （　）ので、すぐ できました。",o:["おもかった","かんたんだった","むずかしかった","ながかった"],a:1,exp:"「かんたんだった」ので早く終わった、という文脈。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　バスが （　）ので、あるいて いきました。",o:["こなかった","はやかった","やすかった","きた"],a:0,exp:"バスが来なかったので歩いた、という文脈。"},
      {sec:"問題4　言い換え類義",q:"＿＿の ぶんと だいたい おなじ いみの ぶんが あります。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　この コーヒーは あついです。",o:["この コーヒーは つめたくないです。","この コーヒーは あまいです。","この コーヒーは にがいです。","この コーヒーは つめたいです。"],a:0,exp:"「あつい」＝「つめたくない」（caliente）。"},
      {q:"＿＿の ぶんと だいたい おなじ いみの ぶんが あります。1・2・3・4から ひとつ えらんで ください。　あの ビルは たかいです。",o:["あの ビルは ひくくないです。","あの ビルは ちいさいです。","あの ビルは ひくいです。","あの ビルは ふるいです。"],a:0,exp:"「たかい」＝「ひくくない」（alto）。"},
      {q:"＿＿の ぶんと だいたい おなじ いみの ぶんが あります。1・2・3・4から ひとつ えらんで ください。　この まちは にぎやかです。",o:["この まちは しずかです。","この まちは きたないです。","この まちは しずかじゃないです。","この まちは せまいです。"],a:2,exp:"「にぎやか」＝「しずかじゃない」（animado）。"}
    ]},
    {id:"b", title:"言語知識（文法）・読解", minutes:40, questions:[
      {sec:"問題1　文法1",q:"（　）に なにを いれますか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　わたしは がっこう（　）行きます。",o:["を","が","の","へ"],a:3,exp:"「へ」は方向を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　これは わたし（　）ほんです。",o:["に","を","が","の"],a:3,exp:"「の」は所有を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　きょうしつに がくせいが 五人 （　）。",o:["います","でした","あります","します"],a:0,exp:"人は「います」。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　テーブルの うえに ほんが 三さつ （　）。",o:["います","でした","あります","します"],a:2,exp:"物は「あります」。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　あの ひとは わたし（　）せんせいです。",o:["に","が","を","の"],a:3,exp:"「の」は所有・関係を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　としょかん（　）ほんを よみます。",o:["で","へ","が","を"],a:0,exp:"「で」は動作の場所を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　きのう ともだち（　）あいました。",o:["で","に","へ","を"],a:1,exp:"「に」は会う相手を示す。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　この ケーキは とても （　）です。",o:["おいしい","おいしくて","おいしいだ","おいしいい"],a:0,exp:"い形容詞＋です。"},
      {q:"（　）に なにを いれますか。1・2・3・4から ひとつ えらんで ください。　あには わたし（　）せが たかいです。",o:["でも","とも","にも","より"],a:3,exp:"比較の「より」。"},
      {sec:"問題2　文法2（文の組み立て）",q:"　★　に はいる ものは どれですか。1・2・3・4から いちばん いい ものを ひとつ えらんで ください。　わたしは　___　___　★　___　います。（1 に　2 まいにち　3 学校　4 かよって）",o:["かよって","まいにち","に","学校"],a:2,exp:"正しい順序：2まいにち→3学校→1に→4かよって「まいにち学校にかよって」。★の位置には1「に」が入る。"},
      {q:"　★　に はいる ものは どれですか。1・2・3・4から ひとつ えらんで ください。　あの　___　___　★　___　です。（1 大きい　2 は　3 建物　4 とても）",o:["とても","は","建物","大きい"],a:3,exp:"正しい順序：3建物→2は→4とても→1大きい「建物はとても大きい」。★の位置には1「大きい」が入る。"},
      {q:"　★　に はいる ものは どれですか。1・2・3・4から ひとつ えらんで ください。　この　みちを　___　___　★　___　行くと、えきに つきます。（1 まっすぐ　2 分ぐらい　3 十　4 で）",o:["十","分ぐらい","で","まっすぐ"],a:3,exp:"正しい順序：1まっすぐ→3十→2分ぐらい→4で「まっすぐ十分ぐらいで」。★の位置には1「まっすぐ」が入る。"},
      {q:"　★　に はいる ものは どれですか。1・2・3・4から ひとつ えらんで ください。　きょうは　___　★　___　___　います。（1 雨　2 が　3 ふって　4 ずっと）",o:["ふって","雨","ずっと","が"],a:1,exp:"正しい順序：4ずっと→1雨→2が→3ふって「きょうは ずっと 雨が ふって います」。★の位置には1「雨」が入る。"},
      {sec:"問題3　文章の文法",passage:"わたしは にほんの アニメが すきです。まいしゅう、あたらしい アニメを（1）見ます。すきな アニメの キャラクターの グッズも 集めて います。（2）、日本語の べんきょうも 頑張って います。アニメを 見る（3）、日本語の 会話が 少し 分かるように なりました。（4）、まだ 漢字は むずかしくて、よく 辞書を つかいます。これからも アニメを（5）、日本語を べんきょうしたいです。",q:"（1）",o:["三回","三人","三本","三さつ"],a:2,exp:"アニメの本数は「本」で数える。"},
      {q:"（2）",o:["それに","でも","だから","または"],a:0,exp:"「それに」＝追加の情報を導く。"},
      {q:"（3）",o:["そうに","ようになって","らしく","ように"],a:1,exp:"「〜ようになって」変化を表す。"},
      {q:"（4）",o:["つまり","でも","それに","それで"],a:1,exp:"逆接の「でも」が文脈に合う。"},
      {q:"（5）",o:["見ないで","見ながら","見た後で","見る前に"],a:1,exp:"「〜ながら」同時進行を表す。"},
      {sec:"問題4　内容理解（短文）",passage:"わたしは まいにち じてんしゃで がっこうへ いきます。がっこうまで 十五ふん かかります。",q:"がっこうまで なにで いきますか。",o:["バス","あるいて","じてんしゃ","でんしゃ"],a:2,exp:"「じてんしゃで がっこうへ いきます」がそのまま答え。"},
      {passage:"きょうは わたしの たんじょうびです。ともだちが パーティーを ひらいて くれました。",q:"だれが パーティーを ひらきましたか。",o:["せんせい","かぞく","かいしゃの ひと","ともだち"],a:3,exp:"「ともだちが パーティーを ひらいて くれました」がそのまま答え。"},
      {passage:"あには だいがくせいです。いもうとは こうこうせいです。わたしは ちゅうがくせいです。",q:"「あに」は なんですか。",o:["ちゅうがくせい","しょうがくせい","こうこうせい","だいがくせい"],a:3,exp:"「あには だいがくせいです」がそのまま答え。"},
      {sec:"問題5　内容理解（中文）",passage:"わたしは にほんの りょうりを つくるのが すきです。まいしゅう、あたらしい りょうりに ちょうせんします。せんしゅうは すしを つくりました。とても むずかしかったですが、たのしかったです。かぞくも みんな よろこんで くれました。",q:"せんしゅう なにを つくりましたか。",o:["てんぷら","すし","カレー","ラーメン"],a:1,exp:"「せんしゅうは すしを つくりました」がそのまま答え。"},
      {q:"かぞくは どうでしたか。",o:["おどろかなかった","かなしんだ","よろこんだ","おこった"],a:2,exp:"「かぞくも みんな よろこんで くれました」がそのまま答え。"},
      {passage:"きょねん、わたしは にほんごの がっこうに はいりました。さいしょは ひらがなも わかりませんでしたが、いま は かんじも すこし よめます。まいにち べんきょうして よかったです。",q:"いま、なにが できますか。",o:["かんじを ぜんぶ よむこと","かんじを すこし よむこと","ひらがなが よめない こと","にほんごが はなせない こと"],a:1,exp:"「いま は かんじも すこし よめます」がそのまま答え。"},
      {q:"この人は いつから にほんごを べんきょうして いますか。",o:["きょうから","きょねんから","らいねんから","せんげつから"],a:1,exp:"「きょねん、わたしは にほんごの がっこうに はいりました」がそのまま答え。"},
      {sec:"問題6　情報検索",passage:"【にほんご きょうしつ　あんない】<br>・レベル：しょきゅう（月・水）／ちゅうきゅう（火・木）／じょうきゅう（金）<br>・じかん：19:00〜20:30<br>・りょうきん：1かげつ 8,000円（きょうざいひ べつ）<br>・体験レッスン：初回のみ 無料（1回だけ）<br>・注意：しょきゅうと ちゅうきゅうを どうじに とる ばあいは、2かげつめから 10%割引",q:"しょきゅうの クラスは なんようびに ありますか。",o:["金","土・日","火・木","月・水"],a:3,exp:"「しょきゅう（月・水）」がそのまま答え。"}
    ]},
    {id:"c", title:"聴解", minutes:30, questions:[
      {sec:"問題1　課題理解",audio:"女：来月の 旅行、何を 持って行けば いいですか。　男：カメラと 予備の バッテリーを 忘れずに。",q:"旅行に 何を 持って行きますか。",o:["カメラと 予備の バッテリー","地図と パスポート","本と ノート","かさと 帽子"],a:0,exp:"「カメラと 予備の バッテリーを 忘れずに」がそのまま答え。"},
      {audio:"男：このレポート、いつまでに 提出すれば いいですか。　女：来週の 水曜日までに お願いします。",q:"レポートは いつまでですか。",o:["今週の 水曜日","来月の 初め","来週の 水曜日","明日"],a:2,exp:"「来週の 水曜日までに お願いします」がそのまま答え。"},
      {audio:"女：すみません、この セーター、色違いは ありますか。　男：申し訳ございません、確認いたします。",q:"店の人は このあと 何を しますか。",o:["セーターを 買う","値段を 下げる","返品を 受け付ける","色違いが あるか 確認する"],a:3,exp:"「確認いたします」がそのまま答え。"},
      {audio:"男：来週の セミナー、資料は 何部 必要ですか。　女：参加者は 二十人なので、二十五部 お願いします。",q:"資料は 何部 必要ですか。",o:["三十部","二十五部","十五部","二十部"],a:1,exp:"「二十五部 お願いします」がそのまま答え。"},
      {audio:"女：すみません、この 花、うちに 送りたいのですが。　男：はい、お届け先の 住所を お願いします。",q:"お客さんは まず 何を しますか。",o:["お店を 出る","花を 選ぶ","住所を 伝える","お金を 払う"],a:2,exp:"「お届け先の住所をお願いします」への流れから、住所を伝える。"},
      {audio:"男：今日の 会議、何時から でしたっけ。　女：二時からです。もう すぐですよ。",q:"会議は 何時からですか。",o:["三時","一時","四時","二時"],a:3,exp:"「二時からです」がそのまま答え。"},
      {sec:"問題2　ポイント理解",audio:"女：この チケット、まだ 買えますか。　男：残り わずかですが、まだ 大丈夫ですよ。",q:"チケットは まだ 買えますか。",o:["買える","来月から 買える","もう 売り切れた","わからない"],a:0,exp:"「残り わずかですが、まだ 大丈夫ですよ」がそのまま答え。"},
      {audio:"男：来週の 出張、新幹線と 飛行機、どちらが いいですか。　女：予算を 考えると、新幹線に しましょう。",q:"出張には 何を 使いますか。",o:["新幹線","車","飛行機","バス"],a:0,exp:"「新幹線に しましょう」がそのまま答え。"},
      {audio:"女：すみません、この 靴、サイズを 交換したいのですが。　男：レシートは お持ちですか。",q:"店員は まず 何を 確認しますか。",o:["レシートが あるか","値段が 高いか","色が 好きか","デザインが いいか"],a:0,exp:"「レシートは お持ちですか」がそのまま答え。"},
      {audio:"男：この 部屋、何人まで 入れますか。　女：最大 十人までです。",q:"この 部屋は 最大 何人まで 入れますか。",o:["二十人","十五人","十人","五人"],a:2,exp:"「最大 十人までです」がそのまま答え。"},
      {audio:"女：すみません、この 電車、次は 何時に 出ますか。　男：あと 五分で 出発します。",q:"次の 電車は いつ 出ますか。",o:["もう 出た","あと 五分で","あと 十分で","あと 一時間で"],a:1,exp:"「あと 五分で 出発します」がそのまま答え。"},
      {audio:"男：この 本、図書館で 借りられますか。　女：はい、貸出期間は 二週間です。",q:"この 本は どのくらい 借りられますか。",o:["一週間","一か月","二週間","三日間"],a:2,exp:"「貸出期間は 二週間です」がそのまま答え。"},
      {sec:"問題3　発話表現",audio:"（え：ともだちが びょうきで がっこうを やすんだ、つぎの日 あった）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["おめでとうございます。","おやすみなさい。","だいじょうぶですか。","いただきます。"],a:2,exp:"体調を気遣う時は「だいじょうぶですか」。"},
      {audio:"（え：としょかんで、ほんを かりたい）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["この 本を 捨てたいです。","この 本を 買いたいです。","この 本を 借りたいです。","この 本を 読みません。"],a:2,exp:"図書館で本を借りたい時の表現。"},
      {audio:"（え：でんしゃの なかで、せきを ゆずる）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["どうぞ、おすわりください。","ありがとう。","すみません。","おじゃまします。"],a:0,exp:"席を譲る時は「どうぞ、おすわりください」。"},
      {audio:"（え：レストランで ちゅうもんしたい）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["おじゃまします。","ごちそうさまでした。","いただきます。","すみません、注文を お願いします。"],a:3,exp:"注文したい時は店員を呼んで「注文をお願いします」。"},
      {audio:"（え：ともだちに しゃしんを とって もらいたい）　こういう とき、なんと いいますか。",q:"なんと いいますか。",o:["写真を 撮らないで ください。","写真を 撮って もらえますか。","写真は いりません。","写真を 見せて ください。"],a:1,exp:"依頼する時は「〜てもらえますか」。"},
      {sec:"問題4　即時応答",audio:"どんな 音楽が すきですか。",q:"いちばん いい へんじは どれですか。",o:["三時です。","はじめまして。","元気です。","ジャズが すきです。"],a:3,exp:"好みを聞かれたら好きなものを答える。"},
      {audio:"週末は なにを しますか。",q:"いちばん いい へんじは どれですか。",o:["友達と 買い物に 行きます。","三時です。","元気です。","ありがとう。"],a:0,exp:"予定を聞かれたら予定を答える。"},
      {audio:"この 席、空いていますか。",q:"いちばん いい へんじは どれですか。",o:["はい、どうぞ。","ありがとう。","いいえ、三時です。","はい、げんきです。"],a:0,exp:"席の確認には「はい、どうぞ」。"},
      {audio:"にほんに すんで、なんねんに なりますか。",q:"いちばん いい へんじは どれですか。",o:["はい、あそこです。","三年に なります。","ありがとうございます。","いいえ、三人です。"],a:1,exp:"期間を聞かれたら期間を答える。"},
      {audio:"また あした。",q:"いちばん いい へんじは どれですか。",o:["おかえりなさい。","また あした。","ただいま。","おじゃまします。"],a:1,exp:"別れの挨拶には同じ挨拶で返す。"},
      {audio:"すみません、これ いくらですか。",q:"いちばん いい へんじは どれですか。",o:["ありがとう。","はい、どうぞ。","元気です。","千円です。"],a:3,exp:"値段を聞かれたら値段を答える。"}
    ]}
  ]
},
{
  id:"o-n4-1", lvl:"N4", title:"Examen oficial N4 · 1", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙）", minutes:25, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 荷物は とても 重いです。",o:["ながい","みじかい","おもい","かるい"],a:2,exp:"重い→おもい「pesado」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　約束の 時間に おくれました。",o:["やくそく","じゃくそく","やくたく","よやく"],a:0,exp:"約束→やくそく「promesa」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　危険ですから、気を つけて ください。",o:["きげん","きせい","きけん","きかい"],a:2,exp:"危険→きけん「peligroso」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　両親に 電話しました。",o:["りょうおや","りょうしん","そふぼ","かぞく"],a:1,exp:"両親→りょうしん「padres」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　新しい 制度が 始まった。",o:["せいと","せいてい","せいたく","せいど"],a:3,exp:"制度→せいど「sistema」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　努力すれば できます。",o:["どりき","どりょく","ぬりょく","つとめりょく"],a:1,exp:"努力→どりょく「esfuerzo」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　経験が 少ない。",o:["けいけん","けいげん","けいい","けいこ"],a:0,exp:"経験→けいけん「experiencia」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　習慣を 変えたい。",o:["しゅかん","じゅうかん","しゅうかん","しゅうがん"],a:2,exp:"習慣→しゅうかん「costumbre」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　出発の 準備を します。",o:["しゅつばつ","しゅっぱつ","しゅっぱち","しゅつはつ"],a:1,exp:"出発→しゅっぱつ「salida」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは どう かきますか。1・2・3・4から いちばん いい ものを 一つ えらんで ください。　しんぱいしないで ください。",o:["信配","真配","心倍","心配"],a:3,exp:"しんぱい→心配「preocupación」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　うんてんが じょうずです。",o:["運動","運転","運送","運命"],a:1,exp:"うんてん→運転「conducir」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　しゅうかんを つづけます。",o:["習慣","収監","週刊","週間"],a:0,exp:"しゅうかん→習慣「hábito」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　よていを かくにんします。",o:["予算","予定","予想","予約"],a:1,exp:"よてい→予定「plan」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　けいけんを いかします。",o:["経験","経検","経見","経件"],a:0,exp:"けいけん→経験「experiencia」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　げんいんを しらべます。",o:["元因","現因","原員","原因"],a:3,exp:"げんいん→原因「causa」。"},
      {sec:"問題3　文脈規定",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　電車が （　）ので、会社に 遅れました。",o:["とまった","うごいた","はやかった","おくれた"],a:3,exp:"遅刻の原因＝電車が「おくれた」（se retrasó）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　会議が （　）ので、出発が おくれました。",o:["みじかかった","ながびいた","なかった","はやかった"],a:1,exp:"遅延の原因＝会議が「ながびいた」（se alargó）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　じかんが なかったので、しゅくだいを （　）。",o:["わすれました","いそいで しました","ゆっくり しました","たのしみました"],a:1,exp:"時間がない時は「いそいで しました」（lo hizo deprisa）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　かぜを ひいたので、くすりを （　）。",o:["かいました","たべました","のみました","つかいました"],a:2,exp:"薬は「のみます」（tomar medicina）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　かぎを （　）まま、でかけて しまった。",o:["しめた","あけた","けした","つけた"],a:1,exp:"「開けたまま」＝dejó la puerta abierta al salir。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 資料は 明日まで（　）作らなければ なりません。",o:["を","に","が","で"],a:1,exp:"「〜までに」（antes de una fecha límite）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　雪が 降る（　）、電車が 止まる ことが あります。",o:["し","のに","と","ながら"],a:2,exp:"「〜と」（condición habitual）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 問題は 難しくて （　）読めません。",o:["なかなか","きっと","ぜひ","もし"],a:0,exp:"「なかなか＋否定」＝'no...fácilmente'。"},
      {sec:"問題4　言い換え類義",q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は あわてて 部屋を 出た。",o:["ゆっくり","楽しそうに","急いで","静かに"],a:2,exp:"「あわてて」≒「急いで」（con prisas）。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼女は てきぱき 仕事を 片付けた。",o:["感情的に","能率よく、素早く","いい加減に","のんびりと"],a:1,exp:"「てきぱき」≒「能率よく、素早く」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は やむを得ず 参加を 諦めた。",o:["積極的に","すぐに","喜んで","仕方なく"],a:3,exp:"「やむを得ず」≒「仕方なく」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は 案の定 遅刻した。",o:["意外にも","偶然に","予想したとおり","急に"],a:2,exp:"「案の定」≒「予想したとおり」。"},
      {sec:"問題5　用法",q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「なかなか」",o:["なかなか明日は晴れます。","なかなか三人来ました。","なかなか元気です。","この漢字はなかなか覚えられません。"],a:3,exp:"「なかなか＋否定」＝no…fácilmente、覚えにくいという文脈に合う。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「案の定」",o:["案の定、早く終わった。","案の定、三時に会議がある。","案の定、明日雨が降るだろう。","案の定、彼は約束の時間に遅れた。"],a:3,exp:"「案の定」＝予想通りの結果を表す。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「せっかく」",o:["せっかく早く終わった。","せっかく明日雨が降る。","せっかく三時に会議がある。","せっかく作ったのに、誰も食べてくれなかった。"],a:3,exp:"「せっかく」＝con esfuerzo especial（それが無駄になる文脈でよく使う）。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「思い切って」",o:["思い切って早く終わった。","思い切って三時に来た。","思い切って明日会議がある。","思い切って新しい仕事に挑戦した。"],a:3,exp:"「思い切って」＝decidirse a hacer algo con determinación。"}
    ]},
    {id:"b", title:"言語知識（文法）・読解", minutes:55, questions:[
      {sec:"問題1　文法1",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　あしたは 雨が ふる（　）です。",o:["よう","こと","もの","そう"],a:3,exp:"「そう」（推量）情報を聞いて推測する時。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　電気を つけた（　）、へやを 出ました。",o:["あいだ","まま","うちに","たびに"],a:1,exp:"「〜まま」＝dejando (algo) tal cual。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 本を 読んだ（　）、感想を 教えて ください。",o:["たら","なら","ら","ても"],a:2,exp:"「〜たら」＝cuando termines de leerlo。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　忙しい（　）、電話にも 出られませんでした。",o:["ばかり","あまり","ほど","くらい"],a:1,exp:"「〜あまり」＝de tanto que。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　先生に 言われた（　）に、レポートを 書き直しました。",o:["かわり","せい","つもり","とおり"],a:3,exp:"「〜とおりに」＝tal como se dijo。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　日本語を 勉強すれば する（　）、面白く なる。",o:["ばかり","だけ","ほど","くらい"],a:2,exp:"「〜ば〜ほど」＝cuanto más...más。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 忙しい（　）、いつも 元気だ。",o:["もので","ばかりに","わりに","ことに"],a:2,exp:"「〜わりに」＝considerando que。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 店の ラーメンは 一度 食べた（　）忘れられません。",o:["ら","なら","ても","と"],a:0,exp:"「〜たら〜られない」＝si lo pruebas, no lo olvidas。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　子どもの時、よく 川で 泳いだ（　）です。",o:["もの","はず","こと","つもり"],a:0,exp:"「〜ものだ」懐かしさを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　雨が 降りそうなので、傘を 持って（　）方が いいです。",o:["いって","いき","いく","いった"],a:3,exp:"「V-た形+方がいい」＝sería mejor。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　体の ため、野菜を 食べる（　）して います。",o:["そうに","ように","はずに","ために"],a:1,exp:"「〜ようにしている」＝procuro hacer。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 映画は 感動的だ（　）評判です。",o:["の","を","と","が"],a:2,exp:"「〜と評判だ」＝tiene fama de。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　社長が 話して いる（　）、電話が 鳴りました。",o:["うちに","次第","最中に","あとで"],a:2,exp:"「〜最中に」＝justo en medio de。"},
      {sec:"問題2　文法2（文の組み立て）",q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 資料は　___　___　★　___　分かりにくい。（1 含む　2 難しい　3 ため　4 内容を）",o:["内容を","ため","難しい","含む"],a:1,exp:"正しい順序：2難しい→4内容を→1含む→3ため「難しい内容を含むため」。★の位置には3「ため」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は　___　★　___　___　最後まで頑張った。（1 経験が　2 わりに　3 少ない　4 にもかかわらず）",o:["にもかかわらず","少ない","経験が","わりに"],a:3,exp:"正しい順序：1経験が→3少ない→2わりに「経験が少ないわりに」。★の位置には2「わりに」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　先生に　___　___　★　___　レポートを 書き直した。（1 言われた　2 に　3 とおり　4 の）",o:["に","とおり","の","言われた"],a:1,exp:"正しい順序：1言われた→3とおり→2に「言われたとおりに」。★の位置には3「とおり」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 店の ラーメンは　___　___　★　___　忘れられません。（1 一度　2 たら　3 食べ　4 も）",o:["食べ","も","たら","一度"],a:2,exp:"正しい順序：1一度→3食べ→2たら「一度食べたら」。★の位置には2「たら」が入る。"},
      {sec:"問題3　文章の文法",passage:"最近、健康の ため 毎朝 走って います。最初は 大変（1）、今は 気持ちよく 走れる（2）なりました。走る（3）、朝の 空気を 感じられるのが 好きです。以前は 朝が 苦手（4）、走るように なってから、早起きが（5）なりました。これからも 続けたいです。",q:"（1）",o:["なのに","でしたし","なので","でしたが"],a:3,exp:"「〜でしたが」逆接。最初は大変だったが、という展開。"},
      {q:"（2）",o:["ように","そうに","みたいに","らしく"],a:0,exp:"「〜ようになる」変化を表す。"},
      {q:"（3）",o:["ところで","もので","わけで","ことで"],a:3,exp:"「〜ことで」＝mediante, gracias a。"},
      {q:"（4）",o:["でしたのに","でしたので","でしたから","でしたが"],a:3,exp:"逆接の「でしたが」。"},
      {q:"（5）",o:["得意に","苦手に","下手に","上手に"],a:0,exp:"文脈上「早起きが得意になった」が自然。"},
      {sec:"問題4　内容理解（短文）",passage:"先週、母から 小包が 届きました。中には 手作りの クッキーと 手紙が 入っていました。とても うれしくて、すぐに 電話を しました。",q:"この 人は 小包が 届いた あと、何を しましたか。",o:["手紙を 書いた","なにも しなかった","クッキーを 送った","すぐに 電話を した"],a:3,exp:"「とても うれしくて、すぐに 電話を しました」がそのまま答え。"},
      {passage:"最近、駅前に 新しい カフェが できました。値段は 少し 高いですが、コーヒーが おいしいので、よく 行きます。",q:"この 人が よく カフェに 行く 理由は 何ですか。",o:["駅から 遠いから","コーヒーが おいしいから","値段が 安いから","広いから"],a:1,exp:"「値段は 少し 高いですが、コーヒーが おいしいので」→ va porque el café es rico。"},
      {passage:"子どもの ころ、私は 泳ぐのが 苦手でした。しかし、毎日 練習した 結果、今では 泳ぐのが 得意に なりました。",q:"この 人は 今、泳ぐのが どうですか。",o:["苦手だ","こわい","得意だ","きらいだ"],a:2,exp:"「今では 泳ぐのが 得意に なりました」がそのまま答え。"},
      {sec:"問題5　内容理解（中文）",passage:"最近、忙しくて 料理を する 時間が ありません。そのため、よく コンビニの お弁当を 買って います。しかし、健康の ことを 考えると、栄養バランスが 気に なります。来月から、週末だけでも 自分で 料理を しようと 思っています。",q:"この 人は なぜ コンビニの お弁当を よく 買いますか。",o:["料理が きらいだから","お金が ないから","料理を する 時間が ないから","お弁当が すきだから"],a:2,exp:"「忙しくて 料理を する 時間が ありません」がそのまま答え。"},
      {q:"この 人が 気に なっている ことは 何ですか。",o:["量","値段","栄養バランス","味"],a:2,exp:"「健康の ことを 考えると、栄養バランスが 気に なります」がそのまま答え。"},
      {q:"来月から 何を する つもりですか。",o:["外食する","お弁当を やめる","毎日 自分で 料理する","週末だけ 自分で 料理する"],a:3,exp:"「来月から、週末だけでも 自分で 料理をしようと 思っています」がそのまま答え。"},
      {passage:"友人の 結婚式に 招待されました。何を 着て 行けば いいか、まだ 決めて いません。友人に 聞いたら、フォーマルな 服装であれば 何でも いいと 言われました。それでも、迷って しまいます。",q:"この 人は 今、何に 困っていますか。",o:["時間の こと","結婚式に 行けない こと","何を 着るか 決まって いない","プレゼントの こと"],a:2,exp:"「何を 着て 行けば いいか、まだ 決めて いません」がそのまま答え。"}
    ]},
    {id:"c", title:"聴解", minutes:35, questions:[
      {sec:"問題1　課題理解",audio:"男：すみません、この コピー機の 使い方が わかりません。　女：ここの ボタンを 押せば、すぐに コピーが できますよ。",q:"コピー機の 使い方は どうすれば いいですか。",o:["紙を 変える","係員を 呼ぶ","電源を 入れ直す","ボタンを 押す"],a:3,exp:"「ここの ボタンを 押せば…できますよ」がそのまま答え。"},
      {audio:"女：来週の 会議、場所が 変わりました。三階の 会議室から 五階に 変わったので、気を つけて ください。",q:"来週の 会議は どこで ありますか。",o:["一階","五階","地下","三階"],a:1,exp:"「五階に 変わった」がそのまま答え。"},
      {audio:"男：この 資料、何部 印刷すれば いいですか。　女：会議の 参加者は 十人なので、十部 お願いします。",q:"何部 印刷しますか。",o:["二十部","十部","五部","十五部"],a:1,exp:"「十部 お願いします」がそのまま答え。"},
      {audio:"女：すみません、電車が おくれて いて、少し 遅刻します。　男：わかりました。気を つけて 来て ください。",q:"この 人は なぜ 電話しましたか。",o:["電車が おくれて 遅刻するから","会議を 忘れたから","道が わからないから","病気に なったから"],a:0,exp:"「電車が おくれて いて、少し 遅刻します」がそのまま答え。"},
      {audio:"男：荷物を 送りたいのですが、いつ 届きますか。　女：今日 送ると、あさって 届きます。",q:"今日 荷物を 送ると、いつ 届きますか。",o:["明日","あさって","今日中","一週間後"],a:1,exp:"「あさって 届きます」がそのまま答え。"},
      {audio:"女：来週の 面接ですが、何を 準備すれば いいですか。　男：履歴書と 写真を 持って来て ください。",q:"面接に 何を 持って行きますか。",o:["履歴書と 写真","パソコン","印鑑だけ","何も 要らない"],a:0,exp:"「履歴書と 写真を 持って来て ください」がそのまま答え。"},
      {audio:"男：すみません、この 靴、履いて みても いいですか。　女：もちろんです。サイズは おいくつですか。",q:"お客さんは 何を したいと 言いましたか。",o:["靴を 買いたい","靴を 履いて みたい","靴を 返品したい","サイズを 知りたい"],a:1,exp:"「履いて みても いいですか」がそのまま答え。"},
      {audio:"女：来週の 出張ですが、飛行機と 新幹線、どちらが いいですか。　男：時間が ないので、飛行機に しましょう。",q:"出張には 何を 使いますか。",o:["バス","新幹線","車","飛行機"],a:3,exp:"「飛行機に しましょう」がそのまま答え。"},
      {sec:"問題2　ポイント理解",audio:"女：今回の キャンペーン、思ったより 反響が ありませんでしたね。　男：広告の タイミングが 悪かったのが 一番の原因だと思います。",q:"男の人は、反響が 少なかった 一番の 原因は 何だと 言っていますか。",o:["予算が 少なかったこと","広告の デザインが 悪かったこと","広告の タイミングが 悪かったこと","商品の 質が 悪かったこと"],a:2,exp:"「広告の タイミングが 悪かったのが 一番の原因」がそのまま答え。"},
      {audio:"男：この 製品、返品が 多いですね。　女：説明書が 分かりにくいのが 一番の 原因だと思います。",q:"女の人は、返品が 多い 一番の 原因は 何だと 言っていますか。",o:["価格が 高すぎること","説明書が 分かりにくいこと","配送が 遅いこと","製品自体の 欠陥"],a:1,exp:"「説明書が 分かりにくいのが 一番の原因」がそのまま答え。"},
      {audio:"女：この 工場、事故が 続いていますね。　男：一番の 問題は 安全確認の 手順が 形骸化していた ことだと思います。",q:"男の人は、事故が 続く 一番の 原因は 何だと 考えていますか。",o:["天候の 悪さ","作業員の 不注意","設備の 老朽化","安全確認の 手順が 形骸化していたこと"],a:3,exp:"「一番の問題は 安全確認の手順が形骸化していたこと」がそのまま答え。"},
      {audio:"男：今回の 新人研修、評判が 良くなかったですね。　女：日程が 詰め込みすぎだった ことが 一番の 問題だったと思います。",q:"女の人は、評判が 悪かった 一番の 原因は 何だと 言っていますか。",o:["講師が 不足していたこと","会場が 狭かったこと","内容が 悪かったこと","日程が 詰め込みすぎだったこと"],a:3,exp:"「日程が詰め込みすぎだったことが一番の問題」がそのまま答え。"},
      {audio:"女：この アプリ、ダウンロード数が 伸び悩んでいますね。　男：広告が 届いていないのが 一番の 原因だと思います。",q:"男の人は、ダウンロード数が 伸び悩む 一番の 原因は 何だと 考えていますか。",o:["広告が 届いていないこと","価格が 高いこと","デザインが 古いこと","機能が 悪いこと"],a:0,exp:"「広告が届いていないのが一番の原因」がそのまま答え。"},
      {audio:"男：この 店舗、離職率が 高いですね。　女：シフトの 融通が 利かないことが 一番の 原因だと 聞いています。",q:"女の人は、離職率が 高い 一番の 原因は 何だと 言っていますか。",o:["シフトの 融通が 利かないこと","人間関係が 悪いこと","仕事が きついこと","給料が 安いこと"],a:0,exp:"「シフトの融通が利かないことが一番の原因」がそのまま答え。"},
      {audio:"女：この レストラン、リピーターが 少ないですね。　男：接客の 質に 問題が あると 思います。",q:"男の人は、リピーターが 少ない 原因は 何だと 考えていますか。",o:["接客の 質","値段","立地","味"],a:0,exp:"「接客の質に問題があると思います」がそのまま答え。"},
      {sec:"問題3　発話表現",audio:"（え：先輩が 重い 荷物を 持って いる）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["いただきます。","おやすみなさい。","おめでとうございます。","お持ちします。"],a:3,exp:"手伝いを申し出る時は「お持ちします」。"},
      {audio:"（え：会議室に 入る 前）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["おかえりなさい。","失礼します。","ただいま。","おやすみなさい。"],a:1,exp:"部屋に入る時は「失礼します」。"},
      {audio:"（え：先生に 質問が ある）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["ごめんなさい。","ありがとうございます。","すみません、質問が あるのですが。","おめでとうございます。"],a:2,exp:"質問がある時は「すみません、質問があるのですが」。"},
      {audio:"（え：上司に 資料を 見て もらいたい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["資料は いりません。","こちらの 資料を 見て いただけますか。","こちらの 資料を 見ないで ください。","資料を 捨てて ください。"],a:1,exp:"丁寧な依頼は「〜ていただけますか」。"},
      {audio:"（え：電車で お年寄りに 席を 譲る）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["ありがとう。","おじゃまします。","すみません。","どうぞ、お座りください。"],a:3,exp:"席を譲る時は「どうぞ、お座りください」。"},
      {sec:"問題4　即時応答",audio:"すみません、この 資料、コピーして いただけますか。",q:"最もよい 返事は どれですか。",o:["はい、げんきです。","ありがとう。","いいえ、三時です。","はい、かしこまりました。"],a:3,exp:"依頼への丁寧な返事は「はい、かしこまりました」。"},
      {audio:"すみません、遅くなりました。",q:"最もよい 返事は どれですか。",o:["それは残念ですね。","おめでとうございます。","もう終わりました。","大丈夫ですよ、気にしないでください。"],a:3,exp:"遅刻の謝罪への自然な返事。"},
      {audio:"この 仕事、手伝って もらえませんか。",q:"最もよい 返事は どれですか。",o:["ありがとう。","はい、いいですよ。","はい、げんきです。","いいえ、三時です。"],a:1,exp:"依頼への承諾は「はい、いいですよ」。"},
      {audio:"日本語の 勉強、順調ですか。",q:"最もよい 返事は どれですか。",o:["いいえ、三人です。","はい、あそこです。","ありがとうございます。","はい、少しずつ 上手に なっています。"],a:3,exp:"進捗を聞かれたら状況を答える。"},
      {audio:"お先に 失礼します。",q:"最もよい 返事は どれですか。",o:["お疲れ様でした。","おかえりなさい。","おやすみなさい。","ただいま。"],a:0,exp:"先に帰る人には「お疲れ様でした」。"},
      {audio:"この 書類、明日までに お願いできますか。",q:"最もよい 返事は どれですか。",o:["それは残念ですね。","もう終わりました。","おめでとうございます。","はい、承知しました。"],a:3,exp:"依頼への承諾は「はい、承知しました」。"},
      {audio:"体調は いかがですか。",q:"最もよい 返事は どれですか。",o:["いいえ、三人です。","はい、あそこです。","ありがとうございます。","おかげさまで、大分 良くなりました。"],a:3,exp:"体調を聞かれたら状態を答える。"},
      {audio:"この 提案について、ご意見を 伺えますか。",q:"最もよい 返事は どれですか。",o:["おめでとうございます。","もう終わりました。","それは大変ですね。","はい、思ったことを お伝えします。"],a:3,exp:"意見を求められた際の自然な返事。"}
    ]}
  ]
},
{
  id:"o-n4-2", lvl:"N4", title:"Examen oficial N4 · 2", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙）", minutes:25, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 問題は 簡単です。",o:["けんたん","かんとん","かんだん","かんたん"],a:3,exp:"簡単→かんたん「sencillo」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　期日までに 出して ください。",o:["きひ","きじつ","きび","きにち"],a:1,exp:"期日→きじつ「fecha límite」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 道は 危険です。",o:["きげん","きせい","きけん","きかい"],a:2,exp:"危険→きけん「peligroso」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼の 主張は 一貫している。",o:["いつかん","いっかんせい","いちかん","いっかん"],a:3,exp:"一貫→いっかん「coherencia」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　柔軟な 対応が 必要だ。",o:["じゅうなん","じゅうやわ","にゅうなん","にゅうねん"],a:0,exp:"柔軟→じゅうなん「flexible」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 荷物は 軽いです。",o:["あつい","おもい","うすい","かるい"],a:3,exp:"軽い→かるい「ligero」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　予定を 確認します。",o:["よそう","よてい","よじょう","よやく"],a:1,exp:"予定→よてい「plan」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　清潔な 部屋が 好きです。",o:["せいけつ","きよけつ","しょうけつ","せいけい"],a:0,exp:"清潔→せいけつ「limpio」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　効率を 上げたい。",o:["こうりつ","こうりょ","こうそつ","こうりゅう"],a:0,exp:"効率→こうりつ「eficiencia」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは どう かきますか。1・2・3・4から いちばん いい ものを 一つ えらんで ください。　こうかんして ください。",o:["交換","好感","公館","交感"],a:0,exp:"こうかん→交換「intercambio」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　じゅうなんに たいおうします。",o:["従軟","柔難","柔軟","重軟"],a:2,exp:"じゅうなん→柔軟「flexible」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　こうりつよく はたらきます。",o:["公立","効律","効率","高率"],a:2,exp:"こうりつ→効率「eficiencia」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　はんだんが むずかしい。",o:["判断","半段","反段","判談"],a:0,exp:"はんだん→判断「juicio」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　けんとうします。",o:["検討","検答","見当","健闘"],a:0,exp:"けんとう→検討「estudio, consideración」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　ふきゅうして います。",o:["不急","不休","不朽","普及"],a:3,exp:"ふきゅう→普及「difusión」。"},
      {sec:"問題3　文脈規定",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　台風の 影響で、電車が （　）。",o:["早くなりました","増えました","止まりました","動きました"],a:2,exp:"台風の影響で電車が「止まりました」（se detuvo）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　準備が （　）ので、少し 待って ください。",o:["終わった","簡単","早い","終わっていない"],a:3,exp:"「終わっていないので」＝aún no ha terminado。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は 経験が （　）にもかかわらず、よく できた。",o:["強い","多い","少ない","高い"],a:2,exp:"「経験が少ないにもかかわらず」＝a pesar de tener poca experiencia。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　資料が （　）ば、会議は 始められません。",o:["あって","あれ","なく","なけれ"],a:3,exp:"「なければ」＝si no hay (仮定形)。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は （　）性格で、みんなに 好かれている。",o:["冷たい","厳しい","暗い","明るい"],a:3,exp:"「明るい性格」＝carácter alegre。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 服は サイズが （　）ので、返品します。",o:["大きい","合わない","小さい","合う"],a:1,exp:"「合わないので」＝porque no le queda bien。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この プロジェクトは 予算が （　）状況だ。",o:["簡単な","自由な","厳しい","楽な"],a:2,exp:"「予算が厳しい状況」＝situación de presupuesto ajustado。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 仕事の （　）で、大学院にも 通っている。",o:["ほかに","うちに","かたわら","あいだに"],a:2,exp:"「〜かたわら」＝mientras hace otra cosa en paralelo。"},
      {sec:"問題4　言い換え類義",q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は 率直に 意見を 言った。",o:["はっきりと、正直に","冷たく","感情的に","遠回しに"],a:0,exp:"「率直に」≒「はっきりと、正直に」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼女は 冷静に 対応した。",o:["落ち着いて","急いで","乱暴に","感情的に"],a:0,exp:"「冷静に」≒「落ち着いて」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は 意外にも 早く 到着した。",o:["わざと","予想通り","思ったより","当然"],a:2,exp:"「意外にも」≒「思ったより」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼女は 慎重に 判断した。",o:["感情的に","注意深く","急いで","適当に"],a:1,exp:"「慎重に」≒「注意深く」。"},
      {sec:"問題5　用法",q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「思わず」",o:["思わず早く終わった。","驚いて、思わず声を上げてしまった。","思わず明日雨が降る。","思わず三時に会議がある。"],a:1,exp:"「思わず」＝sin querer, involuntariamente、反射的な行動に使う。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「あらかじめ」",o:["あらかじめ早く終わった。","あらかじめ明日会議がある。","あらかじめ予約しておいたので、待たずに入れた。","あらかじめ三時に来た。"],a:2,exp:"「あらかじめ」＝de antemano、事前の準備を表す。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「いよいよ」",o:["いよいよ早く終わった。","いよいよ元気だ。","いよいよ明日が試験本番だ。","いよいよ三時に来た。"],a:2,exp:"「いよいよ」＝por fin, finalmente、待ち望んだ事態の到来を表す。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「わざわざ」",o:["わざわざ早く終わった。","わざわざ三時に会議がある。","わざわざ明日雨が降る。","わざわざ遠くから来ていただき、ありがとうございます。"],a:3,exp:"「わざわざ」＝tomarse la molestia de、感謝の文脈で使う。"}
    ]},
    {id:"b", title:"言語知識（文法）・読解", minutes:55, questions:[
      {sec:"問題1　文法1",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 部屋は 静か（　）勉強しやすいです。",o:["と","が","に","で"],a:3,exp:"「な形容詞+で」連用中止形。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　知らない 人に 道を 聞かれた（　）、うまく 説明できませんでした。",o:["のに","たら","ので","が"],a:3,exp:"「〜が」（逆接、pero）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　雨が やんだら 出かける（　）です。",o:["はず","つもり","こと","もの"],a:1,exp:"「〜つもりだ」＝tengo intención de。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　だれ（　）教えて もらった 方法で、成功しました。",o:["かに","でも","にも","とも"],a:0,exp:"「だれかに」＝alguien（indefinido）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 忙しい（　）、いつも 元気だ。",o:["ことに","ばかりに","わりに","もので"],a:2,exp:"「〜わりに」＝considerando que。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 会社は 週に 一日、社員が 自由な テーマで 研究できる 制度が（　）。",o:["あります","でした","います","します"],a:0,exp:"制度は「あります」（存在）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　多忙な 毎日を （　）います。",o:["くれて","送って","もらって","あげて"],a:1,exp:"「日々を送る」＝llevar (una vida, unos días)。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は 若い（　）、しっかりした 考えを 持っている。",o:["からして","ながらも","として","につれて"],a:1,exp:"「〜ながらも」＝aunque, si bien。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 資料は 難しい 内容を 含む（　）、専門家 以外には 分かりにくい。",o:["おかげで","ため","かのように","ものなら"],a:1,exp:"「〜ため」＝por, debido a。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　締め切り（　）、無理な 依頼を するのは 避けたい。",o:["を理由に","をきっかけに","にかけて","にわたって"],a:0,exp:"「〜を理由に」＝con la excusa de。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　社員の 意見を 聞いた（　）で、決定する べきだ。",o:["上に","上","上は","上で"],a:3,exp:"「〜上で」＝tras hacer algo。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　連絡（　）、勝手に 予定を 変更しないで ください。",o:["抜きで","もなく","なしに","なくて"],a:2,exp:"「〜なしに」＝sin previo aviso。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 若い（　）、リーダーとしての 資質を 備えている。",o:["はおろか","ながらも","にひきかえ","にもまして"],a:1,exp:"「〜ながらも」＝aunque sea joven。"},
      {sec:"問題2　文法2（文の組み立て）",q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　知らない　___　___　★　___　説明できませんでした。（1 うまく　2 聞かれた　3 人に　4 道を）",o:["道を","聞かれた","うまく","人に"],a:1,exp:"正しい順序：3人に→4道を→2聞かれた→1うまく「人に道を聞かれたうまく」の並びを整理すると「知らない人に道を聞かれたが、うまく説明できませんでした」。★の位置には2「聞かれた」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は　___　★　___　___　しっかりした 考えを 持っている。（1 ながらも　2 若い　3 も　4 まだ）",o:["も","若い","ながらも","まだ"],a:2,exp:"正しい順序：4まだ→2若い→1ながらも「まだ若いながらも」。★の位置には1「ながらも」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 資料は　___　___　★　___　専門家以外には 分かりにくい。（1 内容を　2 難しい　3 含む　4 ため）",o:["内容を","ため","難しい","含む"],a:3,exp:"正しい順序：2難しい→1内容を→3含む→4ため「難しい内容を含むため」。★の位置には3「含む」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　社員の　___　___　★　___　制度を 見直した。（1 反映する　2 声を　3 べく　4 現場の）",o:["べく","現場の","声を","反映する"],a:0,exp:"正しい順序：4現場の→2声を→1反映する→3べく「現場の声を反映するべく」。★の位置には3「べく」が入る。"},
      {sec:"問題3　文章の文法",passage:"最近、副業を（1）企業が 増えている。従業員の スキルアップに つながる（2）、本業への 影響を 懸念する 声も 根強い。人事担当者たちは、両者の バランスを（3）取るか、模索を 続けている。（4）、労働時間の 管理を 徹底する ことが、副業解禁の（5）条件と なるだろう。",q:"（1）",o:["認めた","認める","認めて","認められる"],a:1,exp:"「〜企業」を修飾する動詞は辞書形「認める」。"},
      {q:"（2）",o:["一方は","一方に","一方","一方で"],a:2,exp:"「〜一方」＝por un lado, mientras que por otro。"},
      {q:"（3）",o:["どれ","どう","どんな","どこ"],a:1,exp:"「どう取るか」＝cómo tomar/lograr。"},
      {q:"（4）",o:["つまり","または","それとも","いずれにせよ"],a:3,exp:"「いずれにせよ」＝en cualquier caso。"},
      {q:"（5）",o:["原因","結果","目的","前提"],a:3,exp:"「前提条件」＝condición previa。"},
      {sec:"問題4　内容理解（短文）",passage:"新しい 携帯電話を 買いましたが、前の ものより 使い方が 複雑で、まだ 慣れて いません。",q:"新しい 携帯電話に ついて 正しい ものは どれですか。",o:["こわれて しまった","使い方に まだ 慣れて いない","前の ものより 簡単だ","もう 使い方に 慣れた"],a:1,exp:"「まだ 慣れて いません」がそのまま答え。"},
      {passage:"来月から 新しい プロジェクトが 始まります。準備することが 多く、みんな 忙しく なりそうです。",q:"来月から どう なりそうですか。",o:["プロジェクトが 終わる","休みが 増える","みんな 忙しく なる","人が 減る"],a:2,exp:"「みんな 忙しく なりそうです」がそのまま答え。"},
      {passage:"引っ越して から、近所の 人と あまり 話す 機会が ありません。少し さびしく 感じて います。",q:"この 人は 今、どう 感じて いますか。",o:["さびしいと 感じている","うれしいと 感じている","忙しいと 感じている","安心していると 感じている"],a:0,exp:"「少し さびしく 感じて います」がそのまま答え。"},
      {sec:"問題5　内容理解（中文）",passage:"最近、朝早く 起きるように なりました。おかげで、朝ごはんを ゆっくり 食べられるように なりました。前は 時間に 追われて 何も 食べずに 家を 出ることも 多かったですが、今は 違います。健康にも 良い 気が します。",q:"朝早く 起きるように なって、何が 変わりましたか。",o:["元気が なく なった","朝ごはんを ゆっくり 食べられる","夜 眠れなく なった","仕事が 増えた"],a:1,exp:"「朝ごはんを ゆっくり 食べられるように なりました」がそのまま答え。"},
      {q:"以前は どうでしたか。",o:["早く 起きていた","何も 食べずに 家を 出ることが 多かった","健康的だった","毎朝 ゆっくり 食べていた"],a:1,exp:"「前は 時間に 追われて 何も 食べずに 家を 出ることも 多かった」がそのまま答え。"},
      {q:"この 人は 今の 生活を どう 感じていますか。",o:["つまらないと 感じている","健康に 良いと 感じている","忙しすぎると 感じている","不便だと 感じている"],a:1,exp:"「健康にも 良い 気が します」がそのまま答え。"},
      {passage:"この アプリを 使うと、外国語の 単語を かんたんに 覚えられます。私も 毎日 使って います。ゲームの ような 感覚で 勉強できるので、続けやすいです。友人にも すすめて います。",q:"この アプリの 特長は 何ですか。",o:["単語を かんたんに 覚えられる","無料で 使える","文法が 学べる","会話の 練習ができる"],a:0,exp:"「単語を かんたんに 覚えられます」がそのまま答え。"}
    ]},
    {id:"c", title:"聴解", minutes:35, questions:[
      {sec:"問題1　課題理解",audio:"男：新しい プロジェクトの 進め方に ついて 相談したいのですが。　女：まずは 関係部署に 意見を 聞いてから、来週の 会議で 方向性を 決めましょう。",q:"来週の 会議で 何を 決めますか。",o:["予算の金額","会議の日程","関係部署の担当者","プロジェクトの方向性"],a:3,exp:"「来週の 会議で 方向性を 決めましょう」がそのまま答え。"},
      {audio:"女：では、これから 面接を 始めます。まず 自己紹介を お願いします。その後、志望動機に ついて 伺い、最後に 質疑応答の 時間を 設けます。",q:"面接の 最後に 何を しますか。",o:["結果の発表","志望動機の説明","自己紹介","質疑応答"],a:3,exp:"「最後に 質疑応答の 時間を 設けます」がそのまま答え。"},
      {audio:"男：来週の 旅行、何を 持って行けば いいですか。　女：カメラと 予備の バッテリーを 忘れずに。",q:"旅行に 何を 持って行きますか。",o:["カメラと 予備の バッテリー","地図と パスポート","本と ノート","かさと 帽子"],a:0,exp:"「カメラと 予備の バッテリーを 忘れずに」がそのまま答え。"},
      {audio:"女：来月の 展示会の 準備、順調ですか。　男：はい、ほぼ 予定通りですが、パンフレットの 印刷だけ 少し 遅れています。",q:"何が 遅れて いますか。",o:["スタッフの 手配","パンフレットの 印刷","会場の 準備","商品の 到着"],a:1,exp:"「パンフレットの 印刷だけ 少し 遅れています」がそのまま答え。"},
      {audio:"男：来週の 出張の 件ですが、予定していた 新幹線が 満席だったので、一本 早い 便に 変更しました。",q:"何が 変更に なりましたか。",o:["参加者","出張先","出張の目的","新幹線の便"],a:3,exp:"「一本 早い 便に 変更しました」がそのまま答え。"},
      {audio:"女：すみません、この 商品、色違いは ありますか。　男：申し訳ございません、現在は この 色のみと なって おります。",q:"この 商品には 何色が ありますか。",o:["三色以上","一色のみ","二色","色は選べない"],a:1,exp:"「現在は この 色のみ」＝solo hay un color。"},
      {audio:"男：来月から 新しい 支店が オープンします。それに 伴い、数名の 異動が あります。",q:"来月 何が ありますか。",o:["給料の変更","閉店","新支店の オープンと 異動","社長の交代"],a:2,exp:"「新しい 支店が オープン…数名の 異動が あります」がそのまま答え。"},
      {audio:"女：明日の 出張、時間が ないので、飛行機に しましょう。あと、ホテルの 予約も お願いできますか。",q:"何を お願いされましたか。",o:["出張の 中止","飛行機の 予約","ホテルの 予約","日程の 変更"],a:2,exp:"「ホテルの予約もお願いできますか」がそのまま答え。"},
      {sec:"問題2　ポイント理解",audio:"男：この 新商品、売り上げが 伸びませんね。　女：価格設定は 問題ないと 思うんですが、広告の 打ち方が 弱かったんじゃないかと。",q:"女の人は、売り上げが 伸びない 一番の 原因は 何だと 考えていますか。",o:["価格が 高すぎること","商品の 品質が 悪いこと","広告の 打ち方が 弱かったこと","競合が 多いこと"],a:2,exp:"「広告の 打ち方が 弱かったんじゃないか」が原因として挙げられている。"},
      {audio:"女：来期の 予算案、営業部からの 要望が 通らなかったようですね。　男：全社的に コスト削減の 方針が 出ていて、一律で 減らされることに なったみたいです。",q:"営業部の 要望が 通らなかった 一番の 理由は 何ですか。",o:["全社的な コスト削減方針が あったから","予算案の書き方が悪かったから","他部署の予算が優先されたから","営業部の実績が悪かったから"],a:0,exp:"「全社的にコスト削減の方針が出ていて」がそのまま理由。"},
      {audio:"男：この 機械、最近 よく 故障しますね。　女：使用年数も ありますが、湿度の 高い 環境で 使い続けたことが 大きいと思います。",q:"女の人は、機械が 故障する 一番の 原因は 何だと 考えていますか。",o:["湿度の 高い 環境で 使い続けたこと","操作方法が 間違っていたこと","使用年数が 長いこと","部品の 品質が 悪いこと"],a:0,exp:"「湿度の 高い 環境で 使い続けたことが 大きい」が原因として挙げられている。"},
      {audio:"女：この 店、最近 お客さんが 減っていますね。　男：近くに 大型スーパーが できたことが 一番 大きいと思います。",q:"男の人は、客が 減った 一番の 原因は 何だと 考えていますか。",o:["営業時間が短くなったこと","近くに 大型スーパーが できたこと","スタッフが減ったこと","商品の質が落ちたこと"],a:1,exp:"「近くに 大型スーパーが できたことが 一番大きい」がそのまま答え。"},
      {audio:"男：新しい システム、導入後も トラブルが 多いですね。　女：社員への 研修が 不十分だったことが 一番の 原因だと思います。",q:"女の人は、トラブルの 一番の 原因は 何だと 考えていますか。",o:["導入の時期が悪かったこと","予算不足","システム自体の欠陥","社員への 研修が 不十分だったこと"],a:3,exp:"「社員への 研修が 不十分だったことが 一番の原因」がそのまま答え。"},
      {audio:"女：この アンケート、回答率が 低かったですね。　男：質問数が 多すぎたのが 一番の 原因じゃないかと 思います。",q:"男の人は、回答率が 低かった 一番の 原因は 何だと 言っていますか。",o:["対象者が少なかったこと","質問内容が難しかったこと","締め切りが早すぎたこと","質問数が 多すぎたこと"],a:3,exp:"「質問数が多すぎたのが一番の原因」がそのまま答え。"},
      {audio:"男：この 地域、若い 世代の 人口流出が 続いていますね。　女：進学の ために 都市部に 出た 若者が そのまま 戻ってこないことが 一番 大きいと思います。",q:"女の人は、人口流出の 一番大きい 原因は 何だと 考えていますか。",o:["進学で 都市部に 出た 若者が 戻らないこと","家賃が高いこと","交通の便が悪いこと","働き口が少ないこと"],a:0,exp:"「進学のために都市部に出た若者がそのまま戻ってこないこと」がそのまま答え。"},
      {sec:"問題3　発話表現",audio:"（え：友人が 引っ越しする）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["おやすみなさい。","いただきます。","何か 手伝えることが あれば 言ってください。","おめでとうございます。"],a:2,exp:"引っ越しする友人には手伝いを申し出るのが自然。"},
      {audio:"（え：レストランで 会計を したい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["おじゃまします。","ごちそうさまでした。","すみません、お会計を お願いします。","いただきます。"],a:2,exp:"会計を頼む時の表現。"},
      {audio:"（え：会議で 反対意見を 言いたい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["少し 違う 意見なのですが。","それは嬉しいです。","もう終わりです。","おめでとうございます。"],a:0,exp:"控えめに反対意見を述べる表現。"},
      {audio:"（え：荷物を 落とした 人を 見かけた）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["すみません、荷物が 落ちましたよ。","おやすみなさい。","おめでとうございます。","いただきます。"],a:0,exp:"忘れ物を伝える時の表現。"},
      {audio:"（え：会議の 開始時間に 遅れそう）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["おめでとうございます。","少し 遅れそうです。申し訳ありません。","それは嬉しいです。","もう終わりです。"],a:1,exp:"遅刻の連絡をする時の表現。"},
      {sec:"問題4　即時応答",audio:"この 資料、目を通して いただけましたか。",q:"最もよい 返事は どれですか。",o:["ありがとう。","はい、げんきです。","はい、拝見しました。","いいえ、三時です。"],a:2,exp:"確認を求められたら「はい、拝見しました」。"},
      {audio:"来週、お時間 いただけますか。",q:"最もよい 返事は どれですか。",o:["もう終わりました。","それは残念ですね。","おめでとうございます。","はい、大丈夫です。"],a:3,exp:"時間の依頼への自然な返事。"},
      {audio:"体調を 崩されたと 伺いましたが。",q:"最もよい 返事は どれですか。",o:["ご心配 おかけしました、もう大丈夫です。","おめでとうございます。","それは嬉しいです。","もう終わりです。"],a:0,exp:"体調を気遣われた際の自然な返事。"},
      {audio:"この件、担当を 代わって いただけますか。",q:"最もよい 返事は どれですか。",o:["はい、承知しました。","ありがとう。","はい、げんきです。","いいえ、三時です。"],a:0,exp:"依頼への承諾は「はい、承知しました」。"},
      {audio:"先ほどの 説明、分かりにくかったでしょうか。",q:"最もよい 返事は どれですか。",o:["もう終わりました。","おめでとうございます。","いえ、よく分かりました。","それは大変ですね。"],a:2,exp:"確認された際の自然な返事。"},
      {audio:"何か お困りのことは ありますか。",q:"最もよい 返事は どれですか。",o:["もう終わりです。","それは残念ですね。","おめでとうございます。","実は、少し 分からないことが あります。"],a:3,exp:"気遣いへの自然な返事。"},
      {audio:"この 案、いかがでしょうか。",q:"最もよい 返事は どれですか。",o:["もう決まりました。","良いと思いますが、少し気になる点があります。","おめでとうございます。","それは嬉しいです。"],a:1,exp:"意見を求められた際の自然な返事。"},
      {audio:"ご迷惑を おかけして 申し訳ありません。",q:"最もよい 返事は どれですか。",o:["もっとやってください。","いえ、気にしないでください。","それは嬉しいです。","おめでとうございます。"],a:1,exp:"謝罪への自然な返事。"}
    ]}
  ]
},
{
  id:"o-n4-3", lvl:"N4", title:"Examen oficial N4 · 3", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙）", minutes:25, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　心配しないで ください。",o:["しんぼう","しんはい","しんかい","しんぱい"],a:3,exp:"心配→しんぱい「preocupación」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　両方 試して みます。",o:["りょうめん","りょうほう","りょうかた","りょうがわ"],a:1,exp:"両方→りょうほう「ambos」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　規則を 守って ください。",o:["きりつ","ぎそく","きそく","きやく"],a:2,exp:"規則→きそく「norma」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　態度を 改める。",o:["たいたい","たいと","たいど","たいたく"],a:2,exp:"態度→たいど「actitud」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　環境を 守りたい。",o:["かんけい","かんしん","かんきょう","かんそう"],a:2,exp:"環境→かんきょう「entorno」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　人気が ある 商品です。",o:["にんき","じんき","ひとけ","じんけ"],a:0,exp:"人気→にんき「popularidad」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　複雑な 問題だ。",o:["ぶくざつ","ふくさつ","ふくざつ","ふくそう"],a:2,exp:"複雑→ふくざつ「complejo」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　解決方法を 考える。",o:["かいぎ","かいせつ","かいけつ","かいけい"],a:2,exp:"解決→かいけつ「resolución」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　原因を 調べます。",o:["げんにん","がんいん","げいいん","げんいん"],a:3,exp:"原因→げんいん「causa」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは どう かきますか。1・2・3・4から いちばん いい ものを 一つ えらんで ください。　しゅっぱつします。",o:["出発","出来","出席","出発点"],a:0,exp:"しゅっぱつ→出発「salida」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　きそくを まもります。",o:["規側","期則","規則","気則"],a:2,exp:"きそく→規則「regla」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　かんきょうを まもります。",o:["感況","環況","感境","環境"],a:3,exp:"かんきょう→環境「entorno」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　げんいんを しらべます。",o:["現因","原因","原員","元因"],a:1,exp:"げんいん→原因「causa」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　たいどが わるい。",o:["対度","体度","態度","待度"],a:2,exp:"たいど→態度「actitud」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　かいけつしました。",o:["開結","解結","開決","解決"],a:3,exp:"かいけつ→解決「resolución」。"},
      {sec:"問題3　文脈規定",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　台風が 近づいて いるので、（　）してください。",o:["納得","安心","注意","満足"],a:2,exp:"台風には「注意」（precaución）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 問題は （　）が 難しい。",o:["解決","反対","理解","賛成"],a:0,exp:"「解決が難しい」＝difícil de resolver。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 会議に （　）遅れて 来た。",o:["なんこ","少し","たくさん","いくつ"],a:1,exp:"時間の程度は「少し」（un poco）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　新しい 規則が （　）ました。",o:["決め","決める","決まり","決まる"],a:2,exp:"規則が「決まりました」（quedó decidido）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 機械は 操作が （　）です。",o:["簡単で","簡単な","簡単","簡単に"],a:2,exp:"な形容詞語幹＋です。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼の 説明は （　）分かりやすかった。",o:["少しも","全然","一向に","非常に"],a:3,exp:"「非常に」＋肯定＝muy。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 資料には （　）が 多い。",o:["成功","失敗","間違い","正解"],a:2,exp:"「間違いが多い」＝tiene muchos errores。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は 会議で 積極的に （　）した。",o:["発言","発表","発達","発見"],a:0,exp:"「発言する」＝tomar la palabra en una reunión。"},
      {sec:"問題4　言い換え類義",q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は 熱心に 勉強している。",o:["適当に","嫌々","たまに","一生懸命に"],a:3,exp:"「熱心に」≒「一生懸命に」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼女は 突然 泣き出した。",o:["予定通り","ゆっくりと","わざと","急に"],a:3,exp:"「突然」≒「急に」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　この 部屋は 十分 広い。",o:["あまり","じゅうぶんに","少し","ぜんぜん"],a:1,exp:"「十分」≒「じゅうぶんに」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は しばしば 遅刻する。",o:["一度も","よく","絶対に","たまに"],a:1,exp:"「しばしば」≒「よく」（con frecuencia）。"},
      {sec:"問題5　用法",q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「たしか」",o:["たしか、彼は今週出張していたはずだ。","たしか明日雨が降る。","たしか三時に会議がある。","たしか早く終わった。"],a:0,exp:"「たしか」＝si mal no recuerdo、記憶に基づく推測を表す。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「とっくに」",o:["とっくに元気だ。","会議はとっくに終わっていた。","とっくに明日会議がある。","とっくに三時に来た。"],a:1,exp:"「とっくに」＝ya hace tiempo、完了した動作の早さを強調。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「せいぜい」",o:["せいぜい早く終わった。","せいぜい三時に会議がある。","せいぜい明日雨が降る。","この仕事はせいぜい二時間で終わるだろう。"],a:3,exp:"「せいぜい」＝como mucho、上限の見積もりを表す。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「まさか」",o:["まさか彼が優勝するとは思わなかった。","まさか三時に来た。","まさか早く終わった。","まさか明日晴れるだろう。"],a:0,exp:"「まさか〜とは」＝no puedo creer que、意外性を強調。"}
    ]},
    {id:"b", title:"言語知識（文法）・読解", minutes:55, questions:[
      {sec:"問題1　文法1",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　日本語が 話せる（　）に なりました。",o:["よう","もの","こと","ところ"],a:0,exp:"「V-可能形+ようになる」＝llegar a poder。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　雨が ふって いる（　）、しあいは 中止です。",o:["ので","でも","まで","のに"],a:0,exp:"「ので」＝porque（causa objetiva）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 忙しい（　）、電話にも 出られなかった。",o:["ばかり","くらい","ほど","あまり"],a:3,exp:"「〜あまり」＝de tanto que。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　先生に 言われた（　）に、直しました。",o:["とおり","せい","かわり","つもり"],a:0,exp:"「〜とおりに」＝tal como se dijo。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　勉強すれば する（　）、面白く なる。",o:["ほど","くらい","ばかり","だけ"],a:0,exp:"「〜ば〜ほど」＝cuanto más...más。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 疲れて いる（　）、元気そうだ。",o:["ことに","もので","ばかりに","わりに"],a:3,exp:"「〜わりに」＝considerando que。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 曲は 一度 聞いた（　）忘れられません。",o:["ら","と","ても","なら"],a:0,exp:"「〜たら〜られない」＝si lo escuchas, no lo olvidas。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　子どもの時、よく ここで 遊んだ（　）です。",o:["はず","こと","もの","つもり"],a:2,exp:"「〜ものだ」懐かしさを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　雨が 降りそうなので、傘を 持って（　）方が いいです。",o:["いった","いき","いく","いって"],a:0,exp:"「V-た形+方がいい」＝sería mejor。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　健康の ため、野菜を 食べる（　）して います。",o:["ように","そうに","はずに","ために"],a:0,exp:"「〜ようにしている」＝procuro hacer。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 映画は 感動的だ（　）評判です。",o:["の","を","が","と"],a:3,exp:"「〜と評判だ」＝tiene fama de。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　部長が 話している（　）、電話が 鳴りました。",o:["あとで","次第","うちに","最中に"],a:3,exp:"「〜最中に」＝justo en medio de。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　経験が ない（　）、彼は とても 上手に できました。",o:["わりに","せいで","ように","ため"],a:0,exp:"「〜わりに」＝considerando que。"},
      {sec:"問題2　文法2（文の組み立て）",q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 曲は　___　___　★　___　忘れられません。（1 聞い　2 たら　3 一度　4 も）",o:["聞い","も","一度","たら"],a:0,exp:"正しい順序：3一度→1聞い→2たら「一度聞いたら」。★の位置には1「聞い」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は　___　★　___　___　元気そうだ。（1 わりに　2 疲れて　3 も　4 いる）",o:["いる","疲れて","わりに","も"],a:2,exp:"正しい順序：2疲れて→4いる→1わりに「疲れているわりに」。★の位置には1「わりに」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　先生に　___　___　★　___　直しました。（1 とおり　2 言われた　3 に　4 も）",o:["言われた","とおり","も","に"],a:3,exp:"正しい順序：2言われた→1とおり→3に「言われたとおりに」。★の位置には3「に」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　健康の　___　___　★　___　しています。（1 ように　2 ため　3 野菜を　4 食べる）",o:["野菜を","食べる","ため","ように"],a:3,exp:"正しい順序：2ため→3野菜を→4食べる→1ように「ため野菜を食べるように」。★の位置には1「ように」が入る。"},
      {sec:"問題3　文章の文法",passage:"私は 引っ越して から、近所の 人と 話す 機会が 減りました。前の 家では よく 隣の 人と（1）を していましたが、今は（2）。少し さびしい 気が します。しかし、先週 マンションの 掃除の 日に（3）人と 少し 話す ことが できました。これから、（4）交流を 増やして いきたいと 思います。近所付き合いは 大切だ（5）思うからです。",q:"（1）",o:["世間話が","世間話","世間話は","世間話を"],a:1,exp:"「世間話をしていました」の目的語。ここは名詞「世間話」がそのまま入る形。"},
      {q:"（2）",o:["そうしています","そうでした","そうでもありません","そうです"],a:2,exp:"「そうでもありません」＝no es tan así（否定的な現状）。"},
      {q:"（3）",o:["近所の","近所を","近所は","近所が"],a:0,exp:"「近所の人」連体修飾の「の」。"},
      {q:"（4）",o:["一気に","全く","少しずつ","二度と"],a:2,exp:"「少しずつ」＝poco a poco、自然な変化を表す。"},
      {q:"（5）",o:["が","の","と","を"],a:2,exp:"「〜と思う」引用の「と」。"},
      {sec:"問題4　内容理解（短文）",passage:"最近、健康の ために 毎朝 走って います。最初は 大変でしたが、今は 気持ちよく 走れるように なりました。",q:"この 人は 今、走ることに ついて どう 感じて いますか。",o:["もう やめたいと 感じている","大変だと 感じている","つまらないと 感じている","気持ちよく 感じている"],a:3,exp:"「今は 気持ちよく 走れるように なりました」がそのまま答え。"},
      {passage:"アパートの 隣に 新しい 家族が 引っ越して来ました。まだ 挨拶を して いないので、今度 会ったら 挨拶しようと 思います。",q:"この 人は これから 何を する つもりですか。",o:["引っ越しを 手伝う","家族を 招待する","何も しない","隣の 家族に 挨拶する"],a:3,exp:"「今度 会ったら 挨拶しようと 思います」がそのまま答え。"},
      {passage:"最近、電子書籍を 読む 人が 増えています。紙の 本と 違い、たくさんの 本を 持ち運べるのが 便利だそうです。",q:"電子書籍の 便利な 点は 何ですか。",o:["たくさんの 本を 持ち運べる","紙より 軽い","目に やさしい","値段が 安い"],a:0,exp:"「たくさんの 本を 持ち運べるのが 便利」がそのまま答え。"},
      {sec:"問題5　内容理解（中文）",passage:"来月、日本語能力試験を 受ける 予定です。毎日 少しずつ 勉強して、準備を 進めて います。特に 聴解が 苦手なので、毎日 三十分は 聞く 練習を するように しています。試験まで あと 一か月、悔いの 残らないように 頑張りたいです。",q:"この 人は 今、何を していますか。",o:["試験を あきらめた","試験の 準備を している","もう 試験を 受けた","何も していない"],a:1,exp:"「毎日 少しずつ 勉強して、準備を 進めて います」がそのまま答え。"},
      {q:"この 人が 苦手な ことは 何ですか。",o:["文法","聴解","漢字","会話"],a:1,exp:"「特に 聴解が 苦手なので」がそのまま答え。"},
      {q:"試験まで あと どのくらいですか。",o:["一か月","一週間","一年","三か月"],a:0,exp:"「試験まで あと 一か月」がそのまま答え。"},
      {passage:"この カフェは Wi-Fiが 使えるので、仕事を しながら コーヒーを 飲む 人が 多いです。座席も 広く、長時間 いても 気にならない 雰囲気です。私も よく ここで 資料を 作ります。",q:"このカフェに 人が 多い 理由は 何ですか。",o:["Wi-Fiが 使えるから","安いから","静かだから","広いから"],a:0,exp:"「Wi-Fiが 使えるので…人が 多い」がそのまま答え。"}
    ]},
    {id:"c", title:"聴解", minutes:35, questions:[
      {sec:"問題1　課題理解",audio:"男：予約の 変更を お願いしたいのですが。　女：かしこまりました。ご希望の 日時を 教えて いただけますか。",q:"この 人は 何を お願いしましたか。",o:["新しい 予約","予約の 取り消し","苦情","予約の 変更"],a:3,exp:"「予約の 変更を お願いしたい」がそのまま答え。"},
      {audio:"女：新しい 携帯電話を 買いましたが、使い方が 分からないんです。　男：説明書を お読みに なりましたか。まずは 電源の 入れ方から ご説明しますね。",q:"男の人は このあと まず 何を しますか。",o:["携帯電話を返品する","電源の入れ方を説明する","新しい説明書を渡す","電話を購入する"],a:1,exp:"「まずは 電源の 入れ方から ご説明しますね」がそのまま答え。"},
      {audio:"男：来週の 会議、資料は 何部 必要ですか。　女：参加者は 十五人なので、十五部 お願いします。",q:"資料は 何部 必要ですか。",o:["十部","五部","十五部","二十部"],a:2,exp:"「十五部 お願いします」がそのまま答え。"},
      {audio:"女：この 荷物、明日までに 届けたいのですが。　男：速達便を ご利用いただければ、明日の午前中に お届けできます。",q:"明日の 午前中に 届けるには どうすれば いいですか。",o:["自分で 届ける","来週まで 待つ","速達便を 利用する","普通便を 利用する"],a:2,exp:"「速達便を ご利用いただければ、明日の午前中に お届けできます」がそのまま答え。"},
      {audio:"男：来月の 出張、ホテルの 予約は できていますか。　女：まだです。今日中に 旅行代理店に 連絡します。",q:"女の人は このあと まず 何を しますか。",o:["新幹線を予約する","旅行代理店に連絡する","ホテルをキャンセルする","出張を延期する"],a:1,exp:"「今日中に 旅行代理店に 連絡します」がそのまま答え。"},
      {audio:"女：この 契約書、サインする 前に もう一度 内容を 確認したいのですが。　男：もちろんです。ゆっくり ご確認ください。",q:"お客様は 何を したいですか。",o:["担当者を 変えたい","値引きを 交渉したい","契約を キャンセルしたい","契約内容を もう一度 確認したい"],a:3,exp:"「サインする 前に もう一度 内容を 確認したい」がそのまま答え。"},
      {audio:"男：来週の セミナー、参加者数の 都合で 会場を 変更しました。詳細は メールで お送りした 通りです。",q:"会場を 変更した 理由は 何ですか。",o:["講師の 都合","予算の 問題","天候の 問題","参加者数の 都合"],a:3,exp:"「参加者数の 都合で 会場を 変更しました」がそのまま答え。"},
      {sec:"問題2　ポイント理解",audio:"女：この 大学、志願者が 減っていますね。　男：立地の 問題も ありますが、一番 大きいのは、就職実績の 情報発信が 弱いことだと 思います。",q:"男の人は、志願者が 減った 一番の 原因は 何だと 考えていますか。",o:["学費が高いこと","定員が少ないこと","立地が悪いこと","就職実績の情報発信が弱いこと"],a:3,exp:"「一番大きいのは、就職実績の情報発信が弱いこと」がそのまま答え。"},
      {audio:"男：この 地域、空き家が 増えていますね。　女：高齢化も ありますが、一番の 原因は、若い 世代の 働き口が 少ないことだと思います。",q:"女の人は、空き家が 増えた 一番の 原因は 何だと 考えていますか。",o:["高齢化が進んでいること","家賃が高いこと","若い世代の働き口が少ないこと","交通の便が悪いこと"],a:2,exp:"「一番の原因は、若い世代の働き口が少ないこと」がそのまま答え。"},
      {audio:"女：この アプリ、評価が 低いですね。　男：デザインの 問題も ありますが、一番の 原因は、動作が 重く 頻繁に 落ちることだと思います。",q:"男の人は、評価が 低い 一番の 原因は 何だと 考えていますか。",o:["機能が少ないこと","価格が高いこと","動作が重く頻繁に落ちること","デザインが悪いこと"],a:2,exp:"「一番の原因は、動作が重く頻繁に落ちること」がそのまま答え。"},
      {audio:"男：この 店舗、リピーターが 少ないですね。　女：ポイントカードの 特典が 魅力的でないことが 一番の 問題だと思います。",q:"女の人は、リピーターが 少ない 一番の 原因は 何だと 考えていますか。",o:["価格が高いこと","ポイントカードの特典が魅力的でないこと","接客の質が悪いこと","立地が悪いこと"],a:1,exp:"「一番の問題は、ポイントカードの特典が魅力的でないこと」がそのまま答え。"},
      {audio:"女：この チーム、最近 ミスが 増えていますね。　男：確認作業を 一人に 頼りすぎていることが 一番の 原因だと思います。",q:"男の人は、ミスが 増えた 一番の 原因は 何だと 考えていますか。",o:["締め切りが厳しいこと","確認作業を一人に頼りすぎていること","業務量が増加したこと","メンバーが未熟なこと"],a:1,exp:"「一番の原因は、確認作業を一人に頼りすぎていること」がそのまま答え。"},
      {audio:"男：この 新サービス、契約が 伸びませんね。　女：料金プランが 分かりにくいのが 一番の 原因だと思います。",q:"女の人は、契約が 伸びない 一番の 原因は 何だと 言っていますか。",o:["広告が少ないこと","サービス自体の質が悪いこと","競合が多いこと","料金プランが分かりにくいこと"],a:3,exp:"「料金プランが分かりにくいのが一番の原因」がそのまま答え。"},
      {audio:"女：この 学校、退学者が 増えていますね。　男：入学前と 実際の 授業内容の ギャップが 一番の 原因だと 言われています。",q:"男の人は、退学者が 増えた 一番の 原因は 何だと 考えていますか。",o:["経済的な理由","施設の古さ","入学前と実際の授業内容のギャップ","教師の質"],a:2,exp:"「一番の原因は、入学前と実際の授業内容のギャップ」がそのまま答え。"},
      {sec:"問題3　発話表現",audio:"（え：会社の 先輩に お礼を 言いたい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["おやすみなさい。","いただきます。","いろいろ お世話に なりました。","おめでとうございます。"],a:2,exp:"お世話になった相手には「いろいろお世話になりました」。"},
      {audio:"（え：電話で 相手が 忙しそうな とき）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["お忙しいところ 恐れ入ります。","おめでとうございます。","それは嬉しいです。","もう終わりです。"],a:0,exp:"相手の状況を気遣う丁寧な表現。"},
      {audio:"（え：初対面の 人に 名刺を 渡す）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["はじめまして、よろしくお願いします。","ただいま。","おかえりなさい。","おやすみなさい。"],a:0,exp:"初対面の挨拶は「はじめまして、よろしくお願いします」。"},
      {audio:"（え：会議で 資料の 配布を 頼みたい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["資料を 配って いただけますか。","資料を 見ないで ください。","資料を 捨てて ください。","資料は いりません。"],a:0,exp:"丁寧な依頼は「〜ていただけますか」。"},
      {audio:"（え：エレベーターで 人を 先に 通す）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["おじゃまします。","お先に どうぞ。","すみません。","ありがとう。"],a:1,exp:"先に通す時は「お先にどうぞ」。"},
      {sec:"問題4　即時応答",audio:"この 案件、来週まで お待ちいただけますか。",q:"最もよい 返事は どれですか。",o:["いいえ、三時です。","ありがとう。","はい、げんきです。","承知しました。"],a:3,exp:"依頼への承諾は「承知しました」。"},
      {audio:"この プロジェクト、うまく いきそうですか。",q:"最もよい 返事は どれですか。",o:["はい、あそこです。","ありがとうございます。","はい、順調に 進んでいます。","いいえ、三人です。"],a:2,exp:"進捗を聞かれたら状況を答える。"},
      {audio:"この 内容で よろしいでしょうか。",q:"最もよい 返事は どれですか。",o:["もう終わりました。","はい、それで お願いします。","おめでとうございます。","それは残念ですね。"],a:1,exp:"確認への自然な返事。"},
      {audio:"何か ご不明な 点は ございますか。",q:"最もよい 返事は どれですか。",o:["それは嬉しいです。","一点だけ 確認させてください。","おめでとうございます。","もう終わりです。"],a:1,exp:"質問がある場合の自然な返事。"},
      {audio:"お疲れ様でした。",q:"最もよい 返事は どれですか。",o:["お疲れ様でした。","おやすみなさい。","ただいま。","おかえりなさい。"],a:0,exp:"「お疲れ様でした」には同じ言葉で返すのが自然。"},
      {audio:"この 度は ありがとう ございました。",q:"最もよい 返事は どれですか。",o:["それは残念ですね。","いえ、こちらこそ ありがとうございました。","おめでとうございます。","もっとやってください。"],a:1,exp:"感謝への自然な返事。"},
      {audio:"来月の 予定、変更に なるかも しれません。",q:"最もよい 返事は どれですか。",o:["もう変更しました。","それは羨ましいです。","分かりました。決まり次第 教えてください。","おめでとうございます。"],a:2,exp:"予定変更の可能性への自然な返事。"},
      {audio:"この 書類、確認いただけましたか。",q:"最もよい 返事は どれですか。",o:["ありがとう。","はい、げんきです。","はい、確認しました。問題ありません。","いいえ、三時です。"],a:2,exp:"確認結果を報告する自然な返事。"}
    ]}
  ]
},
{
  id:"o-n4-4", lvl:"N4", title:"Examen oficial N4 · 4", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙）", minutes:25, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　卒業する 学校を 選びます。",o:["しゅつぎょう","そつぎょ","そついぎょう","そつぎょう"],a:3,exp:"卒業→そつぎょう「graduación」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　景色が きれいです。",o:["けいしき","けしょく","けしき","けいしょく"],a:2,exp:"景色→けしき「paisaje」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　技術が 進歩した。",o:["ぎしゅつ","きじゅつ","ぎじゅう","ぎじゅつ"],a:3,exp:"技術→ぎじゅつ「técnica」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　都合が 悪い。",o:["とごう","とがい","つごう","つがい"],a:2,exp:"都合→つごう「conveniencia」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　関係が 深い。",o:["かんけい","かんかい","かんがい","かんけ"],a:0,exp:"関係→かんけい「relación」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　感想を 聞かせて ください。",o:["かんぞう","かんさく","かんそう","がんそう"],a:2,exp:"感想→かんそう「impresión」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　地域の 特徴を 調べる。",o:["どくちょう","とくてい","とくしょう","とくちょう"],a:3,exp:"特徴→とくちょう「característica」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　目的を 決める。",o:["もくてい","もくひょう","もくちょう","もくてき"],a:3,exp:"目的→もくてき「objetivo」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　条件を 満たす。",o:["じょうこん","じょうけん","じょうげん","じょうかん"],a:1,exp:"条件→じょうけん「condición」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは どう かきますか。1・2・3・4から いちばん いい ものを 一つ えらんで ください。　そつぎょうしました。",o:["率業","卒業","卒行","卒行業"],a:1,exp:"そつぎょう→卒業「graduación」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　もくてきを もちます。",o:["目的","目線","目標","目次"],a:0,exp:"もくてき→目的「objetivo」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　じょうけんを かくにんします。",o:["状件","状建","条件","条建"],a:2,exp:"じょうけん→条件「condición」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　ぎじゅつを みがきます。",o:["技術","伎述","技述","伎術"],a:0,exp:"ぎじゅつ→技術「técnica」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　かんけいを たいせつに します。",o:["関計","関係","感係","感計"],a:1,exp:"かんけい→関係「relación」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　とくちょうを せつめいします。",o:["特長","得徴","特微","特徴"],a:3,exp:"とくちょう→特徴「característica」（特長は「buena cualidad」で別語）。"},
      {sec:"問題3　文脈規定",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 商品は （　）が 高い。",o:["人気","関係","感想","条件"],a:0,exp:"「人気が高い」＝tener mucha popularidad。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 資料は （　）に まとめられている。",o:["納得","満足","解決","簡潔"],a:3,exp:"「簡潔にまとめられている」＝resumido de forma concisa。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 目的を （　）ため、努力を 続けた。",o:["満足する","達成する","解決する","納得する"],a:1,exp:"「目的を達成する」＝lograr un objetivo。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 制度には いくつかの （　）が ある。",o:["条件感","条件性","条件的","条件"],a:3,exp:"「条件がある」＝hay condiciones。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は 会議で しっかり （　）した。",o:["発達","発言","発見","発表"],a:1,exp:"「発言する」＝tomar la palabra。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 説明は （　）が 分かりにくい。",o:["表明","公表","発表","表現"],a:3,exp:"「表現が分かりにくい」＝la expresión es difícil de entender。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は （　）な 性格で、みんなに 信頼されている。",o:["冷酷","誠実","乱暴","無関心"],a:1,exp:"「誠実な性格」＝carácter sincero。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 計画は （　）が 明確だ。",o:["条件","態度","感想","目的"],a:3,exp:"「目的が明確だ」＝el objetivo es claro。"},
      {sec:"問題4　言い換え類義",q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は 冷静に 状況を 判断した。",o:["落ち着いて","乱暴に","急いで","感情的に"],a:0,exp:"「冷静に」≒「落ち着いて」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼女は 誠実に 対応した。",o:["乱暴に","いい加減に","真面目に、正直に","急いで"],a:2,exp:"「誠実に」≒「真面目に、正直に」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は 明確に 説明した。",o:["はっきりと","乱暴に","急いで","曖昧に"],a:0,exp:"「明確に」≒「はっきりと」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼女は 熱心に 取り組んだ。",o:["適当に","一生懸命に","消極的に","嫌々"],a:1,exp:"「熱心に」≒「一生懸命に」。"},
      {sec:"問題5　用法",q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「たまたま」",o:["たまたま早く終わった。","たまたま明日雨が降る。","駅でたまたま昔の友人に会った。","たまたま三時に会議がある。"],a:2,exp:"「たまたま」＝por casualidad、偶然の出来事に使う。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「かならずしも」",o:["高い商品がかならずしも良いとは限らない。","かならずしも早く終わった。","かならずしも三時に会議がある。","かならずしも明日雨が降る。"],a:0,exp:"「かならずしも〜とは限らない」＝no siempre、部分否定。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「思いがけず」",o:["思いがけず明日雨が降る。","思いがけず三時に来た。","思いがけず早く終わった。","思いがけず賞をもらってしまった。"],a:3,exp:"「思いがけず」＝inesperadamente。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「案外」",o:["案外明日雨が降る。","案外早く終わった。","この問題は案外簡単だった。","案外三時に会議がある。"],a:2,exp:"「案外」＝contra lo esperado、予想と違う結果に使う。"}
    ]},
    {id:"b", title:"言語知識（文法）・読解", minutes:55, questions:[
      {sec:"問題1　文法1",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　英語が 話せる（　）に なりました。",o:["よう","ところ","こと","もの"],a:0,exp:"「V-可能形+ようになる」＝llegar a poder。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　道が 混んで いる（　）、遅れて しまいました。",o:["ので","のに","でも","まで"],a:0,exp:"「ので」＝porque（causa objetiva）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 本を 読んだ（　）、感想を 教えて ください。",o:["なら","たら","ら","ても"],a:2,exp:"「〜たら」＝cuando termines。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　忙しい（　）、返事が 遅く なりました。",o:["ほど","あまり","ばかり","くらい"],a:1,exp:"「〜あまり」＝de tanto que。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　言われた（　）に やって みました。",o:["とおり","かわり","せい","つもり"],a:0,exp:"「〜とおりに」＝tal como se dijo。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　練習すれば する（　）、上手に なる。",o:["ばかり","ほど","だけ","くらい"],a:1,exp:"「〜ば〜ほど」＝cuanto más...más。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 若い（　）、しっかりしている。",o:["ばかりに","わりに","ことに","もので"],a:1,exp:"「〜わりに」＝considerando que。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 歌は 一度 聞いた（　）忘れられません。",o:["ても","ら","なら","と"],a:1,exp:"「〜たら〜られない」＝si lo escuchas, no lo olvidas。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　昔、よく この 川で 泳いだ（　）です。",o:["こと","もの","はず","つもり"],a:1,exp:"「〜ものだ」懐かしさを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　早めに 出発した（　）いいです。",o:["のが","方が","ことが","ものが"],a:1,exp:"「V-た形+方がいい」＝sería mejor。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　体の ため、早寝早起きを する（　）して います。",o:["ために","ように","そうに","はずに"],a:1,exp:"「〜ようにしている」＝procuro hacer。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この ドラマは 面白い（　）評判です。",o:["が","を","と","の"],a:2,exp:"「〜と評判だ」＝tiene fama de。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　先生が 説明して いる（　）、質問しては いけません。",o:["最中に","次第","うちに","あとで"],a:0,exp:"「〜最中に」＝justo en medio de。"},
      {sec:"問題2　文法2（文の組み立て）",q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 歌は　___　___　★　___　忘れられません。（1 一度　2 聞い　3 たら　4 も）",o:["たら","も","一度","聞い"],a:3,exp:"正しい順序：1一度→2聞い→3たら「一度聞いたら」。★の位置には2「聞い」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は　___　★　___　___　しっかりしている。（1 わりに　2 若い　3 も　4 まだ）",o:["も","わりに","まだ","若い"],a:1,exp:"正しい順序：4まだ→2若い→1わりに「まだ若いわりに」。★の位置には1「わりに」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　言われた　___　___　★　___　やって みました。（1 に　2 とおり　3 も　4 まず）",o:["も","とおり","まず","に"],a:3,exp:"正しい順序：2とおり→1に→4まず「とおりにまず」の並びを整えると「言われたとおりにまずやってみました」。★の位置には1「に」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　体の　___　___　★　___　しています。（1 ように　2 早寝早起きを　3 ため　4 する）",o:["する","早寝早起きを","ため","ように"],a:3,exp:"正しい順序：3ため→2早寝早起きを→4する→1ように「ため早寝早起きをするように」。★の位置には1「ように」が入る。"},
      {sec:"問題3　文章の文法",passage:"私は 最近、地域の ボランティア活動に（1）ように なりました。きっかけは、近所の 掃除活動に 誘われた ことです。最初は（2）気持ちで 参加しましたが、参加してみると、思った（3）楽しく、地域の 人と 交流する 良い 機会だと 感じました。（4）、月に 一度は 何らかの 活動に 参加するように しています。これからも、無理の ない 範囲で（5）続けたいと 思います。",q:"（1）",o:["参加して","参加され","参加する","参加した"],a:2,exp:"「〜ようになりました」に続く動詞は辞書形「参加する」。"},
      {q:"（2）",o:["重い","強い","軽い","弱い"],a:2,exp:"「軽い気持ちで」＝con una actitud despreocupada。"},
      {q:"（3）",o:["くらい","より","ばかり","ほど"],a:1,exp:"「思ったより」＝más de lo que pensaba。"},
      {q:"（4）",o:["以前","以下","以来","以後"],a:2,exp:"「以来」＝desde entonces。"},
      {q:"（5）",o:["活動が","活動は","活動へ","活動を"],a:3,exp:"「活動を続ける」動詞の対象を示す「を」。"},
      {sec:"問題4　内容理解（短文）",passage:"最近、朝早く 起きるように なりました。おかげで、朝ごはんを ゆっくり 食べられるように なりました。",q:"朝早く 起きるように なって、何が 変わりましたか。",o:["元気が なく なった","朝ごはんを ゆっくり 食べられる","夜 眠れなく なった","仕事が 増えた"],a:1,exp:"「朝ごはんを ゆっくり 食べられるように なりました」がそのまま答え。"},
      {passage:"友人の 結婚式に 招待されました。何を 着て 行けば いいか、まだ 決めて いません。",q:"この 人は 今、何に 困っていますか。",o:["時間の こと","結婚式に 行けない こと","何を 着るか 決まって いない","プレゼントの こと"],a:2,exp:"「何を 着て 行けば いいか、まだ 決めて いません」がそのまま答え。"},
      {passage:"来月から 新しい アルバイトを 始めます。少し 緊張しますが、新しい ことを 学べるので 楽しみです。",q:"この 人の 気持ちと 合う ものは どれですか。",o:["こわくて 行きたくない","もう やめたいと 思って いる","何も 感じて いない","緊張しながらも 楽しみに している"],a:3,exp:"「少し 緊張しますが…楽しみです」がそのまま答え。"},
      {sec:"問題5　内容理解（中文）",passage:"この 地域では 空き店舗を 利用した イベントが 定期的に 開かれて おり、地域の 活性化に つながって いる。以前は シャッターが 閉まった 店が 目立ったが、今では 週末に なると たくさんの 人で にぎわう ように なった。",q:"空き店舗の 利用は 何に つながって いるか。",o:["人口の 減少","犯罪の 増加","家賃の 上昇","地域の 活性化"],a:3,exp:"「地域の 活性化に つながっている」がそのまま答え。"},
      {q:"以前は どのような 様子でしたか。",o:["いつも 人で にぎわっていた","観光客が 多かった","シャッターが 閉まった 店が 目立った","新しい 店が 多かった"],a:2,exp:"「以前は シャッターが 閉まった 店が 目立った」がそのまま答え。"},
      {q:"今の 様子は どうですか。",o:["誰も 来ない","週末に 人で にぎわう","静かな ままだ","店が 全部 閉まっている"],a:1,exp:"「今では 週末に なると たくさんの 人で にぎわう ように なった」がそのまま答え。"},
      {passage:"最近、朝食を 抜く 人が 増えている。しかし、朝食を 抜くと 集中力が 下がる ことが 研究で 分かって いる。忙しい 朝でも、簡単な ものだけでも 食べる ことが 勧められて いる。",q:"研究で 分かった ことは 何ですか。",o:["朝食を 抜くと 集中力が 下がる","朝食は 不要である","運動が 集中力を 高める","昼食が 最も 重要だ"],a:0,exp:"「朝食を 抜くと 集中力が 下がる ことが 研究で 分かって いる」がそのまま答え。"}
    ]},
    {id:"c", title:"聴解", minutes:35, questions:[
      {sec:"問題1　課題理解",audio:"男：来週の 研修について 連絡します。場所が 変更に なり、本社ビルの 会議室から 隣の 研修センターに 変わりました。",q:"変わったのは 何ですか。",o:["場所","内容","時間","講師"],a:0,exp:"「場所が 変更に なり」がそのまま答え。"},
      {audio:"女：お客様、ご注文いただいた 商品ですが、在庫切れのため、お届けが 一週間ほど 遅れる 見込みです。",q:"商品が 遅れる 理由は 何ですか。",o:["注文の 間違い","天候不順","在庫切れ","配送業者の ミス"],a:2,exp:"「在庫切れのため…遅れる 見込み」がそのまま答え。"},
      {audio:"男：次の バスは 十分後に 出発します。この バスは 空港行きですので、市内観光の 方は 次の 便を お待ちください。",q:"このバスは どこ行きですか。",o:["空港","ホテル","市内観光","駅"],a:0,exp:"「この バスは 空港行きです」がそのまま答え。"},
      {audio:"女：来月の 展示会ですが、出展する 商品の リストを 今週中に 提出して ください。写真も 一緒に お願いします。",q:"今週中に 何を 提出しますか。",o:["参加者名簿","商品リストと 写真","会場の 図面","予算案"],a:1,exp:"「商品の リストを…写真も 一緒に」がそのまま答え。"},
      {audio:"男：来週の 出張、飛行機の 予約は できていますか。　女：まだです。今日中に 手配します。",q:"女の人は このあと まず 何を しますか。",o:["出張を延期する","飛行機を予約する","ホテルをキャンセルする","新幹線を予約する"],a:1,exp:"「今日中に 手配します」がそのまま答え。"},
      {audio:"女：この レポート、来週の 会議までに 仕上げないといけないんですが。　男：手伝いますよ。どこまで 進んでいますか。",q:"男の人は このあと 何を しますか。",o:["レポート作成を手伝う","レポートを提出する","会議を中止する","会議の日程を変更する"],a:0,exp:"「手伝いますよ」がそのまま答え。"},
      {audio:"男：新しい プロジェクトの メンバーですが、田中さんと 鈴木さんに 加えて、来月から 一人 増える 予定です。",q:"来月から どう なりますか。",o:["プロジェクトが 終わる","メンバーが 一人 増える","メンバーが 一人 減る","田中さんが 抜ける"],a:1,exp:"「来月から 一人 増える 予定」がそのまま答え。"},
      {sec:"問題2　ポイント理解",audio:"男：この 部署、離職率が 高いですね。　女：仕事の 内容よりも、上司との コミュニケーション不足が 一番の 原因だと 聞いています。",q:"女の人は、離職率が 高い 一番の 原因は 何だと 言っていますか。",o:["上司とのコミュニケーション不足","仕事の内容","給料が安いこと","勤務時間が長いこと"],a:0,exp:"「上司とのコミュニケーション不足が一番の原因」がそのまま答え。"},
      {audio:"女：この 商品、クレームが 多いですね。　男：品質自体より、配送時の 破損が 一番の 原因だと 思います。",q:"男の人は、クレームが 多い 一番の 原因は 何だと 考えていますか。",o:["配送時の破損","接客の問題","価格の問題","品質の問題"],a:0,exp:"「配送時の破損が一番の原因」がそのまま答え。"},
      {audio:"男：この 会社、新人の 定着率が 低いですね。　女：入社前の 説明と 実際の 仕事内容の ギャップが 一番の 原因だと思います。",q:"女の人は、定着率が 低い 一番の 原因は 何だと 考えていますか。",o:["給料が安いこと","勤務地が遠いこと","研修が長すぎること","入社前の説明と実際の仕事内容のギャップ"],a:3,exp:"「入社前の説明と実際の仕事内容のギャップが一番の原因」がそのまま答え。"},
      {audio:"女：この 商品、売り上げが 落ちていますね。　男：類似品が 増えたことが 一番の 原因だと思います。",q:"男の人は、売り上げが 落ちた 一番の 原因は 何だと 考えていますか。",o:["広告をやめたこと","類似品が増えたこと","価格を上げたこと","品質が落ちたこと"],a:1,exp:"「類似品が増えたことが一番の原因」がそのまま答え。"},
      {audio:"男：この 教室、生徒数が 減っていますね。　女：オンライン授業を 導入している 他の 教室に 生徒が 流れたことが 一番の 原因だと思います。",q:"女の人は、生徒数が 減った 一番の 原因は 何だと 考えていますか。",o:["講師の質が落ちたこと","料金が上がったこと","生徒がオンライン授業のある教室に流れたこと","場所が不便になったこと"],a:2,exp:"「生徒がオンライン授業のある教室に流れたことが一番の原因」がそのまま答え。"},
      {audio:"女：この イベント、参加者が 少なかったですね。　男：告知の 開始時期が 遅かったことが 一番の 原因だと思います。",q:"男の人は、参加者が 少なかった 一番の 原因は 何だと 考えていますか。",o:["内容がつまらなかったこと","告知の開始時期が遅かったこと","天候が悪かったこと","会場が狭かったこと"],a:1,exp:"「告知の開始時期が遅かったことが一番の原因」がそのまま答え。"},
      {audio:"男：この 製品、返品率が 高いですね。　女：使い方の 説明が 不足していることが 一番の 原因だと思います。",q:"女の人は、返品率が 高い 一番の 原因は 何だと 考えていますか。",o:["使い方の説明が不足していること","配送の遅さ","製品の欠陥","価格の高さ"],a:0,exp:"「使い方の説明が不足していることが一番の原因」がそのまま答え。"},
      {sec:"問題3　発話表現",audio:"（え：取引先に 商品の 到着が 遅れることを 伝える）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["おやすみなさい。","おめでとうございます。","いただきます。","申し訳ございません、到着が 少し 遅れそうです。"],a:3,exp:"遅延の連絡は謝罪から始めるのが自然。"},
      {audio:"（え：会議室の 予約を 変更したい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["すみません、予約を 変更したいのですが。","おじゃまします。","ごちそうさまでした。","いただきます。"],a:0,exp:"変更を依頼する時の表現。"},
      {audio:"（え：先輩の 意見に 賛成できない）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["少し 別の 考え方も あるかと思いますが。","それは嬉しいです。","おめでとうございます。","もう終わりです。"],a:0,exp:"控えめに異なる意見を述べる表現。"},
      {audio:"（え：新しい 同僚を 紹介したい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["こちら、新しく 入った 田中さんです。","おやすみなさい。","おめでとうございます。","いただきます。"],a:0,exp:"人を紹介する時の自然な表現。"},
      {audio:"（え：レストランで 予約の 確認を したい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["ごちそうさまでした。","予約の 確認を お願いしたいのですが。","おじゃまします。","いただきます。"],a:1,exp:"予約確認を依頼する表現。"},
      {sec:"問題4　即時応答",audio:"この 件、担当者に 確認して いただけますか。",q:"最もよい 返事は どれですか。",o:["承知しました、確認いたします。","いいえ、三時です。","ありがとう。","はい、げんきです。"],a:0,exp:"依頼への承諾は「承知しました」。"},
      {audio:"来週の 予定、変更は ありませんか。",q:"最もよい 返事は どれですか。",o:["おめでとうございます。","もう終わりました。","それは残念ですね。","今のところ ありません。"],a:3,exp:"予定確認への自然な返事。"},
      {audio:"この 商品、いかがでしたか。",q:"最もよい 返事は どれですか。",o:["はい、あそこです。","とても 気に入りました。","ありがとうございます。","いいえ、三人です。"],a:1,exp:"感想を聞かれたら感想を答える。"},
      {audio:"何か お手伝い できることは ありますか。",q:"最もよい 返事は どれですか。",o:["おめでとうございます。","それは大変ですね。","もう終わりました。","ありがとうございます、大丈夫です。"],a:3,exp:"申し出への自然な返事。"},
      {audio:"この 資料で 問題ないでしょうか。",q:"最もよい 返事は どれですか。",o:["はい、問題ありません。","はい、げんきです。","ありがとう。","いいえ、三時です。"],a:0,exp:"確認への自然な返事。"},
      {audio:"来月から 担当が 変わります。",q:"最もよい 返事は どれですか。",o:["それは残念ですね。","承知しました。よろしくお願いします。","おめでとうございます。","もう終わりました。"],a:1,exp:"担当変更の連絡への自然な返事。"},
      {audio:"少し 相談したいことが あるのですが。",q:"最もよい 返事は どれですか。",o:["おめでとうございます。","もう終わりです。","それは嬉しいです。","はい、どうぞ。"],a:3,exp:"相談を持ちかけられた際の自然な返事。"},
      {audio:"この 度は 大変 お世話に なりました。",q:"最もよい 返事は どれですか。",o:["いえ、こちらこそ お世話になりました。","おめでとうございます。","それは残念ですね。","もっとやってください。"],a:0,exp:"感謝への自然な返事。"}
    ]}
  ]
},
{
  id:"o-n4-5", lvl:"N4", title:"Examen oficial N4 · 5", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙）", minutes:25, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　現在の 状況を 説明します。",o:["げんざい","けんさい","けんざい","げんさい"],a:0,exp:"現在→げんざい「actualmente」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　性格が よく 似ています。",o:["せいかい","しょうかい","しょうかく","せいかく"],a:3,exp:"性格→せいかく「carácter」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　欠席の 連絡を する。",o:["けつせき","けっしき","けっせき","けいせき"],a:2,exp:"欠席→けっせき「ausencia」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　増加の 傾向に ある。",o:["ぞうき","ぞうだい","ぞうか","ぞうげん"],a:2,exp:"増加→ぞうか「aumento」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　効果が ある。",o:["こうこう","こうが","こうか","きょうか"],a:2,exp:"効果→こうか「efecto」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　都市に 住んで います。",o:["とうじ","とうし","とじ","とし"],a:3,exp:"都市→とし「ciudad」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　将来の 夢が ある。",o:["しょうらい","しょうらく","しょらい","じょうらい"],a:0,exp:"将来→しょうらい「futuro」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　利用者が 増えた。",o:["りゆうじゃ","りゆうしゃ","りようしゃ","りようじゃ"],a:2,exp:"利用者→りようしゃ「usuario」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　実際に 見て みる。",o:["じっざい","じっさい","じつざい","じつさい"],a:1,exp:"実際→じっさい「en realidad」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは どう かきますか。1・2・3・4から いちばん いい ものを 一つ えらんで ください。　げんざいの じょうきょうです。",o:["原在","現存","元在","現在"],a:3,exp:"げんざい→現在「actualmente」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　せいかくが いいです。",o:["精格","正格","生格","性格"],a:3,exp:"せいかく→性格「carácter」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　しょうらいの ゆめです。",o:["小来","召来","招来","将来"],a:3,exp:"しょうらい→将来「futuro」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　りようしゃが おおいです。",o:["利容者","理用者","利要者","利用者"],a:3,exp:"りようしゃ→利用者「usuario」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　こうかが あります。",o:["効果","効化","高価","高果"],a:0,exp:"こうか→効果「efecto」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　じっさいに ためして みます。",o:["実際","実裁","実祭","実斎"],a:0,exp:"じっさい→実際「en realidad」。"},
      {sec:"問題3　文脈規定",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 薬は （　）が ある。",o:["効果","態度","感想","条件"],a:0,exp:"「効果がある」＝tener efecto。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は （　）な 性格で、よく 笑う。",o:["冷たい","厳しい","明るい","暗い"],a:2,exp:"「明るい性格」＝carácter alegre。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 地域は 人口が （　）傾向に ある。",o:["解決する","満足する","増加する","納得する"],a:2,exp:"「増加する傾向」＝tendencia al aumento。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は （　）に 都市へ 引っ越した。",o:["現在の ため","将来の ため","以前の ため","過去の ため"],a:1,exp:"「将来のため」＝para el futuro。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この アプリの （　）は 増え続けている。",o:["利用者","態度","条件","感想"],a:0,exp:"「利用者が増える」＝aumentan los usuarios。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　実際に （　）と、想像と 違いました。",o:["忘れてみる","考えてみる","やってみる","やめてみる"],a:2,exp:"「実際にやってみると」＝al hacerlo de verdad。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼の 発言は 会議で （　）を 呼んだ。",o:["満足","賛成","注目","納得"],a:2,exp:"「注目を呼ぶ」＝llamar la atención（連語）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は 欠席の （　）を 事前に した。",o:["感想","態度","連絡","条件"],a:2,exp:"「連絡をする」＝hacer una notificación。"},
      {sec:"問題4　言い換え類義",q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は 積極的に 参加した。",o:["仕方なく","消極的に","嫌々","自分から進んで"],a:3,exp:"「積極的に」≒「自分から進んで」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼女は 正確に 説明した。",o:["乱暴に","間違いなく","曖昧に","急いで"],a:1,exp:"「正確に」≒「間違いなく」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は 十分 準備した。",o:["急いで","適当に","少しだけ","しっかりと"],a:3,exp:"「十分」≒「しっかりと」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼女は 急速に 上達した。",o:["少しずつ","なかなか","急いで、すぐに","ゆっくりと"],a:2,exp:"「急速に」≒「急いで、すぐに」。"},
      {sec:"問題5　用法",q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「たびたび」",o:["たびたび三時に会議がある。","たびたび早く終わった。","彼はたびたび遅刻する。","たびたび明日雨が降る。"],a:2,exp:"「たびたび」＝a menudo、繰り返しの行為に使う。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「どうにか」",o:["どうにか三時に来た。","どうにか明日雨が降る。","どうにか元気だ。","締め切りにどうにか間に合った。"],a:3,exp:"「どうにか」＝de alguna manera、苦労してぎりぎり達成した文脈。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「あくまで」",o:["あくまで三時に会議がある。","これはあくまで私の意見です。","あくまで明日雨が降る。","あくまで早く終わった。"],a:1,exp:"「あくまで」＝hasta el final、自分の立場を限定する表現。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「めったに」",o:["彼はめったに怒らない。","めったに三時に来た。","めったに明日会議がある。","めったに早く終わった。"],a:0,exp:"「めったに〜ない」＝raramente、頻度の低さを表す。"}
    ]},
    {id:"b", title:"言語知識（文法）・読解", minutes:55, questions:[
      {sec:"問題1　文法1",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　自転車に 乗れる（　）に なりました。",o:["こと","もの","よう","ところ"],a:2,exp:"「V-可能形+ようになる」＝llegar a poder。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　台風が 近づいている（　）、旅行を 中止しました。",o:["ので","でも","まで","のに"],a:0,exp:"「ので」＝porque（causa objetiva）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 映画を 見た（　）、感動しました。",o:["ても","たら","なら","ら"],a:3,exp:"「〜たら」結果を導く用法。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　疲れて いた（　）、宿題を 忘れて しまいました。",o:["ほど","くらい","あまり","ばかり"],a:2,exp:"「〜あまり」＝de tanto que。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　教えられた（　）に 作って みました。",o:["つもり","かわり","せい","とおり"],a:3,exp:"「〜とおりに」＝tal como se dijo。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　考えれば 考える（　）、分からなく なる。",o:["くらい","ほど","ばかり","だけ"],a:1,exp:"「〜ば〜ほど」＝cuanto más...más。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は 小さい（　）、力が 強い。",o:["もので","ことに","わりに","ばかりに"],a:2,exp:"「〜わりに」＝considerando que。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 本は 一度 読んだ（　）忘れられません。",o:["と","ら","ても","なら"],a:1,exp:"「〜たら〜られない」＝si lo lees, no lo olvidas。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　昔は よく ここで 遊んだ（　）です。",o:["もの","こと","つもり","はず"],a:0,exp:"「〜ものだ」懐かしさを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　早めに 準備した（　）安心です。",o:["ものが","ことが","のが","方が"],a:3,exp:"「V-た形+方がいい」構文。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　規則正しい 生活を する（　）して います。",o:["ように","そうに","はずに","ために"],a:0,exp:"「〜ようにしている」＝procuro hacer。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 本は 役に 立つ（　）評判です。",o:["と","を","が","の"],a:0,exp:"「〜と評判だ」＝tiene fama de。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　会議の 最中に（　）、電話は 出ません。",o:["は","が","に","を"],a:0,exp:"「〜は」対比のテーマを示す。"},
      {sec:"問題2　文法2（文の組み立て）",q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 本は　___　___　★　___　忘れられません。（1 読ん　2 も　3 一度　4 だら）",o:["読ん","だら","一度","も"],a:0,exp:"正しい順序：3一度→1読ん→4だら「一度読んだら」。★の位置には1「読ん」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は　___　★　___　___　力が 強い。（1 小さい　2 わりに　3 も　4 体は）",o:["体は","小さい","も","わりに"],a:3,exp:"正しい順序：4体は→1小さい→2わりに「体は小さいわりに」。★の位置には2「わりに」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　教えられた　___　___　★　___　作って みました。（1 に　2 とおり　3 も　4 まず）",o:["に","まず","とおり","も"],a:0,exp:"正しい順序：2とおり→1に→4まず「とおりにまず」の並びを整えて「教えられたとおりにまず作ってみました」。★の位置には1「に」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　規則正しい　___　___　★　___　しています。（1 生活を　2 する　3 ように　4 を）",o:["ように","する","を","生活を"],a:1,exp:"正しい順序：1生活を→2する→3ように「生活をするように」。★の位置には2「する」が入る。"},
      {sec:"問題3　文章の文法",passage:"最近、実家を 離れて 一人暮らしを 始めました。最初は 不安（1）、今は 生活にも 慣れて きました。自炊を するように なって（2）、料理の 大変さを 実感しました。家族が いつも 作ってくれた 料理の ありがたさに、改めて 気づかされました。（3）、掃除や 洗濯も 全部 自分で しなければ ならず、時間の 使い方を（4）ように なりました。一人暮らしは 大変な ことも 多いですが、（5）分だけ 成長できたと 感じています。",q:"（1）",o:["なので","なのに","でしたし","でしたが"],a:3,exp:"「〜でしたが」逆接、不安だったが慣れてきた、という展開。"},
      {q:"（2）",o:["へ","まで","より","から"],a:3,exp:"「〜てから」動作の開始点を示す。"},
      {q:"（3）",o:["または","だから","それに","でも"],a:2,exp:"「それに」＝追加の情報を導く。"},
      {q:"（4）",o:["放棄する","無視する","忘れる","工夫する"],a:3,exp:"「時間の使い方を工夫する」＝ingeniárselas con el uso del tiempo。"},
      {q:"（5）",o:["苦労した","簡単だった","楽だった","つまらなかった"],a:0,exp:"「苦労した分だけ成長できた」＝se creció en proporción al esfuerzo。"},
      {sec:"問題4　内容理解（短文）",passage:"来月から 新しい 支店で 働くことに なりました。まだ 詳しい 仕事内容は 分かりませんが、新しい 環境で 頑張りたいと 思います。",q:"この 人の 気持ちと 合う ものは どれですか。",o:["不安で仕事を辞めたいと思っている","何も感じていない","前の支店に戻りたいと思っている","新しい環境で頑張りたいと思っている"],a:3,exp:"「新しい 環境で 頑張りたいと 思います」がそのまま答え。"},
      {passage:"最近、朝早く 起きて 散歩する 習慣を 始めました。体調が よく なった 気が します。",q:"この 人は 何を 始めましたか。",o:["朝の散歩","ヨガ","夜のランニング","水泳"],a:0,exp:"「朝早く 起きて 散歩する 習慣を 始めました」がそのまま答え。"},
      {passage:"来週、大切な プレゼンが あります。資料は できましたが、話す 練習が まだ 足りません。",q:"この 人に 足りない ことは 何ですか。",o:["資料の作成","話す練習","会場の予約","プレゼンの日程"],a:1,exp:"「話す 練習が まだ 足りません」がそのまま答え。"},
      {sec:"問題5　内容理解（中文）",passage:"この 会社では、新入社員の 早期離職が 課題と なっており、入社後 半年間の メンター制度を 導入した。ベテラン社員が マンツーマンで 指導する 仕組みで、新入社員が 気軽に 相談できる 相手が いることが、離職率の 低下に つながって いる。",q:"メンター制度は 何を 目的として いるか。",o:["給料を上げること","採用人数を増やすこと","業務量を減らすこと","新入社員の早期離職を防ぐこと"],a:3,exp:"「新入社員の早期離職が課題となっており…メンター制度を導入した」がそのまま答え。"},
      {q:"メンター制度の 効果は 何ですか。",o:["採用人数の増加","離職率の低下","給料の上昇","業務量の増加"],a:1,exp:"「離職率の低下につながっている」がそのまま答え。"},
      {q:"メンター制度は どのような 仕組みですか。",o:["ベテラン社員がマンツーマンで指導する","外部講師が指導する","全員で会議をする","新人同士で教え合う"],a:0,exp:"「ベテラン社員が マンツーマンで 指導する 仕組み」がそのまま答え。"},
      {passage:"高齢化が 進む 農村部では、農業の 担い手不足が 深刻だ。この 課題に 対し、ドローンや ロボットを 活用した「スマート農業」の 導入が 進んで いる。少ない 人手でも 効率的に 作業できるように なりつつある。",q:"担い手不足への 対策として 何が 進んで いるか。",o:["海外からの輸入拡大","若者への補助金支給","スマート農業の導入","農地の売却"],a:2,exp:"「ドローンや ロボットを 活用した『スマート農業』の 導入が 進んでいる」がそのまま答え。"}
    ]},
    {id:"c", title:"聴解", minutes:35, questions:[
      {sec:"問題1　課題理解",audio:"男：来週の セミナー、資料は 準備できていますか。　女：ほぼ 完成していますが、最後の ページの 図を もう少し 見やすく したいです。今日中に 直します。",q:"女の人は このあと まず 何を しますか。",o:["参加者に連絡する","資料を印刷する","図を見やすく修正する","セミナーを中止する"],a:2,exp:"「今日中に 直します」がそのまま答え。"},
      {audio:"女：新しい ロゴの デザイン、三案 ありますが、どれが いいと 思いますか。　男：正直 迷いますね。デザイン部の 意見も 聞いてから 決めませんか。",q:"この後 まず 何を しますか。",o:["デザイン部の意見を聞く","三案とも採用する","ロゴをすぐに決める","デザインをやり直す"],a:0,exp:"「デザイン部の 意見も 聞いてから 決めませんか」がそのまま答え。"},
      {audio:"男：来月の 出張の 交通手段、まだ 決めていませんでした。　女：新幹線の 方が 早いですが、予算的には バスの 方が 安いです。上司に 確認してから 決めましょう。",q:"この後 まず 何を しますか。",o:["出張を中止する","上司に確認する","新幹線を予約する","バスを予約する"],a:1,exp:"「上司に 確認してから 決めましょう」がそのまま答え。"},
      {audio:"女：来週の 展示会の 準備、順調ですか。　男：はい、ほぼ 予定通りですが、パンフレットの 印刷だけ 少し 遅れています。",q:"何が 遅れて いますか。",o:["パンフレットの印刷","スタッフの手配","商品の到着","会場の準備"],a:0,exp:"「パンフレットの 印刷だけ 少し 遅れています」がそのまま答え。"},
      {audio:"男：新しい システムの 導入、社員への 説明会は いつ 行いますか。　女：来週の 水曜日に 予定しています。今日中に 案内メールを 送ります。",q:"女の人は このあと まず 何を しますか。",o:["システムを変更する","説明会を延期する","案内メールを送る","社員を集める"],a:2,exp:"「今日中に 案内メールを 送ります」がそのまま答え。"},
      {audio:"女：この 契約書、内容を 確認したいのですが、専門用語が 多くて 分かりにくいです。　男：法務部に 相談して みましょう。",q:"この後 まず 何を しますか。",o:["法務部に相談する","サインする","契約書を破棄する","契約を延期する"],a:0,exp:"「法務部に 相談して みましょう」がそのまま答え。"},
      {audio:"男：来月の 会社説明会、会場の 候補が 二つ あるんですが。　女：それぞれの 収容人数と アクセスを 比較した 資料を 作ってもらえますか。",q:"男の人は このあと 何を しますか。",o:["会場の比較資料を作る","会場を予約する","参加者を募集する","説明会を中止する"],a:0,exp:"「比較した資料を作ってもらえますか」への流れから、比較資料を作成する。"},
      {sec:"問題2　ポイント理解",audio:"女：この 商品、海外での 売り上げが 伸びませんね。　男：現地の 文化に 合わせた マーケティングが 不足していることが 一番の 原因だと思います。",q:"男の人は、海外での 売り上げが 伸びない 一番の 原因は 何だと 考えていますか。",o:["品質が悪いこと","競合が多いこと","価格が高すぎること","現地の文化に合わせたマーケティングの不足"],a:3,exp:"「現地の文化に合わせたマーケティングが不足していることが一番の原因」がそのまま答え。"},
      {audio:"男：この 部署、残業が 多いですね。　女：業務の 分担が 偏っていることが 一番の 原因だと思います。",q:"女の人は、残業が 多い 一番の 原因は 何だと 考えていますか。",o:["人手が足りないこと","業務の分担が偏っていること","効率が悪いこと","仕事の量が多すぎること"],a:1,exp:"「業務の分担が偏っていることが一番の原因」がそのまま答え。"},
      {audio:"女：この 店、常連客が 減っていますね。　男：接客態度に 問題が あったことが 一番の 原因だと 聞いています。",q:"男の人は、常連客が 減った 一番の 原因は 何だと 考えていますか。",o:["接客態度の問題","価格の値上げ","立地の悪さ","メニューの変更"],a:0,exp:"「接客態度に問題があったことが一番の原因」がそのまま答え。"},
      {audio:"男：この 大学、留学生が 減っていますね。　女：奨学金制度が 他大学に 比べて 少ないことが 一番の 原因だと思います。",q:"女の人は、留学生が 減った 一番の 原因は 何だと 考えていますか。",o:["奨学金制度が少ないこと","講義が英語で行われないこと","立地が悪いこと","授業料が高いこと"],a:0,exp:"「奨学金制度が他大学に比べて少ないことが一番の原因」がそのまま答え。"},
      {audio:"女：この プロジェクト、スケジュールが 遅れていますね。　男：初期段階での 要件定義が 不十分だったことが 一番の 原因だと思います。",q:"男の人は、スケジュールが 遅れた 一番の 原因は 何だと 考えていますか。",o:["予算が少なかったこと","技術的な問題があったこと","初期段階での要件定義が不十分だったこと","人員が不足していたこと"],a:2,exp:"「初期段階での要件定義が不十分だったことが一番の原因」がそのまま答え。"},
      {audio:"男：この 商品、SNSでの 評判が 悪いですね。　女：発売前の 情報公開が 不十分だったことが 一番の 原因だと思います。",q:"女の人は、評判が 悪い 一番の 原因は 何だと 考えていますか。",o:["発売前の情報公開が不十分だったこと","競合が優れていること","デザインが悪いこと","価格が高すぎること"],a:0,exp:"「発売前の情報公開が不十分だったことが一番の原因」がそのまま答え。"},
      {audio:"女：この 施設、利用者が 減っていますね。　男：予約システムが 使いにくいことが 一番の 原因だと思います。",q:"男の人は、利用者が 減った 一番の 原因は 何だと 考えていますか。",o:["設備が古いこと","場所が不便なこと","料金が高いこと","予約システムが使いにくいこと"],a:3,exp:"「予約システムが使いにくいことが一番の原因」がそのまま答え。"},
      {sec:"問題3　発話表現",audio:"（え：後輩が 大きな 契約を 取った）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["よく 頑張ったね、おめでとう。","おやすみなさい。","おだいじに。","いただきます。"],a:0,exp:"成果を上げた後輩を称える表現。"},
      {audio:"（え：会議室の 予約が 重なって しまった）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["いただきます。","すみません、時間を ずらして いただけますか。","おじゃまします。","ごちそうさまでした。"],a:1,exp:"調整を依頼する表現。"},
      {audio:"（え：取引先の 担当者に 久しぶりに 会った）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["はじめまして。","ご無沙汰しております。","おかえりなさい。","おやすみなさい。"],a:1,exp:"久しぶりに会う相手への挨拶は「ご無沙汰しております」。"},
      {audio:"（え：会議で 発言の 機会が 欲しい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["おやすみなさい。","少し よろしいでしょうか。","おめでとうございます。","いただきます。"],a:1,exp:"発言の許可を求める丁寧な表現。"},
      {audio:"（え：忙しい 同僚に 資料の 確認を お願いしたい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["いただきます。","おじゃまします。","ごちそうさまでした。","お忙しいところ 恐れ入りますが、ご確認 いただけますか。"],a:3,exp:"忙しい相手への丁寧な依頼表現。"},
      {sec:"問題4　即時応答",audio:"この 業務、引き継いで いただけますか。",q:"最もよい 返事は どれですか。",o:["はい、げんきです。","いいえ、三時です。","承知しました、しっかり 引き継ぎます。","ありがとう。"],a:2,exp:"引き継ぎ依頼への承諾。"},
      {audio:"来月、異動に なるそうですね。",q:"最もよい 返事は どれですか。",o:["おめでとうございます。","もう終わりました。","それは残念ですね。","はい、新しい部署でも頑張ります。"],a:3,exp:"異動の話への自然な返事。"},
      {audio:"この 会議、時間通りに 始められそうですか。",q:"最もよい 返事は どれですか。",o:["ありがとうございます。","はい、大丈夫です。","いいえ、三人です。","はい、あそこです。"],a:1,exp:"確認への自然な返事。"},
      {audio:"最近、お忙しそうですね。",q:"最もよい 返事は どれですか。",o:["それは大変ですね。","もう終わりました。","おめでとうございます。","ええ、少し立て込んでいます。"],a:3,exp:"忙しさを気遣われた際の自然な返事。"},
      {audio:"この プロジェクト、無事に 終わりましたね。",q:"最もよい 返事は どれですか。",o:["いいえ、三時です。","はい、皆様のおかげです。","はい、げんきです。","ありがとう。"],a:1,exp:"成果を称えられた際の謙虚な返事。"},
      {audio:"来週、休みを 取っても よろしいでしょうか。",q:"最もよい 返事は どれですか。",o:["はい、問題ありません。","おめでとうございます。","もう終わりました。","それは残念ですね。"],a:0,exp:"休暇の許可を求められた際の返事。"},
      {audio:"この 度は 大変 助かりました。",q:"最もよい 返事は どれですか。",o:["それは残念ですね。","おめでとうございます。","もっとやってください。","いえいえ、お役に立てて 良かったです。"],a:3,exp:"感謝への自然な返事。"},
      {audio:"何か ご不安な 点は ございますか。",q:"最もよい 返事は どれですか。",o:["おめでとうございます。","それは嬉しいです。","一つだけ 確認したいことが あります。","もう終わりです。"],a:2,exp:"気遣いに対する自然な返事。"}
    ]}
  ]
},
{
  id:"o-n3-1", lvl:"N3", title:"Examen oficial N3 · 1", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙）", minutes:30, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 商品は 大変 人気です。",o:["じんき","にんき","じんけ","ひとけ"],a:1,exp:"人気→にんき「popularidad」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女の 態度に 驚いた。",o:["たいと","たいたく","たいど","たいたい"],a:2,exp:"態度→たいど「actitud」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　環境を 守りたい。",o:["かんしん","かんそう","かんけい","かんきょう"],a:3,exp:"環境→かんきょう「entorno」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　複雑な 問題だ。",o:["ふくさつ","ふくそう","ぶくざつ","ふくざつ"],a:3,exp:"複雑→ふくざつ「complejo」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　解決方法を 考える。",o:["かいけい","かいけつ","かいせつ","かいぎ"],a:1,exp:"解決→かいけつ「resolución」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　原因を 調べる。",o:["がんいん","げいいん","げんにん","げんいん"],a:3,exp:"原因→げんいん「causa」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　効率が 良い。",o:["こうりょ","こうそつ","こうりゅう","こうりつ"],a:3,exp:"効率→こうりつ「eficiencia」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　規則を 守る。",o:["きりつ","きそく","きやく","ぎそく"],a:1,exp:"規則→きそく「norma」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは どう かきますか。1・2・3・4から いちばん いい ものを 一つ えらんで ください。　かんきょうを まもる。",o:["感況","感境","環境","環況"],a:2,exp:"かんきょう→環境「entorno」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　げんいんを しらべる。",o:["元因","原因","現因","原員"],a:1,exp:"げんいん→原因「causa」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　かいけつしました。",o:["開決","開結","解決","解結"],a:2,exp:"かいけつ→解決「resolución」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　こうりつよく はたらく。",o:["高率","効律","効率","公立"],a:2,exp:"こうりつ→効率「eficiencia」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　きそくを まもる。",o:["規則","気則","期則","規側"],a:0,exp:"きそく→規則「regla」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　たいどが わるい。",o:["待度","体度","態度","対度"],a:2,exp:"たいど→態度「actitud」。"},
      {sec:"問題3　文脈規定",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼の 発言は 会議で （　）を 呼んだ。",o:["満足","納得","賛成","注目"],a:3,exp:"「注目を呼ぶ」＝llamar la atención。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 資料は （　）に まとめられている。",o:["簡潔","納得","満足","解決"],a:0,exp:"「簡潔にまとめられている」＝resumido de forma concisa。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　台風が 近づいて いるので、（　）してください。",o:["安心","満足","納得","注意"],a:3,exp:"台風には「注意」（precaución）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 目的を （　）ため、努力を 続けた。",o:["達成する","解決する","納得する","満足する"],a:0,exp:"「目的を達成する」＝lograr un objetivo。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は 会議で しっかり （　）した。",o:["発達","発表","発言","発見"],a:2,exp:"「発言する」＝tomar la palabra。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 計画は （　）が 明確だ。",o:["感想","態度","目的","条件"],a:2,exp:"「目的が明確だ」＝el objetivo es claro。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は （　）な 性格で、みんなに 信頼されている。",o:["誠実","冷酷","乱暴","無関心"],a:0,exp:"「誠実な性格」＝carácter sincero。"},
      {sec:"問題4　言い換え類義",q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は 熱心に 勉強している。",o:["適当に","一生懸命に","嫌々","たまに"],a:1,exp:"「熱心に」≒「一生懸命に」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼女は 突然 泣き出した。",o:["ゆっくりと","わざと","急に","予定通り"],a:2,exp:"「突然」≒「急に」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　この 部屋は 十分 広い。",o:["あまり","じゅうぶんに","少し","ぜんぜん"],a:1,exp:"「十分」≒「じゅうぶんに」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は しばしば 遅刻する。",o:["よく","たまに","一度も","絶対に"],a:0,exp:"「しばしば」≒「よく」（con frecuencia）。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼女は 冷静に 判断した。",o:["乱暴に","急いで","感情的に","落ち着いて"],a:3,exp:"「冷静に」≒「落ち着いて」。"},
      {sec:"問題5　用法",q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「たまたま」",o:["たまたま早く終わった。","たまたま三時に会議がある。","たまたま明日雨が降る。","駅でたまたま昔の友人に会った。"],a:3,exp:"「たまたま」＝por casualidad。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「思わず」",o:["驚いて、思わず声を上げてしまった。","思わず三時に会議がある。","思わず明日雨が降る。","思わず早く終わった。"],a:0,exp:"「思わず」＝sin querer, involuntariamente。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「あらかじめ」",o:["あらかじめ早く終わった。","あらかじめ三時に来た。","あらかじめ明日会議がある。","あらかじめ予約しておいたので、待たずに入れた。"],a:3,exp:"「あらかじめ」＝de antemano。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「案外」",o:["案外三時に会議がある。","案外明日雨が降る。","この問題は案外簡単だった。","案外早く終わった。"],a:2,exp:"「案外」＝contra lo esperado。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「せっかく」",o:["せっかく三時に会議がある。","せっかく早く終わった。","せっかく明日雨が降る。","せっかく作ったのに、誰も食べてくれなかった。"],a:3,exp:"「せっかく」＝con esfuerzo especial（無駄になる文脈でよく使う）。"}
    ]},
    {id:"b", title:"言語知識（文法）・読解", minutes:70, questions:[
      {sec:"問題1　文法1",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　日本に 来た（　）、日本語が 上手に なった。",o:["せいで","ために","ように","おかげで"],a:3,exp:"「おかげで」＝gracias a（結果が良い場合）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　先生の 説明を 聞いて、やっと 意味が わかる（　）に なった。",o:["よう","はず","こと","もの"],a:0,exp:"「Vる+ようになる」＝llegar a (un estado)。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 忙しい（　）、いつも 元気だ。",o:["もので","わりに","ことに","ばかりに"],a:1,exp:"「〜わりに」＝considerando que。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　規則を 破った（　）、罰せられるのは 当然だ。",o:["以上","うちに","上に","かたわら"],a:0,exp:"「〜以上」＝dado que。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は 若い（　）、しっかりした 考えを 持っている。",o:["からして","として","ながらも","につれて"],a:2,exp:"「〜ながらも」＝aunque, si bien。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　努力した（　）、結果が 出なかった。",o:["ものの","ことから","につけ","ばかりに"],a:0,exp:"「〜ものの」＝aunque, si bien。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 資料は 難しい 内容を 含む（　）、専門家 以外には 分かりにくい。",o:["ため","おかげで","かのように","ものなら"],a:0,exp:"「〜ため」＝por, debido a。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 部長（　）、部下からの 信頼も 厚い。",o:["にとって","にしたら","というより","でありながら"],a:3,exp:"「〜でありながら」＝a pesar de ser。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　連絡（　）、勝手に 予定を 変更しないで ください。",o:["なくて","もなく","抜きで","なしに"],a:3,exp:"「〜なしに」＝sin previo aviso。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は 経験の 浅い（　）、よく やった 方だ。",o:["にとって","につき","にかけては","にしては"],a:3,exp:"「〜にしては」＝para ser (algo)。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　努力した（　）で、結果が 出ないことも ある。",o:["うえ","もの","はず","ところ"],a:3,exp:"「〜たところで」＝aunque se haga, por mucho que se haga。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼の 話は 具体性に （　）、説得力に 欠ける。",o:["欠く","欠いて","欠け","欠かず"],a:2,exp:"連用中止形「欠け」で文をつなぐ。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 説明は 具体性に 欠ける（　）分かりにくい。",o:["かわりに","ことなく","おかげで","ため"],a:3,exp:"「〜ため」＝debido a。"},
      {sec:"問題2　文法2（文の組み立て）",q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は　___　___　★　___　見事な 対応を 見せた。（1 経験の　2 も　3 浅さ　4 にもかかわらず）",o:["も","浅さ","にもかかわらず","経験の"],a:2,exp:"正しい順序：1経験の→3浅さ→4にもかかわらず「経験の浅さにもかかわらず」。★の位置には4「にもかかわらず」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　規則を　___　★　___　___　罰せられて 当然だ。（1 破った　2 以上　3 は　4 も）",o:["破った","以上","は","も"],a:1,exp:"正しい順序：1破った→2以上→3は「破った以上は」。★の位置には2「以上」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は　___　___　★　___　いつも 元気だ。（1 わりに　2 忙しい　3 も　4 とても）",o:["も","とても","わりに","忙しい"],a:2,exp:"正しい順序：2忙しい→1わりに「忙しいわりに」。★の位置には1「わりに」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 資料は　___　___　★　___　分かりにくい。（1 内容を　2 難しい　3 ため　4 含む）",o:["含む","難しい","ため","内容を"],a:2,exp:"正しい順序：2難しい→1内容を→4含む→3ため「難しい内容を含むため」。★の位置には3「ため」が入る。"},
      {sec:"問題3　文章の文法",passage:"最近、地域の 図書館で ボランティア活動を 始めました。きっかけは、（1）近所の 人に 誘われた ことです。最初は （2）気持ちで 参加しましたが、参加してみると、思った（3）楽しく、本の 整理を 通して 地域の 人と 交流する 良い 機会だと 感じました。（4）、月に 二回は 図書館に 通うように しています。これからも、無理のない 範囲で（5）続けたいと 思います。",q:"（1）",o:["わざと","必ず","絶対に","たまたま"],a:3,exp:"「たまたま」＝por casualidad、きっかけの偶然性を表す。"},
      {q:"（2）",o:["軽い","弱い","強い","重い"],a:0,exp:"「軽い気持ちで」＝con una actitud despreocupada。"},
      {q:"（3）",o:["より","ほど","くらい","ばかり"],a:0,exp:"「思ったより」＝más de lo que pensaba。"},
      {q:"（4）",o:["以後","以下","以前","以来"],a:3,exp:"「以来」＝desde entonces。"},
      {q:"（5）",o:["活動を","活動は","活動が","活動へ"],a:0,exp:"「活動を続ける」動詞の対象を示す「を」。"},
      {sec:"問題4　内容理解（短文）",passage:"最近、健康の ために 毎朝 走って います。最初は 大変でしたが、今は 気持ちよく 走れるように なりました。",q:"この 人は 今、走ることに ついて どう 感じて いますか。",o:["もう やめたいと 感じている","大変だと 感じている","つまらないと 感じている","気持ちよく 感じている"],a:3,exp:"「今は 気持ちよく 走れるように なりました」がそのまま答え。"},
      {passage:"来月から 新しい プロジェクトが 始まります。準備することが 多く、みんな 忙しく なりそうです。",q:"来月から どう なりそうですか。",o:["プロジェクトが 終わる","みんな 忙しく なる","人が 減る","休みが 増える"],a:1,exp:"「みんな 忙しく なりそうです」がそのまま答え。"},
      {passage:"アパートの 隣に 新しい 家族が 引っ越して来ました。まだ 挨拶を して いないので、今度 会ったら 挨拶しようと 思います。",q:"この 人は これから 何を する つもりですか。",o:["隣の 家族に 挨拶する","引っ越しを 手伝う","何も しない","家族を 招待する"],a:0,exp:"「今度 会ったら 挨拶しようと 思います」がそのまま答え。"},
      {passage:"最近、電子書籍を 読む 人が 増えて います。紙の 本と 違い、たくさんの 本を 持ち運べるのが 便利だそうです。",q:"電子書籍の 便利な 点は 何ですか。",o:["たくさんの 本を 持ち運べる","値段が 安い","目に やさしい","紙より 軽い"],a:0,exp:"「たくさんの 本を 持ち運べるのが 便利」がそのまま答え。"},
      {sec:"問題5　内容理解（中文）",passage:"最近、リモートワークを 導入する 企業が 増えている。通勤の 負担が 減る 一方で、仕事と 家庭の 境界が あいまいに なるという 課題も 指摘されている。企業側も、社員が 適切に 休息を 取れるよう、就業時間外の 連絡を 控える などの 対策を 始めている。",q:"リモートワークの 課題として 挙げられているのは 何か。",o:["給料が 下がる こと","仕事と 家庭の 境界が あいまいに なる こと","通勤時間が 長く なる こと","社員が 減る こと"],a:1,exp:"「仕事と 家庭の 境界が あいまいに なる という 課題」がそのまま答え。"},
      {q:"企業側が 始めている 対策は 何か。",o:["リモートワークを廃止すること","給料を減らすこと","出勤日数を増やすこと","就業時間外の連絡を控えること"],a:3,exp:"「就業時間外の 連絡を 控える などの 対策」がそのまま答え。"},
      {q:"この文章の 要旨として 最も適切な ものは どれか。",o:["リモートワークに課題は存在しない","通勤の負担は増加している","リモートワークは廃止すべきだ","リモートワークには利点と課題の両面があり企業が対策を進めている"],a:3,exp:"利点・課題・対策の3点を扱っている。"},
      {passage:"この 地域は 昔から 農業が 盛んで、特に 米作りで 知られている。しかし 近年、若い 世代の 農業離れが 進み、後継者不足が 深刻な 問題と なっている。行政は 新規就農者への 補助金制度を 設けるなど、対策に 乗り出している。",q:"この 地域の 問題は 何か。",o:["観光客が 少ない こと","土地が 狭い こと","米の 生産量が 多すぎる こと","後継者不足"],a:3,exp:"「後継者不足が 深刻な 問題」がそのまま答え。"},
      {q:"行政が 行っている 対策は 何か。",o:["新規就農者への補助金制度","米の輸入拡大","農地の売却促進","観光振興"],a:0,exp:"「新規就農者への 補助金制度を 設ける」がそのまま答え。"},
      {sec:"問題6　内容理解（長文）",passage:"読書は 想像力を 育てると 言われる。文字だけの 情報から 場面を 思い描く 過程が、脳を 活性化させるからだ。映像作品では すでに 完成された 映像が 提示されるのに 対し、小説を 読む 際には、読者一人ひとりが 自分の 経験や 知識を もとに、独自の イメージを 作り上げる 必要が ある。<br><br>この 想像の プロセスこそが、読書の 最大の 魅力であり、同時に 教育的な 価値でも あると 言えるだろう。子どもの 読書量の 減少が しばしば 問題視されるが、それは 単に 娯楽が 減った ということ 以上に、想像力を 育む 機会が 失われつつある ことを 意味しているのかもしれない。<br><br>もちろん、映像作品にも 独自の 価値が あり、読書が 唯一の 教育手段だと 主張する つもりは ない。しかし、少なくとも、両者が それぞれ 異なる 種類の 認知能力を 育てて いる ことは 意識しておく べきだろう。",q:"読書が 想像力を 育てる 理由は 何か。",o:["本の 内容が 面白いから","字が 大きいから","時間が かかるから","場面を 思い描く 過程が 脳を 活性化させるから"],a:3,exp:"「場面を 思い描く 過程が、脳を 活性化させるから」がそのまま答え。"},
      {q:"筆者が 子どもの 読書量減少について 述べていることは 何か。",o:["全く問題ではない","映像作品の増加が原因だ","単なる娯楽の減少に過ぎない","想像力を育む機会が失われつつあることを意味するかもしれない"],a:3,exp:"「想像力を 育む 機会が 失われつつある ことを 意味しているのかもしれない」がそのまま答え。"},
      {q:"筆者は 映像作品について どう考えているか。",o:["読書の代わりになるべきだ","読書より劣っている","全く価値がない","独自の価値があり読書とは異なる認知能力を育てる"],a:3,exp:"「映像作品にも 独自の 価値が あり…異なる 種類の 認知能力を 育てている」がそのまま答え。"},
      {sec:"問題7　情報検索",passage:"【地域スポーツセンター　利用案内】<br>・利用時間：午前9時〜午後9時<br>・休館日：毎月 第3月曜日<br>・利用料金：一般 500円、学生 300円（学生証提示）、65歳以上 200円<br>・回数券：11回分の料金で 12回 利用できる（本人のみ有効）<br>・団体利用：5名以上の場合、事前予約が必要。団体割引で 1人あたり 100円引き。<br>・注意：更衣室のロッカーは 100円硬貨が必要（使用後 返却されます）。",q:"65歳の 人が 5人の 団体で 利用する 場合、1人あたりの 料金は いくらか。",o:["200円","300円","100円","500円"],a:2,exp:"65歳以上の料金200円から団体割引100円引きで100円。"},
      {q:"この 案内から 分かる ことは 何か。",o:["団体利用に予約は不要","回数券は誰でも使える","休館日は毎週月曜日","ロッカーの100円硬貨は使用後返却される"],a:3,exp:"「ロッカーは 100円硬貨が必要（使用後 返却されます）」がそのまま該当。"}
    ]},
    {id:"c", title:"聴解", minutes:40, questions:[
      {sec:"問題1　課題理解",audio:"男：来週の 展示会の 準備、順調ですか。　女：はい、ほぼ 予定通りですが、パンフレットの 印刷だけ 少し 遅れています。今日中に 印刷会社に 確認の 連絡を 入れます。",q:"女の人は このあと、まず 何を しますか。",o:["会場を変更する","印刷会社に連絡する","パンフレットを作り直す","展示会を延期する"],a:1,exp:"「今日中に 印刷会社に 確認の 連絡を 入れます」がそのまま答え。"},
      {audio:"女：すみません、この 資料、コピーして いただけますか。　男：はい、何部 必要ですか。　女：十部 お願いします。",q:"男の人は このあと 何を しますか。",o:["資料を十部コピーする","参加者に連絡する","資料を書き直す","会議を中止する"],a:0,exp:"「十部 お願いします」への流れから、コピーする。"},
      {audio:"男：来月の セミナー、会場の 候補が 二つ あるんですが。　女：それぞれの 収容人数と 料金を 比較した 資料を 作ってもらえますか。",q:"男の人は このあと 何を しますか。",o:["参加者を募集する","セミナーを中止する","会場の比較資料を作る","会場を予約する"],a:2,exp:"「比較した資料を作ってもらえますか」への流れから、比較資料を作成する。"},
      {audio:"女：来週の 出張、ホテルの 予約は できていますか。　男：まだです。今日中に 旅行代理店に 連絡します。",q:"男の人は このあと まず 何を しますか。",o:["新幹線を予約する","ホテルをキャンセルする","旅行代理店に連絡する","出張を延期する"],a:2,exp:"「今日中に 旅行代理店に 連絡します」がそのまま答え。"},
      {audio:"男：新しい プロジェクトの 進め方に ついて 相談したいのですが。　女：まずは 関係部署に 意見を 聞いてから、来週の 会議で 方向性を 決めましょう。",q:"来週の 会議で 何を 決めますか。",o:["会議の日程","予算の金額","プロジェクトの方向性","関係部署の担当者"],a:2,exp:"「来週の 会議で 方向性を 決めましょう」がそのまま答え。"},
      {audio:"女：この 契約書、サインする 前に もう一度 内容を 確認したいのですが。　男：もちろんです。念のため、法務部にも 目を通して もらいましょうか。",q:"男の人は このあと まず 何を しますか。",o:["契約書にサインする","新しい契約書を作る","契約を解除する","法務部に確認を依頼する"],a:3,exp:"「法務部にも 目を通して もらいましょうか」がそのまま答え。"},
      {audio:"男：来週の 面接、履歴書の 確認は 済んでいますか。　女：まだです。今日の 午後、全員分に 目を通します。",q:"履歴書の 確認は いつ しますか。",o:["今日の午後","明日の朝","来週の月曜日","もう済んでいる"],a:0,exp:"「今日の 午後、全員分に 目を通します」がそのまま答え。"},
      {audio:"女：この 荷物、宅配便で 送りたいんですが。　男：サイズと 重さを 測りますので、少々 お待ちください。",q:"店の人は まず 何を しますか。",o:["サイズと重さを測る","箱を探す","料金を計算する","住所を聞く"],a:0,exp:"「サイズと 重さを 測りますので」がそのまま答え。"},
      {sec:"問題2　ポイント理解",audio:"女：今回の プロジェクト、予定より 遅れていますね。原因は 何だと 思いますか。　男：人手不足も 一因ですが、一番 大きいのは 仕様変更が 何度も あったことだと 思います。",q:"男の人は、プロジェクトが 遅れている 一番の 原因は 何だと 言っていますか。",o:["設計者が交代したこと","仕様変更が何度もあったこと","予算が足りないこと","人手が不足していること"],a:1,exp:"「一番 大きいのは 仕様変更が 何度も あったこと」がそのまま答え。"},
      {audio:"男：新しい 店舗の 場所、駅前と 郊外の ショッピングモール、どちらに しますか。　女：家賃は 駅前の方が 高いですが、集客力を 考えると 駅前の 一択でしょう。",q:"女の人が 駅前を 選ぶ 一番の 理由は 何ですか。",o:["家賃が安いから","集客力が高く長期的に採算が取れるから","面積が広いから","駅から近く通勤が楽だから"],a:1,exp:"「集客力を 考えると…駅前の 一択でしょう」がそのまま答え。"},
      {audio:"男：今度の 講演会、参加者が 少なかったですね。　女：告知の 時期が 遅かったのが 一番の 問題だったと 思います。",q:"女の人は、参加者が 少なかった 一番の 原因は 何だと 言っていますか。",o:["日程が悪かったこと","会場が悪かったこと","告知の時期が遅かったこと","講師の話がつまらなかったこと"],a:2,exp:"「告知の 時期が 遅かったのが 一番の 問題」がそのまま答え。"},
      {audio:"女：新商品の 売り上げ、思ったほど 伸びていませんね。　男：価格設定は 問題ないと 思うんですが、広告の 打ち方が 弱かったんじゃないかと。",q:"男の人は、売り上げが 伸びない 一番の 原因は 何だと 考えていますか。",o:["商品の品質が悪いこと","競合が多いこと","価格が高すぎること","広告がターゲット層に届いていないこと"],a:3,exp:"「広告の 打ち方が 弱かった」が原因として挙げられている。"},
      {audio:"男：来期の 予算案、営業部からの 要望が 通らなかったようですね。　女：全社的に コスト削減の 方針が 出ていて、どの 部署も 一律で 減らされる ことに なったみたいです。",q:"営業部の 要望が 通らなかった 一番の 理由は 何ですか。",o:["営業部の実績が悪かったから","予算案の書き方が悪かったから","全社的なコスト削減方針があったから","他部署の予算が優先されたから"],a:2,exp:"「全社的に コスト削減の 方針が 出ていて…一律で 減らされる」がそのまま理由。"},
      {audio:"女：この 機械、最近 よく 故障しますね。　男：使用年数も ありますが、それより 湿度の 高い 環境で 使い続けたことが 大きいと思います。",q:"男の人は、機械が 故障する 一番の 原因は 何だと 考えていますか。",o:["使用年数が長いこと","操作方法が間違っていたこと","部品の品質が悪いこと","湿度の高い環境で使い続けたこと"],a:3,exp:"「それより 湿度の 高い 環境で 使い続けたことが 大きい」が原因として挙げられている。"},
      {audio:"男：この 店、最近 お客さんが 減っていますね。　女：近くに 大型スーパーが できたことが 一番 大きいと思います。",q:"女の人は、客が 減った 一番の 原因は 何だと 考えていますか。",o:["スタッフが減ったこと","近くに大型スーパーができたこと","商品の質が落ちたこと","営業時間が短くなったこと"],a:1,exp:"「近くに 大型スーパーが できたことが 一番大きい」がそのまま答え。"},
      {sec:"問題3　概要理解",audio:"近年、企業の 意思決定に データ分析を 活用する 動きが 加速している。ただし、データに 過度に 依存する あまり、現場の 経験や 直感に 基づく 判断が 軽視される 傾向も 見られ、両者の バランスが 課題と なっている。",q:"この話は、主に何について述べていますか。",o:["経験や直感の完全な排除","データと経験・直感のバランス","意思決定の遅さ","データ分析の技術不足"],a:1,exp:"データと経験・直感のバランスについての話。"},
      {audio:"言葉は 常に 変化し続ける ものである。新しい 表現の 誕生を「乱れ」と 断じるのは 早計であり、むしろ 言語の 生命力の 証と 見るべきだろう。",q:"この話は、主に何について述べていますか。",o:["正しい日本語の使い方の解説","言葉の変化についての一つの見方","若者言葉の具体的な例","言語教育の方法"],a:1,exp:"言葉の変化を肯定的に捉える視点についての話。"},
      {audio:"科学技術の 進歩は 人類に 多大な 恩恵を もたらしてきたが、同時に 新たな 倫理的 課題も 生み出して きた。技術の 可能性と 社会が 許容すべき 範囲との 線引きを、我々は 常に 問い続ける 必要が ある。",q:"この話は、主に何について述べていますか。",o:["技術の可能性と社会的許容の線引きを問い続ける必要性","倫理的課題は存在しないということ","技術の恩恵のみを重視すべきこと","科学技術の発展を止めるべきだということ"],a:0,exp:"技術の可能性と社会的許容のバランスについての話。"},
      {audio:"読書は 想像力を 育てると 言われる。文字だけの 情報から 場面を 思い描く 過程が、脳を 活性化させるからだ。子どもの 読書量の 減少が しばしば 問題視されるのも、この点と 関係が あるのかもしれない。",q:"この話は、主に何について述べていますか。",o:["読書の歴史","図書館の利用方法","読書が想像力を育てる仕組みとその意義","本の選び方"],a:2,exp:"読書と想像力の関係についての話。"},
      {sec:"問題4　発話表現",audio:"（え：後輩が 大事な 会議に 遅刻しそうだ）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["おめでとうございます。","急いだ方がいいですよ。","いただきます。","おやすみなさい。"],a:1,exp:"急いだ方がいいと助言する表現。"},
      {audio:"（え：会議室に 入る 前）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["おやすみなさい。","失礼します。","おかえりなさい。","ただいま。"],a:1,exp:"部屋に入る時は「失礼します」。"},
      {audio:"（え：先輩に 仕事の 相談を したい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["いただきます。","おやすみなさい。","おめでとうございます。","少し ご相談したいことが あるのですが。"],a:3,exp:"相談を持ちかける丁寧な表現。"},
      {audio:"（え：会議で 反対意見を 言いたい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["少し 違う 意見なのですが。","おめでとうございます。","もう終わりです。","それは嬉しいです。"],a:0,exp:"控えめに反対意見を述べる表現。"},
      {audio:"（え：電車で お年寄りに 席を 譲る）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["ありがとう。","おじゃまします。","どうぞ、お座りください。","すみません。"],a:2,exp:"席を譲る時は「どうぞ、お座りください」。"},
      {sec:"問題5　即時応答",audio:"この 資料、目を通して いただけましたか。",q:"最もよい 返事は どれですか。",o:["いいえ、三時です。","ありがとう。","はい、げんきです。","はい、拝見しました。"],a:3,exp:"確認への自然な返事は「はい、拝見しました」。"},
      {audio:"来週、お時間 いただけますか。",q:"最もよい 返事は どれですか。",o:["おめでとうございます。","はい、大丈夫です。","それは残念ですね。","もう終わりました。"],a:1,exp:"時間の依頼への自然な返事。"},
      {audio:"この 案、いかがでしょうか。",q:"最もよい 返事は どれですか。",o:["おめでとうございます。","良いと思いますが、少し気になる点があります。","それは嬉しいです。","もう決まりました。"],a:1,exp:"意見を求められた際の自然な返事。"},
      {audio:"ご迷惑を おかけして 申し訳ありません。",q:"最もよい 返事は どれですか。",o:["もっとやってください。","いえ、気にしないでください。","それは嬉しいです。","おめでとうございます。"],a:1,exp:"謝罪への自然な返事。"},
      {audio:"何か お困りのことは ありますか。",q:"最もよい 返事は どれですか。",o:["おめでとうございます。","実は、少し 分からないことが あります。","それは残念ですね。","もう終わりです。"],a:1,exp:"気遣いへの自然な返事。"},
      {audio:"この 件、担当を 代わって いただけますか。",q:"最もよい 返事は どれですか。",o:["いいえ、三時です。","ありがとう。","はい、げんきです。","はい、承知しました。"],a:3,exp:"依頼への承諾は「はい、承知しました」。"},
      {audio:"体調は いかがですか。",q:"最もよい 返事は どれですか。",o:["おかげさまで、大分 良くなりました。","いいえ、三人です。","ありがとうございます。","はい、あそこです。"],a:0,exp:"体調を聞かれたら状態を答える。"},
      {audio:"この 提案について、ご意見を 伺えますか。",q:"最もよい 返事は どれですか。",o:["はい、思ったことを お伝えします。","もう終わりました。","それは大変ですね。","おめでとうございます。"],a:0,exp:"意見を求められた際の自然な返事。"}
    ]}
  ]
},
{
  id:"o-n3-2", lvl:"N3", title:"Examen oficial N3 · 2", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙）", minutes:30, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　新しい 制度が 始まった。",o:["せいてい","せいたく","せいと","せいど"],a:3,exp:"制度→せいど「sistema」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　増加の 傾向に ある。",o:["ぞうか","ぞうげん","ぞうき","ぞうだい"],a:0,exp:"増加→ぞうか「aumento」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　判断が 難しい。",o:["はんだん","はんたん","ばんだん","はんてい"],a:0,exp:"判断→はんだん「juicio」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　検討します。",o:["けんとう","けんちょう","けんこう","けんどう"],a:0,exp:"検討→けんとう「estudio」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　普及して いる。",o:["ふきゅ","ぶきゅう","ふきゅう","ふうきゅう"],a:2,exp:"普及→ふきゅう「difusión」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　抵抗を 感じる。",o:["ていぎ","ていこ","ていこう","ていかん"],a:2,exp:"抵抗→ていこう「resistencia」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　妥当な 判断だ。",o:["たとう","だどう","たどう","だとう"],a:3,exp:"妥当→だとう「razonable」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　実態を 調査する。",o:["じったい","しったい","しつたい","じつたい"],a:0,exp:"実態→じったい「situación real」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは どう かきますか。1・2・3・4から いちばん いい ものを 一つ えらんで ください。　せいどを かえます。",o:["精度","製度","制度","政度"],a:2,exp:"せいど→制度「sistema」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　けんとうします。",o:["検討","見当","検答","健闘"],a:0,exp:"けんとう→検討「estudio, consideración」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　ふきゅうして います。",o:["不朽","不急","普及","不休"],a:2,exp:"ふきゅう→普及「difusión」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　ていこうを かんじる。",o:["底抗","抵抗","定抗","低抗"],a:1,exp:"ていこう→抵抗「resistencia」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　だとうな はんだん。",o:["打党","妥当","妥党","打当"],a:1,exp:"だとう→妥当「razonable」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　じったいを ちょうさする。",o:["実大","実体","実態","実代"],a:2,exp:"じったい→実態「situación real」。"},
      {sec:"問題3　文脈規定",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼の 意見は （　）に 富んでいる。",o:["納得感","賛成感","説得力","満足感"],a:2,exp:"「説得力に富む」＝tener gran poder de convicción。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 制度は （　）に 見直される。",o:["突発的","定期的","一時的","偶発的"],a:1,exp:"「定期的に見直す」＝revisar periódicamente。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 難しい 状況を （　）乗り越えた。",o:["強引に","巧みに","過剰に","急激に"],a:1,exp:"「巧みに」＝hábilmente。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 問題の （　）は 深刻だ。",o:["感想","条件","実態","態度"],a:2,exp:"「実態は深刻だ」＝la situación real es grave。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女の 指摘は （　）を 突いていた。",o:["核心","本心","中心","内心"],a:0,exp:"「核心を突く」＝dar en el meollo。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 案には （　）の 余地が ある。",o:["検討","満足","納得","賛成"],a:0,exp:"「検討の余地がある」＝hay margen para reconsiderar。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼の 発言は 会議で （　）を 呼んだ。",o:["注目","話題","物議","評判"],a:2,exp:"物議を呼ぶ＝causar controversia。"},
      {sec:"問題4　言い換え類義",q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は 状況を 的確に 判断した。",o:["遅れて","感情的に","正確に、適切に","おおざっぱに"],a:2,exp:"「的確に」≒「正確に、適切に」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼女は あっさり 断った。",o:["時間を かけて","悲しそうに","怒って","すぐに、簡単に"],a:3,exp:"「あっさり」≒「すぐに、簡単に」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は てきぱき 仕事を 片付けた。",o:["能率よく、素早く","のんびりと","感情的に","いい加減に"],a:0,exp:"「てきぱき」≒「能率よく、素早く」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼女は やむを得ず 参加を 諦めた。",o:["積極的に","仕方なく","すぐに","喜んで"],a:1,exp:"「やむを得ず」≒「仕方なく」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は 案の定 遅刻した。",o:["偶然に","予想したとおり","急に","意外にも"],a:1,exp:"「案の定」≒「予想したとおり」。"},
      {sec:"問題5　用法",q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「なかなか」",o:["なかなか三人来ました。","なかなか元気です。","この漢字はなかなか覚えられません。","なかなか明日は晴れます。"],a:2,exp:"「なかなか＋否定」＝no…fácilmente。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「とっくに」",o:["とっくに元気だ。","会議はとっくに終わっていた。","とっくに明日会議がある。","とっくに三時に来た。"],a:1,exp:"「とっくに」＝ya hace tiempo。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「せいぜい」",o:["この仕事はせいぜい二時間で終わるだろう。","せいぜい三時に会議がある。","せいぜい早く終わった。","せいぜい明日雨が降る。"],a:0,exp:"「せいぜい」＝como mucho。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「まさか」",o:["まさか明日晴れるだろう。","まさか早く終わった。","まさか彼が優勝するとは思わなかった。","まさか三時に来た。"],a:2,exp:"「まさか〜とは」＝no puedo creer que。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「たしか」",o:["たしか、彼は今週出張していたはずだ。","たしか明日雨が降る。","たしか三時に会議がある。","たしか早く終わった。"],a:0,exp:"「たしか」＝si mal no recuerdo。"}
    ]},
    {id:"b", title:"言語知識（文法）・読解", minutes:70, questions:[
      {sec:"問題1　文法1",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　忙しい（　）、彼は 毎日 運動を 欠かさない。",o:["ばかりに","せいで","にもかかわらず","おかげで"],a:2,exp:"「〜にもかかわらず」＝a pesar de。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　約束の 時間に なった（　）、彼は まだ 来ない。",o:["し","ので","のに","から"],a:2,exp:"「〜のに」＝a pesar de que。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 説明書（　）、正しく 設置できます。",o:["につれて","にとって","に従って","にわたって"],a:2,exp:"「〜に従って」＝siguiendo, conforme a。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　一度 やる（　）、最後まで 頑張るべきだ。",o:["からには","としても","にしても","にしては"],a:0,exp:"「〜からには」＝una vez que te comprometes。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 映画は 面白い（　）、少し 長すぎる。",o:["以上に","反面","おかげで","上に"],a:1,exp:"「〜反面」＝por otra parte, en contraste。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　社員の 意見を 聞いた（　）で、決定する べきだ。",o:["上は","上で","上","上に"],a:1,exp:"「〜上で」＝tras hacer algo。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　連絡（　）、勝手に 予定を 変更しないで ください。",o:["もなく","なくて","なしに","抜きで"],a:2,exp:"「〜なしに」＝sin previo aviso。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は 若い（　）、しっかりした 考えを 持って いる。",o:["として","につれて","からして","ながらも"],a:3,exp:"「〜ながらも」＝aunque, si bien。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　働き方改革が 進む（　）、有給休暇の 取得率を 上げようとする 企業が 増えている。",o:["中","あいだ","うえ","うちに"],a:0,exp:"「〜中」＝mientras (en el proceso de)。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 忙しい（　）、いつも 元気だ。",o:["もので","ことに","わりに","ばかりに"],a:2,exp:"「〜わりに」＝considerando que。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 資料は 難しい 内容を 含む（　）、専門家 以外には 分かりにくい。",o:["かのように","ため","おかげで","ものなら"],a:1,exp:"「〜ため」＝por, debido a。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　締め切り（　）、無理な 依頼を するのは 避けたい。",o:["にわたって","にかけて","を理由に","をきっかけに"],a:2,exp:"「〜を理由に」＝con la excusa de。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 会社は 週に 一日、自由な テーマで 研究できる 制度が（　）。",o:["ある","でした","いる","する"],a:0,exp:"制度は「ある」（存在）。"},
      {sec:"問題2　文法2（文の組み立て）",q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 制度は　___　___　★　___　導入された。（1 声を　2 現場の　3 反映して　4 も）",o:["現場の","反映して","も","声を"],a:1,exp:"正しい順序：2現場の→1声を→3反映して「現場の声を反映して」。★の位置には3「反映して」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は　___　★　___　___　しっかりした 考えを 持っている。（1 ながらも　2 若い　3 も　4 まだ）",o:["若い","ながらも","まだ","も"],a:1,exp:"正しい順序：4まだ→2若い→1ながらも「まだ若いながらも」。★の位置には1「ながらも」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 映画は　___　___　★　___　長すぎる。（1 反面　2 面白い　3 少し　4 も）",o:["反面","面白い","も","少し"],a:3,exp:"正しい順序：2面白い→1反面→3少し「面白い反面少し」。★の位置には3「少し」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　社員の　___　___　★　___　決定する べきだ。（1 意見を　2 聞いた　3 上で　4 も）",o:["上で","も","意見を","聞いた"],a:0,exp:"正しい順序：1意見を→2聞いた→3上で「意見を聞いた上で」。★の位置には3「上で」が入る。"},
      {sec:"問題3　文章の文法",passage:"近年、健康志向の 高まりから、糖質を 控える 食生活を 実践する 人が 増えている。（1）、極端な 糖質制限は、体調不良を 引き起こす 危険性も 指摘されている。専門家に（2）と、栄養バランスを 保ちながら、適度に 糖質を 減らす ことが 望ましいと いう。（3）、自己流の 極端な ダイエットには 注意が 必要だ。健康の ために 始めた ことが、（4）体を 壊す 原因に なっては 本末転倒である。専門家の 助言を 参考に しながら、自分に 合った 方法を（5）べきだろう。",q:"（1）",o:["ゆえに","そのうえ","つまり","しかし"],a:3,exp:"逆接の「しかし」が文脈に合う。"},
      {q:"（2）",o:["よる","かかる","とる","なる"],a:0,exp:"「専門家によると」情報源を示す表現。"},
      {q:"（3）",o:["それゆえ","ところが","むしろ","つまり"],a:0,exp:"「それゆえ」＝por lo tanto。"},
      {q:"（4）",o:["つまり","したがって","かえって","むしろ"],a:2,exp:"「かえって」＝al contrario、逆効果を表す。"},
      {q:"（5）",o:["忘れる","放棄する","見つける","無視する"],a:2,exp:"「自分に合った方法を見つける」が文脈に合う。"},
      {sec:"問題4　内容理解（短文）",passage:"この企業は環境負荷の軽減を経営方針の柱に据え、生産工程の見直しを進めている。短期的なコスト増加は避けられないが、長期的な企業価値の向上を見込んでいる。",q:"この企業が見込んでいることは何か。",o:["従業員数の削減","海外進出の拡大","長期的な企業価値の向上","短期的な利益の拡大"],a:2,exp:"「長期的な企業価値の向上を見込んでいる」がそのまま答え。"},
      {passage:"この地域では、伝統工芸品の後継者不足が深刻化しており、行政と民間が連携した育成プログラムが開始された。若い世代への技術継承が急務とされている。",q:"育成プログラムの目的は何か。",o:["観光客の誘致","若い世代への技術継承","価格の引き上げ","輸出の拡大"],a:1,exp:"「若い世代への技術継承が急務」がそのまま答え。"},
      {passage:"この調査によれば、リモートワークの普及により、地方への移住を検討する都市部の若者が増加している。働く場所の制約が減ったことが背景にある。",q:"地方移住の増加の背景は何か。",o:["交通網の発達","働く場所の制約が減ったこと","都市部の家賃高騰","地方の経済成長"],a:1,exp:"「働く場所の制約が減ったことが背景」がそのまま答え。"},
      {passage:"この病院では、電子カルテの導入により、医師間の情報共有が円滑になり、診断の精度が向上したと報告されている。",q:"電子カルテ導入の効果は何か。",o:["診断の精度向上","患者数の増加","診療時間の短縮","医療費の削減"],a:0,exp:"「情報共有が円滑になり、診断の精度が向上した」がそのまま答え。"},
      {sec:"問題5　内容理解（中文）",passage:"この 街では 空き店舗を 利用した イベントが 定期的に 開かれて おり、地域の 活性化に つながって いる。以前は シャッターが 閉まった 店が 目立ったが、今では 週末に なると たくさんの 人で にぎわう ように なった。行政も この 動きを 後押しする ため、店舗の 改装費用の 一部を 補助する 制度を 設けている。",q:"空き店舗の 利用は 何に つながって いるか。",o:["人口の減少","家賃の上昇","地域の活性化","犯罪の増加"],a:2,exp:"「地域の 活性化に つながっている」がそのまま答え。"},
      {q:"行政が 行っている 支援は 何か。",o:["無償での店舗提供","家賃の全額負担","税金の引き上げ","改装費用の一部補助"],a:3,exp:"「店舗の 改装費用の 一部を 補助する 制度」がそのまま答え。"},
      {q:"この文章の 要旨として 最も適切な ものは どれか。",o:["空き店舗の活用と行政支援が地域活性化に寄与している","空き店舗は増加し続けている","行政は空き店舗問題に無関心だ","週末の人出は減少している"],a:0,exp:"活用の成果と行政支援の両方に言及している。"},
      {passage:"AI技術の 発達により、翻訳作業の 効率が 大きく 向上した。ただし、文化的な 背景を 考慮した 翻訳には まだ 人間の 手が 必要だと される。単語を 直訳するだけでは、文脈に 合わない 不自然な 表現に なる ことが 少なくない。",q:"AI翻訳に ついて 正しいのは どれか。",o:["翻訳作業は遅くなった","AIが完全に人間に取って代わった","文化的背景を考慮するには人間が必要","AI技術はまだ発達していない"],a:2,exp:"「文化的な 背景を 考慮した 翻訳には まだ 人間の 手が 必要」がそのまま答え。"},
      {q:"直訳の問題点として 挙げられているのは 何か。",o:["費用が高いこと","文脈に合わない不自然な表現になること","著作権の問題があること","翻訳速度が遅いこと"],a:1,exp:"「文脈に 合わない 不自然な 表現に なる ことが 少なくない」がそのまま答え。"},
      {sec:"問題6　内容理解（長文）",passage:"働き方改革が 進む 中、有給休暇の 取得率を 上げようとする 企業が 増えて いる。しかし、実際には 取りにくい 雰囲気が 残る 職場も 少なくない。上司の 目を 気にして、休みたくても 言い出せないという 声も 聞かれる。<br><br>この 課題を 解決する ために、いくつかの 企業では、取得を 促進する 独自の 工夫を 始めている。例えば、有給休暇の 計画的な 取得を 義務付ける 制度や、上司が 率先して 休暇を 取る ことで、部下が 休みやすい 雰囲気を 作る 取り組みなどが 挙げられる。<br><br>制度を 整えるだけでは 不十分で、職場の 文化を 変えていく ことこそが、真の 課題解決には 不可欠だと 言えるだろう。単なる ルールの 変更では なく、一人ひとりの 意識改革が 求められて いるのである。",q:"文章の 内容と 合う ものは どれか。",o:["働き方改革は終わった","有給取得率は全企業で上がった","有給休暇は廃止された","有給を取りにくい職場もまだ多い"],a:3,exp:"「実際には 取りにくい 雰囲気が 残る 職場も 少なくない」がそのまま答え。"},
      {q:"企業が 行っている 工夫として 挙げられているのは 何か。",o:["有給休暇の完全廃止","休暇日数の削減","上司による休暇の禁止","計画的な取得の義務付けや上司が率先して休むこと"],a:3,exp:"「計画的な 取得を 義務付ける 制度や…上司が 率先して 休暇を 取る」がそのまま答え。"},
      {q:"筆者が 真に 必要だと 述べていることは 何か。",o:["職場の文化を変え一人ひとりの意識改革を進めること","制度だけを厳格に整えること","上司の権限を強化すること","休暇そのものをなくすこと"],a:0,exp:"「職場の 文化を 変えていく ことこそが、真の 課題解決には 不可欠」がそのまま答え。"},
      {sec:"問題7　情報検索",passage:"【市民講座　参加案内】<br>・講座：Ａ「パソコン基礎」（全4回）／Ｂ「英会話入門」（全6回）／Ｃ「写真撮影テクニック」（全3回）<br>・受講料：1講座につき3,000円（65歳以上は半額）。2講座以上の同時申込みで、2講座目から1,000円引き。<br>・申込方法：市役所窓口または公式サイトから、開講日の10日前までに申込み。<br>・注意事項：欠席が多い場合（全体の半分以上）、修了証は発行されません。教材費は別途必要な場合があります。",q:"65歳の人が AとBの講座を同時に申し込む場合、受講料はいくらか。",o:["6,000円","4,000円","3,000円","2,000円"],a:3,exp:"65歳以上は半額なので各1,500円、さらに2講座目から1,000円引きで1,500円+500円=2,000円。"},
      {q:"この案内から分かることとして正しいものはどれか。",o:["申込みは開講日当日でもできる","欠席が多いと修了証が発行されない","講座は1つしか申し込めない","教材費は常に無料である"],a:1,exp:"「欠席が多い場合…修了証は発行されません」がそのまま該当。"}
    ]},
    {id:"c", title:"聴解", minutes:40, questions:[
      {sec:"問題1　課題理解",audio:"男：来月の 引っ越しですが、荷物の 量を 確認したいので、今週中に 見積もりに 伺っても よろしいですか。　女：はい、土曜日の 午後なら 大丈夫です。",q:"見積もりは いつ 行われますか。",o:["土曜日の午後","今日","日曜日の午前","来月"],a:0,exp:"「土曜日の 午後なら 大丈夫です」がそのまま答え。"},
      {audio:"女：今日の 会議は 三十分ほど 延長する ことに なりました。次の 予定が ある方は 先に 退席して いただいて 構いません。",q:"次の 予定が ある人は どう すれば いいですか。",o:["先に退席してもいい","会議を中止する","部屋を変える","必ず最後まで残る"],a:0,exp:"「先に 退席して いただいて 構いません」がそのまま答え。"},
      {audio:"男：すみません、この カメラ、修理を お願いしたいのですが。　女：保証書は お持ちですか。保証期間内でしたら 無料で 修理できます。",q:"何が あれば 無料で 修理できますか。",o:["保証書","説明書","購入時の箱","レシート"],a:0,exp:"「保証書は お持ちですか。保証期間内でしたら 無料で」がそのまま答え。"},
      {audio:"女：新しい プロジェクトの メンバーですが、田中さんと 鈴木さんに 加えて、来月から 一人 増える 予定です。",q:"来月から どう なりますか。",o:["プロジェクトが終わる","メンバーが一人減る","田中さんが抜ける","メンバーが一人増える"],a:3,exp:"「来月から 一人 増える 予定」がそのまま答え。"},
      {audio:"男：来週の 出張の 件ですが、予定して いた 新幹線が 満席だったので、一本 早い 便に 変更しました。集合時間も 三十分 早めて ください。",q:"何が 変更に なりましたか。",o:["出張先","参加者","出張の目的","新幹線の便と集合時間"],a:3,exp:"「一本 早い 便に 変更…集合時間も 三十分 早めて」がそのまま答え。"},
      {audio:"女：お客様、申し訳ございません。ご注文いただいた 商品ですが、在庫切れのため、お届けが 一週間ほど 遅れる 見込みです。",q:"商品が 遅れる 理由は 何ですか。",o:["在庫切れ","配送業者のミス","天候不順","注文の間違い"],a:0,exp:"「在庫切れのため…遅れる 見込み」がそのまま答え。"},
      {audio:"男：来月の 展示会の 準備、順調ですか。　女：はい、ほぼ 予定通りですが、パンフレットの 印刷だけ 少し 遅れて います。",q:"何が 遅れて いますか。",o:["パンフレットの印刷","会場の準備","商品の到着","スタッフの手配"],a:0,exp:"「パンフレットの 印刷だけ 少し 遅れています」がそのまま答え。"},
      {audio:"女：すみません、この 電車、次の 駅で 特急に 乗り換えられますか。　男：はい、次の 駅の 二番線から 特急が 出ますよ。",q:"特急は どこから 出ますか。",o:["次の駅の一番線","今の駅","終点","次の駅の二番線"],a:3,exp:"「次の 駅の 二番線から 特急が 出ます」がそのまま答え。"},
      {sec:"問題2　ポイント理解",audio:"女：この 病院、待ち時間が 長いですね。　男：医師の 数もありますが、予約システムが うまく 機能していないことが 一番の 原因だと思います。",q:"男の人は、待ち時間が 長い 一番の 原因は 何だと 考えていますか。",o:["予約システムがうまく機能していないこと","設備が古いこと","医師の数が少ないこと","患者数が多すぎること"],a:0,exp:"「予約システムが うまく 機能していないことが 一番の 原因」がそのまま答え。"},
      {audio:"男：この 商店街、閉店する 店が 増えていますね。　女：後継者不足が 一番の 原因だと 聞いています。",q:"女の人は、閉店が 増える 一番の 原因は 何だと 言っていますか。",o:["家賃の上昇","客の減少","後継者不足","競合の増加"],a:2,exp:"「後継者不足が一番の原因」がそのまま答え。"},
      {audio:"女：この 会社、離職率が 高いですね。　男：評価制度が 不透明なことが 一番の 原因だと思います。",q:"男の人は、離職率が 高い 一番の 原因は 何だと 考えていますか。",o:["勤務地が遠いこと","仕事がきついこと","評価制度が不透明なこと","給料が安いこと"],a:2,exp:"「評価制度が不透明なことが一番の原因」がそのまま答え。"},
      {audio:"男：この 地域、観光客が 減っていますね。　女：SNSでの 発信が 他の 観光地に 比べて 弱いことが 一番の 原因だと思います。",q:"女の人は、観光客が 減った 一番の 原因は 何だと 考えていますか。",o:["天候が悪いこと","SNSでの発信が弱いこと","交通の便が悪いこと","宿泊施設が少ないこと"],a:1,exp:"「SNSでの発信が弱いことが一番の原因」がそのまま答え。"},
      {audio:"女：この 製品、返品率が 高いですね。　男：使い方の 説明が 不足していることが 一番の 原因だと思います。",q:"男の人は、返品率が 高い 一番の 原因は 何だと 考えていますか。",o:["配送の遅さ","使い方の説明が不足していること","製品の欠陥","価格の高さ"],a:1,exp:"「使い方の説明が不足していることが一番の原因」がそのまま答え。"},
      {audio:"男：この プロジェクト、スケジュールが 遅れていますね。　女：初期段階での 要件定義が 不十分だったことが 一番の 原因だと思います。",q:"女の人は、スケジュールが 遅れた 一番の 原因は 何だと 考えていますか。",o:["人員が不足していたこと","初期段階での要件定義が不十分だったこと","予算が少なかったこと","技術的な問題があったこと"],a:1,exp:"「初期段階での要件定義が不十分だったことが一番の原因」がそのまま答え。"},
      {audio:"女：この 学校、退学者が 増えていますね。　男：入学前と 実際の 授業内容の ギャップが 一番の 原因だと 言われています。",q:"男の人は、退学者が 増えた 一番の 原因は 何だと 考えていますか。",o:["教師の質","入学前と実際の授業内容のギャップ","施設の古さ","経済的な理由"],a:1,exp:"「入学前と実際の授業内容のギャップが一番の原因」がそのまま答え。"},
      {sec:"問題3　概要理解",audio:"働き方改革が 進む 中、有給休暇の 取得率を 上げようとする 企業が 増えて いる。しかし、実際には 取りにくい 雰囲気が 残る 職場も 少なくなく、職場文化を 変える ことが 課題と なっている。",q:"この話は、主に何について述べていますか。",o:["退職金の制度","給料の計算方法","有給休暇取得を巡る企業の課題","採用面接の方法"],a:2,exp:"有給休暇取得の課題についての話。"},
      {audio:"AI技術の 発達により 翻訳作業の 効率が 向上した 一方、文化的な 背景を 考慮した 翻訳には まだ 人間の 手が 必要だと されている。",q:"この話は、主に何について述べていますか。",o:["AIの開発費用","AI翻訳の進歩と限界","外国語教育の方法","翻訳者の資格制度"],a:1,exp:"AI翻訳の進歩と限界についての話。"},
      {audio:"糖質を 控える 食生活を 実践する 人が 増えているが、極端な 制限は 体調不良を 招く 危険も あり、栄養バランスを 保ちながら 適度に 行う ことが 望ましいとされる。",q:"この話は、主に何について述べていますか。",o:["糖尿病の治療法","運動の効果","食品の値段","糖質制限の適切な行い方についての注意"],a:3,exp:"糖質制限の適切な方法についての話。"},
      {audio:"空き店舗を 利用した イベントが 定期的に 開かれ、地域の 活性化に つながって いる。行政も 改装費用の 一部を 補助する 制度を 設けて 後押ししている。",q:"この話は、主に何について述べていますか。",o:["人口減少の原因","店舗の家賃相場","空き店舗活用による地域活性化とその支援","商店街の歴史"],a:2,exp:"空き店舗活用と行政支援についての話。"},
      {sec:"問題4　発話表現",audio:"（え：取引先の 担当者に 資料の 送付を 依頼したい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["資料を 見ないで ください。","資料を 送って いただけますか。","資料は いりません。","資料を 捨てて ください。"],a:1,exp:"丁寧な依頼は「〜ていただけますか」。"},
      {audio:"（え：後輩の ミスを やんわりと 指摘したい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["それは嬉しいです。","おめでとうございます。","もう終わりです。","ここ、少し 確認した方が いいかもしれません。"],a:3,exp:"控えめに指摘する丁寧な表現。"},
      {audio:"（え：忙しい 上司に 話しかけたい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["おやすみなさい。","お忙しいところ 恐れ入ります。","いただきます。","おめでとうございます。"],a:1,exp:"忙しい相手への丁寧な前置き。"},
      {audio:"（え：会議で 意見が 対立している）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["おめでとうございます。","双方の 意見の 良い点を 取り入れられないでしょうか。","それは残念ですね。","もう決まりました。"],a:1,exp:"対立を和らげる建設的な提案。"},
      {audio:"（え：初めて 会う 取引先に 挨拶する）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["ただいま。","はじめまして、よろしくお願いいたします。","おかえりなさい。","おやすみなさい。"],a:1,exp:"初対面の丁寧な挨拶。"},
      {sec:"問題5　即時応答",audio:"この 件、来週まで 持ち越しという ことで よろしいでしょうか。",q:"最もよい 返事は どれですか。",o:["はい、それで結構です。","それはおめでとうございます。","いいえ、もう終わっています。","もう来週です。"],a:0,exp:"持ち越しの確認への自然な返事は「はい、それで結構です」。"},
      {audio:"念のため 伺いますが、この 内容で 間違いないでしょうか。",q:"最もよい 返事は どれですか。",o:["いいえ、まだ始まっていません。","はい、間違いありません。","もう終わった話です。","それはすごいですね。"],a:1,exp:"内容確認への自然な返事は「はい、間違いありません」。"},
      {audio:"申し訳ございませんが、少々 お時間を いただいております。",q:"最もよい 返事は どれですか。",o:["おめでとうございます。","それは嬉しいです。","承知しました。どのくらいかかりそうですか。","もう終わったんですね。"],a:2,exp:"時間を要するという連絡への自然な返事。"},
      {audio:"この 度は 貴重な ご意見を ありがとうございました。",q:"最もよい 返事は どれですか。",o:["いえ、お役に立てて何よりです。","もう終わりです。","それは残念ですね。","おめでとうございます。"],a:0,exp:"感謝の言葉への自然な返事。"},
      {audio:"恐縮ですが、こちらの 内容、少々 お待ちいただけますか。",q:"最もよい 返事は どれですか。",o:["もう終わりました。","はい、ゆっくりで構いません。","いいえ、待てません。","それはすごいですね。"],a:1,exp:"待ってほしいという依頼への自然な返事。"},
      {audio:"この 件、正式に 決定する 前に 一度 社内で 共有していただけますか。",q:"最もよい 返事は どれですか。",o:["それは大変ですね。","承知しました。共有の場を設けます。","もう共有しました。","おめでとうございます。"],a:1,exp:"共有依頼への自然な返事。"},
      {audio:"お客様、恐れ入りますが、こちらの 商品は 修理中でして、来週まで お渡しできません。",q:"最もよい 返事は どれですか。",o:["もう受け取りました。","おめでとうございます。","分かりました、来週まで待ちます。","それは残念ですね。"],a:2,exp:"待ち時間の連絡への自然な返事。"},
      {audio:"来月から 新しい 支店が オープンします。",q:"最もよい 返事は どれですか。",o:["それは残念ですね。","それは楽しみですね。","おめでとうございます。","もう閉店しました。"],a:1,exp:"良い知らせへの自然な反応。"}
    ]}
  ]
},
{
  id:"o-n3-3", lvl:"N3", title:"Examen oficial N3 · 3", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙）", minutes:30, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼の 意見は もっともだ。",o:["いけん","いぎ","いみ","いこう"],a:0,exp:"意見→いけん「opinión」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　解決方法を 考える。",o:["かいせつ","かいぎ","かいけつ","かいけい"],a:2,exp:"解決→かいけつ「resolución」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　原因を 調べる。",o:["げいいん","がんいん","げんいん","げんにん"],a:2,exp:"原因→げんいん「causa」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　新しい 方針を 発表した。",o:["ほうしき","ほうしん","ほうこう","ほうさく"],a:1,exp:"方針→ほうしん「política, dirección」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　効率を 上げる。",o:["こうそつ","こうりつ","こうりゅう","こうりょ"],a:1,exp:"効率→こうりつ「eficiencia」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　両者の 差は 小さい。",o:["べつ","さ","さい","ちが"],a:1,exp:"差→さ「diferencia」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　人気が ある 商品です。",o:["にんき","じんき","じんけ","ひとけ"],a:0,exp:"人気→にんき「popularidad」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　態度を 改める。",o:["たいたい","たいど","たいと","たいたく"],a:1,exp:"態度→たいど「actitud」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは どう かきますか。1・2・3・4から いちばん いい ものを 一つ えらんで ください。　こうりつを あげる。",o:["効率","高率","効律","公立"],a:0,exp:"こうりつ→効率「eficiencia」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　ほうしんを かえる。",o:["方信","方深","方針","放針"],a:2,exp:"ほうしん→方針「política」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　げんいんを しらべる。",o:["原員","元因","原因","現因"],a:2,exp:"げんいん→原因「causa」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　かいけつしました。",o:["解結","解決","開結","開決"],a:1,exp:"かいけつ→解決「resolución」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　たいどが わるい。",o:["体度","対度","待度","態度"],a:3,exp:"たいど→態度「actitud」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　りょうしゃの さ。",o:["両者","両社","良者","良社"],a:0,exp:"りょうしゃ→両者「ambas partes」。"},
      {sec:"問題3　文脈規定",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 状況を （　）に 判断した。",o:["的確","満足","納得","感動"],a:0,exp:"「的確に判断する」＝juzgar con precisión。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 会社の 方針は （　）だ。",o:["感動","満足","納得","明確"],a:3,exp:"「方針が明確だ」＝la política es clara。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は （　）を 得ず、腑に 落ちない 様子だった。",o:["理解","納得","承知","了承"],a:1,exp:"「納得を得ない」＝no resultar convincente。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 商品は （　）が 高い。",o:["人気","感想","態度","条件"],a:0,exp:"「人気が高い」＝tener mucha popularidad。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 難局を （　）乗り切った。",o:["急激に","巧みに","強引に","過剰に"],a:1,exp:"「巧みに」＝hábilmente。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 資料は （　）に まとめられている。",o:["簡潔","解決","納得","満足"],a:0,exp:"「簡潔にまとめられている」＝resumido de forma concisa。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女の 指摘は （　）を 突いていた。",o:["内心","中心","核心","本心"],a:2,exp:"「核心を突く」＝dar en el meollo。"},
      {sec:"問題4　言い換え類義",q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼の 意見は もっともだ。",o:["間違っている","理にかなっている","曖昧だ","おかしい"],a:1,exp:"「もっともだ」≒「理にかなっている」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は やんわりと 断った。",o:["強く、はっきりと","穏やかに、遠回しに","急に","何も言わずに"],a:1,exp:"「やんわりと」≒「穏やかに、遠回しに」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼女は したたかに 交渉を 進めた。",o:["無計画に","巧妙に、抜け目なく","率直に","乱暴に"],a:1,exp:"「したたかに」≒「巧妙に、抜け目なく」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は いたって 冷静だった。",o:["非常に","急に","少し","時々"],a:0,exp:"「いたって」≒「非常に」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は もはや 若くない。",o:["決して","すでに、今となっては","まだ","たぶん"],a:1,exp:"「もはや」≒「すでに」。"},
      {sec:"問題5　用法",q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「あくまで」",o:["これはあくまで私の意見です。","あくまで三時に会議がある。","あくまで明日雨が降る。","あくまで早く終わった。"],a:0,exp:"「あくまで」＝hasta el final、自分の立場を限定する表現。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「めったに」",o:["めったに明日会議がある。","彼はめったに怒らない。","めったに三時に来た。","めったに早く終わった。"],a:1,exp:"「めったに〜ない」＝raramente。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「どうにか」",o:["どうにか元気だ。","どうにか三時に来た。","どうにか明日雨が降る。","締め切りにどうにか間に合った。"],a:3,exp:"「どうにか」＝de alguna manera（苦労してぎりぎり達成）。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「かならずしも」",o:["かならずしも三時に会議がある。","かならずしも明日雨が降る。","高い商品がかならずしも良いとは限らない。","かならずしも早く終わった。"],a:2,exp:"「かならずしも〜とは限らない」＝no siempre。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「思いがけず」",o:["思いがけず明日雨が降る。","思いがけず賞をもらってしまった。","思いがけず早く終わった。","思いがけず三時に来た。"],a:1,exp:"「思いがけず」＝inesperadamente。"}
    ]},
    {id:"b", title:"言語知識（文法）・読解", minutes:70, questions:[
      {sec:"問題1　文法1",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は 若手（　）、堂々とした 態度で 発表した。",o:["というより","にとって","でありながら","にしたら"],a:2,exp:"「〜でありながら」＝a pesar de ser。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 結果は 偶然（　）必然の 産物だ。",o:["といえども","というのに","というより","というもの"],a:2,exp:"「〜というより」＝más que。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　規則の 大小（　）、この 問題は 軽視できない。",o:["にわたって","を問わず","につき","にそくして"],a:1,exp:"「〜を問わず」＝independientemente de。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 逆境（　）、決して 諦めなかった。",o:["はおろか","ときたら","にひきかえ","にあっても"],a:3,exp:"「〜にあっても」＝incluso en (adversidad)。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は 経験の 乏しさ（　）、見事な 対応を 見せた。",o:["にひきかえ","はおろか","ときたら","をものともせず"],a:3,exp:"「〜をものともせず」＝sin dejarse afectar por。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　規則を 破った（　）、罰せられるのは 当然だ。",o:["かたわら","以上","うちに","上に"],a:1,exp:"「〜以上」＝dado que。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 疲れていた（　）、最後まで やり遂げた。",o:["かたわら","にもかかわらず","とあって","ゆえに"],a:1,exp:"「〜にもかかわらず」＝a pesar de。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 問題は 議論すれば する（　）、複雑さを 増す ばかりだ。",o:["くらい","だけ","ほど","のみ"],a:2,exp:"「〜ば〜ほど」＝cuanto más...más。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼の 貢献（　）、この 成功は なかっただろう。",o:["なくして","ときたら","にひきかえ","はおろか"],a:0,exp:"「〜なくして（は）」＝sin (algo)。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 反対意見（　）、自説を 曲げなかった。",o:["にひきかえ","といえども","をよそに","にもまして"],a:2,exp:"「〜をよそに」＝haciendo caso omiso de。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼の 実績（　）、この 昇進は 妥当だろう。",o:["はおろか","をよそに","に照らせば","にひきかえ"],a:2,exp:"「〜に照らせば」＝a la luz de。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　規則に 反する（　）、罰則が 科される。",o:["次第では","場合には","ものは","につれ"],a:1,exp:"「〜場合には」＝en caso de。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は 若い（　）、しっかりした 考えを 持って いる。",o:["として","ながらも","からして","につれて"],a:1,exp:"「〜ながらも」＝aunque, si bien。"},
      {sec:"問題2　文法2（文の組み立て）",q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は　___　___　★　___　見事な 対応を 見せた。（1 経験の　2 をものともせず　3 乏しさ　4 も）",o:["をものともせず","経験の","も","乏しさ"],a:0,exp:"正しい順序：1経験の→3乏しさ→2をものともせず「経験の乏しさをものともせず」。★の位置には2「をものともせず」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼の　___　★　___　___　この 成功は なかっただろう。（1 貢献　2 なくして　3 も　4 は）",o:["貢献","なくして","は","も"],a:1,exp:"正しい順序：1貢献→2なくして「貢献なくして」。★の位置には2「なくして」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 結果は　___　___　★　___　産物だ。（1 より　2 偶然　3 必然の　4 という）",o:["必然の","より","偶然","という"],a:1,exp:"正しい順序：2偶然→4という→1より→3必然の「偶然というより必然の」。★の位置には1「より」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は　___　___　★　___　諦めなかった。（1 あっても　2 逆境に　3 決して　4 も）",o:["あっても","も","逆境に","決して"],a:0,exp:"正しい順序：2逆境に→1あっても→3決して「逆境にあっても決して」。★の位置には1「あっても」が入る。"},
      {sec:"問題3　文章の文法",passage:"最近、地域の 防災訓練に 参加する 機会が ありました。（1）、これほど 本格的な 訓練を 経験するのは 初めてでした。実際に 避難所での 生活を 体験する（2）、災害時に 何が 必要かを 具体的に イメージできる ように なりました。特に、情報伝達の 難しさを 実感しました。停電時には スマートフォンも 使えず、（3）ラジオや 紙の 掲示板が 重要な 役割を 果たす ことを 学びました。（4）、日頃からの 備えの 大切さを 改めて 感じました。今後は 家族とも 避難場所を（5）おきたいと 思います。",q:"（1）",o:["確実","正直","絶対","必ず"],a:1,exp:"「正直、これほど〜は初めてでした」＝a decir verdad。"},
      {q:"（2）",o:["ところで","もので","わけで","ことで"],a:3,exp:"「〜ことで」＝mediante, gracias a。"},
      {q:"（3）",o:["したがって","つまり","むしろ","または"],a:2,exp:"「むしろ」＝más bien（スマホより優先される手段を導く）。"},
      {q:"（4）",o:["改めて","以下","以後","以前"],a:0,exp:"「改めて」＝de nuevo, una vez más。"},
      {q:"（5）",o:["確認したまま","確認せず","確認して","確認しないで"],a:2,exp:"「〜ておきたい」に続く動詞は「て形」の「確認して」。"},
      {sec:"問題4　内容理解（短文）",passage:"組織の持続的な成長には、既存事業の深化と新規事業の探索、この二つを同時に追求する経営姿勢が求められるという考え方がある。",q:"筆者が求めている経営姿勢は何か。",o:["既存事業の深化と新規事業の探索を同時に追求する姿勢","新規事業のみに集中する姿勢","変化を避ける姿勢","既存事業のみに集中する姿勢"],a:0,exp:"「深化と探索、この二つを同時に追求する経営姿勢が求められる」がそのまま答え。"},
      {passage:"この地域では、若い世代の農業離れが進み、後継者不足が深刻な問題となっている。行政は新規就農者への補助金制度を設けるなど、対策に乗り出している。",q:"行政が行っている対策は何か。",o:["新規就農者への補助金制度","農地の売却促進","観光振興","米の輸入拡大"],a:0,exp:"「新規就農者への 補助金制度を 設ける」がそのまま答え。"},
      {passage:"最近、朝食を抜く人が増えている。しかし、朝食を抜くと集中力が下がることが研究で分かっている。",q:"研究で分かったことは何ですか。",o:["運動が集中力を高める","朝食は不要である","朝食を抜くと集中力が下がる","昼食が最も重要だ"],a:2,exp:"「朝食を 抜くと 集中力が 下がる ことが 研究で 分かって いる」がそのまま答え。"},
      {passage:"この会社では、社員の提案から生まれた新商品が好調な売れ行きを見せている。社員のアイデアを大切にする社風が実を結んだ形だ。",q:"新商品の好調な売れ行きは何の結果か。",o:["競合の撤退","社員のアイデアを大切にする社風","広告の効果","値下げ"],a:1,exp:"「社員のアイデアを大切にする社風が実を結んだ」がそのまま答え。"},
      {sec:"問題5　内容理解（中文）",passage:"近年、地方創生というキーワードのもと、様々な政策が打ち出されている。しかし、一律の施策を全国に適用するだけでは、各地域固有の課題に対応しきれないという指摘がある。地域によって異なる歴史や産業構造を無視した画一的な支援策は、必ずしも効果を上げにくい。",q:"筆者が指摘する課題は何か。",o:["一律の施策では各地域固有の課題に対応できないこと","政策が全く実施されていないこと","地方創生自体が不要であること","歴史や産業構造が全国で同じであること"],a:0,exp:"「一律の施策を全国に適用するだけでは、各地域固有の課題に対応しきれない」がそのまま答え。"},
      {q:"筆者が求めている支援策は何か。",o:["全国一律の画一的な支援","支援策の完全な廃止","地域の実情を踏まえたきめ細やかな支援","中央集権的な政策決定"],a:2,exp:"「それぞれの 地域の 実情を 踏まえた、きめ細やかな 支援」が求められている。"},
      {q:"この文章の要旨として最も適切なものはどれか。",o:["地域の歴史は無視してよい","地方創生政策はすべて失敗している","画一的な支援策が最も効果的だ","地方創生には行政と住民の協働が鍵となる"],a:3,exp:"行政と住民双方の協働の重要性を訴える文章。"},
      {passage:"組織における心理的安全性という概念が、近年注目を集めている。率直な意見を言っても罰せられないという確信をメンバーが共有している状態を指すが、これは単に居心地のよい環境を意味するわけではない。",q:"筆者が定義する心理的安全性とは何か。",o:["対立を一切避ける環境","上司にのみ意見が許される環境","率直な意見を言っても罰せられないという確信の共有","居心地のよいぬるま湯的な環境"],a:2,exp:"「率直な意見や懸念を口にしても…罰せられたりしない確信を、メンバーが共有している状態」が定義。"},
      {q:"筆者が心理的安全性について指摘する誤解は何か。",o:["単に居心地のよい環境だという誤解","効果がないという誤解","測定不可能だという誤解","上司にのみ必要だという誤解"],a:0,exp:"「単に居心地の良い、ぬるま湯的な環境を意味するわけではない」がそのまま答え。"},
      {sec:"問題6　内容理解（長文）",passage:"言葉というものは、常に変化し続けるものである。新しい表現の誕生を「言葉の乱れ」と断じて批判する声は、いつの時代にも存在してきた。しかし、こうした変化を単純に否定的に捉えることは、言語という生きたシステムの本質を見誤っているのではないだろうか。<br><br>言語は、話者たちの日々のコミュニケーションの中で、絶えず磨かれ、作り替えられていくものである。新しい語彙や言い回しが生まれるのは、既存の表現では言い表せない微妙なニュアンスを、話者たちが必要としているからにほかならない。<br><br>もちろん、あらゆる変化を無条件に肯定すべきだというわけではない。コミュニケーションの円滑さを著しく損なうような変化については、一定の抑制も必要だろう。重要なのは、変化そのものを一律に「乱れ」として排斥するのではなく、その変化が言語コミュニティにとってどのような意味を持つのかを、丁寧に見極めていく姿勢である。",q:"筆者が「言葉の乱れ」という捉え方についてどう考えているか。",o:["正しい捉え方であり支持すべきだ","古い言葉のみに当てはまる捉え方だ","言語という生きたシステムの本質を見誤った捉え方だ","言語学的に証明された事実だ"],a:2,exp:"「言語という生きたシステムの本質を見誤っているのではないか」がそのまま答え。"},
      {q:"筆者は新しい語彙が生まれる理由をどう説明しているか。",o:["若者が年配者に反抗したいから","言語学者が意図的に作るから","既存の表現では言い表せないニュアンスを話者が必要とするから","偶然生まれるだけで理由はない"],a:2,exp:"「既存の表現では言い表せない微妙なニュアンスを、話者たちが必要としているから」がそのまま答え。"},
      {q:"この文章全体を通して筆者が最も伝えたいことは何か。",o:["言語は変化させてはならない","言葉の乱れはすべて排除すべきだ","若者言葉は正しい日本語ではない","言語変化の意味を丁寧に見極める姿勢が重要だ"],a:3,exp:"「変化が言語コミュニティにとってどのような意味を持つのかを、丁寧に見極めていく姿勢」が結論。"},
      {sec:"問題7　情報検索",passage:"【地域防災訓練　参加案内】<br>・日時：来月第2土曜日 午前9時〜正午<br>・対象：市内在住・在勤者（未就学児は保護者同伴）<br>・内容：初期消火訓練、避難所体験、応急手当講習（希望者のみ、別途30分）<br>・申込み：不要（当日会場に直接お越しください）<br>・持ち物：動きやすい服装、飲み物。雨天の場合は一部内容を変更して実施。<br>・注意：応急手当講習の修了者には認定証を発行。認定証は3年間有効。",q:"応急手当講習を受けたい場合、どうすればよいか。",o:["別の日に予約する","事前に申込みが必要","当日会場で希望者として参加する","認定証を持参する"],a:2,exp:"「応急手当講習（希望者のみ、別途30分）」「申込み：不要」から、当日会場で参加すればよい。"},
      {q:"この案内から分かることとして正しいものはどれか。",o:["雨天の場合は中止になる","事前申込みが必須である","認定証は生涯有効である","雨天でも一部内容を変更して実施される"],a:3,exp:"「雨天の場合は一部内容を変更して実施」がそのまま該当。"}
    ]},
    {id:"c", title:"聴解", minutes:40, questions:[
      {sec:"問題1　課題理解",audio:"男：来週の 防災訓練、参加者リストの 確認は 済んでいますか。　女：まだです。今日中に 全員分を 確認します。",q:"女の人は このあと まず 何を しますか。",o:["訓練を延期する","案内状を作成する","会場を変更する","参加者リストを確認する"],a:3,exp:"「今日中に 全員分を 確認します」がそのまま答え。"},
      {audio:"女：この 契約書、サインする 前に もう一度 内容を 確認したいのですが。　男：もちろんです。念のため、法務部にも 目を通して もらいましょうか。",q:"男の人は このあと まず 何を しますか。",o:["契約書にサインする","契約を解除する","法務部に確認を依頼する","新しい契約書を作る"],a:2,exp:"「法務部にも 目を通して もらいましょうか」がそのまま答え。"},
      {audio:"男：来月の 展示会、ブースの デザイン案は 決まりましたか。　女：三案の 中から、社内アンケートで 人気だった ものに 決めようと 思っています。今日 結果を 集計します。",q:"女の人は このあと まず 何を しますか。",o:["業者に発注する","デザインをやり直す","展示会を中止する","アンケート結果を集計する"],a:3,exp:"「今日 結果を 集計します」がそのまま答え。"},
      {audio:"女：来週の 海外出張、ホテルの 予約は できていますか。　男：まだです。今日中に、会社指定の 旅行代理店に 連絡します。",q:"男の人は このあと まず 何を しますか。",o:["旅行代理店に連絡する","航空券を購入する","出張を中止する","現地の会社に連絡する"],a:0,exp:"「今日中に、会社指定の 旅行代理店に 連絡します」がそのまま答え。"},
      {audio:"男：新しい プロジェクトの メンバーですが、田中さんと 鈴木さんに 加えて、来月から 一人 増える 予定です。",q:"来月から どう なりますか。",o:["メンバーが一人減る","メンバーが一人増える","プロジェクトが終わる","田中さんが抜ける"],a:1,exp:"「来月から 一人 増える 予定」がそのまま答え。"},
      {audio:"女：この 資料、来週の 役員会議までに 仕上げないといけないんですが。　男：手伝いますよ。どこまで 進んでいますか。　女：本文は できているので、あとは 要約の 部分を お願いできますか。",q:"男の人は このあと 何を しますか。",o:["報告書の要約部分を書く","報告書を印刷する","会議の日程を変更する","本文を書き直す"],a:0,exp:"「要約の 部分を お願いできますか」への流れから、要約を担当する。"},
      {audio:"男：来週の セミナー、参加者数の 都合で 会場を 変更しました。詳細は メールで お送りした 通りです。",q:"会場を 変更した 理由は 何ですか。",o:["予算の問題","天候の問題","参加者数の都合","講師の都合"],a:2,exp:"「参加者数の 都合で 会場を 変更しました」がそのまま答え。"},
      {sec:"問題2　ポイント理解",audio:"男：この ソフトウェア、なかなか 普及しませんね。　女：価格の 高さも 一因ですが、一番の 問題は 操作が 複雑すぎることだと思います。",q:"女の人は、普及しない 一番の 原因は 何だと 言っていますか。",o:["広告が少ないこと","操作が複雑すぎること","価格が高いこと","競合が多いこと"],a:1,exp:"「一番の問題は操作が複雑すぎること」がそのまま答え。"},
      {audio:"女：この 地域、観光客が 減っていますね。　男：交通の 便も ありますが、一番 大きいのは、SNSでの 発信が 他の 観光地に 比べて 弱いことだと思います。",q:"男の人は、観光客が 減った 一番の 原因は 何だと 考えていますか。",o:["SNSでの発信が弱いこと","宿泊施設が少ないこと","交通の便が悪いこと","天候が悪いこと"],a:0,exp:"「一番大きいのは、SNSでの発信が…弱いこと」がそのまま答え。"},
      {audio:"男：この 製品、クレームが 増えていますね。　女：品質自体よりも、説明書の 翻訳が 不自然なことが 一番の 原因だと 聞いています。",q:"女の人は、クレームが 増えた 一番の 原因は 何だと 言っていますか。",o:["配送が遅いこと","製品の品質が悪いこと","価格が高すぎること","説明書の翻訳が不自然なこと"],a:3,exp:"「説明書の翻訳が不自然なことが一番の原因」がそのまま答え。"},
      {audio:"女：この 学校、退学者が 増えていますね。　男：経済的な 理由も ありますが、一番の 原因は、入学前と 実際の 授業内容の ギャップだと 言われています。",q:"男の人は、退学者が 増えた 一番の 原因は 何だと 考えていますか。",o:["入学前と実際の授業内容のギャップ","教師の質","経済的な理由","施設の古さ"],a:0,exp:"「一番の原因は、入学前と実際の授業内容のギャップ」がそのまま答え。"},
      {audio:"男：この 工場、生産効率が 落ちていますね。　女：設備の 老朽化も ありますが、一番の 原因は、作業手順の 見直しが 長年 されていないことだと思います。",q:"女の人は、生産効率低下の 一番の 原因は 何だと 考えていますか。",o:["作業手順の見直しがされていないこと","設備の老朽化","人員の不足","原材料の不足"],a:0,exp:"「一番の原因は、作業手順の見直しが長年されていないこと」がそのまま答え。"},
      {audio:"女：この 飲食店、客の 回転率が 悪いですね。　男：メニューの 品数も ありますが、一番の 問題は、会計システムに 時間が かかりすぎることだと思います。",q:"男の人は、回転率が 悪い 一番の 原因は 何だと 考えていますか。",o:["席の配置が悪いこと","メニューの品数が多いこと","スタッフが少ないこと","会計システムに時間がかかること"],a:3,exp:"「一番の問題は、会計システムに時間がかかりすぎること」がそのまま答え。"},
      {audio:"男：この 大学、志願者が 減っていますね。　女：立地の 問題も ありますが、一番 大きいのは、就職実績の 情報発信が 弱いことだと思います。",q:"女の人は、志願者が 減った 一番の 原因は 何だと 考えていますか。",o:["立地が悪いこと","就職実績の情報発信が弱いこと","学費が高いこと","定員が少ないこと"],a:1,exp:"「一番大きいのは、就職実績の情報発信が弱いこと」がそのまま答え。"},
      {sec:"問題3　概要理解",audio:"地方創生の 政策が 打ち出される 中、一律の 施策では 各地域固有の 課題に 対応しきれないという 指摘があり、地域の 実情を 踏まえた きめ細やかな 支援が 求められている。",q:"この話は、主に何について述べていますか。",o:["地方への交通アクセス","地方の人口統計","地方創生政策に必要な地域ごとの対応","地方の観光名所"],a:2,exp:"地方創生政策における地域固有の対応の必要性についての話。"},
      {audio:"組織の 心理的安全性とは、率直な 意見を 言っても 罰せられないという 確信を メンバーが 共有している 状態を 指すが、単に 居心地のよい 環境を 意味する わけではない。",q:"この話は、主に何について述べていますか。",o:["心理的安全性の本質についての考え方","会議の司会の進め方","人事評価の基準","給与制度の設計"],a:0,exp:"心理的安全性とは何かについての考察が主題。"},
      {audio:"言葉は 常に 変化し続ける ものであり、新しい 表現の 誕生を 単純に「乱れ」と 否定するのではなく、その 意味を 丁寧に 見極める 姿勢が 重要だという 指摘がある。",q:"この話は、主に何について述べていますか。",o:["方言の分類","外来語の増加","正しい敬語の使い方","言語変化を捉える姿勢についての考え方"],a:3,exp:"言語変化への向き合い方についての話。"},
      {audio:"地域の 防災訓練に 参加した ことで、災害時の 情報伝達の 難しさを 実感し、日頃からの 備えの 大切さを 改めて 感じたという 体験談が 語られている。",q:"この話は、主に何について述べていますか。",o:["防災訓練を通じて感じた備えの大切さ","地震の発生メカニズム","消防署の組織図","避難所の設備一覧"],a:0,exp:"防災訓練の体験を通じた気づきについての話。"},
      {sec:"問題4　発話表現",audio:"（え：会議室に 入る 前）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["おかえりなさい。","ただいま。","失礼します。","おやすみなさい。"],a:2,exp:"部屋に入る時は「失礼します」。"},
      {audio:"（え：後輩に 資料の 誤りを やんわりと 指摘したい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["おめでとうございます。","それは嬉しいです。","ここ、もう一度 確認した方が いいかもしれません。","もう終わりです。"],a:2,exp:"控えめに指摘する丁寧な表現。"},
      {audio:"（え：忙しい 同僚に 手伝いを 申し出たい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["いただきます。","何か 手伝えることは ありますか。","おやすみなさい。","おめでとうございます。"],a:1,exp:"手伝いを申し出る自然な表現。"},
      {audio:"（え：会議で 発言の 機会が 欲しい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["おやすみなさい。","いただきます。","おめでとうございます。","少し よろしいでしょうか。"],a:3,exp:"発言の許可を求める丁寧な表現。"},
      {audio:"（え：取引先に 資料の 到着が 遅れることを 伝える）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["おやすみなさい。","いただきます。","申し訳ございません、到着が少し遅れそうです。","おめでとうございます。"],a:2,exp:"遅延の連絡は謝罪から始めるのが自然。"},
      {sec:"問題5　即時応答",audio:"この 案件、少々 お時間を いただいても よろしいでしょうか。",q:"最もよい 返事は どれですか。",o:["もう終わりました。","おめでとうございます。","はい、構いません。","それは残念です。"],a:2,exp:"時間の猶予を求める依頼への自然な返事は「はい、構いません」。"},
      {audio:"この 資料、少し 修正した方が いいと思います。",q:"最もよい 返事は どれですか。",o:["もう修正済みです。","おめでとうございます。","それはすごいですね。","ありがとうございます。具体的に教えていただけますか。"],a:3,exp:"修正の指摘への自然な返事は、感謝しつつ詳細を尋ねる形。"},
      {audio:"この 件、来週まで 持ち越しという ことで よろしいでしょうか。",q:"最もよい 返事は どれですか。",o:["それはおめでとうございます。","いいえ、もう終わっています。","はい、それで結構です。","もう来週です。"],a:2,exp:"持ち越しの確認への自然な返事は「はい、それで結構です」。"},
      {audio:"念のため 伺いますが、この 内容で 間違いないでしょうか。",q:"最もよい 返事は どれですか。",o:["いいえ、まだ始まっていません。","はい、間違いありません。","もう終わった話です。","それはすごいですね。"],a:1,exp:"内容確認への自然な返事は「はい、間違いありません」。"},
      {audio:"この 度は 多大な ご協力を いただき、感謝申し上げます。",q:"最もよい 返事は どれですか。",o:["それは残念ですね。","もう終わりです。","いえ、こちらこそ良い経験になりました。","おめでとうございます。"],a:2,exp:"感謝の言葉への自然な返事。"},
      {audio:"来週の 予定、変更に なるかも しれません。",q:"最もよい 返事は どれですか。",o:["おめでとうございます。","それは羨ましいです。","もう変更しました。","分かりました。決まり次第 教えてください。"],a:3,exp:"予定変更の可能性への自然な返事。"},
      {audio:"この 資料で 問題ないでしょうか。",q:"最もよい 返事は どれですか。",o:["はい、問題ありません。","はい、げんきです。","いいえ、三時です。","ありがとう。"],a:0,exp:"確認への自然な返事。"},
      {audio:"何か お手伝い できることが あれば 言ってください。",q:"最もよい 返事は どれですか。",o:["それは大変でしたね。","ありがとうございます。では、これをお願いできますか。","おめでとうございます。","もう大丈夫だったんです。"],a:1,exp:"手伝いの申し出への自然な返事。"}
    ]}
  ]
},
{
  id:"o-n3-4", lvl:"N3", title:"Examen oficial N3 · 4", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙）", minutes:30, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　両国の 関係は 緊張している。",o:["こんちょう","きんきょう","きんちょう","きんじょう"],a:2,exp:"緊張→きんちょう「tensión」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　妥当な 判断だ。",o:["たどう","だとう","たとう","だどう"],a:1,exp:"妥当→だとう「razonable」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　検討します。",o:["けんこう","けんどう","けんとう","けんちょう"],a:2,exp:"検討→けんとう「estudio」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼の 意見は もっともだ。",o:["いぎ","いけん","いこう","いみ"],a:1,exp:"意見→いけん「opinión」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　実態を 調査する。",o:["しったい","じつたい","じったい","しつたい"],a:2,exp:"実態→じったい「situación real」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　抵抗を 感じる。",o:["ていぎ","ていこ","ていこう","ていかん"],a:2,exp:"抵抗→ていこう「resistencia」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　効率を 上げる。",o:["こうりょ","こうそつ","こうりゅう","こうりつ"],a:3,exp:"効率→こうりつ「eficiencia」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　規則を 守る。",o:["きりつ","きやく","ぎそく","きそく"],a:3,exp:"規則→きそく「norma」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは どう かきますか。1・2・3・4から いちばん いい ものを 一つ えらんで ください。　きんちょうしている。",o:["緊張","緊帳","近張","緊調"],a:0,exp:"きんちょう→緊張「tensión」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　だとうな はんだん。",o:["妥当","打当","打党","妥党"],a:0,exp:"だとう→妥当「razonable」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　けんとうします。",o:["検討","検答","健闘","見当"],a:0,exp:"けんとう→検討「estudio, consideración」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　じったいを ちょうさする。",o:["実体","実代","実大","実態"],a:3,exp:"じったい→実態「situación real」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　ていこうを かんじる。",o:["定抗","底抗","抵抗","低抗"],a:2,exp:"ていこう→抵抗「resistencia」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　きそくを まもる。",o:["期則","規則","規側","気則"],a:1,exp:"きそく→規則「regla」。"},
      {sec:"問題3　文脈規定",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼の 説明には （　）が ある。",o:["納得感","満足感","賛成感","説得力"],a:3,exp:"「説得力がある」＝tener poder de convicción。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 事業は （　）が 取れない。",o:["感想","採算","条件","態度"],a:1,exp:"「採算が取れない」＝no ser rentable。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は （　）として 批判に 耐えた。",o:["漠然","超然","毅然","茫然"],a:2,exp:"「毅然として」＝con firmeza, sin flaquear。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 提案には （　）が 多い。",o:["利点","難点","焦点","要点"],a:1,exp:"「難点が多い」＝tener muchos puntos problemáticos。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女の 話は （　）に 富んでいる。",o:["賛成","納得","示唆","満足"],a:2,exp:"「示唆に富む」＝rico en sugerencias。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 問題の （　）は 深刻だ。",o:["態度","実態","条件","感想"],a:1,exp:"「実態は深刻だ」＝la situación real es grave。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 難局を （　）乗り切った。",o:["急激に","過剰に","巧みに","強引に"],a:2,exp:"「巧みに」＝hábilmente。"},
      {sec:"問題4　言い換え類義",q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼の 話は 釈然と しなかった。",o:["面白かった","分かりやすかった","納得できなかった","感動した"],a:2,exp:"「釈然としない」≒「納得できなかった」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は 謙虚な 態度を 保っている。",o:["控えめで礼儀正しい","積極的な","無関心な","傲慢な"],a:0,exp:"「謙虚」≒「控えめで礼儀正しい」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　この 計画は 採算が 取れない。",o:["人気がない","利益が出ない","時間がかかる","評判が悪い"],a:1,exp:"「採算が取れない」≒「利益が出ない」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は 巧みに 危機を 乗り越えた。",o:["仕方なく","無理やり","偶然に","うまく、器用に"],a:3,exp:"「巧みに」≒「うまく、器用に」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼女の 意見は 核心を 突いていた。",o:["表面的な部分","不必要な部分","過去の部分","最も重要な部分"],a:3,exp:"「核心」≒「最も重要な部分」。"},
      {sec:"問題5　用法",q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「せめて」",o:["全部は無理でも、せめて半分だけでも終わらせたい。","せめて明日晴れるだろう。","せめて三人来た。","せめて怒って叫んだ。"],a:0,exp:"「せめて」＝al menos、最低限の希望を表す。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「案の定」",o:["案の定、彼は約束の時間に遅れた。","案の定、三時に会議がある。","案の定、早く終わった。","案の定、明日雨が降るだろう。"],a:0,exp:"「案の定」＝tal como se esperaba。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「にわかに」",o:["空がにわかにかき曇り、雨が降り出した。","にわかに明日会議がある。","にわかに早く終わった。","にわかに三時に来た。"],a:0,exp:"「にわかに」＝de repente。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「あえて」",o:["あえて三人来た。","あえて怒って叫んだ。","あえて明日晴れるだろう。","彼はあえて厳しい道を選んだ。"],a:3,exp:"「あえて」＝a propósito, deliberadamente。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「もっぱら」",o:["もっぱら早く終わった。","最近はもっぱら在宅で仕事をしている。","もっぱら明日雨が降る。","もっぱら三時に会議がある。"],a:1,exp:"「もっぱら」＝exclusivamente。"}
    ]},
    {id:"b", title:"言語知識（文法）・読解", minutes:70, questions:[
      {sec:"問題1　文法1",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 提案は 斬新である（　）、実現には 課題が 多い。",o:["べく","反面","つつ","あまり"],a:1,exp:"「〜反面」＝por otro lado。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は 若手（　）、堂々とした 態度で 発表した。",o:["にとって","というより","でありながら","にしたら"],a:2,exp:"「〜でありながら」＝a pesar de ser。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 反対意見（　）、自説を 曲げなかった。",o:["にもまして","にひきかえ","をよそに","といえども"],a:2,exp:"「〜をよそに」＝haciendo caso omiso de。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼の 実績（　）、この 昇進は 妥当だろう。",o:["にひきかえ","に照らせば","はおろか","をよそに"],a:1,exp:"「〜に照らせば」＝a la luz de。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　規則に 反する（　）、罰則が 科される。",o:["ものは","場合には","次第では","につれ"],a:1,exp:"「〜場合には」＝en caso de。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は 経験の 乏しさ（　）、見事な 対応を 見せた。",o:["にひきかえ","はおろか","をものともせず","ときたら"],a:2,exp:"「〜をものともせず」＝sin dejarse afectar por。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 問題は 議論すれば する（　）、複雑さを 増す ばかりだ。",o:["のみ","ほど","くらい","だけ"],a:1,exp:"「〜ば〜ほど」＝cuanto más...más。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 疲れていた（　）、最後まで やり遂げた。",o:["ゆえに","にもかかわらず","とあって","かたわら"],a:1,exp:"「〜にもかかわらず」＝a pesar de。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼の 貢献（　）、この 成功は なかっただろう。",o:["なくして","はおろか","ときたら","にひきかえ"],a:0,exp:"「〜なくして（は）」＝sin (algo)。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 逆境（　）、決して 諦めなかった。",o:["はおろか","ときたら","にひきかえ","にあっても"],a:3,exp:"「〜にあっても」＝incluso en (adversidad)。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　社員の 意見を 聞いた（　）で、決定する べきだ。",o:["上","上に","上で","上は"],a:2,exp:"「〜上で」＝tras hacer algo。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　連絡（　）、勝手に 予定を 変更しないで ください。",o:["もなく","抜きで","なしに","なくて"],a:2,exp:"「〜なしに」＝sin previo aviso。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 資料は 難しい 内容を 含む（　）、専門家 以外には 分かりにくい。",o:["ものなら","おかげで","かのように","ため"],a:3,exp:"「〜ため」＝por, debido a。"},
      {sec:"問題2　文法2（文の組み立て）",q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 提案は　___　___　★　___　実現には 課題が 多い。（1 反面　2 斬新である　3 も　4 実に）",o:["も","実に","斬新である","反面"],a:3,exp:"正しい順序：2斬新である→1反面「斬新である反面」。★の位置には1「反面」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は　___　★　___　___　自説を 曲げなかった。（1 反対意見　2 をよそに　3 も　4 の）",o:["反対意見","をよそに","の","も"],a:1,exp:"正しい順序：1反対意見→2をよそに「反対意見をよそに」。★の位置には2「をよそに」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼の　___　___　★　___　この 昇進は 妥当だろう。（1 に照らせば　2 実績　3 の　4 も）",o:["に照らせば","実績","の","も"],a:0,exp:"正しい順序：2実績→1に照らせば「実績に照らせば」。★の位置には1「に照らせば」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は　___　___　★　___　見事な 対応を 見せた。（1 経験の　2 も　3 乏しさ　4 をものともせず）",o:["をものともせず","乏しさ","も","経験の"],a:0,exp:"正しい順序：1経験の→3乏しさ→4をものともせず「経験の乏しさをものともせず」。★の位置には4「をものともせず」が入る。"},
      {sec:"問題3　文章の文法",passage:"最近、副業を 認める 企業が 増えている。従業員の スキルアップに つながる（1）、本業への 影響を 懸念する 声も 根強い。人事担当者たちは、両者の バランスを どう 取るか、模索を 続けている。（2）、労働時間の 管理を 徹底する ことが、副業解禁の（3）条件と なるだろう。（4）、社員自身が 自己管理能力を 高める ことも 同様に 重要だと 言えよう。制度と 意識、この 両輪が（5）初めて、副業は 双方にとって 有益な 仕組みと なるのである。",q:"（1）",o:["一方","一方は","一方で","一方に"],a:0,exp:"「〜一方」＝por un lado, mientras que por otro。"},
      {q:"（2）",o:["いずれにせよ","それとも","つまり","または"],a:0,exp:"「いずれにせよ」＝en cualquier caso。"},
      {q:"（3）",o:["原因","前提","結果","目的"],a:1,exp:"「前提条件」＝condición previa。"},
      {q:"（4）",o:["ところが","つまり","ただし","同時に"],a:3,exp:"追加の論点を導く「同時に」が文脈に合う。"},
      {q:"（5）",o:["消えて","対立して","分かれて","かみ合って"],a:3,exp:"「両輪がかみ合って」＝ambas ruedas encajan（比喩表現）。"},
      {sec:"問題4　内容理解（短文）",passage:"インターネット広告市場は急速に拡大しており、従来のテレビや新聞広告の市場規模を上回りつつある。企業側も広告戦略の見直しを迫られている。",q:"企業が迫られていることは何か。",o:["新聞購読の促進","テレビ広告の増加","広告戦略の見直し","広告費の削減"],a:2,exp:"「企業側も広告戦略の見直しを迫られている」がそのまま答え。"},
      {passage:"この大学では、留学生と日本人学生が共同で生活する寮を新設した。異文化交流を通じた相互理解の促進が狙いだ。",q:"新しい寮の目的は何か。",o:["施設の老朽化対策","異文化交流を通じた相互理解の促進","家賃収入の増加","留学生数の制限"],a:1,exp:"「異文化交流を通じた相互理解の促進が狙い」がそのまま答え。"},
      {passage:"この自治体では、子育て世帯への支援策として、保育料の無償化を実施した。その結果、若い世帯の転入が増加している。",q:"保育料無償化の結果、何が起きたか。",o:["若い世帯の転入増加","税収の減少","人口の減少","保育士の不足"],a:0,exp:"「若い世帯の転入が増加している」がそのまま答え。"},
      {passage:"この病院では、待ち時間の長さが患者の不満の原因となっていた。予約システムを改善した結果、待ち時間が大幅に短縮された。",q:"待ち時間が短縮された理由は何か。",o:["患者数の減少","予約システムの改善","診療時間の延長","医師の増員"],a:1,exp:"「予約システムを改善した結果、待ち時間が大幅に短縮された」がそのまま答え。"},
      {sec:"問題5　内容理解（中文）",passage:"少子高齢化が進む日本では、労働力不足を補うため、外国人労働者の受け入れ拡大が議論されている。一方で、言語や文化の違いによる職場での摩擦を懸念する声も根強い。受け入れ企業側には、単なる労働力としてではなく、共に働く仲間としての意識改革が求められている。",q:"外国人労働者の受け入れに関して懸念されていることは何か。",o:["賃金の高騰","言語や文化の違いによる摩擦","住居不足","治安の悪化"],a:1,exp:"「言語や文化の違いによる職場での摩擦を懸念する声も根強い」がそのまま答え。"},
      {q:"受け入れ企業側に求められていることは何か。",o:["賃金の引き下げ","共に働く仲間としての意識改革","労働力としてのみ扱うこと","受け入れの完全な停止"],a:1,exp:"「共に働く仲間としての意識改革が求められている」がそのまま答え。"},
      {q:"この文章の要旨として最も適切なものはどれか。",o:["外国人労働者受け入れには制度と意識の両面の変化が必要だ","外国人労働者の受け入れは不要である","賃金さえ上げれば全て解決する","言語の違いは全く問題にならない"],a:0,exp:"制度的な議論と意識改革の両方に言及している。"},
      {passage:"効率化ばかりを追求する現代社会において、雑談や余白といった一見無駄に見えるものの中にこそ、新しい発想の種が潜んでいるのではないかという指摘がある。無駄を一律に排除する姿勢は、かえって組織の創造性を損なう危険をはらんでいる。",q:"筆者が指摘する危険は何か。",o:["余白が多すぎること","効率化が全く進まないこと","雑談を推奨しすぎること","無駄を一律に排除することが創造性を損なうこと"],a:3,exp:"「無駄を一律に排除する姿勢は、かえって組織の創造性を損なう危険」がそのまま答え。"},
      {sec:"問題6　内容理解（長文）",passage:"組織における意思決定の遅さは、しばしば責任の所在の不明確さに起因すると言われる。誰もが責任を負いたがらない風土からは、迅速で大胆な決断は生まれにくい。この課題を打開するには、権限と責任を明確に紐づける制度設計が不可欠だとされる。<br><br>しかし、ここで注意すべき逆説がある。責任の所在を明確にしすぎると、今度は失敗を過度に恐れる萎縮した組織風土を生みかねないという点である。誰が責任者かが明確であればあるほど、その人物は挑戦的な決断を避け、無難な選択に流れやすくなる可能性がある。<br><br>したがって、真に求められているのは、単純な責任の明確化ではなく、挑戦の結果としての失敗を許容する文化と、責任の所在の明確化を両立させる、繊細なバランス感覚なのかもしれない。",q:"筆者が指摘する意思決定の遅さの原因は何か。",o:["予算の制約","責任の所在の不明確さ","情報不足","人材の不足"],a:1,exp:"「責任の所在の不明確さに起因する」がそのまま答え。"},
      {q:"筆者が指摘する「逆説」とは何か。",o:["責任を明確にしすぎると挑戦を避ける風土を生みかねないこと","制度設計は不要だということ","責任があいまいなほうが効率的なこと","権限が多いほど責任も軽くなること"],a:0,exp:"「責任の所在を明確にしすぎると…萎縮した組織風土を生みかねない」がそのまま答え。"},
      {q:"筆者が真に求めているものは何か。",o:["責任の所在を徹底的に明確にすること","責任の所在を完全に曖昧にすること","失敗を許容する文化と責任明確化のバランス","制度設計を放棄すること"],a:2,exp:"「失敗を許容する文化と、責任の所在の明確化を両立させる…バランス感覚」がそのまま答え。"},
      {sec:"問題7　情報検索",passage:"【市民オンライン講座　参加案内】<br>・対象：市内在住・在勤・在学の18歳以上（学生は学生証提示で受講料半額）<br>・講座：Ａ「防災の基礎」（全2回）／Ｂ「地域経済入門」（全4回）／Ｃ「日本語ボランティア養成」（全6回、修了者は登録ボランティアとして活動可）<br>・受講料：1講座につき2,000円（学生1,000円）。複数講座の同時申込みで500円割引（1講座あたり）。<br>・申込方法：市の公式サイトから、開講日の1週間前までに登録。定員に達し次第、締め切り。<br>・注意事項：全回数の3分の2以上出席しないと、修了証は発行されない。",q:"市内在住の大学生が、AとB講座を同時に申し込む場合の受講料はいくらか。",o:["2,000円","1,500円","4,000円","3,000円"],a:1,exp:"学生価格1,000円×2講座＝2,000円から、同時申込割引500円を差し引いて1,500円。"},
      {q:"Ｃ講座を修了した人ができることは何か。",o:["受講料の返金を受けること","無料で他の講座を受けること","講師になること","登録ボランティアとして活動すること"],a:3,exp:"「Ｃ講座のみ、修了証がボランティア登録の条件となる」がそのまま答え。"}
    ]},
    {id:"c", title:"聴解", minutes:40, questions:[
      {sec:"問題1　課題理解",audio:"男：今回の 事案に つきましては、社内調査委員会を 設置し、原因究明に あたる ことに いたしました。",q:"今後、何が 行われますか。",o:["社内調査委員会による原因究明","事業の即時停止","担当者の即時解雇","外部への責任転嫁"],a:0,exp:"「社内調査委員会を 設置し、原因究明に あたる」がそのまま答え。"},
      {audio:"女：来週の 出張ですが、飛行機と 新幹線、どちらが いいですか。　男：時間が ないので、飛行機に しましょう。あ、それと、ホテルの 予約も お願いできますか。",q:"女の人は このあと まず 何を しますか。",o:["出張の日程を決める","ホテルを予約する","新幹線の切符を買う","飛行機を予約する"],a:1,exp:"「ホテルの 予約も お願いできますか」がそのまま答え。"},
      {audio:"男：この 資料、何部 印刷すれば いいですか。　女：会議の 参加者は 十人なので、十部 お願いします。",q:"何部 印刷しますか。",o:["五部","二十部","十五部","十部"],a:3,exp:"「十部 お願いします」がそのまま答え。"},
      {audio:"女：明日の 会議、場所が 変わりました。三階の 会議室から 五階に 変わったので、気を つけて ください。",q:"明日の 会議は どこで ありますか。",o:["三階","一階","五階","地下"],a:2,exp:"「五階に 変わった」がそのまま答え。"},
      {audio:"男：来月の 展示会ですが、出展する 商品の リストを 今週中に 提出して ください。写真も 一緒に お願いします。",q:"今週中に 何を 提出しますか。",o:["商品リストと写真","予算案","会場の図面","参加者名簿"],a:0,exp:"「商品の リストを…写真も 一緒に」がそのまま答え。"},
      {audio:"女：この 契約書、内容を 確認したいのですが、専門用語が 多くて 分かりにくいです。　男：法務部に 相談して みましょう。",q:"この後 まず 何を しますか。",o:["契約書を破棄する","サインする","法務部に相談する","契約を延期する"],a:2,exp:"「法務部に 相談して みましょう」がそのまま答え。"},
      {audio:"男：来月の 出張の 交通手段、まだ 決めていませんでした。　女：新幹線の 方が 早いですが、予算的には 高速バスの 方が 安いです。上司に 確認してから 決めましょう。",q:"この後 まず 何を しますか。",o:["バスを予約する","出張を中止する","新幹線を予約する","上司に確認する"],a:3,exp:"「上司に 確認してから 決めましょう」がそのまま答え。"},
      {sec:"問題2　ポイント理解",audio:"女：この 商品、海外での 売り上げが 伸びませんね。　男：現地の 文化に 合わせた マーケティングが 不足していることが 一番の 原因だと思います。",q:"男の人は、海外での 売り上げが 伸びない 一番の 原因は 何だと 考えていますか。",o:["価格が高すぎること","現地の文化に合わせたマーケティングの不足","品質が悪いこと","競合が多いこと"],a:1,exp:"「現地の文化に合わせたマーケティングが不足していることが一番の原因」がそのまま答え。"},
      {audio:"男：この 部署、残業が 多いですね。　女：業務の 分担が 偏っていることが 一番の 原因だと思います。",q:"女の人は、残業が 多い 一番の 原因は 何だと 考えていますか。",o:["仕事の量が多すぎること","効率が悪いこと","業務の分担が偏っていること","人手が足りないこと"],a:2,exp:"「業務の分担が偏っていることが一番の原因」がそのまま答え。"},
      {audio:"女：この 大学、留学生が 減っていますね。　男：奨学金制度が 他大学に 比べて 少ないことが 一番の 原因だと思います。",q:"男の人は、留学生が 減った 一番の 原因は 何だと 考えていますか。",o:["講義が英語で行われないこと","授業料が高いこと","立地が悪いこと","奨学金制度が少ないこと"],a:3,exp:"「奨学金制度が他大学に比べて少ないことが一番の原因」がそのまま答え。"},
      {audio:"男：この プロジェクト、スケジュールが 遅れていますね。　女：初期段階での 要件定義が 不十分だったことが 一番の 原因だと思います。",q:"女の人は、スケジュールが 遅れた 一番の 原因は 何だと 考えていますか。",o:["技術的な問題があったこと","初期段階での要件定義が不十分だったこと","予算が少なかったこと","人員が不足していたこと"],a:1,exp:"「初期段階での要件定義が不十分だったことが一番の原因」がそのまま答え。"},
      {audio:"女：この 商品、SNSでの 評判が 悪いですね。　男：発売前の 情報公開が 不十分だったことが 一番の 原因だと思います。",q:"男の人は、評判が 悪い 一番の 原因は 何だと 考えていますか。",o:["価格が高すぎること","競合が優れていること","デザインが悪いこと","発売前の情報公開が不十分だったこと"],a:3,exp:"「発売前の情報公開が不十分だったことが一番の原因」がそのまま答え。"},
      {audio:"男：この 施設、利用者が 減っていますね。　女：予約システムが 使いにくいことが 一番の 原因だと思います。",q:"女の人は、利用者が 減った 一番の 原因は 何だと 考えていますか。",o:["設備が古いこと","場所が不便なこと","予約システムが使いにくいこと","料金が高いこと"],a:2,exp:"「予約システムが使いにくいことが一番の原因」がそのまま答え。"},
      {audio:"女：この 店、常連客が 減っていますね。　男：接客態度に 問題が あったことが 一番の 原因だと 聞いています。",q:"男の人は、常連客が 減った 一番の 原因は 何だと 考えていますか。",o:["価格の値上げ","接客態度の問題","立地の悪さ","メニューの変更"],a:1,exp:"「接客態度に問題があったことが一番の原因」がそのまま答え。"},
      {sec:"問題3　概要理解",audio:"副業を 認める 企業が 増える 中、労働者にも 企業にも メリットが あるという 意見が ある 一方、健康被害や 情報漏洩を 懸念する 声も あり、労働時間の 管理体制が 課題と なっている。",q:"この話は、主に何について述べていますか。",o:["副業禁止の歴史","副業の税制上の扱い","副業の探し方","副業解禁のメリットと課題"],a:3,exp:"副業解禁の利点と課題についての話。"},
      {audio:"組織の 意思決定の 遅さは、責任の 所在の 不明確さに 起因すると 言われる 一方、責任を 明確にしすぎると 挑戦を 避ける 風土を 生むという 逆説も ある。",q:"この話は、主に何について述べていますか。",o:["給与制度の設計","会議の効率的な進め方","人事評価の方法","組織の意思決定における責任と挑戦のバランス"],a:3,exp:"責任の明確化と挑戦を許容する文化のバランスについての話。"},
      {audio:"効率化を 追求する あまり、雑談や 余白と いった 一見 無駄に 見える ものの 中に ある 創造性の 芽まで 失われつつあるのではないかという 指摘が あり、効率と 余白の 共存が 求められている。",q:"この話は、主に何について述べていますか。",o:["過度な効率化が創造性を損なう可能性への懸念","効率的な会議の進め方","労働時間の短縮策","職場のルール作り"],a:0,exp:"効率偏重への懸念と、余白の価値についての話。"},
      {audio:"外国人労働者の 受け入れが 議論される 中、言語や 文化の 違いによる 摩擦を 懸念する 声も あり、企業側の 意識改革が 求められている。",q:"この話は、主に何について述べていますか。",o:["入国管理の手続き","外国人労働者受け入れに必要な企業の意識改革","労働ビザの種類","外国人労働者の給与水準"],a:1,exp:"受け入れ企業側の意識改革の必要性についての話。"},
      {sec:"問題4　発話表現",audio:"（え：取引先に 商品の 到着が 遅れることを 伝える）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["申し訳ございません、到着が少し遅れそうです。","おめでとうございます。","いただきます。","おやすみなさい。"],a:0,exp:"遅延の連絡は謝罪から始めるのが自然。"},
      {audio:"（え：会議室の 予約を 変更したい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["いただきます。","ごちそうさまでした。","すみません、予約を変更したいのですが。","おじゃまします。"],a:2,exp:"変更を依頼する時の表現。"},
      {audio:"（え：先輩の 意見に 賛成できない）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["少し別の考え方もあるかと思いますが。","おめでとうございます。","もう終わりです。","それは嬉しいです。"],a:0,exp:"控えめに異なる意見を述べる表現。"},
      {audio:"（え：新しい 同僚を 紹介したい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["いただきます。","おやすみなさい。","おめでとうございます。","こちら、新しく入った田中さんです。"],a:3,exp:"人を紹介する時の自然な表現。"},
      {audio:"（え：レストランで 予約の 確認を したい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["いただきます。","予約の確認をお願いしたいのですが。","おじゃまします。","ごちそうさまでした。"],a:1,exp:"予約確認を依頼する表現。"},
      {sec:"問題5　即時応答",audio:"この 件、担当者に 確認して いただけますか。",q:"最もよい 返事は どれですか。",o:["ありがとう。","はい、げんきです。","承知しました、確認いたします。","いいえ、三時です。"],a:2,exp:"依頼への承諾は「承知しました」。"},
      {audio:"来週の 予定、変更は ありませんか。",q:"最もよい 返事は どれですか。",o:["もう終わりました。","今のところありません。","それは残念ですね。","おめでとうございます。"],a:1,exp:"予定確認への自然な返事。"},
      {audio:"この 商品、いかがでしたか。",q:"最もよい 返事は どれですか。",o:["ありがとうございます。","はい、あそこです。","いいえ、三人です。","とても気に入りました。"],a:3,exp:"感想を聞かれたら感想を答える。"},
      {audio:"何か お手伝い できることは ありますか。",q:"最もよい 返事は どれですか。",o:["おめでとうございます。","それは大変ですね。","ありがとうございます、大丈夫です。","もう終わりました。"],a:2,exp:"申し出への自然な返事。"},
      {audio:"この 資料で 問題ないでしょうか。",q:"最もよい 返事は どれですか。",o:["はい、げんきです。","はい、問題ありません。","いいえ、三時です。","ありがとう。"],a:1,exp:"確認への自然な返事。"},
      {audio:"来月から 担当が 変わります。",q:"最もよい 返事は どれですか。",o:["おめでとうございます。","もう終わりました。","それは残念ですね。","承知しました。よろしくお願いします。"],a:3,exp:"担当変更の連絡への自然な返事。"},
      {audio:"少し 相談したいことが あるのですが。",q:"最もよい 返事は どれですか。",o:["はい、どうぞ。","もう終わりです。","それは嬉しいです。","おめでとうございます。"],a:0,exp:"相談を持ちかけられた際の自然な返事。"},
      {audio:"この 度は 大変 お世話に なりました。",q:"最もよい 返事は どれですか。",o:["おめでとうございます。","もっとやってください。","それは残念ですね。","いえ、こちらこそお世話になりました。"],a:3,exp:"感謝への自然な返事。"}
    ]}
  ]
},
{
  id:"o-n3-5", lvl:"N3", title:"Examen oficial N3 · 5", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙）", minutes:30, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　新しい 方針を 発表した。",o:["ほうさく","ほうしき","ほうしん","ほうこう"],a:2,exp:"方針→ほうしん「política, dirección」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　効率を 上げる。",o:["こうりょ","こうりゅう","こうそつ","こうりつ"],a:3,exp:"効率→こうりつ「eficiencia」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　両者の 差は 小さい。",o:["べつ","ちが","さ","さい"],a:2,exp:"差→さ「diferencia」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　態度を 改める。",o:["たいと","たいたく","たいたい","たいど"],a:3,exp:"態度→たいど「actitud」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　人気が ある 商品です。",o:["ひとけ","じんけ","じんき","にんき"],a:3,exp:"人気→にんき「popularidad」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　規則を 守る。",o:["きやく","きりつ","きそく","ぎそく"],a:2,exp:"規則→きそく「norma」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼の 意見は もっともだ。",o:["いこう","いけん","いぎ","いみ"],a:1,exp:"意見→いけん「opinión」。"},
      {q:"＿＿の ことばの よみかたと して 最もよい ものを、1・2・3・4から 一つ えらんで ください。　解決方法を 考える。",o:["かいせつ","かいけい","かいけつ","かいぎ"],a:2,exp:"解決→かいけつ「resolución」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは どう かきますか。1・2・3・4から いちばん いい ものを 一つ えらんで ください。　ほうしんを かえる。",o:["放針","方深","方針","方信"],a:2,exp:"ほうしん→方針「política」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　こうりつを あげる。",o:["効率","高率","公立","効律"],a:0,exp:"こうりつ→効率「eficiencia」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　たいどが わるい。",o:["対度","態度","待度","体度"],a:1,exp:"たいど→態度「actitud」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　きそくを まもる。",o:["規側","気則","期則","規則"],a:3,exp:"きそく→規則「regla」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　かいけつしました。",o:["解決","解結","開決","開結"],a:0,exp:"かいけつ→解決「resolución」。"},
      {q:"＿＿の ことばは どう かきますか。1・2・3・4から 一つ えらんで ください。　りょうしゃの さ。",o:["良者","良社","両社","両者"],a:3,exp:"りょうしゃ→両者「ambas partes」。"},
      {sec:"問題3　文脈規定",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼の 話は （　）を 得ず、聞いていて 疲れる。",o:["要因","要領","要素","要求"],a:1,exp:"「要領を得ない」＝no ir al grano。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 反対派の 説得に （　）を 尽くした。",o:["手","力","方法","知恵"],a:0,exp:"「手を尽くす」＝agotar todos los medios。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は （　）交渉を 進めた。",o:["無計画に","したたかに","率直に","乱暴に"],a:1,exp:"「したたかに」＝con astucia。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 結果には （　）の 余地が ない。",o:["不審","懐疑","疑い","疑問"],a:3,exp:"「疑問の余地がない」＝no hay lugar a dudas。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 難局を （　）乗り切った。",o:["急激に","巧みに","過剰に","強引に"],a:1,exp:"「巧みに」＝hábilmente。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女の 指摘は （　）を 突いていた。",o:["中心","本心","核心","内心"],a:2,exp:"「核心を突く」＝dar en el meollo。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 案には （　）の 余地が ある。",o:["検討","納得","満足","賛成"],a:0,exp:"「検討の余地がある」＝hay margen para reconsiderar。"},
      {sec:"問題4　言い換え類義",q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は 意外にも 早く 到着した。",o:["予想通り","思ったより","当然","わざと"],a:1,exp:"「意外にも」≒「思ったより」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼女は 慎重に 判断した。",o:["適当に","感情的に","急いで","注意深く"],a:3,exp:"「慎重に」≒「注意深く」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は 熱心に 勉強している。",o:["適当に","嫌々","たまに","一生懸命に"],a:3,exp:"「熱心に」≒「一生懸命に」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼女は 突然 泣き出した。",o:["予定通り","急に","ゆっくりと","わざと"],a:1,exp:"「突然」≒「急に」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ えらんで ください。　彼は しばしば 遅刻する。",o:["よく","一度も","たまに","絶対に"],a:0,exp:"「しばしば」≒「よく」。"},
      {sec:"問題5　用法",q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「たまたま」",o:["駅でたまたま昔の友人に会った。","たまたま明日雨が降る。","たまたま三時に会議がある。","たまたま早く終わった。"],a:0,exp:"「たまたま」＝por casualidad。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「思わず」",o:["思わず早く終わった。","思わず三時に会議がある。","思わず明日雨が降る。","驚いて、思わず声を上げてしまった。"],a:3,exp:"「思わず」＝sin querer, involuntariamente。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「あらかじめ」",o:["あらかじめ早く終わった。","あらかじめ明日会議がある。","あらかじめ三時に来た。","あらかじめ予約しておいたので、待たずに入れた。"],a:3,exp:"「あらかじめ」＝de antemano。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「案外」",o:["案外早く終わった。","この問題は案外簡単だった。","案外明日雨が降る。","案外三時に会議がある。"],a:1,exp:"「案外」＝contra lo esperado。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ えらんで ください。「せっかく」",o:["せっかく作ったのに、誰も食べてくれなかった。","せっかく早く終わった。","せっかく三時に会議がある。","せっかく明日雨が降る。"],a:0,exp:"「せっかく」＝con esfuerzo especial。"}
    ]},
    {id:"b", title:"言語知識（文法）・読解", minutes:70, questions:[
      {sec:"問題1　文法1",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　日本に 来た（　）、日本語が 上手に なった。",o:["ように","ために","せいで","おかげで"],a:3,exp:"「おかげで」＝gracias a（resultado positivo）。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　先生の 説明を 聞いて、やっと 意味が わかる（　）に なった。",o:["こと","もの","よう","はず"],a:2,exp:"「Vる+ようになる」＝llegar a (un estado)。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 忙しい（　）、いつも 元気だ。",o:["ことに","わりに","もので","ばかりに"],a:1,exp:"「〜わりに」＝considerando que。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　規則を 破った（　）、罰せられるのは 当然だ。",o:["うちに","上に","以上","かたわら"],a:2,exp:"「〜以上」＝dado que。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は 若い（　）、しっかりした 考えを 持っている。",o:["につれて","として","ながらも","からして"],a:2,exp:"「〜ながらも」＝aunque, si bien。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　努力した（　）、結果が 出なかった。",o:["ことから","につけ","ものの","ばかりに"],a:2,exp:"「〜ものの」＝aunque, si bien。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 資料は 難しい 内容を 含む（　）、専門家 以外には 分かりにくい。",o:["ため","かのように","ものなら","おかげで"],a:0,exp:"「〜ため」＝por, debido a。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は 部長（　）、部下からの 信頼も 厚い。",o:["というより","にしたら","でありながら","にとって"],a:2,exp:"「〜でありながら」＝a pesar de ser。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　連絡（　）、勝手に 予定を 変更しないで ください。",o:["なくて","なしに","抜きで","もなく"],a:1,exp:"「〜なしに」＝sin previo aviso。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は 経験の 浅い（　）、よく やった 方だ。",o:["にしては","につき","にとって","にかけては"],a:0,exp:"「〜にしては」＝para ser (algo)。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　努力した（　）で、結果が 出ないことも ある。",o:["ところ","うえ","もの","はず"],a:0,exp:"「〜たところで」＝aunque se haga。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼の 話は 具体性に （　）、説得力に 欠ける。",o:["欠いて","欠く","欠かず","欠け"],a:3,exp:"連用中止形「欠け」で文をつなぐ。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 説明は 具体性に 欠ける（　）分かりにくい。",o:["ため","おかげで","かわりに","ことなく"],a:0,exp:"「〜ため」＝debido a。"},
      {sec:"問題2　文法2（文の組み立て）",q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼女は　___　___　★　___　よく やった 方だ。（1 経験の　2 浅い　3 にしては　4 も）",o:["浅い","も","経験の","にしては"],a:3,exp:"正しい順序：1経験の→2浅い→3にしては「経験の浅いにしては」。★の位置には3「にしては」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　規則を　___　★　___　___　罰せられて 当然だ。（1 破った　2 以上　3 は　4 も）",o:["は","も","破った","以上"],a:3,exp:"正しい順序：1破った→2以上→3は「破った以上は」。★の位置には2「以上」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　彼は　___　___　★　___　いつも 元気だ。（1 わりに　2 忙しい　3 も　4 とても）",o:["も","とても","忙しい","わりに"],a:3,exp:"正しい順序：2忙しい→1わりに「忙しいわりに」。★の位置には1「わりに」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ えらんで ください。　この 資料は　___　___　★　___　分かりにくい。（1 内容を　2 難しい　3 ため　4 含む）",o:["難しい","含む","ため","内容を"],a:2,exp:"正しい順序：2難しい→1内容を→4含む→3ため「難しい内容を含むため」。★の位置には3「ため」が入る。"},
      {sec:"問題3　文章の文法",passage:"最近、地域の 図書館で ボランティア活動を 始めました。きっかけは、（1）近所の 人に 誘われた ことです。最初は （2）気持ちで 参加しましたが、参加してみると、思った（3）楽しく、本の 整理を 通して 地域の 人と 交流する 良い 機会だと 感じました。（4）、月に 二回は 図書館に 通うように しています。これからも、無理のない 範囲で（5）続けたいと 思います。",q:"（1）",o:["わざと","必ず","絶対に","たまたま"],a:3,exp:"「たまたま」＝por casualidad。"},
      {q:"（2）",o:["強い","軽い","弱い","重い"],a:1,exp:"「軽い気持ちで」＝con una actitud despreocupada。"},
      {q:"（3）",o:["くらい","ばかり","ほど","より"],a:3,exp:"「思ったより」＝más de lo que pensaba。"},
      {q:"（4）",o:["以後","以前","以来","以下"],a:2,exp:"「以来」＝desde entonces。"},
      {q:"（5）",o:["活動を","活動は","活動が","活動へ"],a:0,exp:"「活動を続ける」動詞の対象を示す「を」。"},
      {sec:"問題4　内容理解（短文）",passage:"最近、健康の ために 毎朝 走って います。最初は 大変でしたが、今は 気持ちよく 走れるように なりました。",q:"この 人は 今、走ることに ついて どう 感じて いますか。",o:["もうやめたいと感じている","気持ちよく感じている","つまらないと感じている","大変だと感じている"],a:1,exp:"「今は 気持ちよく 走れるように なりました」がそのまま答え。"},
      {passage:"来月から 新しい プロジェクトが 始まります。準備することが 多く、みんな 忙しく なりそうです。",q:"来月から どう なりそうですか。",o:["人が減る","休みが増える","プロジェクトが終わる","みんな忙しくなる"],a:3,exp:"「みんな 忙しく なりそうです」がそのまま答え。"},
      {passage:"アパートの 隣に 新しい 家族が 引っ越して来ました。まだ 挨拶を して いないので、今度 会ったら 挨拶しようと 思います。",q:"この 人は これから 何を する つもりですか。",o:["家族を招待する","何もしない","隣の家族に挨拶する","引っ越しを手伝う"],a:2,exp:"「今度 会ったら 挨拶しようと 思います」がそのまま答え。"},
      {passage:"最近、電子書籍を 読む 人が 増えて います。紙の 本と 違い、たくさんの 本を 持ち運べるのが 便利だそうです。",q:"電子書籍の 便利な 点は 何ですか。",o:["値段が安い","紙より軽い","たくさんの本を持ち運べる","目にやさしい"],a:2,exp:"「たくさんの 本を 持ち運べるのが 便利」がそのまま答え。"},
      {sec:"問題5　内容理解（中文）",passage:"近年、リモートワークを 導入する 企業が 増えている。通勤の 負担が 減る 一方で、仕事と 家庭の 境界が あいまいに なるという 課題も 指摘されている。企業側も、社員が 適切に 休息を 取れるよう、就業時間外の 連絡を 控える などの 対策を 始めている。",q:"リモートワークの 課題として 挙げられているのは 何か。",o:["通勤時間が長くなること","社員が減ること","仕事と家庭の境界があいまいになること","給料が下がること"],a:2,exp:"「仕事と 家庭の 境界が あいまいに なる という 課題」がそのまま答え。"},
      {q:"企業側が 始めている 対策は 何か。",o:["給料を減らすこと","リモートワークを廃止すること","就業時間外の連絡を控えること","出勤日数を増やすこと"],a:2,exp:"「就業時間外の 連絡を 控える などの 対策」がそのまま答え。"},
      {q:"この文章の 要旨として 最も適切な ものは どれか。",o:["リモートワークには利点と課題の両面があり企業が対策を進めている","通勤の負担は増加している","リモートワークは廃止すべきだ","リモートワークに課題は存在しない"],a:0,exp:"利点・課題・対策の3点を扱っている。"},
      {passage:"この地域は昔から農業が盛んで、特に米作りで知られている。しかし近年、若い世代の農業離れが進み、後継者不足が深刻な問題となっている。行政は新規就農者への補助金制度を設けるなど、対策に乗り出している。",q:"この地域の問題は何か。",o:["土地が狭いこと","米の生産量が多すぎること","後継者不足","観光客が少ないこと"],a:2,exp:"「後継者不足が 深刻な 問題」がそのまま答え。"},
      {q:"行政が行っている対策は何か。",o:["新規就農者への補助金制度","観光振興","米の輸入拡大","農地の売却促進"],a:0,exp:"「新規就農者への 補助金制度を 設ける」がそのまま答え。"},
      {sec:"問題6　内容理解（長文）",passage:"読書は 想像力を 育てると 言われる。文字だけの 情報から 場面を 思い描く 過程が、脳を 活性化させるからだ。映像作品では すでに 完成された 映像が 提示されるのに 対し、小説を 読む 際には、読者一人ひとりが 自分の 経験や 知識を もとに、独自の イメージを 作り上げる 必要が ある。<br><br>この 想像の プロセスこそが、読書の 最大の 魅力であり、同時に 教育的な 価値でも あると 言えるだろう。子どもの 読書量の 減少が しばしば 問題視されるが、それは 単に 娯楽が 減った ということ 以上に、想像力を 育む 機会が 失われつつある ことを 意味しているのかもしれない。<br><br>もちろん、映像作品にも 独自の 価値が あり、読書が 唯一の 教育手段だと 主張する つもりは ない。しかし、少なくとも、両者が それぞれ 異なる 種類の 認知能力を 育てて いる ことは 意識しておく べきだろう。",q:"読書が 想像力を 育てる 理由は 何か。",o:["場面を思い描く過程が脳を活性化させるから","時間がかかるから","字が大きいから","本の内容が面白いから"],a:0,exp:"「場面を 思い描く 過程が、脳を 活性化させるから」がそのまま答え。"},
      {q:"筆者が 子どもの 読書量減少について 述べていることは 何か。",o:["全く問題ではない","映像作品の増加が原因だ","単なる娯楽の減少に過ぎない","想像力を育む機会が失われつつあることを意味するかもしれない"],a:3,exp:"「想像力を 育む 機会が 失われつつある ことを 意味しているのかもしれない」がそのまま答え。"},
      {q:"筆者は 映像作品について どう考えているか。",o:["読書の代わりになるべきだ","全く価値がない","読書より劣っている","独自の価値があり読書とは異なる認知能力を育てる"],a:3,exp:"「映像作品にも 独自の 価値が あり…異なる 種類の 認知能力を 育てている」がそのまま答え。"},
      {sec:"問題7　情報検索",passage:"【地域スポーツセンター　利用案内】<br>・利用時間：午前9時〜午後9時<br>・休館日：毎月 第3月曜日<br>・利用料金：一般 500円、学生 300円（学生証提示）、65歳以上 200円<br>・回数券：11回分の料金で 12回 利用できる（本人のみ有効）<br>・団体利用：5名以上の場合、事前予約が必要。団体割引で 1人あたり 100円引き。<br>・注意：更衣室のロッカーは 100円硬貨が必要（使用後 返却されます）。",q:"65歳の 人が 5人の 団体で 利用する 場合、1人あたりの 料金は いくらか。",o:["200円","100円","300円","500円"],a:1,exp:"65歳以上の料金200円から団体割引100円引きで100円。"},
      {q:"この 案内から 分かる ことは 何か。",o:["ロッカーの100円硬貨は使用後返却される","休館日は毎週月曜日","団体利用に予約は不要","回数券は誰でも使える"],a:0,exp:"「ロッカーは 100円硬貨が必要（使用後 返却されます）」がそのまま該当。"}
    ]},
    {id:"c", title:"聴解", minutes:40, questions:[
      {sec:"問題1　課題理解",audio:"男：来週の 展示会の 準備、順調ですか。　女：はい、ほぼ 予定通りですが、パンフレットの 印刷だけ 少し 遅れています。今日中に 印刷会社に 確認の 連絡を 入れます。",q:"女の人は このあと、まず 何を しますか。",o:["展示会を延期する","パンフレットを作り直す","印刷会社に連絡する","会場を変更する"],a:2,exp:"「今日中に 印刷会社に 確認の 連絡を 入れます」がそのまま答え。"},
      {audio:"女：すみません、この 資料、コピーして いただけますか。　男：はい、何部 必要ですか。　女：十部 お願いします。",q:"男の人は このあと 何を しますか。",o:["参加者に連絡する","資料を書き直す","会議を中止する","資料を十部コピーする"],a:3,exp:"「十部 お願いします」への流れから、コピーする。"},
      {audio:"男：来月の セミナー、会場の 候補が 二つ あるんですが。　女：それぞれの 収容人数と 料金を 比較した 資料を 作ってもらえますか。",q:"男の人は このあと 何を しますか。",o:["参加者を募集する","会場の比較資料を作る","会場を予約する","セミナーを中止する"],a:1,exp:"「比較した資料を作ってもらえますか」への流れから、比較資料を作成する。"},
      {audio:"女：来週の 出張、ホテルの 予約は できていますか。　男：まだです。今日中に 旅行代理店に 連絡します。",q:"男の人は このあと まず 何を しますか。",o:["新幹線を予約する","旅行代理店に連絡する","ホテルをキャンセルする","出張を延期する"],a:1,exp:"「今日中に 旅行代理店に 連絡します」がそのまま答え。"},
      {audio:"男：新しい プロジェクトの 進め方に ついて 相談したいのですが。　女：まずは 関係部署に 意見を 聞いてから、来週の 会議で 方向性を 決めましょう。",q:"来週の 会議で 何を 決めますか。",o:["予算の金額","プロジェクトの方向性","関係部署の担当者","会議の日程"],a:1,exp:"「来週の 会議で 方向性を 決めましょう」がそのまま答え。"},
      {audio:"女：この 契約書、サインする 前に もう一度 内容を 確認したいのですが。　男：もちろんです。念のため、法務部にも 目を通して もらいましょうか。",q:"男の人は このあと まず 何を しますか。",o:["契約を解除する","新しい契約書を作る","法務部に確認を依頼する","契約書にサインする"],a:2,exp:"「法務部にも 目を通して もらいましょうか」がそのまま答え。"},
      {audio:"男：来週の 面接、履歴書の 確認は 済んでいますか。　女：まだです。今日の 午後、全員分に 目を通します。",q:"履歴書の 確認は いつ しますか。",o:["明日の朝","来週の月曜日","今日の午後","もう済んでいる"],a:2,exp:"「今日の 午後、全員分に 目を通します」がそのまま答え。"},
      {sec:"問題2　ポイント理解",audio:"女：今回の プロジェクト、予定より 遅れていますね。原因は 何だと 思いますか。　男：人手不足も 一因ですが、一番 大きいのは 仕様変更が 何度も あったことだと 思います。",q:"男の人は、プロジェクトが 遅れている 一番の 原因は 何だと 言っていますか。",o:["設計者が交代したこと","予算が足りないこと","人手が不足していること","仕様変更が何度もあったこと"],a:3,exp:"「一番 大きいのは 仕様変更が 何度も あったこと」がそのまま答え。"},
      {audio:"男：新しい 店舗の 場所、駅前と 郊外の ショッピングモール、どちらに しますか。　女：家賃は 駅前の方が 高いですが、集客力を 考えると 駅前の 一択でしょう。",q:"女の人が 駅前を 選ぶ 一番の 理由は 何ですか。",o:["集客力が高く長期的に採算が取れるから","面積が広いから","家賃が安いから","駅から近く通勤が楽だから"],a:0,exp:"「集客力を 考えると…駅前の 一択でしょう」がそのまま答え。"},
      {audio:"男：今度の 講演会、参加者が 少なかったですね。　女：告知の 時期が 遅かったのが 一番の 問題だったと 思います。",q:"女の人は、参加者が 少なかった 一番の 原因は 何だと 言っていますか。",o:["日程が悪かったこと","会場が悪かったこと","講師の話がつまらなかったこと","告知の時期が遅かったこと"],a:3,exp:"「告知の 時期が 遅かったのが 一番の 問題」がそのまま答え。"},
      {audio:"女：新商品の 売り上げ、思ったほど 伸びていませんね。　男：価格設定は 問題ないと 思うんですが、広告の 打ち方が 弱かったんじゃないかと。",q:"男の人は、売り上げが 伸びない 一番の 原因は 何だと 考えていますか。",o:["競合が多いこと","商品の品質が悪いこと","広告がターゲット層に届いていないこと","価格が高すぎること"],a:2,exp:"「広告の 打ち方が 弱かった」が原因として挙げられている。"},
      {audio:"男：来期の 予算案、営業部からの 要望が 通らなかったようですね。　女：全社的に コスト削減の 方針が 出ていて、どの 部署も 一律で 減らされる ことに なったみたいです。",q:"営業部の 要望が 通らなかった 一番の 理由は 何ですか。",o:["予算案の書き方が悪かったから","他部署の予算が優先されたから","全社的なコスト削減方針があったから","営業部の実績が悪かったから"],a:2,exp:"「全社的に コスト削減の 方針が 出ていて…一律で 減らされる」がそのまま理由。"},
      {audio:"女：この 機械、最近 よく 故障しますね。　男：使用年数も ありますが、それより 湿度の 高い 環境で 使い続けたことが 大きいと思います。",q:"男の人は、機械が 故障する 一番の 原因は 何だと 考えていますか。",o:["湿度の高い環境で使い続けたこと","使用年数が長いこと","操作方法が間違っていたこと","部品の品質が悪いこと"],a:0,exp:"「それより 湿度の 高い 環境で 使い続けたことが 大きい」が原因として挙げられている。"},
      {audio:"男：この 店、最近 お客さんが 減っていますね。　女：近くに 大型スーパーが できたことが 一番 大きいと思います。",q:"女の人は、客が 減った 一番の 原因は 何だと 考えていますか。",o:["商品の質が落ちたこと","営業時間が短くなったこと","スタッフが減ったこと","近くに大型スーパーができたこと"],a:3,exp:"「近くに 大型スーパーが できたことが 一番大きい」がそのまま答え。"},
      {sec:"問題3　概要理解",audio:"近年、企業の 意思決定に データ分析を 活用する 動きが 加速している。ただし、データに 過度に 依存する あまり、現場の 経験や 直感に 基づく 判断が 軽視される 傾向も 見られ、両者の バランスが 課題と なっている。",q:"この話は、主に何について述べていますか。",o:["経験や直感の完全な排除","データと経験・直感のバランス","データ分析の技術不足","意思決定の遅さ"],a:1,exp:"データと経験・直感のバランスについての話。"},
      {audio:"言葉は 常に 変化し続ける ものである。新しい 表現の 誕生を「乱れ」と 断じるのは 早計であり、むしろ 言語の 生命力の 証と 見るべきだろう。",q:"この話は、主に何について述べていますか。",o:["若者言葉の具体的な例","言葉の変化についての一つの見方","言語教育の方法","正しい日本語の使い方の解説"],a:1,exp:"言葉の変化を肯定的に捉える視点についての話。"},
      {audio:"科学技術の 進歩は 人類に 多大な 恩恵を もたらしてきたが、同時に 新たな 倫理的 課題も 生み出して きた。技術の 可能性と 社会が 許容すべき 範囲との 線引きを、我々は 常に 問い続ける 必要が ある。",q:"この話は、主に何について述べていますか。",o:["技術の可能性と社会的許容の線引きを問い続ける必要性","倫理的課題は存在しないということ","科学技術の発展を止めるべきだということ","技術の恩恵のみを重視すべきこと"],a:0,exp:"技術の可能性と社会的許容のバランスについての話。"},
      {audio:"読書は 想像力を 育てると 言われる。文字だけの 情報から 場面を 思い描く 過程が、脳を 活性化させるからだ。子どもの 読書量の 減少が しばしば 問題視されるのも、この点と 関係が あるのかもしれない。",q:"この話は、主に何について述べていますか。",o:["図書館の利用方法","本の選び方","読書の歴史","読書が想像力を育てる仕組みとその意義"],a:3,exp:"読書と想像力の関係についての話。"},
      {sec:"問題4　発話表現",audio:"（え：後輩が 大事な 会議に 遅刻しそうだ）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["急いだ方がいいですよ。","おやすみなさい。","いただきます。","おめでとうございます。"],a:0,exp:"急いだ方がいいと助言する表現。"},
      {audio:"（え：会議室に 入る 前）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["ただいま。","失礼します。","おかえりなさい。","おやすみなさい。"],a:1,exp:"部屋に入る時は「失礼します」。"},
      {audio:"（え：先輩に 仕事の 相談を したい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["少しご相談したいことがあるのですが。","おやすみなさい。","いただきます。","おめでとうございます。"],a:0,exp:"相談を持ちかける丁寧な表現。"},
      {audio:"（え：会議で 反対意見を 言いたい）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["少し違う意見なのですが。","それは嬉しいです。","もう終わりです。","おめでとうございます。"],a:0,exp:"控えめに反対意見を述べる表現。"},
      {audio:"（え：電車で お年寄りに 席を 譲る）　こういう とき、何と 言いますか。",q:"何と 言いますか。",o:["おじゃまします。","ありがとう。","すみません。","どうぞ、お座りください。"],a:3,exp:"席を譲る時は「どうぞ、お座りください」。"},
      {sec:"問題5　即時応答",audio:"この 資料、目を通して いただけましたか。",q:"最もよい 返事は どれですか。",o:["いいえ、三時です。","ありがとう。","はい、拝見しました。","はい、げんきです。"],a:2,exp:"確認への自然な返事は「はい、拝見しました」。"},
      {audio:"来週、お時間 いただけますか。",q:"最もよい 返事は どれですか。",o:["おめでとうございます。","はい、大丈夫です。","それは残念ですね。","もう終わりました。"],a:1,exp:"時間の依頼への自然な返事。"},
      {audio:"この 案、いかがでしょうか。",q:"最もよい 返事は どれですか。",o:["それは嬉しいです。","おめでとうございます。","もう決まりました。","良いと思いますが、少し気になる点があります。"],a:3,exp:"意見を求められた際の自然な返事。"},
      {audio:"ご迷惑を おかけして 申し訳ありません。",q:"最もよい 返事は どれですか。",o:["おめでとうございます。","もっとやってください。","いえ、気にしないでください。","それは嬉しいです。"],a:2,exp:"謝罪への自然な返事。"},
      {audio:"何か お困りのことは ありますか。",q:"最もよい 返事は どれですか。",o:["おめでとうございます。","それは残念ですね。","実は、少し分からないことがあります。","もう終わりです。"],a:2,exp:"気遣いへの自然な返事。"},
      {audio:"この 件、担当を 代わって いただけますか。",q:"最もよい 返事は どれですか。",o:["はい、承知しました。","いいえ、三時です。","ありがとう。","はい、げんきです。"],a:0,exp:"依頼への承諾は「はい、承知しました」。"},
      {audio:"体調は いかがですか。",q:"最もよい 返事は どれですか。",o:["はい、あそこです。","ありがとうございます。","いいえ、三人です。","おかげさまで、大分良くなりました。"],a:3,exp:"体調を聞かれたら状態を答える。"},
      {audio:"この 提案について、ご意見を 伺えますか。",q:"最もよい 返事は どれですか。",o:["それは大変ですね。","もう終わりました。","はい、思ったことをお伝えします。","おめでとうございます。"],a:2,exp:"意見を求められた際の自然な返事。"}
    ]}
  ]
},
{
  id:"o-n2-1", lvl:"N2", title:"Examen oficial N2 · 1", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙・文法）・読解", minutes:105, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 提案は 斬新だ。",o:["ざんしん","ぜんしん","ざんじん","ざんせい"],a:0,exp:"斬新→ざんしん「innovador」。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　矛盾した 説明だ。",o:["むそん","むしゅん","ぼうじゅん","むじゅん"],a:3,exp:"矛盾→むじゅん「contradicción」。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 計画には 難点が ある。",o:["なんでん","かたてん","なんてい","なんてん"],a:3,exp:"難点→なんてん「punto problemático」。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 主張は 一貫している。",o:["いっかん","いつかん","いっかんせい","いちかん"],a:0,exp:"一貫→いっかん「coherencia」。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　柔軟な 対応を する。",o:["じゅうやわ","にゅうなん","じゅなん","じゅうなん"],a:3,exp:"柔軟→じゅうなん「flexible」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　そちを とる。",o:["処置","処理","措置","対処"],a:2,exp:"そち→措置「medida, disposición」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　じゅうなんに たいおうする。",o:["柔難","従軟","柔軟","重軟"],a:2,exp:"じゅうなん→柔軟「flexible」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　ふきゅうしている。",o:["不朽","不急","不休","普及"],a:3,exp:"ふきゅう→普及「difusión」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　こうかんする。",o:["好感","交換","交感","公館"],a:1,exp:"こうかん→交換「intercambio」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　けんとうします。",o:["検討","検答","健闘","見当"],a:0,exp:"けんとう→検討「estudio」。"},
      {sec:"問題3　語形成",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 資料は （　）専門的で、初心者には 難しい。",o:["超","不","非","無"],a:0,exp:"「超専門的」＝超（接頭語）+専門的、極端に程度が高いことを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 態度は （　）常識だ。",o:["不","未","超","非"],a:3,exp:"「非常識」＝非（接頭語）+常識、常識に反することを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　まだ 完成（　）の 作品だ。",o:["中","後","内","前"],a:3,exp:"「完成前」＝completar+前（接尾語）、まだ完成していない段階を表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 商品は 使用（　）だ。",o:["前","中","済み","後"],a:2,exp:"「使用済み」＝使用+済み（接尾語）、すでに使われたことを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は （　）専門家だ。",o:["旧","元","古","前"],a:1,exp:"「元専門家」＝元（接頭語）+専門家、以前その職業だったことを表す。"},
      {sec:"問題4　文脈規定",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 話は （　）を 得ず、聞いていて 疲れる。",o:["要領","要求","要因","要素"],a:0,exp:"「要領を得ない」＝no ir al grano。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は 反対派の 説得に （　）を 尽くした。",o:["方法","知恵","手","力"],a:2,exp:"「手を尽くす」＝agotar todos los medios。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　その 提案は 物議を （　）。",o:["呼んだ","起こした","醸した","招いた"],a:2,exp:"「物議を醸す」＝causar controversia。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 結果には （　）の 余地が ない。",o:["疑い","不審","懐疑","疑問"],a:3,exp:"「疑問の余地がない」＝no hay lugar a dudas。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女の 指摘は （　）を 突いていた。",o:["本心","核心","中心","内心"],a:1,exp:"「核心を突く」＝dar en el meollo。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は 難局を （　）乗り切った。",o:["強引に","過剰に","巧みに","急激に"],a:2,exp:"「巧みに」＝hábilmente。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 案には （　）の 余地が ある。",o:["納得","検討","賛成","満足"],a:1,exp:"「検討の余地がある」＝hay margen para reconsiderar。"},
      {sec:"問題5　言い換え類義",q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼は あくまで 反対した。",o:["最後まで、徹底的に","仕方なく","一時的に","少しだけ"],a:0,exp:"「あくまで」≒「最後まで、徹底的に」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼は 状況を 的確に 判断した。",o:["遅れて","おおざっぱに","感情的に","正確に、適切に"],a:3,exp:"「的確に」≒「正確に、適切に」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼女は いたって 冷静だった。",o:["時々","少し","急に","非常に"],a:3,exp:"「いたって」≒「非常に」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼は もはや 若くない。",o:["たぶん","すでに、今となっては","まだ","決して"],a:1,exp:"「もはや」≒「すでに」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼女は したたかに 交渉を 進めた。",o:["無計画に","乱暴に","巧妙に、抜け目なく","率直に"],a:2,exp:"「したたかに」≒「巧妙に、抜け目なく」。"},
      {sec:"問題6　用法",q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「せめて」",o:["せめて怒って叫んだ。","全部は無理でも、せめて半分だけでも終わらせたい。","せめて三人来た。","せめて明日晴れるだろう。"],a:1,exp:"「せめて」＝al menos。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「案の定」",o:["案の定、三時に会議がある。","案の定、彼は約束の時間に遅れた。","案の定、早く終わった。","案の定、明日雨が降るだろう。"],a:1,exp:"「案の定」＝tal como se esperaba。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「あえて」",o:["あえて明日晴れるだろう。","彼はあえて厳しい道を選んだ。","あえて三人来た。","あえて怒って叫んだ。"],a:1,exp:"「あえて」＝a propósito, deliberadamente。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「もっぱら」",o:["最近はもっぱら在宅で仕事をしている。","もっぱら明日雨が降る。","もっぱら早く終わった。","もっぱら三時に会議がある。"],a:0,exp:"「もっぱら」＝exclusivamente。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「あわよくば」",o:["あわよくば、優勝も狙えるかもしれない。","あわよくば三時に来た。","あわよくば早く終わった。","あわよくば明日会議がある。"],a:0,exp:"「あわよくば」＝con suerte。"},
      {sec:"問題7　文法1（文法形式の判断）",q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　さすが プロ（　）、すばらしい 演奏だ。",o:["だけで","ばかりに","につれて","だけあって"],a:3,exp:"「〜だけあって」＝como cabe esperar de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　部長に （　）、私が 挨拶を いたします。",o:["かわって","おいて","ついて","たいして"],a:0,exp:"「〜にかわって」＝en lugar de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 問題は 複雑な（　）、簡単には 解決できない。",o:["うえに","ものの","だけで","だけに"],a:3,exp:"「〜だけに」＝precisamente porque。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 発言（　）、社内に 動揺が 広がった。",o:["を受けて","にわたって","にかけて","につけて"],a:0,exp:"「〜を受けて」＝en respuesta a。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 結果は 努力（　）ほかならない。",o:["で","が","の","に"],a:3,exp:"「〜にほかならない」＝no es sino。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　予算が 限られている（　）、できる ことは 限られる。",o:["ものなら","上に","以上","反面"],a:2,exp:"「〜以上」＝dado que (es un hecho)。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女の 演技は 素人（　）本格的だった。",o:["につき","にしては","にとって","にかけては"],a:1,exp:"「〜にしては」＝para ser (algo)。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　苦労した（　）、成功の 喜びは 大きい。",o:["のみか","ばかりに","だけに","だけで"],a:2,exp:"「〜だけに」＝precisamente porque。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　規則に 反する（　）、罰則が 科される。",o:["につれ","次第では","ものは","場合には"],a:3,exp:"「〜場合には」＝en caso de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は 部長（　）、部下からの 信頼も 厚い。",o:["にとって","でありながら","にしたら","というより"],a:1,exp:"「〜でありながら」＝a pesar de ser。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　予算の 都合（　）、計画の 一部を 見直した。",o:["上","上で","上は","上に"],a:0,exp:"「〜上」＝desde el punto de vista de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　経験の 浅い 彼女（　）、よく やった 方だ。",o:["にしては","につき","にとって","にかけては"],a:0,exp:"「〜にしては」＝para ser (algo)。"},
      {sec:"問題8　文法2（文の組み立て）",q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の　___　___　★　___　社内に 動揺が 広がった。（1 発言　2 を　3 受けて　4 も）",o:["も","を","発言","受けて"],a:3,exp:"正しい順序：1発言→2を→3受けて「発言を受けて」。★の位置には3「受けて」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 結果は　___　___　★　___　ほかならない。（1 に　2 努力　3 も　4 の 結果）",o:["も","に","努力","の 結果"],a:1,exp:"正しい順序：2努力→4の結果→1に「努力の結果に」の並びを整えて「努力にほかならない」。★の位置には1「に」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　予算が　___　★　___　___　できる ことは 限られる。（1 いる　2 限られて　3 以上　4 も）",o:["も","いる","以上","限られて"],a:2,exp:"正しい順序：2限られて→1いる→3以上「限られている以上」。★の位置には3「以上」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は　___　___　★　___　本格的だった。（1 素人　2 にしては　3 演技は　4 も）",o:["素人","も","にしては","演技は"],a:2,exp:"正しい順序：3演技は→1素人→2にしては「演技は素人にしては」。★の位置には2「にしては」が入る。"},
      {sec:"問題9　文章の文法",passage:"組織における 心理的安全性という 概念が、近年 注目を 集めている。これは、率直な 意見や 懸念を 口にしても、罰せられたり 恥を かかされたりしない（1）確信を、メンバーが 共有している 状態を 指す。この 安全性が 低い 組織では、メンバーは 失敗を 恐れる あまり 本音を 言わなくなり、（2）問題の 早期発見が 遅れがちに なる。<br><br>ただし、心理的安全性とは、単に 居心地の良い、ぬるま湯的な 環境を 意味する わけでは ない（3）。むしろ、率直な 指摘や 建設的な 対立を 歓迎する 土壌が あってこそ、真の 心理的安全性は 成立する。（4）、心地よさだけを 追求する 組織は、かえって 成長の 機会を 逃しかねない。<br><br>心理的安全性を 高める ことは、決して 簡単な 取り組みでは ない。しかし、その（5）は、組織の 長期的な 競争力に 直結する 重要な 課題だと 言えるだろう。",q:"（1）",o:["とばかりの","ときたる","といった","という"],a:3,exp:"〜という確信「la convicción de que」内容を示す。"},
      {q:"（2）",o:["ところが","結果として","それゆえ","ともあれ"],a:1,exp:"結果として「como resultado」因果関係を導く。"},
      {q:"（3）",o:["というのは誤解だ","ということはあり得ない","ということに注意が必要だ","ということは間違いない"],a:2,exp:"誤解されやすい点への注意喚起として自然。"},
      {q:"（4）",o:["したがって","むしろ","つまり","ところで"],a:1,exp:"逆説的な補足を導く「むしろ」が文脈に合う。"},
      {q:"（5）",o:["放棄","構築","否定","消滅"],a:1,exp:"心理的安全性の「構築」が競争力に直結するという結論が自然。"},
      {sec:"問題10　内容理解（短文）",passage:"この企業は環境負荷の軽減を経営方針の柱に据え、生産工程の見直しを進めている。短期的なコスト増加は避けられないが、長期的な企業価値の向上を見込んでいる。",q:"この企業が見込んでいることは何か。",o:["短期的な利益の拡大","海外進出の拡大","従業員数の削減","長期的な企業価値の向上"],a:3,exp:"「長期的な企業価値の向上を見込んでいる」がそのまま答え。"},
      {passage:"この地域では、伝統工芸品の後継者不足が深刻化しており、行政と民間が連携した育成プログラムが開始された。若い世代への技術継承が急務とされている。",q:"育成プログラムの目的は何か。",o:["若い世代への技術継承","価格の引き上げ","輸出の拡大","観光客の誘致"],a:0,exp:"「若い世代への技術継承が急務」がそのまま答え。"},
      {passage:"この調査によれば、リモートワークの普及により、地方への移住を検討する都市部の若者が増加している。働く場所の制約が減ったことが背景にある。",q:"地方移住の増加の背景は何か。",o:["地方の経済成長","働く場所の制約が減ったこと","交通網の発達","都市部の家賃高騰"],a:1,exp:"「働く場所の制約が減ったことが背景」がそのまま答え。"},
      {passage:"この病院では、電子カルテの導入により、医師間の情報共有が円滑になり、診断の精度が向上したと報告されている。",q:"電子カルテ導入の効果は何か。",o:["診療時間の短縮","医療費の削減","診断の精度向上","患者数の増加"],a:2,exp:"「情報共有が円滑になり、診断の精度が向上した」がそのまま答え。"},
      {passage:"インターネット広告市場は急速に拡大しており、従来のテレビや新聞広告の市場規模を上回りつつある。企業側も広告戦略の見直しを迫られている。",q:"企業が迫られていることは何か。",o:["広告戦略の見直し","広告費の削減","テレビ広告の増加","新聞購読の促進"],a:0,exp:"「企業側も広告戦略の見直しを迫られている」がそのまま答え。"},
      {sec:"問題11　内容理解（中文）",passage:"少子高齢化が進む日本では、労働力不足を補うため、外国人労働者の受け入れ拡大が議論されている。一方で、言語や文化の違いによる職場での摩擦を懸念する声も根強い。受け入れ企業側には、単なる労働力としてではなく、共に働く仲間としての意識改革が求められている。",q:"外国人労働者の受け入れに関して懸念されていることは何か。",o:["言語や文化の違いによる摩擦","住居不足","賃金の高騰","治安の悪化"],a:0,exp:"「言語や文化の違いによる職場での摩擦を懸念する声も根強い」がそのまま答え。"},
      {q:"受け入れ企業側に求められていることは何か。",o:["労働力としてのみ扱うこと","賃金の引き下げ","共に働く仲間としての意識改革","受け入れの完全な停止"],a:2,exp:"「共に働く仲間としての意識改革が求められている」がそのまま答え。"},
      {q:"この文章の要旨として最も適切なものはどれか。",o:["賃金さえ上げれば全て解決する","外国人労働者の受け入れは不要である","外国人労働者受け入れには制度と意識の両面の変化が必要だ","言語の違いは全く問題にならない"],a:2,exp:"制度的な議論と意識改革の両方に言及している。"},
      {passage:"人工知能の発達により、これまで人間にしかできないと思われていた仕事の一部が自動化されつつある。ただし、創造性や対人関係を要する分野では、人間の役割は依然として大きい。技術が進歩するほど、逆に人間ならではの資質の価値が際立つという逆説的な現象が起きている。",q:"人間の役割が依然として大きい分野はどこか。",o:["単純作業の分野","データ入力の分野","計算処理の分野","創造性や対人関係を要する分野"],a:3,exp:"「創造性や対人関係を要する分野では、人間の役割は依然として大きい」がそのまま答え。"},
      {q:"筆者が指摘する「逆説的な現象」とは何か。",o:["技術が進歩するほど人間らしい資質の価値が際立つこと","人間の資質が失われつつあること","技術が退化していること","技術が進歩するほど人間の仕事が増えること"],a:0,exp:"「技術が進歩するほど、逆に人間ならではの資質の価値が際立つ」がそのまま答え。"},
      {q:"この文章の要旨として最も適切なものはどれか。",o:["AIの発達により人間ならではの資質の価値が再評価されている","AIはすべての仕事を代替する","人間の仕事は今後完全になくなる","創造性はAIにも備わっている"],a:0,exp:"文章全体を通して人間的資質の再評価を論じている。"},
      {passage:"効率化ばかりを追求する現代社会において、雑談や余白といった一見無駄に見えるものの中にこそ、新しい発想の種が潜んでいるのではないかという指摘がある。無駄を一律に排除する姿勢は、かえって組織の創造性を損なう危険をはらんでいる。",q:"筆者が指摘する危険は何か。",o:["無駄を一律に排除することが創造性を損なうこと","効率化が全く進まないこと","余白が多すぎること","雑談を推奨しすぎること"],a:0,exp:"「無駄を一律に排除する姿勢は、かえって組織の創造性を損なう危険」がそのまま答え。"},
      {q:"筆者は雑談や余白をどう捉えているか。",o:["完全に無駄なもの","新しい発想の種になりうるもの","業務効率を下げるだけのもの","時間の浪費でしかないもの"],a:1,exp:"「新しい発想の種が潜んでいるのではないか」と肯定的に捉えている。"},
      {q:"この文章の要旨として最も適切なものはどれか。",o:["余白は完全に排除すべきだ","効率偏重の姿勢が組織の創造性を損なう危険がある","雑談は業務の妨げにしかならない","効率化はすべて推進すべきだ"],a:1,exp:"効率偏重への警鐘が文章全体の要旨。"},
      {sec:"問題12　統合理解",passage:"【A】在宅勤務の普及は、通勤時間の削減や柔軟な働き方を可能にし、多くの労働者から歓迎されている。企業側もオフィスコストの削減という利点を享受しており、双方にとって望ましい変化と言えるだろう。<br><br>【B】しかし、在宅勤務には見過ごせない課題もある。同僚との偶発的な交流が失われることで、新しいアイデアが生まれにくくなったという指摘や、若手社員が先輩の仕事ぶりを間近で観察する機会が減り、育成が滞っているという声も聞かれる。",q:"Aの筆者が在宅勤務について述べていることは何か。",o:["企業のコストが増加している","育児や介護との両立は不可能だ","従来の働き方に戻すべきだ","労働者にも企業にも恩恵がある望ましい変化だ"],a:3,exp:"Aは「双方にとって望ましい変化」と肯定的に評価している。"},
      {q:"Bの筆者が懸念していることは何か。",o:["偶発的な交流の減少による弊害","企業コストの増加","労働時間の増加","通勤時間の増加"],a:0,exp:"Bは「偶発的な交流が失われる」ことによる弊害を懸念している。"},
      {sec:"問題13　主張理解（長文）",passage:"教育の目的は、知識の詰め込みではなく、自ら考え、判断する力を養うことにあると言えよう。試験の点数のみで学びの成果を測ろうとする姿勢は、この本質を見誤らせる危険をはらんでいる。<br><br>もちろん、基礎知識の習得は不可欠であり、それなしには思考の材料そのものが不足してしまう。しかし、知識を「持っていること」と、それを「使いこなせること」の間には大きな隔たりがある。<br><br>真に求められているのは、既知の知識を新しい状況に応用し、未知の問題に対して自分なりの答えを導き出す力である。そのためには、正解が一つに定まらない問いに向き合う経験を、教育の中により多く取り入れていく必要があるだろう。",q:"筆者が危惧していることは何か。",o:["基礎知識の習得が不要になること","試験制度そのものの廃止","知識の詰め込みが不十分であること","試験の点数のみで学びを測ることが本質を見誤らせること"],a:3,exp:"「試験の点数のみで…測ろうとする姿勢は…本質を見誤らせる危険」がそのまま答え。"},
      {q:"筆者は基礎知識の習得についてどう考えているか。",o:["知識より応用力のほうが先に必要だ","思考の材料として不可欠である","不要であり廃止すべきだ","試験でのみ評価すべきだ"],a:1,exp:"「基礎知識の習得は不可欠であり、それなしには思考の材料そのものが不足してしまう」と述べている。"},
      {q:"筆者が教育に取り入れるべきだと述べているのはどのような経験か。",o:["試験で高得点を取る経験","教師の話を聞くだけの経験","知識を暗記する経験","正解が一つに定まらない問いに向き合う経験"],a:3,exp:"「正解が一つに定まらない問いに向き合う経験を…取り入れていく必要がある」がそのまま答え。"},
      {sec:"問題14　情報検索",passage:"【日本語スピーチコンテスト　参加案内】<br>・対象：日本語を学習する外国人（国籍不問、レベル制限なし）<br>・部門：初級の部（学習歴1年未満）／中上級の部（学習歴1年以上）<br>・持ち時間：各部門とも3分以内（超過した場合、減点対象）<br>・申込方法：ウェブサイトの申込フォームより、10月15日（水）までに登録。学習歴の証明は不要。<br>・当日の流れ：受付は開始30分前から。初級の部から開始し、その後、休憩を挟んで中上級の部を行う。<br>・注意事項：原稿の持ち込みは可。ただし、原稿を読み上げるだけのスピーチは減点対象となる場合がある。",q:"学習歴8か月の人が参加する場合、当てはまるのはどれか。",o:["初級の部に申し込み、学習歴の証明書類は不要","中上級の部に申し込み、証明書類が必要","参加資格がない","両方の部門に申し込める"],a:0,exp:"学習歴1年未満は初級の部。「学習歴の証明は不要」なので証明書類は不要。"},
      {q:"この案内から分かることとして正しいものはどれか。",o:["持ち時間を超過すると減点される可能性がある","参加者は上位者しか参加証をもらえない","中上級の部が先に行われる","原稿を見ながら話すことは一切禁止されている"],a:0,exp:"「超過した場合、減点対象」がそのまま該当。"}
    ]},
    {id:"b", title:"聴解", minutes:50, questions:[
      {sec:"問題1　課題理解",audio:"男：来週の 展示会の 準備、順調ですか。　女：はい、ほぼ 予定通りですが、パンフレットの 印刷だけ 少し 遅れています。今日中に 印刷会社に 確認の 連絡を 入れます。",q:"女の人は このあと、まず 何を しますか。",o:["パンフレットを作り直す","展示会を延期する","印刷会社に連絡する","会場を変更する"],a:2,exp:"「今日中に 印刷会社に 確認の 連絡を 入れます」がそのまま答え。"},
      {audio:"女：この 契約書、サインする 前に もう一度 内容を 確認したいのですが。　男：もちろんです。念のため、法務部にも 目を通して もらいましょうか。",q:"男の人は このあと まず 何を しますか。",o:["新しい契約書を作る","契約を解除する","法務部に確認を依頼する","契約書にサインする"],a:2,exp:"「法務部にも 目を通して もらいましょうか」がそのまま答え。"},
      {audio:"男：来月の セミナー、会場の 候補が 二つ あるんですが。　女：それぞれの 収容人数と 料金を 比較した 資料を 作ってもらえますか。",q:"男の人は このあと 何を しますか。",o:["セミナーを中止する","会場の比較資料を作る","会場を予約する","参加者を募集する"],a:1,exp:"「比較した資料を作ってもらえますか」への流れから、比較資料を作成する。"},
      {audio:"女：来週の 出張、ホテルの 予約は できていますか。　男：まだです。今日中に 旅行代理店に 連絡します。",q:"男の人は このあと まず 何を しますか。",o:["ホテルをキャンセルする","旅行代理店に連絡する","新幹線を予約する","出張を延期する"],a:1,exp:"「今日中に 旅行代理店に 連絡します」がそのまま答え。"},
      {audio:"男：新しい プロジェクトの 進め方に ついて 相談したいのですが。　女：まずは 関係部署に 意見を 聞いてから、来週の 会議で 方向性を 決めましょう。",q:"来週の 会議で 何を 決めますか。",o:["会議の日程","関係部署の担当者","予算の金額","プロジェクトの方向性"],a:3,exp:"「来週の 会議で 方向性を 決めましょう」がそのまま答え。"},
      {sec:"問題2　ポイント理解",audio:"男：今回の プロジェクト、予定より 遅れていますね。原因は 何だと 思いますか。　女：人手不足も 一因ですが、一番 大きいのは 仕様変更が 何度も あったことだと 思います。",q:"女の人は、プロジェクトが 遅れている 一番の 原因は 何だと 言っていますか。",o:["設計者が交代したこと","人手が不足していること","仕様変更が何度もあったこと","予算が足りないこと"],a:2,exp:"「一番 大きいのは 仕様変更が 何度も あったこと」がそのまま答え。"},
      {audio:"女：新しい 店舗の 場所、駅前と 郊外の ショッピングモール、どちらに しますか。　男：家賃は 駅前の方が 高いですが、集客力を 考えると 駅前の 一択でしょう。",q:"男の人が 駅前を 選ぶ 一番の 理由は 何ですか。",o:["駅から近く通勤が楽だから","集客力が高く長期的に採算が取れるから","面積が広いから","家賃が安いから"],a:1,exp:"「集客力を 考えると…駅前の 一択でしょう」がそのまま答え。"},
      {audio:"男：今度の 講演会、参加者が 少なかったですね。　女：告知の 時期が 遅かったのが 一番の 問題だったと 思います。",q:"女の人は、参加者が 少なかった 一番の 原因は 何だと 言っていますか。",o:["会場が悪かったこと","日程が悪かったこと","告知の時期が遅かったこと","講師の話がつまらなかったこと"],a:2,exp:"「告知の 時期が 遅かったのが 一番の 問題」がそのまま答え。"},
      {audio:"女：新商品の 売り上げ、思ったほど 伸びていませんね。　男：価格設定は 問題ないと 思うんですが、広告の 打ち方が 弱かったんじゃないかと。",q:"男の人は、売り上げが 伸びない 一番の 原因は 何だと 考えていますか。",o:["競合が多いこと","商品の品質が悪いこと","価格が高すぎること","広告がターゲット層に届いていないこと"],a:3,exp:"「広告の 打ち方が 弱かった」が原因として挙げられている。"},
      {audio:"男：来期の 予算案、営業部からの 要望が 通らなかったようですね。　女：全社的に コスト削減の 方針が 出ていて、どの 部署も 一律で 減らされる ことに なったみたいです。",q:"営業部の 要望が 通らなかった 一番の 理由は 何ですか。",o:["他部署の予算が優先されたから","予算案の書き方が悪かったから","全社的なコスト削減方針があったから","営業部の実績が悪かったから"],a:2,exp:"「全社的に コスト削減の 方針が 出ていて…一律で 減らされる」がそのまま理由。"},
      {audio:"女：この 機械、最近 よく 故障しますね。　男：使用年数も ありますが、それより 湿度の 高い 環境で 使い続けたことが 大きいと思います。",q:"男の人は、機械が 故障する 一番の 原因は 何だと 考えていますか。",o:["操作方法が間違っていたこと","湿度の高い環境で使い続けたこと","使用年数が長いこと","部品の品質が悪いこと"],a:1,exp:"「それより 湿度の 高い 環境で 使い続けたことが 大きい」が原因として挙げられている。"},
      {sec:"問題3　概要理解",audio:"近年、企業の 意思決定に データ分析を 活用する 動きが 加速している。ただし、データに 過度に 依存する あまり、現場の 経験や 直感に 基づく 判断が 軽視される 傾向も 見られ、両者の バランスが 課題と なっている。",q:"この話は、主に何について述べていますか。",o:["データ分析の技術不足","データと経験・直感のバランス","意思決定の遅さ","経験や直感の完全な排除"],a:1,exp:"データと経験・直感のバランスについての話。"},
      {audio:"言葉は 常に 変化し続ける ものである。新しい 表現の 誕生を「乱れ」と 断じるのは 早計であり、むしろ 言語の 生命力の 証と 見るべきだろう。",q:"この話は、主に何について述べていますか。",o:["言葉の変化についての一つの見方","若者言葉の具体的な例","正しい日本語の使い方の解説","言語教育の方法"],a:0,exp:"言葉の変化を肯定的に捉える視点についての話。"},
      {audio:"組織における 心理的安全性という 概念が 注目されており、率直な 意見を 言っても 罰せられないという 確信を メンバーが 共有している 状態を 指すが、単に 居心地のよい 環境を 意味する わけではない。",q:"この話は、主に何について述べていますか。",o:["給与制度の設計","会議の司会の進め方","心理的安全性の本質についての考え方","人事評価の基準"],a:2,exp:"心理的安全性とは何かについての考察が主題。"},
      {audio:"効率化ばかりを 追求する 風潮に 対し、雑談や 余白と いった 一見 無駄に 見える ものの 中にこそ、新しい 発想の 種が あるのではないかという 指摘が なされている。",q:"この話は、主に何について述べていますか。",o:["職場のルール作り","雑談の内容の分析","効率化の行き過ぎがもたらす弊害への懸念","効率的な仕事の進め方"],a:2,exp:"効率化偏重への懸念と、余白の価値についての話。"},
      {audio:"外国人労働者の 受け入れが 議論される 中、言語や 文化の 違いによる 摩擦を 懸念する 声も あり、企業側の 意識改革が 求められている。",q:"この話は、主に何について述べていますか。",o:["労働ビザの種類","入国管理の手続き","外国人労働者受け入れに必要な企業の意識改革","外国人労働者の給与水準"],a:2,exp:"受け入れ企業側の意識改革の必要性についての話。"},
      {sec:"問題4　即時応答",audio:"この件、少し検討させていただけますか。",q:"最もよい返答はどれですか。",o:["いいえ、まだです。","もう終わりました。","それは残念ですね。","はい、どうぞ。"],a:3,exp:"確認の申し出に対して自然な返答は「はい、どうぞ」。"},
      {audio:"申し訳ございませんが、本日中の対応は難しい状況です。",q:"最もよい返答はどれですか。",o:["それは良かったです。","おめでとうございます。","はい、すぐやります。","では、いつ頃なら可能でしょうか。"],a:3,exp:"対応が難しいという連絡への自然な返答は、代替案を尋ねる形。"},
      {audio:"この資料、ちょっと目を通していただけますか。",q:"最もよい返答はどれですか。",o:["いいえ、要りません。","それはおめでとうございます。","もう捨てました。","はい、拝見します。"],a:3,exp:"資料を確認してほしいという依頼への自然な返答は「はい、拝見します」。"},
      {audio:"恐れ入りますが、少々お待ちいただけますでしょうか。",q:"最もよい返答はどれですか。",o:["はい、かしこまりました。","いいえ、待てません。","もう終わりです。","それはすごいですね。"],a:0,exp:"待ってほしいという依頼への自然な返答は「はい、かしこまりました」。"},
      {audio:"この度は大変ご迷惑をおかけし、申し訳ございませんでした。",q:"最もよい返答はどれですか。",o:["もっとやってください。","おめでとうございます。","それは嬉しいです。","いえ、こちらこそ確認不足がありました。"],a:3,exp:"謝罪への自然な返答として、相手を責めずに応じる形。"},
      {audio:"来週の予定、変更になる可能性があります。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","もう変更しました。","分かりました。決まり次第教えてください。","それは羨ましいです。"],a:2,exp:"予定変更の可能性を知らされた自然な返答は「決まり次第教えてください」。"},
      {audio:"この企画、正直あまり自信がないんです。",q:"最もよい返答はどれですか。",o:["それはよかったですね。","おめでとうございます。","もうやめましょう。","どの部分が気になりますか。一緒に考えましょう。"],a:3,exp:"不安を打ち明けられた際の自然な返答は、具体的に寄り添う形。"},
      {audio:"この書類、ハンコを押していただけますか。",q:"最もよい返答はどれですか。",o:["いいえ、書きません。","はい、こちらに押しますね。","それは大変ですね。","もう押されています。"],a:1,exp:"押印の依頼への自然な返答は「はい、こちらに押しますね」。"},
      {audio:"すみません、少し声が小さくて聞き取れませんでした。",q:"最もよい返答はどれですか。",o:["もう聞こえています。","失礼しました。もう一度お伝えします。","それは残念ですね。","おめでとうございます。"],a:1,exp:"聞き取れなかったという指摘への自然な返答は「もう一度お伝えします」。"},
      {audio:"この案で進めてもよろしいでしょうか。",q:"最もよい返答はどれですか。",o:["もう終わった話です。","いいえ、まだ始まっていません。","それはすごいですね。","はい、それでお願いします。"],a:3,exp:"承認を求められた際の自然な返答は「はい、それでお願いします」。"},
      {audio:"何かお手伝いできることがあれば言ってください。",q:"最もよい返答はどれですか。",o:["ありがとうございます。では、これをお願いできますか。","もう大丈夫だったんです。","それは大変でしたね。","おめでとうございます。"],a:0,exp:"手伝いの申し出への自然な返答は、感謝したうえで具体的に依頼する流れ。"},
      {audio:"この提案、社内での反応はいかがでしょうか。",q:"最もよい返答はどれですか。",o:["もう終わりました。","おめでとうございます。","それは残念ですね。","概ね好評ですが、一部懸念の声もあります。"],a:3,exp:"社内の反応を尋ねられた際の自然な返答。"},
      {sec:"問題5　統合理解",audio:"司会：新しいオフィスのレイアウトについて、三つの案が出ています。それぞれの意見を聞きましょう。<br>男性A：私はオープンスペース案がいいと思います。部署間のコミュニケーションが活発になりますし、コストも抑えられます。<br>女性：私は個室中心の案を推します。集中して作業したいという社員の声も多いですし、機密情報を扱う部署もありますから。<br>男性B：私はその中間の、半個室のブース形式がいいと思います。ある程度の集中力も保てますし、コストもオープン案ほどではないですが、個室案よりは抑えられます。<br>司会：なるほど。それでは、コストと集中力のバランスを重視して、ブース形式で進めることにしましょう。",q:"最終的にどの案で進めることになりましたか。",o:["ブース形式の案","個室中心の案","オープンスペース案","三つの案を組み合わせた新しい案"],a:0,exp:"司会が最後に「ブース形式で進めることにしましょう」と決定している。"},
      {q:"女性が個室中心の案を推した理由は何ですか。",o:["コストが最も安いから","集中したい社員の声や機密情報への配慮","男性Aの意見に賛成だったから","部署間の交流を増やすため"],a:1,exp:"「集中して作業したいという社員の声…機密情報を扱う部署もある」が理由。"},
      {audio:"司会：来年度の新入社員研修について、三つの案があります。<br>男性A：私は座学中心の研修がいいと思います。基礎知識をしっかり身につけさせるべきです。<br>女性：私は実地研修を増やすべきだと思います。現場での経験がないと、座学だけでは実践力が身につきません。<br>男性B：両方を組み合わせて、午前は座学、午後は実地という形にするのはどうでしょうか。バランスが取れると思います。<br>司会：それでは、午前座学・午後実地の組み合わせ案で進めましょう。",q:"最終的にどの案で進めることになりましたか。",o:["案がまとまらなかった","午前座学・午後実地の組み合わせ案","実地研修中心の案","座学中心の案"],a:1,exp:"司会が「午前座学・午後実地の組み合わせ案で進めましょう」と決定している。"}
    ]}
  ]
},
{
  id:"o-n2-2", lvl:"N2", title:"Examen oficial N2 · 2", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙・文法）・読解", minutes:105, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は 冷静さを 失わずに 対応した。",o:["うしないずに","うしなわずに","しっしずに","しつわずに"],a:1,exp:"失わずに→うしなわずに「sin perder」。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 発言は 波紋を 呼んだ。",o:["はもん","はぶん","なみもん","はんもん"],a:0,exp:"波紋→はもん「onda expansiva」。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 提案には 難点が ある。",o:["なんでん","かたてん","なんてい","なんてん"],a:3,exp:"難点→なんてん「punto problemático」。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　新しい 制度が 導入された。",o:["どうにゅ","どうい","とうにゅう","どうにゅう"],a:3,exp:"導入→どうにゅう「introducción」。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　妥当な 判断だ。",o:["だどう","だとう","たとう","たどう"],a:1,exp:"妥当→だとう「razonable」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　どうにゅうします。",o:["道人","導入","導人","道入"],a:1,exp:"どうにゅう→導入「introducción」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　だとうな はんだん。",o:["打党","妥当","打当","妥党"],a:1,exp:"だとう→妥当「razonable」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　なんてんが おおい。",o:["難転","難点","難典","難店"],a:1,exp:"なんてん→難点「punto problemático」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　はもんを よんだ。",o:["波聞","波問","波文","波紋"],a:3,exp:"はもん→波紋「onda expansiva」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　うしなわずに たいおうする。",o:["失うずに","夫わずに","失わずに","矢わずに"],a:2,exp:"うしなわずに→失わずに「sin perder」。"},
      {sec:"問題3　語形成",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 制度は （　）改正された。",o:["超","再","非","不"],a:1,exp:"「再改正」＝再（接頭語）+改正、再び行うことを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は （　）大学生だ。",o:["古","前","旧","元"],a:3,exp:"「元大学生」＝元（接頭語）+大学生、以前その立場だったことを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 商品は 発売（　）だ。",o:["内","中","前","後"],a:1,exp:"「発売中」＝発売+中（接尾語）、その最中であることを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は （　）常識な 行動を した。",o:["非","未","超","不"],a:0,exp:"「非常識」＝非（接頭語）+常識、常識に反することを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 問題は 解決（　）だ。",o:["済み","中","後","前"],a:0,exp:"「解決済み」＝解決+済み（接尾語）、すでに解決されたことを表す。"},
      {sec:"問題4　文脈規定",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 態度は 傲慢（　）ほかならない。",o:["の","と","に","で"],a:2,exp:"「〜にほかならない」＝no es sino。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は （　）として 批判に 耐えた。",o:["毅然","漠然","茫然","超然"],a:0,exp:"「毅然として」＝con firmeza, sin flaquear。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 資料には （　）が 多い。",o:["正解","成功","失敗","間違い"],a:3,exp:"「間違いが多い」＝tiene muchos errores。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は 会議で 積極的に （　）した。",o:["発表","発達","発言","発見"],a:2,exp:"「発言する」＝tomar la palabra。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は （　）な 性格で、みんなに 信頼されている。",o:["乱暴","冷酷","誠実","無関心"],a:2,exp:"「誠実な性格」＝carácter sincero。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 計画は （　）が 明確だ。",o:["態度","感想","目的","条件"],a:2,exp:"「目的が明確だ」＝el objetivo es claro。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 発言は 会議で （　）を 呼んだ。",o:["話題","注目","物議","評判"],a:2,exp:"物議を呼ぶ＝causar controversia。"},
      {sec:"問題5　言い換え類義",q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼は 冷静に 状況を 判断した。",o:["感情的に","乱暴に","急いで","落ち着いて"],a:3,exp:"「冷静に」≒「落ち着いて」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼女は 誠実に 対応した。",o:["いい加減に","乱暴に","真面目に、正直に","急いで"],a:2,exp:"「誠実に」≒「真面目に、正直に」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼は 明確に 説明した。",o:["急いで","はっきりと","乱暴に","曖昧に"],a:1,exp:"「明確に」≒「はっきりと」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼女は 熱心に 取り組んだ。",o:["適当に","嫌々","消極的に","一生懸命に"],a:3,exp:"「熱心に」≒「一生懸命に」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼は 積極的に 参加した。",o:["仕方なく","消極的に","嫌々","自分から進んで"],a:3,exp:"「積極的に」≒「自分から進んで」。"},
      {sec:"問題6　用法",q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「たまたま」",o:["たまたま明日雨が降る。","たまたま三時に会議がある。","たまたま早く終わった。","駅でたまたま昔の友人に会った。"],a:3,exp:"「たまたま」＝por casualidad。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「かならずしも」",o:["かならずしも三時に会議がある。","かならずしも早く終わった。","かならずしも明日雨が降る。","高い商品がかならずしも良いとは限らない。"],a:3,exp:"「かならずしも〜とは限らない」＝no siempre。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「思いがけず」",o:["思いがけず明日雨が降る。","思いがけず早く終わった。","思いがけず三時に来た。","思いがけず賞をもらってしまった。"],a:3,exp:"「思いがけず」＝inesperadamente。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「案外」",o:["この問題は案外簡単だった。","案外三時に会議がある。","案外明日雨が降る。","案外早く終わった。"],a:0,exp:"「案外」＝contra lo esperado。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「せっかく」",o:["せっかく早く終わった。","せっかく作ったのに、誰も食べてくれなかった。","せっかく三時に会議がある。","せっかく明日雨が降る。"],a:1,exp:"「せっかく」＝con esfuerzo especial。"},
      {sec:"問題7　文法1（文法形式の判断）",q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は 若手（　）、堂々とした 態度で 発表した。",o:["というより","にしたら","でありながら","にとって"],a:2,exp:"「〜でありながら」＝a pesar de ser。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　予算の 都合（　）、計画の 一部を 見直した。",o:["上で","上は","上に","上"],a:3,exp:"「〜上」＝desde el punto de vista de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 実績（　）、この 昇進は 妥当だろう。",o:["に照らせば","をよそに","にひきかえ","はおろか"],a:0,exp:"「〜に照らせば」＝a la luz de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は 反対意見（　）、自説を 曲げなかった。",o:["をよそに","にもまして","にひきかえ","といえども"],a:0,exp:"「〜をよそに」＝haciendo caso omiso de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　規則に 反する（　）、罰則が 科される。",o:["ものは","につれ","場合には","次第では"],a:2,exp:"「〜場合には」＝en caso de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は 経験の 乏しさ（　）、見事な 対応を 見せた。",o:["にひきかえ","をものともせず","ときたら","はおろか"],a:1,exp:"「〜をものともせず」＝sin dejarse afectar por。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 問題は 議論すれば する（　）、複雑さを 増す ばかりだ。",o:["ほど","だけ","のみ","くらい"],a:0,exp:"「〜ば〜ほど」＝cuanto más...más。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は 疲れていた（　）、最後まで やり遂げた。",o:["にもかかわらず","とあって","ゆえに","かたわら"],a:0,exp:"「〜にもかかわらず」＝a pesar de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 貢献（　）、この 成功は なかっただろう。",o:["ときたら","なくして","はおろか","にひきかえ"],a:1,exp:"「〜なくして（は）」＝sin (algo)。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　規模の 大小（　）、この 問題は 軽視できない。",o:["を問わず","につき","にそくして","にわたって"],a:0,exp:"「〜を問わず」＝independientemente de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は 逆境（　）、決して 諦めなかった。",o:["ときたら","にひきかえ","にあっても","はおろか"],a:2,exp:"「〜にあっても」＝incluso en (adversidad)。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 結果は 偶然（　）必然の 産物だ。",o:["といえども","というのに","というより","というもの"],a:2,exp:"「〜というより」＝más que。"},
      {sec:"問題8　文法2（文の組み立て）",q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の　___　___　★　___　この 成功は なかっただろう。（1 貢献　2 なくして　3 も　4 は）",o:["なくして","貢献","も","は"],a:0,exp:"正しい順序：1貢献→2なくして「貢献なくして」。★の位置には2「なくして」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 結果は　___　___　★　___　産物だ。（1 という　2 偶然　3 より　4 必然の）",o:["必然の","という","より","偶然"],a:2,exp:"正しい順序：2偶然→1という→3より→4必然の「偶然というより必然の」。★の位置には3「より」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は　___　___　★　___　見事な 対応を 見せた。（1 経験の　2 をものともせず　3 乏しさ　4 も）",o:["をものともせず","経験の","乏しさ","も"],a:0,exp:"正しい順序：1経験の→3乏しさ→2をものともせず「経験の乏しさをものともせず」。★の位置には2「をものともせず」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は　___　★　___　___　自説を 曲げなかった。（1 反対意見　2 をよそに　3 も　4 の）",o:["も","の","をよそに","反対意見"],a:2,exp:"正しい順序：1反対意見→2をよそに「反対意見をよそに」。★の位置には2「をよそに」が入る。"},
      {sec:"問題9　文章の文法",passage:"効率化ばかりを 追求する 現代社会に おいて、あらゆる 無駄が 排除されるべきだという 風潮が 強まっている。しかし、この 考え方（1）、見落とされている ものが あるのではないか。一見 無駄に 見える 雑談や 余白（2）、新しい アイデアが 生まれる ことも 少なくない。（3）、効率を 追求する あまり、こうした 偶発的な 創造性の 芽まで 摘み取ってしまう 危険が ある。もちろん、無駄を 完全に 肯定する わけでは ない。（4）、適度な 余裕を 持つ ことの 価値を、改めて 見直す 必要が あるという ことだ。効率と 余白、この 両者の（5）こそが、これからの 時代に 求められて いるのだろう。",q:"（1）",o:["でも","なら","には","とは"],a:2,exp:"〜には「en (esta idea)」対象を示す助詞。"},
      {q:"（2）",o:["から","ばかり","まで","ゆえ"],a:0,exp:"〜から「a partir de」原因・出発点を示す。"},
      {q:"（3）",o:["ゆえに","ところが","したがって","つまり"],a:1,exp:"逆接の接続詞「ところが」が文脈に合う。"},
      {q:"（4）",o:["言われてみれば","言うまでもなく","言いたいのは","言われるとおり"],a:2,exp:"「言いたいのは〜ということだ」筆者の主張をまとめる定型表現。"},
      {q:"（5）",o:["優劣","バランス","分離","対立"],a:1,exp:"文脈上、両者の「バランス」が求められているという結論が自然。"},
      {sec:"問題10　内容理解（短文）",passage:"再生可能エネルギーの普及が進む一方、天候に左右される発電量の不安定さが課題として指摘されている。蓄電技術の進歩が解決の鍵とされる。",q:"再生可能エネルギーの課題は何か。",o:["コストが高すぎること","設置場所がないこと","発電量が天候に左右される不安定さ","法律で禁止されていること"],a:2,exp:"「天候に左右される発電量の不安定さが課題」がそのまま答え。"},
      {passage:"この病院では、待ち時間の長さが患者の不満の原因となっていた。予約システムを改善した結果、待ち時間が大幅に短縮された。",q:"待ち時間が短縮された理由は何か。",o:["予約システムの改善","患者数の減少","医師の増員","診療時間の延長"],a:0,exp:"「予約システムを改善した結果、待ち時間が大幅に短縮された」がそのまま答え。"},
      {passage:"若者の政治への関心の低さが長年指摘されてきたが、SNSを通じた情報発信により、若い世代の投票率が改善しつつある地域もある。",q:"若者の投票率改善に貢献しているものは何か。",o:["SNSを通じた情報発信","学校教育の変化","選挙制度の変更","法律の改正"],a:0,exp:"「SNSを通じた情報発信により…投票率が改善しつつある」がそのまま答え。"},
      {passage:"この企業では、社員のメンタルヘルスケアの一環として、専門カウンセラーへの相談窓口を設置した。利用は匿名で行えるため、利用者数は着実に増えている。",q:"相談窓口の利用者数が増えている理由は何か。",o:["強制されているから","匿名で利用できるから","料金が無料だから","評判が良いから"],a:1,exp:"「利用は匿名で行えるため、利用者数は着実に増えている」がそのまま答え。"},
      {passage:"この地域は昔から農業が盛んで、特に米作りで知られている。しかし近年、若い世代の農業離れが進み、後継者不足が深刻な問題となっている。",q:"この地域の問題は何か。",o:["土地が狭いこと","米の生産量が多すぎること","観光客が少ないこと","後継者不足"],a:3,exp:"「後継者不足が深刻な問題」がそのまま答え。"},
      {sec:"問題11　内容理解（中文）",passage:"組織における意思決定の遅さは、しばしば責任の所在の不明確さに起因する。誰もが責任を負いたがらない風土からは、迅速で大胆な決断は生まれにくい。それを打開するには、権限と責任を明確に紐づける制度設計が不可欠である。とはいえ、責任の所在を明確にしすぎると、今度は挑戦を避ける萎縮した組織風土を生みかねないという逆説もはらんでいる。",q:"意思決定が遅くなる原因として筆者が挙げていることは何か。",o:["人材の不足","予算の制約","情報不足","責任の所在が不明確な組織風土"],a:3,exp:"「責任の所在の不明確さに起因する」がそのまま答え。"},
      {q:"筆者が指摘する打開策は何か。",o:["責任を誰にも負わせない制度","人材を増やすこと","決断を先送りにする仕組み","権限と責任を明確に紐づける制度設計"],a:3,exp:"「権限と責任を明確に紐づける制度設計が不可欠」がそのまま答え。"},
      {q:"筆者が指摘する「逆説」とは何か。",o:["責任を明確にしすぎると挑戦を避ける風土を生みかねないこと","権限が多いほど責任も軽くなること","制度設計は不要だということ","責任があいまいなほうが効率的なこと"],a:0,exp:"「責任の所在を明確にしすぎると…萎縮した組織風土を生みかねない」がそのまま答え。"},
      {passage:"言語習得において、母語の影響を完全に排除することは不可能である。むしろ母語との違いを意識的に比較することこそが、効率的な学習につながると考えられる。学習者が自らの母語の癖に自覚的であればあるほど、誤りのパターンを予測し、対策を立てやすくなるからだ。",q:"筆者の考えに近いものはどれか。",o:["母語との違いを意識的に比較することが効率的な学習につながる","母語の影響は完全に排除すべきだ","比較は学習効果を下げる","母語は学習の妨げにしかならない"],a:0,exp:"「母語との違いを意識的に比較することこそが…学習につながる」が主張。"},
      {q:"母語の癖に自覚的であることの利点は何か。",o:["誤りのパターンを予測し対策を立てやすくなる","発音が自然に良くなる","文法を暗記しやすくなる","母語を完全に忘れられる"],a:0,exp:"「誤りのパターンを予測し、対策を立てやすくなる」がそのまま答え。"},
      {q:"この文章全体の要旨として最も適切なものはどれか。",o:["学習効果は母語と無関係だ","母語は学習において無視すべきだ","誤りを気にすべきではない","母語との対比を意識することが効果的な言語学習につながる"],a:3,exp:"文章全体を通して母語比較の有用性を訴えている。"},
      {passage:"批判的思考とは、単に他者の意見を否定することではない。自らの前提をも疑い、多角的な視点から物事を検証する姿勢を指すのである。この姿勢は一朝一夕に身につくものではなく、日々の小さな問いかけの積み重ねによって、徐々に養われていくものだ。",q:"筆者が定義する批判的思考とは何か。",o:["他者の意見を否定すること","議論に勝つための技術","自分の意見を主張すること","自らの前提も疑い多角的に検証する姿勢"],a:3,exp:"「自らの前提をも疑い、多角的な視点から…検証する姿勢」が定義。"},
      {q:"筆者は批判的思考がどのように養われると述べているか。",o:["日々の小さな問いかけの積み重ねによって","他者から教えられるだけで身につく","生まれつきの才能による","一度の訓練で完成する"],a:0,exp:"「日々の小さな問いかけの積み重ねによって、徐々に養われていく」がそのまま答え。"},
      {q:"この文章全体の趣旨として最も適切なものはどれか。",o:["批判的思考は短期間で完成する","他者の意見への反論こそが批判的思考だ","批判的思考は日々の積み重ねで徐々に養われる姿勢だ","批判的思考は生まれつきの才能だ"],a:2,exp:"文章全体を通して「日々の積み重ねで養われる姿勢」であることを強調している。"},
      {sec:"問題12　統合理解",passage:"【A】終身雇用制度は、従業員に安定と忠誠心をもたらし、長期的な人材育成を可能にしてきた。企業にとっても、離職率の低さは大きなメリットであり、この制度を安易に手放すべきではないという意見がある。<br><br>【B】しかし、終身雇用制度は、変化の激しい現代のビジネス環境には適していないという指摘もある。年功序列と結びついたこの制度は、若手の意欲的な挑戦を阻害し、企業の新陳代謝を妨げる要因にもなりかねない。",q:"Aの筆者が主張していることは何か。",o:["離職率は高い方がよい","若手の挑戦を阻害すべきだ","終身雇用制度をすぐに廃止すべきだ","終身雇用制度を安易に手放すべきではない"],a:3,exp:"Aは終身雇用制度の維持を支持している。"},
      {q:"Bの筆者が懸念していることは何か。",o:["終身雇用制度が若手の挑戦を阻害すること","離職率が低すぎること","終身雇用制度がすぐになくなること","雇用が流動的すぎること"],a:0,exp:"「若手の意欲的な挑戦を阻害し…新陳代謝を妨げる要因」が懸念。"},
      {sec:"問題13　主張理解（長文）",passage:"組織におけるリーダーシップとは、単に指示を出す能力ではなく、メンバーそれぞれの強みを引き出し、全体としての成果を最大化する力を指すと言えよう。優れたリーダーは、自らが前面に立って主導するだけでなく、時にはあえて一歩引き、メンバーが自律的に判断し行動できる環境を整えることに長けている。<br><br>この考え方に立てば、リーダーシップの評価基準も見直す必要が出てくる。従来は、決断力やカリスマ性が重視されがちであったが、それだけでは組織全体の持続的な成長を支えることは難しい。むしろ、メンバーの成長を辛抱強く見守り、失敗から学ぶ機会を与える度量こそが、真に評価されるべき資質ではないだろうか。",q:"筆者が定義するリーダーシップとは何か。",o:["指示を的確に出す能力","失敗を許さない厳格さ","権威を持って統率する力","メンバーの強みを引き出し成果を最大化する力"],a:3,exp:"「メンバーそれぞれの強みを引き出し…最大化する力」が定義。"},
      {q:"筆者が評価されるべきだと述べている資質は何か。",o:["決断力とカリスマ性のみ","メンバーに一切任せない厳格さ","常に前面に立ち主導する姿勢","メンバーの成長を見守り失敗から学ぶ機会を与える度量"],a:3,exp:"「メンバーの成長を辛抱強く見守り、失敗から学ぶ機会を与える度量」がそのまま答え。"},
      {q:"この文章全体を通して筆者が伝えたいことは何か。",o:["リーダーシップに正解は存在しない","リーダーシップは状況に応じた柔軟な使い分けが重要だ","リーダーは常に前面に立つべきだ","カリスマ性こそが唯一の評価基準だ"],a:1,exp:"従来の評価基準の見直しの必要性を訴える結論。"},
      {sec:"問題14　情報検索",passage:"【地域図書館　貸出サービス案内】<br>・利用登録：市内在住・在勤・在学者は無料。市外在住者は年間登録料1,000円。<br>・貸出冊数：一般書10冊、雑誌・DVD各2点まで、貸出期間は2週間。<br>・延長：予約が入っていない資料に限り、1回だけ2週間延長可能。<br>・予約サービス：他の利用者が借りている資料の予約が可能。準備ができ次第、メールで通知（登録者のみ）。<br>・注意：延滞が続いた場合、新規の貸出および予約サービスの利用が一時停止される。",q:"市外在住のAさんが本を借りたい場合、まず何をする必要があるか。",o:["年間登録料1,000円を払って利用登録をする","市内に転居する","無料で登録する","図書館に問い合わせるだけでよい"],a:0,exp:"「市外在住者は年間登録料1,000円」を払って登録する必要がある。"},
      {q:"この案内から分かることとして正しいものはどれか。",o:["延滞が続くと新規貸出が一時停止される","貸出期間は1か月である","予約は登録者以外も利用できる","延長は何回でもできる"],a:0,exp:"「延滞が続いた場合、新規の貸出および予約サービスの利用が一時停止される」がそのまま該当。"}
    ]},
    {id:"b", title:"聴解", minutes:50, questions:[
      {sec:"問題1　課題理解",audio:"男：来週の 株主総会の 準備、進んでいますか。　女：資料の 作成は ほぼ 終わりましたが、会場の 最終確認が まだです。今日中に 会場に 電話して 確認します。",q:"女の人は このあと、まず 何を しますか。",o:["会場に電話して確認する","司会者を決める","株主総会を延期する","資料を作り直す"],a:0,exp:"「今日中に 会場に 電話して 確認します」がそのまま答え。"},
      {audio:"女：新商品の 発売日、来月の 10日で よろしいですか。　男：はい、それで 進めてください。あと、プレスリリースの 原稿も 確認を お願いできますか。",q:"男の人は このあと まず 何を しますか。",o:["発売日を変更する","商品を回収する","会議を開く","プレスリリースの原稿を確認する"],a:3,exp:"「プレスリリースの 原稿も 確認を お願いできますか」がそのまま答え。"},
      {audio:"男：来週の 面接、履歴書の 確認は 済んでいますか。　女：まだです。今日の 午後、全員分に 目を通します。あと、面接会場の 準備も お願いできますか。",q:"女の人は このあと まず 何を しますか。",o:["面接を延期する","候補者に連絡する","履歴書を確認する","面接会場を準備する"],a:3,exp:"男性から依頼された「面接会場の準備」に「はい」と応じている。"},
      {audio:"女：来月の イベント、出演者の スケジュール調整は どうなっていますか。　男：ほぼ 固まりましたが、一人だけ 返事待ちです。今日中に 確認の 連絡を 入れます。",q:"男の人は このあと まず 何を しますか。",o:["出演者を増やす","会場を変更する","イベントを中止する","出演者に確認の連絡を入れる"],a:3,exp:"「今日中に 確認の 連絡を 入れます」がそのまま答え。"},
      {audio:"女：この 報告書、来週の 会議までに 仕上げないといけないんですが。　男：手伝いますよ。どこまで 進んでいますか。　女：データは まとまっているので、あとは 考察の 部分を お願いできますか。",q:"男の人は このあと、何を しますか。",o:["データをまとめる","報告書の考察の部分を書く","報告書を印刷する","会議の日程を変更する"],a:1,exp:"「考察の 部分を お願いできますか」への流れから、男性は考察部分を担当する。"},
      {sec:"問題2　ポイント理解",audio:"男：この 製品、返品が 多いですね。　女：説明書が 分かりにくいのが 一番の 原因だと 思います。",q:"女の人は、返品が 多い 一番の 原因は 何だと 言っていますか。",o:["価格が高すぎること","配送が遅いこと","説明書が分かりにくいこと","製品自体の欠陥"],a:2,exp:"「説明書が分かりにくいのが一番の原因」がそのまま答え。"},
      {audio:"女：この 工場、事故が 続いていますね。　男：老朽化した 設備も ありますが、一番の 問題は 安全確認の 手順が 形骸化していた ことだと思います。",q:"男の人は、事故が 続く 一番の 原因は 何だと 考えていますか。",o:["設備の老朽化","作業員の不注意","安全確認の手順が形骸化していたこと","天候の悪さ"],a:2,exp:"「一番の問題は安全確認の手順が形骸化していたこと」がそのまま答え。"},
      {audio:"男：今回の 新人研修、評判が 良くなかったですね。　女：内容よりも、日程が 詰め込みすぎだった ことが 一番の 問題だったと 思います。",q:"女の人は、評判が 悪かった 一番の 原因は 何だと 言っていますか。",o:["内容が悪かったこと","会場が狭かったこと","講師が不足していたこと","日程が詰め込みすぎだったこと"],a:3,exp:"「内容よりも、日程が詰め込みすぎだったことが一番の問題」がそのまま答え。"},
      {audio:"女：この アプリ、ダウンロード数が 伸び悩んでいますね。　男：機能自体は いいんですが、広告が 届いていないのが 一番の 原因だと思います。",q:"男の人は、ダウンロード数が 伸び悩む 一番の 原因は 何だと 考えていますか。",o:["機能が悪いこと","価格が高いこと","広告が届いていないこと","デザインが古いこと"],a:2,exp:"「機能自体はいいんですが、広告が届いていないのが一番の原因」がそのまま答え。"},
      {audio:"男：この 店舗、離職率が 高いですね。　女：シフトの 融通が 利かない ことが 一番の 原因だと 聞いています。",q:"女の人は、離職率が 高い 一番の 原因は 何だと 言っていますか。",o:["給料が安いこと","人間関係が悪いこと","仕事がきついこと","シフトの融通が利かないこと"],a:3,exp:"「シフトの融通が利かないことが一番の原因」がそのまま答え。"},
      {audio:"男：この プロジェクト、予算オーバーしていますね。　女：初期の 見積もりが 甘かった ことが 一番の 原因だと思います。",q:"女の人は、予算オーバーの 一番の 原因は 何だと 考えていますか。",o:["人件費の高騰","初期の見積もりが甘かったこと","為替の変動","追加要望が多すぎたこと"],a:1,exp:"「初期の見積もりが甘かったことが一番の原因」がそのまま答え。"},
      {sec:"問題3　概要理解",audio:"再生可能エネルギーの 普及に 伴い、電力供給の 安定性を どう 確保するかが 新たな 課題として 浮上している。天候による 発電量の 変動を 補う ため、蓄電技術への 投資が 急速に 進められている。",q:"この話は、主に何について述べていますか。",o:["停電の原因","再生可能エネルギー普及に伴う課題と対策","電気料金の値上げ","発電所の建設計画"],a:1,exp:"再生可能エネルギー普及に伴う電力安定性の課題と、蓄電技術による対策についての話。"},
      {audio:"歴史を 学ぶ 意義は、単なる 暗記に あるのではなく、現在を 相対化し、未来への 教訓を 得る ことに あるとされる。過去の 事例から 学ぶ ことで、同じ 過ちを 繰り返さずに 済むという 考え方である。",q:"この話は、主に何について述べていますか。",o:["歴史の年号の覚え方","歴史学者の役割","歴史を学ぶ意義についての一つの考え方","過去の戦争の原因"],a:2,exp:"歴史を学ぶ意義についての考察が主題。"},
      {audio:"多様性を 尊重する 社会とは、あらゆる 意見を 無条件に 受け入れる ことではなく、対話を 通じて 互いを 理解しようと 努め続ける プロセスそのものだという 指摘が ある。",q:"この話は、主に何について述べていますか。",o:["対立を避ける方法","多様性を測る指標","多様性の尊重の本質についての考え方","法律による多様性の保護"],a:2,exp:"多様性の尊重とは何かについての考察が主題。"},
      {audio:"人工知能の 発達によって、多くの 仕事が 自動化されつつある 一方、新しい 仕事が 失われる 仕事の 数を 上回るかどうかは 不確かであり、楽観的な 見方には 慎重で あるべきだという 意見が ある。",q:"この話は、主に何について述べていますか。",o:["AIによる雇用への影響への懸念","AIの開発費用","AI規制の法律","AIの技術的な仕組み"],a:0,exp:"AIによる雇用への影響とその不確実性についての話。"},
      {audio:"効率化ばかりを 追求する 風潮に 対し、雑談や 余白と いった 一見 無駄に 見える ものの 中にこそ、新しい 発想の 種が あるのではないかという 指摘が なされている。",q:"この話は、主に何について述べていますか。",o:["職場のルール作り","効率的な仕事の進め方","効率化の行き過ぎがもたらす弊害への懸念","雑談の内容の分析"],a:2,exp:"効率化偏重への懸念と、余白の価値についての話。"},
      {sec:"問題4　即時応答",audio:"この案件、少しお時間をいただけますか。",q:"最もよい返答はどれですか。",o:["はい、大丈夫です。","それは残念です。","おめでとうございます。","もう終わりました。"],a:0,exp:"時間の猶予を求める依頼への自然な返答は「はい、大丈夫です」。"},
      {audio:"恐縮ですが、この件は一旦白紙に戻させていただきたく。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","もう決まったことです。","それは嬉しいです。","承知しました。理由を伺ってもよろしいですか。"],a:3,exp:"白紙撤回の申し出への自然な返答は、承諾しつつ理由を尋ねる形。"},
      {audio:"このデータ、念のためもう一度確認していただけますか。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","それはすごいですね。","もう確認済みです、以上です。","承知しました。すぐ確認します。"],a:3,exp:"確認依頼への自然な返答は「承知しました。すぐ確認します」。"},
      {audio:"この提案、少々厳しいというのが正直な感想です。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","それは嬉しいです。","具体的にどの点が厳しいでしょうか。","もう決まりました。"],a:2,exp:"否定的な感想への自然な返答は、具体的な理由を尋ねる形。"},
      {audio:"恐れ入りますが、担当が変わりまして。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","もう変わっていません。","それは残念すぎます。","承知しました。新しいご担当者様をご紹介いただけますか。"],a:3,exp:"担当変更の連絡への自然な返答は、新担当者を確認する形。"},
      {audio:"この件、来週まで持ち越しということでよろしいでしょうか。",q:"最もよい返答はどれですか。",o:["それはおめでとうございます。","はい、それで結構です。","もう来週です。","いいえ、もう終わっています。"],a:1,exp:"持ち越しの確認への自然な返答は「はい、それで結構です」。"},
      {audio:"念のため伺いますが、この内容で間違いないでしょうか。",q:"最もよい返答はどれですか。",o:["それはすごいですね。","もう終わった話です。","はい、間違いありません。","いいえ、まだ始まっていません。"],a:2,exp:"内容確認への自然な返答は「はい、間違いありません」。"},
      {audio:"申し訳ございませんが、少々お時間をいただいております。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","もう終わったんですね。","それは嬉しいです。","承知しました。どのくらいかかりそうですか。"],a:3,exp:"時間を要するという連絡への自然な返答は、目安を尋ねる形。"},
      {audio:"この度は貴重なご意見をありがとうございました。",q:"最もよい返答はどれですか。",o:["いえ、お役に立てて何よりです。","もう終わりです。","それは残念ですね。","おめでとうございます。"],a:0,exp:"感謝の言葉への自然な返答は「お役に立てて何よりです」。"},
      {audio:"恐縮ですが、こちらの内容、少々お待ちいただけますか。",q:"最もよい返答はどれですか。",o:["はい、ゆっくりで構いません。","もう終わりました。","それはすごいですね。","いいえ、待てません。"],a:0,exp:"待ってほしいという依頼への自然な返答は「ゆっくりで構いません」。"},
      {audio:"この件、正式に決定する前に一度社内で共有していただけますか。",q:"最もよい返答はどれですか。",o:["もう共有しました、以上です。","それは大変ですね。","おめでとうございます。","承知しました。共有の場を設けます。"],a:3,exp:"共有依頼への自然な返答は「承知しました。共有の場を設けます」。"},
      {sec:"問題5　統合理解",audio:"司会：来年度の社員旅行、行き先の候補が三つ出ています。<br>男性A：私は温泉地がいいと思います。日頃の疲れを癒せますし、幅広い年代に喜ばれると思います。<br>女性：私は海外がいいと思います。非日常感がありますし、若手社員のモチベーションにもつながるのではないでしょうか。<br>男性B：予算とスケジュールを考えると、近場の観光地が現実的だと思います。一泊二日で行けますし、費用も抑えられます。<br>司会：予算の制約もありますし、今回は近場の観光地案で進めましょう。",q:"最終的にどの案で進めることになりましたか。",o:["温泉地案","海外案","三つを組み合わせた案","近場の観光地案"],a:3,exp:"司会が最後に「近場の観光地案で進めましょう」と決定している。"},
      {q:"男性Aが温泉地を推した理由は何ですか。",o:["スケジュールが組みやすいから","予算が最も安いから","若手のモチベーションが上がるから","疲れを癒せて幅広い年代に喜ばれるから"],a:3,exp:"「日頃の疲れを癒せますし、幅広い年代に喜ばれる」が理由。"},
      {audio:"司会：新しい社内報のテーマについて、三つ案があります。<br>男性A：社員紹介を中心にした企画がいいと思います。社内の交流が深まります。<br>女性：業界の最新動向を扱う専門的な内容にすべきだと思います。社員の知識向上につながります。<br>男性B：両方を組み合わせて、前半に社員紹介、後半に業界動向を載せるのはどうでしょうか。<br>司会：それでは、前半に社員紹介、後半に業界動向という組み合わせ案で進めましょう。",q:"最終的にどの案で進めることになりましたか。",o:["案がまとまらなかった","社員紹介と業界動向を組み合わせた案","業界動向のみの案","社員紹介のみの案"],a:1,exp:"司会が「前半に社員紹介、後半に業界動向という組み合わせ案で進めましょう」と決定している。"}
    ]}
  ]
},
{
  id:"o-n2-3", lvl:"N2", title:"Examen oficial N2 · 3", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙・文法）・読解", minutes:105, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 主張は 一理 ある。",o:["ひとり","いつり","いちり","いちりん"],a:2,exp:"一理→いちり「parte de razón」。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　その 事実は 顕在化しつつある。",o:["けんぜん","けんざい","けんさい","げんざい"],a:1,exp:"顕在→けんざい「manifiesto」。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は 寛容な 人だ。",o:["かんよ","かんよう","かんいよう","かんよん"],a:1,exp:"寛容→かんよう「tolerante」。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　その 説明は 釈然と しない。",o:["しゃくぜん","せきねん","しゃくねん","せきぜん"],a:0,exp:"釈然→しゃくぜん（釈然としない＝no quedar convencido）。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は 謙虚な 姿勢を 崩さない。",o:["けんぎょ","げんきょ","けんこ","けんきょ"],a:3,exp:"謙虚→けんきょ「humilde」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　いちりある はなし。",o:["一理","一律","一利","一里"],a:0,exp:"いちり→一理「parte de razón」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　けんきょな たいど。",o:["兼居","兼虚","謙居","謙虚"],a:3,exp:"けんきょ→謙虚「humilde」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　かんような せいかく。",o:["感用","感容","寛容","寛用"],a:2,exp:"かんよう→寛容「tolerante」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　けんざいかしつつある。",o:["権在","険在","現在","顕在"],a:3,exp:"けんざい→顕在「manifiesto」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　しゃくぜんと しない。",o:["昔然","石然","積然","釈然"],a:3,exp:"しゃくぜん→釈然「clarificado」。"},
      {sec:"問題3　語形成",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 資料は （　）専門的で、初心者には 難しい。",o:["無","不","超","非"],a:2,exp:"「超専門的」＝超（接頭語）+専門的、極端な程度を表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は （　）会長だ。",o:["旧","古","元","前"],a:2,exp:"「元会長」＝元（接頭語）+会長、以前その職だったことを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 商品は 生産（　）だ。",o:["内","後","前","中"],a:3,exp:"「生産中」＝生産+中（接尾語）、その最中であることを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女の 意見は （　）常識だ。",o:["未","非","超","不"],a:1,exp:"「非常識」＝非（接頭語）+常識、常識に反することを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 問題は 対応（　）だ。",o:["前","後","中","済み"],a:3,exp:"「対応済み」＝対応+済み（接尾語）、すでに対応したことを表す。"},
      {sec:"問題4　文脈規定",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 説明は （　）を 得ず、腑に 落ちない。",o:["理解","納得","承知","了承"],a:1,exp:"「納得を得ない」＝no resultar convincente。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は 反対派の 説得に （　）を 尽くした。",o:["方法","力","知恵","手"],a:3,exp:"「手を尽くす」＝agotar todos los medios。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　その 提案は 物議を （　）。",o:["呼んだ","醸した","招いた","起こした"],a:1,exp:"物議を醸す＝causar controversia。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は （　）交渉を 進めた。",o:["無計画に","乱暴に","率直に","したたかに"],a:3,exp:"「したたかに」＝con astucia。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 結果には （　）の 余地が ない。",o:["疑い","懐疑","疑問","不審"],a:2,exp:"「疑問の余地がない」＝no hay lugar a dudas。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は 難局を （　）乗り切った。",o:["巧みに","強引に","急激に","過剰に"],a:0,exp:"「巧みに」＝hábilmente。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女の 指摘は （　）を 突いていた。",o:["内心","核心","本心","中心"],a:1,exp:"「核心を突く」＝dar en el meollo。"},
      {sec:"問題5　言い換え類義",q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼の 話は 釈然と しなかった。",o:["感動した","面白かった","納得できなかった","分かりやすかった"],a:2,exp:"「釈然としない」≒「納得できなかった」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼は 謙虚な 態度を 保っている。",o:["無関心な","積極的な","傲慢な","控えめで礼儀正しい"],a:3,exp:"「謙虚」≒「控えめで礼儀正しい」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　この 計画は 採算が 取れない。",o:["人気がない","評判が悪い","時間がかかる","利益が出ない"],a:3,exp:"「採算が取れない」≒「利益が出ない」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼は 巧みに 危機を 乗り越えた。",o:["偶然に","仕方なく","無理やり","うまく、器用に"],a:3,exp:"「巧みに」≒「うまく、器用に」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼女の 意見は 核心を 突いていた。",o:["表面的な部分","最も重要な部分","過去の部分","不必要な部分"],a:1,exp:"「核心」≒「最も重要な部分」。"},
      {sec:"問題6　用法",q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「せめて」",o:["せめて怒って叫んだ。","せめて明日晴れるだろう。","せめて三人来た。","全部は無理でも、せめて半分だけでも終わらせたい。"],a:3,exp:"「せめて」＝al menos。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「にわかに」",o:["にわかに明日会議がある。","空がにわかにかき曇り、雨が降り出した。","にわかに三時に来た。","にわかに早く終わった。"],a:1,exp:"「にわかに」＝de repente。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「あえて」",o:["彼はあえて厳しい道を選んだ。","あえて三人来た。","あえて怒って叫んだ。","あえて明日晴れるだろう。"],a:0,exp:"「あえて」＝a propósito。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「もっぱら」",o:["もっぱら明日雨が降る。","もっぱら早く終わった。","最近はもっぱら在宅で仕事をしている。","もっぱら三時に会議がある。"],a:2,exp:"「もっぱら」＝exclusivamente。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「あわよくば」",o:["あわよくば明日会議がある。","あわよくば、優勝も狙えるかもしれない。","あわよくば三時に来た。","あわよくば早く終わった。"],a:1,exp:"「あわよくば」＝con suerte。"},
      {sec:"問題7　文法1（文法形式の判断）",q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　規則を 破った（　）、罰せられるのは 当然だ。",o:["うちに","以上","かたわら","上に"],a:1,exp:"「〜以上」＝dado que。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女の 才能（　）、成功は 時間の 問題だった。",o:["をもってすれば","ときたら","にひきかえ","はおろか"],a:0,exp:"「〜をもってすれば」＝con tal capacidad。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　失敗を 重ねた（　）、彼は ようやく 成功を つかんだ。",o:["ところで","なくして","すえに","かたわら"],a:2,exp:"「〜すえに」＝tras un largo proceso。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 態度は 傲慢（　）ほかならない。",o:["の","で","と","に"],a:3,exp:"「〜にほかならない」＝no es sino。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 問題は 議論すれば する（　）、複雑さを 増す ばかりだ。",o:["のみ","だけ","くらい","ほど"],a:3,exp:"「〜ば〜ほど」＝cuanto más...más。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は 疲れていた（　）、最後まで やり遂げた。",o:["かたわら","ゆえに","とあって","にもかかわらず"],a:3,exp:"「〜にもかかわらず」＝a pesar de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　規模の 大小（　）、この 問題は 軽視できない。",o:["を問わず","につき","にそくして","にわたって"],a:0,exp:"「〜を問わず」＝independientemente de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 貢献（　）、この プロジェクトは 成功しなかっただろう。",o:["ときたら","なくして","はおろか","にひきかえ"],a:1,exp:"「〜なくして（は）」＝sin (algo)。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は 逆境（　）、決して 諦めなかった。",o:["にひきかえ","ときたら","にあっても","はおろか"],a:2,exp:"「〜にあっても」＝incluso en (adversidad)。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は 経験の 乏しさ（　）、見事な 対応を 見せた。",o:["にひきかえ","をものともせず","ときたら","はおろか"],a:1,exp:"「〜をものともせず」＝sin dejarse afectar por。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　周囲の 反対（　）、彼は 計画を 実行した。",o:["を押し切って","にひきかえ","といえども","にもまして"],a:0,exp:"「〜を押し切って」＝haciendo caso omiso de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 実力（　）、この 結果は 当然だ。",o:["にひきかえ","はさておき","をものともせず","からすれば"],a:3,exp:"「〜からすれば」＝desde el punto de vista de。"},
      {sec:"問題8　文法2（文の組み立て）",q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女の　___　___　★　___　成功は 時間の 問題だった。（1 才能　2 を　3 もってすれば　4 も）",o:["も","才能","を","もってすれば"],a:3,exp:"正しい順序：1才能→2を→3もってすれば「才能をもってすれば」。★の位置には3「もってすれば」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　周囲の　___　★　___　___　彼は 計画を 実行した。（1 反対　2 を　3 押し切って　4 も）",o:["を","押し切って","も","反対"],a:1,exp:"正しい順序：1反対→2を→3押し切って「反対を押し切って」。★の位置には3「押し切って」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の　___　___　★　___　この 結果は 当然だ。（1 から　2 実力　3 すれば　4 も）",o:["から","も","すれば","実力"],a:0,exp:"正しい順序：2実力→1から→3すれば「実力からすれば」。★の位置には1「から」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の　___　___　★　___　このプロジェクトは 成功しなかっただろう。（1 貢献　2 なくして　3 も　4 は）",o:["貢献","も","は","なくして"],a:3,exp:"正しい順序：1貢献→2なくして「貢献なくして」。★の位置には2「なくして」が入る。"},
      {sec:"問題9　文章の文法",passage:"近年、地方創生という キーワードの もと、様々な 政策が 打ち出されて いる。しかし、一律の 施策を 全国に（1）だけでは、各地域固有の 課題に 対応しきれないという 指摘が ある。地域（2）異なる 歴史や 産業構造を 無視した 画一的な 支援策は、（3）効果を 上げにくい。真に 求められて いるのは、それぞれの 地域の 実情を 踏まえた、きめ細やかな 支援である。（4）、地域住民自身が 主体と なって 課題解決に 取り組む 姿勢も、同様に 重要だと 言えよう。行政と 住民、双方の（5）が、地方創生の 鍵を 握っているのである。",q:"（1）",o:["適用して","適用する","適用され","適用した"],a:1,exp:"「〜だけでは」に続く形として辞書形「適用する」が自然。"},
      {q:"（2）",o:["によって","に対して","にとって","において"],a:0,exp:"〜によって「según, dependiendo de」個体差を示す。"},
      {q:"（3）",o:["必ずしも","いっそう","むしろ","かえって"],a:0,exp:"「必ずしも〜にくい」で部分否定を導く。"},
      {q:"（4）",o:["ただし","つまり","同時に","ところが"],a:2,exp:"追加の論点を導く「同時に」が文脈に合う。"},
      {q:"（5）",o:["対立","分離","協働","競争"],a:2,exp:"文脈上、行政と住民の「協働」が地方創生の鍵になるという結論が自然。"},
      {sec:"問題10　内容理解（短文）",passage:"この企業は環境負荷の軽減を経営方針の柱に据え、生産工程の見直しを進めている。短期的なコスト増加は避けられないが、長期的な企業価値の向上を見込んでいる。",q:"この企業が見込んでいることは何か。",o:["従業員数の削減","長期的な企業価値の向上","短期的な利益の拡大","海外進出の拡大"],a:1,exp:"「長期的な企業価値の向上を見込んでいる」がそのまま答え。"},
      {passage:"この地域では、伝統工芸品の後継者不足が深刻化しており、行政と民間が連携した育成プログラムが開始された。若い世代への技術継承が急務とされている。",q:"育成プログラムの目的は何か。",o:["価格の引き上げ","若い世代への技術継承","観光客の誘致","輸出の拡大"],a:1,exp:"「若い世代への技術継承が急務」がそのまま答え。"},
      {passage:"この調査によれば、リモートワークの普及により、地方への移住を検討する都市部の若者が増加している。働く場所の制約が減ったことが背景にある。",q:"地方移住の増加の背景は何か。",o:["働く場所の制約が減ったこと","都市部の家賃高騰","地方の経済成長","交通網の発達"],a:0,exp:"「働く場所の制約が減ったことが背景」がそのまま答え。"},
      {passage:"この病院では、電子カルテの導入により、医師間の情報共有が円滑になり、診断の精度が向上したと報告されている。",q:"電子カルテ導入の効果は何か。",o:["患者数の増加","診療時間の短縮","医療費の削減","診断の精度向上"],a:3,exp:"「情報共有が円滑になり、診断の精度が向上した」がそのまま答え。"},
      {passage:"インターネット広告市場は急速に拡大しており、従来のテレビや新聞広告の市場規模を上回りつつある。企業側も広告戦略の見直しを迫られている。",q:"企業が迫られていることは何か。",o:["広告戦略の見直し","広告費の削減","新聞購読の促進","テレビ広告の増加"],a:0,exp:"「企業側も広告戦略の見直しを迫られている」がそのまま答え。"},
      {sec:"問題11　内容理解（中文）",passage:"教育の目的は、知識の詰め込みではなく、自ら考え、判断する力を養うことにあると言えよう。試験の点数のみで学びの成果を測ろうとする姿勢は、この本質を見誤らせる危険をはらんでいる。もちろん、基礎知識の習得は不可欠であり、それなしには思考の材料そのものが不足してしまう。",q:"筆者が危惧していることは何か。",o:["知識の詰め込みが不十分であること","試験の点数のみで学びを測ることが本質を見誤らせること","基礎知識の習得が不要になること","試験制度そのものの廃止"],a:1,exp:"「試験の点数のみで…測ろうとする姿勢は…本質を見誤らせる危険」がそのまま答え。"},
      {q:"筆者は基礎知識の習得についてどう考えているか。",o:["知識より応用力のほうが先に必要だ","思考の材料として不可欠である","不要であり廃止すべきだ","試験でのみ評価すべきだ"],a:1,exp:"「基礎知識の習得は不可欠であり、それなしには思考の材料そのものが不足してしまう」と述べている。"},
      {q:"この文章全体の趣旨として最も適切なものはどれか。",o:["思考力は生まれつきのものだ","試験は教育に不可欠な唯一の指標だ","試験の点数偏重が教育の本質を見誤らせる危険がある","基礎知識は不要である"],a:2,exp:"試験偏重への警鐘が文章全体の趣旨。"},
      {passage:"研究者にとって最も重要な資質は、既存の常識を疑う姿勢である。定説を鵜呑みにせず、あえて問い直すことから、新たな発見は生まれる。もっとも、根拠なく何でも疑えばよいというものではなく、疑いには相応の論理的な裏付けが必要である。",q:"筆者が述べる研究者にとって重要な資質は何か。",o:["効率よく実験を行う能力","論文を多く書く能力","既存の常識を疑う姿勢","定説を忠実に守る姿勢"],a:2,exp:"「既存の常識を疑う姿勢」が最重要資質とされている。"},
      {q:"筆者が付け加えている条件は何か。",o:["定説は常に正しいということ","疑いには論理的な裏付けが必要であること","疑うこと自体が目的だということ","何でも疑ってよいということ"],a:1,exp:"「疑いには相応の論理的な裏付けが必要である」がそのまま答え。"},
      {q:"この文章全体の趣旨として最も適切なものはどれか。",o:["何でも疑うことが研究の本質だ","常識は疑うべきではない","定説を守ることが研究者の使命だ","論理的根拠に基づいて常識を疑う姿勢が研究者に重要だ"],a:3,exp:"根拠ある懐疑の姿勢の重要性が文章全体の趣旨。"},
      {passage:"組織における心理的安全性という概念が、近年注目を集めている。率直な意見を言っても罰せられないという確信をメンバーが共有している状態を指すが、これは単に居心地のよい環境を意味するわけではない。むしろ、建設的な対立を歓迎する土壌があってこそ成立するものである。",q:"筆者が定義する心理的安全性とは何か。",o:["率直な意見を言っても罰せられないという確信の共有","居心地のよいぬるま湯的な環境","対立を一切避ける環境","上司にのみ意見が許される環境"],a:0,exp:"「率直な意見や懸念を口にしても…罰せられたりしない確信を、メンバーが共有している状態」が定義。"},
      {q:"筆者は心理的安全性についてどのような誤解を指摘しているか。",o:["効果がないという誤解","測定不可能だという誤解","単に居心地のよい環境だという誤解","上司にのみ必要だという誤解"],a:2,exp:"「単に居心地の良い、ぬるま湯的な環境を意味するわけではない」がそのまま答え。"},
      {q:"この文章全体の趣旨として最も適切なものはどれか。",o:["心理的安全性は建設的な対立があってこそ成立する","心理的安全性は対立を避けることで成立する","心理的安全性は上司だけが持つべきものだ","心理的安全性は不要な概念だ"],a:0,exp:"「建設的な対立を歓迎する土壌があってこそ、真の心理的安全性は成立する」が趣旨。"},
      {sec:"問題12　統合理解",passage:"【A】副業を認める企業が増えている。従業員が新たなスキルを身につけ、収入源を分散できることは、労働者にとって大きなメリットだ。企業にとっても、社外で得た知見が本業に還元される可能性があり、双方にとって有益な制度だと言えよう。<br><br>【B】しかし、副業解禁には慎重であるべきだという意見も根強い。本業への集中力が削がれ、長時間労働による健康被害のリスクが高まるという懸念がある。",q:"Aの筆者が主張していることは何か。",o:["副業は禁止すべきだ","副業は労働者にも企業にも有益な制度だ","副業は企業にのみ利益がある","副業は労働者にのみ利益がある"],a:1,exp:"Aは「双方にとって有益な制度」と述べている。"},
      {q:"Bの筆者が懸念していることは何か。",o:["副業を行う人がいなくなること","労働時間が短くなりすぎること","副業がすぐになくなること","健康被害のリスクや長時間労働"],a:3,exp:"「長時間労働による健康被害のリスク」が懸念。"},
      {sec:"問題13　主張理解（長文）",passage:"多様性を尊重する社会とは、異なる意見を単に許容するだけでなく、それらが交わることで新たな価値が生まれることを積極的に歓迎する社会である。対立を恐れず、そこから学ぶ姿勢こそが求められる。<br><br>ただし、ここで注意すべきは、「多様性の尊重」という言葉が、時に思考停止の言い訳として使われてしまう危険性である。あらゆる意見を無批判に等価値として扱うことは、真の多様性の尊重とは言えない。時には、明らかに誤った主張に対しては、毅然と反論する必要がある。",q:"筆者が定義する多様性を尊重する社会とは何か。",o:["一つの意見に統一される社会","対立を完全に避ける社会","異なる意見の交わりから新たな価値を歓迎する社会","異なる意見を無視する社会"],a:2,exp:"「異なる意見…交わることで新たな価値が生まれることを積極的に歓迎する社会」が定義。"},
      {q:"筆者が危険性として指摘していることは何か。",o:["対立が全く起きないこと","異なる意見が少ないこと","多様性の尊重が思考停止の言い訳に使われること","多様性を重視しすぎること"],a:2,exp:"「『多様性の尊重』という言葉が、時に思考停止の言い訳として使われてしまう危険性」がそのまま答え。"},
      {q:"筆者は誤った主張に対してどうすべきだと述べているか。",o:["無条件に受け入れるべきだ","毅然と反論する必要がある","無視すべきだ","議論を避けるべきだ"],a:1,exp:"「明らかに誤った主張…に対しては、毅然と反論する必要がある」がそのまま答え。"},
      {sec:"問題14　情報検索",passage:"【企業向け研修プログラム　案内】<br>・コース：Ａ「新人研修」（1日）／Ｂ「管理職研修」（2日）／Ｃ「グローバル人材育成」（3日、英語での実施）<br>・料金：1名につきＡ 30,000円、Ｂ 60,000円、Ｃ 100,000円（税別）。同一企業から5名以上の同時申込みで全体の10％割引。<br>・開催形式：対面またはオンライン、企業ごとに選択可能。ただし、Ｃコースは対面のみ。<br>・注意事項：Ｃコースの受講には、事前の英語力診断テスト（無料）の受験が必須。基準に満たない場合は受講をお断りする場合がある。",q:"ある企業がＣコースをオンラインで受講したい場合、どうなるか。",o:["追加料金を払えばオンラインで受講できる","Ｃコースはオンラインでは受講できない","事前診断テストなしで受講できる","問題なくオンラインで受講できる"],a:1,exp:"「Ｃコースは対面のみ」とあるため、オンラインでは受講できない。"},
      {q:"この案内から分かることとして正しいものはどれか。",o:["5名未満でも割引が適用される","すべてのコースはオンラインのみで実施される","Ｃコース受講には事前の英語力診断テストが必須である","キャンセルには一切料金がかからない"],a:2,exp:"「事前の英語力診断テスト…の受験が必須」がそのまま該当。"}
    ]},
    {id:"b", title:"聴解", minutes:50, questions:[
      {sec:"問題1　課題理解",audio:"男：来週の 取締役会の 資料、準備は 進んでいますか。　女：ほぼ 終わりましたが、財務データの 最終確認が まだです。今日中に 経理部に 確認を 取ります。",q:"女の人は このあと、まず 何を しますか。",o:["資料を作り直す","取締役会を延期する","財務データを削除する","経理部に確認を取る"],a:3,exp:"「今日中に 経理部に 確認を 取ります」がそのまま答え。"},
      {audio:"女：新しい オフィスの 内装、業者は 決まりましたか。　男：まだ 二社に 絞った 段階です。今日の 午後、見積もりを 比較します。",q:"男の人は このあと、まず 何を しますか。",o:["業者と契約する","オフィスを移転する","見積もりを比較する","内装工事を始める"],a:2,exp:"「今日の 午後、見積もりを 比較します」がそのまま答え。"},
      {audio:"男：来月の 展示会、ブースの デザイン案は 決まりましたか。　女：三案の 中から、社内アンケートで 人気だった ものに 決めようと 思っています。今日 結果を 集計します。",q:"女の人は このあと、まず 何を しますか。",o:["アンケート結果を集計する","展示会を中止する","デザインをやり直す","業者に発注する"],a:0,exp:"「今日 結果を 集計します」がそのまま答え。"},
      {audio:"女：来週の 海外出張、ホテルの 予約は できていますか。　男：まだです。今日中に、会社指定の 旅行代理店に 連絡します。",q:"男の人は このあと、まず 何を しますか。",o:["旅行代理店に連絡する","出張を中止する","航空券を購入する","現地の会社に連絡する"],a:0,exp:"「今日中に、会社指定の 旅行代理店に 連絡します」がそのまま答え。"},
      {audio:"女：この 提案書、来週の プレゼンまでに 仕上げないといけないんですが。　男：手伝いますよ。どこまで 進んでいますか。　女：構成は できているので、あとは グラフの 作成を お願いできますか。",q:"男の人は このあと、何を しますか。",o:["提案書を印刷する","プレゼンの日程を変更する","提案書のグラフを作成する","構成を作り直す"],a:2,exp:"「グラフの 作成を お願いできますか」への流れから、男性はグラフ作成を担当する。"},
      {sec:"問題2　ポイント理解",audio:"男：このソフトウェア、なかなか普及しませんね。　女：価格の高さも一因ですが、一番の問題は操作が複雑すぎることだと思います。",q:"女の人は、普及しない 一番の 原因は 何だと 言っていますか。",o:["価格が高いこと","広告が少ないこと","操作が複雑すぎること","競合が多いこと"],a:2,exp:"「一番の問題は操作が複雑すぎること」がそのまま答え。"},
      {audio:"女：この地域、観光客が減っていますね。　男：交通の便もありますが、一番大きいのは、SNSでの発信が他の観光地に比べて弱いことだと思います。",q:"男の人は、観光客が 減った 一番の 原因は 何だと 考えていますか。",o:["交通の便が悪いこと","宿泊施設が少ないこと","SNSでの発信が弱いこと","天候が悪いこと"],a:2,exp:"「一番大きいのは、SNSでの発信が…弱いこと」がそのまま答え。"},
      {audio:"男：この製品、クレームが増えていますね。　女：品質自体よりも、説明書の翻訳が不自然なことが一番の原因だと聞いています。",q:"女の人は、クレームが 増えた 一番の 原因は 何だと 言っていますか。",o:["価格が高すぎること","配送が遅いこと","説明書の翻訳が不自然なこと","製品の品質が悪いこと"],a:2,exp:"「説明書の翻訳が不自然なことが一番の原因」がそのまま答え。"},
      {audio:"女：この学校、退学者が増えていますね。　男：経済的な理由もありますが、一番の原因は、入学前と実際の授業内容のギャップだと言われています。",q:"男の人は、退学者が 増えた 一番の 原因は 何だと 考えていますか。",o:["教師の質","経済的な理由","施設の古さ","入学前と実際の授業内容のギャップ"],a:3,exp:"「一番の原因は、入学前と実際の授業内容のギャップ」がそのまま答え。"},
      {audio:"男：この工場、生産効率が落ちていますね。　女：設備の老朽化もありますが、一番の原因は、作業手順の見直しが長年されていないことだと思います。",q:"女の人は、生産効率低下の 一番の 原因は 何だと 考えていますか。",o:["設備の老朽化","人員の不足","原材料の不足","作業手順の見直しがされていないこと"],a:3,exp:"「一番の原因は、作業手順の見直しが長年されていないこと」がそのまま答え。"},
      {audio:"女：この飲食店、客の回転率が悪いですね。　男：メニューの品数もありますが、一番の問題は、会計システムに時間がかかりすぎることだと思います。",q:"男の人は、回転率が 悪い 一番の 原因は 何だと 考えていますか。",o:["スタッフが少ないこと","会計システムに時間がかかること","席の配置が悪いこと","メニューの品数が多いこと"],a:1,exp:"「一番の問題は、会計システムに時間がかかりすぎること」がそのまま答え。"},
      {sec:"問題3　概要理解",audio:"組織の意思決定の遅さは、責任の所在の不明確さに起因すると言われる一方、責任を明確にしすぎると挑戦を避ける風土を生むという逆説もある。",q:"この話は、主に何について述べていますか。",o:["人事評価の方法","組織の意思決定における責任と挑戦のバランス","会議の効率的な進め方","給与制度の設計"],a:1,exp:"責任の明確化と挑戦を許容する文化のバランスについての話。"},
      {audio:"副業を認める企業が増える中、労働者にも企業にもメリットがあるという意見がある一方、健康被害や情報漏洩を懸念する声もあり、労働時間の管理体制が課題となっている。",q:"この話は、主に何について述べていますか。",o:["副業解禁のメリットと課題","副業禁止の歴史","副業の税制上の扱い","副業の探し方"],a:0,exp:"副業解禁の利点と課題についての話。"},
      {audio:"効率化を追求するあまり、雑談や余白といった一見無駄に見えるものの中にある創造性の芽まで失われつつあるのではないかという指摘があり、効率と余白の共存が求められている。",q:"この話は、主に何について述べていますか。",o:["効率的な会議の進め方","職場のルール作り","過度な効率化が創造性を損なう可能性への懸念","労働時間の短縮策"],a:2,exp:"効率偏重への懸念と、余白の価値についての話。"},
      {audio:"研究者にとって重要な資質は既存の常識を疑う姿勢だが、根拠のない懐疑は意味がなく、疑いには論理的な裏付けが必要だという指摘がある。",q:"この話は、主に何について述べていますか。",o:["研究費の獲得方法","学会発表の準備","研究者に必要な批判的思考のあり方","論文の書き方"],a:2,exp:"研究者に求められる思考態度についての話。"},
      {audio:"教育の目的は知識の詰め込みではなく自ら考え判断する力を養うことにあるとされるが、基礎知識の習得もまた不可欠だという指摘がある。",q:"この話は、主に何について述べていますか。",o:["学校の設備投資","教育における基礎知識と思考力の関係","入試制度の改革","教員の待遇改善"],a:1,exp:"教育の目的と基礎知識の重要性についての話。"},
      {sec:"問題4　即時応答",audio:"この案件、少々お時間をいただいてもよろしいでしょうか。",q:"最もよい返答はどれですか。",o:["もう終わりました。","おめでとうございます。","それは残念です。","はい、構いません。"],a:3,exp:"時間の猶予を求める依頼への自然な返答は「はい、構いません」。"},
      {audio:"申し訳ございませんが、この価格ではお引き受けしかねます。",q:"最もよい返答はどれですか。",o:["それは嬉しいです。","もう決まったことです。","では、どのくらいの価格であれば可能でしょうか。","おめでとうございます。"],a:2,exp:"価格を理由に断られた際の自然な返答は、条件を尋ねる形。"},
      {audio:"この企画、正直な感想をお聞かせいただけますか。",q:"最もよい返答はどれですか。",o:["もう決まりました。","それはすごいですね。","おめでとうございます。","率直に申し上げますと、少し懸念があります。"],a:3,exp:"率直な感想を求められた際の自然な返答。"},
      {audio:"恐縮ですが、少々検討にお時間をいただいております。",q:"最もよい返答はどれですか。",o:["承知しました。目安を教えていただけますか。","もう終わったんですね。","それは嬉しいです。","おめでとうございます。"],a:0,exp:"時間を要するという連絡への自然な返答は、目安を尋ねる形。"},
      {audio:"この件、上層部の承認が必要になりそうです。",q:"最もよい返答はどれですか。",o:["承知しました。どのくらいで結果が分かりますか。","それは残念すぎます。","おめでとうございます。","もう承認されています。"],a:0,exp:"承認プロセスの連絡への自然な返答は、期間を確認する形。"},
      {audio:"念のため、この認識で相違ないか確認させてください。",q:"最もよい返答はどれですか。",o:["もう終わった話です。","それはすごいですね。","はい、その認識で間違いありません。","いいえ、まだ始まっていません。"],a:2,exp:"認識確認への自然な返答は「はい、その認識で間違いありません」。"},
      {audio:"この度は多大なご迷惑をおかけし、深くお詫び申し上げます。",q:"最もよい返答はどれですか。",o:["いえ、こちらこそ配慮が足りませんでした。","もっとやってください。","おめでとうございます。","それは嬉しいです。"],a:0,exp:"謝罪への自然な返答は、相手を責めずに応じる形。"},
      {audio:"この提案、社内での反応はいかがでしょうか。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","それは残念ですね。","もう終わりました。","概ね好評ですが、一部懸念の声もあります。"],a:3,exp:"社内の反応を尋ねられた際の自然な返答。"},
      {audio:"この度はご丁寧なご説明をいただき、恐縮です。",q:"最もよい返答はどれですか。",o:["それは残念ですね。","おめでとうございます。","もう終わりです。","いえ、お役に立てば幸いです。"],a:3,exp:"感謝の言葉への自然な返答。"},
      {audio:"恐れ入りますが、こちらの資料、少々古い可能性がございます。",q:"最もよい返答はどれですか。",o:["承知しました。最新版を確認いたします。","もう最新版です、以上です。","おめでとうございます。","それはすごいですね。"],a:0,exp:"資料が古い可能性を指摘された際の自然な返答。"},
      {audio:"この件、事前に社内で共有しておいていただけますか。",q:"最もよい返答はどれですか。",o:["もう共有済みです。","おめでとうございます。","承知しました。明日までに共有します。","それは大変ですね。"],a:2,exp:"共有依頼への自然な返答。"},
      {sec:"問題5　統合理解",audio:"司会：新しい社員食堂のメニュー方針について、三つ案があります。<br>男性A：健康志向のメニューを中心にすべきだと思います。低カロリーで栄養バランスの取れたものを増やすべきです。<br>女性：私はボリューム重視のメニューがいいと思います。特に体力仕事の社員には量が大事です。<br>男性B：両方のニーズに応えるため、日替わりで健康メニューとボリュームメニューを両方用意するのはどうでしょうか。<br>司会：それでは、日替わりで両方のメニューを用意する案で進めましょう。",q:"最終的にどの案で進めることになりましたか。",o:["ボリューム重視メニューのみの案","日替わりで両方のメニューを用意する案","現状維持の案","健康志向メニューのみの案"],a:1,exp:"司会が「日替わりで両方のメニューを用意する案で進めましょう」と決定している。"},
      {q:"女性がボリューム重視のメニューを推した理由は何ですか。",o:["体力仕事の社員には量が大事だから","健康志向の社員が少ないから","調理が簡単だから","予算が最も安いから"],a:0,exp:"「特に体力仕事の社員には量が大事です」が理由。"},
      {audio:"司会：新入社員のメンター制度について、三つ案があります。<br>男性A：ベテラン社員一人につき新人一人のマンツーマン方式がいいと思います。<br>女性：私はチーム全体でサポートする方式がいいと思います。特定の人に負担が偏りません。<br>男性B：両方を組み合わせて、メインのメンターを一人決めつつ、チーム全体でもサポートする形はどうでしょうか。<br>司会：それでは、メインメンターとチームサポートを組み合わせる案で進めましょう。",q:"最終的にどの案で進めることになりましたか。",o:["チーム全体でサポートする案のみ","制度自体を導入しない案","メインメンターとチームサポートを組み合わせる案","マンツーマン方式のみの案"],a:2,exp:"司会が「メインメンターとチームサポートを組み合わせる案で進めましょう」と決定している。"}
    ]}
  ]
},
{
  id:"o-n2-4", lvl:"N2", title:"Examen oficial N2 · 4", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙・文法）・読解", minutes:105, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 事業は 採算が 取れない。",o:["さいさん","さいざん","さいさく","さいそん"],a:0,exp:"採算→さいさん「rentabilidad」。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は 寡黙な 人だ。",o:["かもつ","かもく","かぼく","がもく"],a:1,exp:"寡黙→かもく「taciturno」。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女の 対応は 秀逸だった。",o:["ひでおつ","ひでいつ","しゅういつ","しゅうえつ"],a:2,exp:"秀逸→しゅういつ「excelente」。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　その 決定は 拙速だった。",o:["せつすみ","せっすみ","せつそく","せっそく"],a:3,exp:"拙速→せっそく「apresurado」。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は 執着を 捨てられなかった。",o:["しつちゃく","しゅうじゃく","しっちゃく","しゅうちゃく"],a:3,exp:"執着→しゅうちゃく「apego」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　さいさんが とれない。",o:["裁算","採参","裁参","採算"],a:3,exp:"さいさん→採算「rentabilidad」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　かもくな ひと。",o:["過默","寡默","過黙","寡黙"],a:3,exp:"かもく→寡黙「taciturno」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　しゅういつな たいおう。",o:["秀逸","習逸","集逸","秀一"],a:0,exp:"しゅういつ→秀逸「excelente」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　せっそくな はんだん。",o:["説速","接速","切速","拙速"],a:3,exp:"せっそく→拙速「apresurado」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　しゅうちゃくを すてる。",o:["習着","執著","執着","集着"],a:2,exp:"しゅうちゃく→執着「apego」。"},
      {sec:"問題3　語形成",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 計画は （　）実現的だ。",o:["不","超","非","未"],a:2,exp:"「非現実的」＝非（接頭語）+現実的、現実離れしていることを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は （　）担当者だ。",o:["旧","前","元","古"],a:1,exp:"「前担当者」＝前（接頭語）+担当者、以前その職だったことを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この システムは 開発（　）だ。",o:["前","内","後","中"],a:3,exp:"「開発中」＝開発+中（接尾語）、その最中であることを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は （　）合理的な 判断を した。",o:["未","非","超","不"],a:2,exp:"「超合理的」＝超（接頭語）+合理的、極端な程度を表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 問題は 確認（　）だ。",o:["中","済み","後","前"],a:1,exp:"「確認済み」＝確認+済み（接尾語）、すでに確認したことを表す。"},
      {sec:"問題4　文脈規定",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 意見は （　）に 富んでいる。",o:["納得感","説得力","満足感","賛成感"],a:1,exp:"「説得力に富む」＝tener gran poder de convicción。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 制度は （　）に 見直される。",o:["一時的","定期的","突発的","偶発的"],a:1,exp:"「定期的に見直す」＝revisar periódicamente。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は 難しい 状況を （　）乗り越えた。",o:["強引に","巧みに","急激に","過剰に"],a:1,exp:"「巧みに」＝hábilmente。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 問題の （　）は 深刻だ。",o:["態度","実態","感想","条件"],a:1,exp:"「実態は深刻だ」＝la situación real es grave。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女の 指摘は （　）を 突いていた。",o:["内心","核心","本心","中心"],a:1,exp:"「核心を突く」＝dar en el meollo。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 案には （　）の 余地が ある。",o:["検討","賛成","満足","納得"],a:0,exp:"「検討の余地がある」＝hay margen para reconsiderar。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 発言は 会議で （　）を 呼んだ。",o:["物議","話題","評判","注目"],a:0,exp:"物議を呼ぶ＝causar controversia。"},
      {sec:"問題5　言い換え類義",q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼の 話は 釈然と しなかった。",o:["面白かった","分かりやすかった","納得できなかった","感動した"],a:2,exp:"「釈然としない」≒「納得できなかった」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼は 謙虚な 態度を 保っている。",o:["無関心な","控えめで礼儀正しい","傲慢な","積極的な"],a:1,exp:"「謙虚」≒「控えめで礼儀正しい」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　この 計画は 採算が 取れない。",o:["評判が悪い","人気がない","利益が出ない","時間がかかる"],a:2,exp:"「採算が取れない」≒「利益が出ない」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼は 巧みに 危機を 乗り越えた。",o:["偶然に","無理やり","うまく、器用に","仕方なく"],a:2,exp:"「巧みに」≒「うまく、器用に」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼女の 意見は 核心を 突いていた。",o:["過去の部分","最も重要な部分","不必要な部分","表面的な部分"],a:1,exp:"「核心」≒「最も重要な部分」。"},
      {sec:"問題6　用法",q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「よしんば」",o:["よしんば早く終わった。","よしんば三時に来た。","よしんば失敗したとしても、後悔はしない。","よしんば明日晴れるだろう。"],a:2,exp:"「よしんば〜としても」＝incluso suponiendo que。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「かろうじて」",o:["かろうじて明日雨が降る。","かろうじて早く終わった。","終電にかろうじて間に合った。","かろうじて三時に会議がある。"],a:2,exp:"「かろうじて」＝a duras penas。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「言わずもがな」",o:["彼の実力は言わずもがな、誰もが認めるところだ。","言わずもがな三時に来た。","言わずもがな明日晴れるだろう。","言わずもがな早く終わった。"],a:0,exp:"「言わずもがな」＝ni que decir tiene。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「なまじ」",o:["なまじ早く終わった。","なまじ三時に会議がある。","なまじ知識があるばかりに、かえって迷うことがある。","なまじ明日雨が降る。"],a:2,exp:"「なまじ」＝precisamente porque (algo) resulta contraproducente。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「ひいては」",o:["ひいては三時に来た。","ひいては早く終わった。","ひいては明日雨が降る。","個人の成長は、ひいては組織全体の発展につながる。"],a:3,exp:"「ひいては」＝y por extensión。"},
      {sec:"問題7　文法1（文法形式の判断）",q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 提案は 斬新である（　）、実現には 課題が 多い。",o:["反面","べく","つつ","あまり"],a:0,exp:"「〜反面」＝por otro lado。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は 若手（　）、堂々とした 態度で 発表した。",o:["にしたら","というより","にとって","でありながら"],a:3,exp:"「〜でありながら」＝a pesar de ser。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は 反対意見（　）、自説を 曲げなかった。",o:["にもまして","にひきかえ","といえども","をよそに"],a:3,exp:"「〜をよそに」＝haciendo caso omiso de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 実績（　）、この 昇進は 妥当だろう。",o:["に照らせば","をよそに","はおろか","にひきかえ"],a:0,exp:"「〜に照らせば」＝a la luz de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　規則に 反する（　）、罰則が 科される。",o:["ものは","場合には","につれ","次第では"],a:1,exp:"「〜場合には」＝en caso de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は 経験の 乏しさ（　）、見事な 対応を 見せた。",o:["ときたら","はおろか","にひきかえ","をものともせず"],a:3,exp:"「〜をものともせず」＝sin dejarse afectar por。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 問題は 議論すれば する（　）、複雑さを 増す ばかりだ。",o:["のみ","くらい","ほど","だけ"],a:2,exp:"「〜ば〜ほど」＝cuanto más...más。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　社員の 声を 反映する（　）、制度を 見直した。",o:["がてら","べく","かねて","もかまわず"],a:1,exp:"「〜べく」＝con el fin de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　周囲の 反対を （　）、彼は 計画を 実行した。",o:["もとに","押し切って","かねて","めぐって"],a:1,exp:"「〜を押し切って」＝haciendo caso omiso de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　経験の 有無に （　）、誰でも 参加できる。",o:["わたって","こたえて","そって","かかわらず"],a:3,exp:"「〜にかかわらず」＝independientemente de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　失敗を 重ねた（　）、彼は ようやく 成功を つかんだ。",o:["なくして","すえに","ところで","かたわら"],a:1,exp:"「〜すえに」＝tras un largo proceso。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　規則を 破った（　）、罰せられるのは 当然だ。",o:["上に","うちに","以上","かたわら"],a:2,exp:"「〜以上」＝dado que。"},
      {sec:"問題8　文法2（文の組み立て）",q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　社員の　___　___　★　___　制度を 見直した。（1 反映する　2 声を　3 べく　4 現場の）",o:["反映する","声を","べく","現場の"],a:2,exp:"正しい順序：4現場の→2声を→1反映する→3べく「現場の声を反映するべく」。★の位置には3「べく」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 提案は　___　___　★　___　実現には 課題が 多い。（1 反面　2 斬新である　3 も　4 実に）",o:["斬新である","反面","も","実に"],a:1,exp:"正しい順序：2斬新である→1反面「斬新である反面」。★の位置には1「反面」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　周囲の　___　___　★　___　彼は 計画を 実行した。（1 反対　2 を　3 押し切って　4 も）",o:["押し切って","反対","も","を"],a:0,exp:"正しい順序：1反対→2を→3押し切って「反対を押し切って」。★の位置には3「押し切って」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　経験の　___　___　★　___　誰でも 参加できる。（1 に　2 かかわらず　3 有無　4 も）",o:["かかわらず","に","有無","も"],a:0,exp:"正しい順序：3有無→1に→2かかわらず「有無にかかわらず」。★の位置には2「かかわらず」が入る。"},
      {sec:"問題9　文章の文法",passage:"科学研究の 世界では、失敗は 避けるべき ものと いうより、むしろ 新たな 発見への（1）と 捉えられる ことが 多い。仮説が 誤っていたと 分かる こと自体が、次の 仮説を（2）ための 貴重な 手がかりと なるからだ。しかし、成果主義が 強まる 昨今、失敗を 許容しない 風潮も 同時に 強まっている（3）指摘される。研究者が 失敗を 恐れる あまり、確実に 成果の 出る 安全な 研究テーマばかりを 選ぶように なれば、（4）画期的な 発見の 芽は 摘まれてしまいかねない。真に 創造的な 研究を 育むには、失敗を（5）評価する 文化の 醸成が 不可欠だと 言えよう。",q:"（1）",o:["結果","終着点","布石","義務"],a:2,exp:"布石「preparación para el futuro」比喩的に次への一歩を表す。"},
      {q:"（2）",o:["立てられ","立てた","立てる","立てて"],a:2,exp:"「〜ための」に続く動詞は辞書形「立てる」。"},
      {q:"（3）",o:["に","が","と","を"],a:2,exp:"「〜と指摘される」引用・内容を示す助詞。"},
      {q:"（4）",o:["したがって","むしろ","かえって","つまり"],a:2,exp:"逆説的な結果を導く「かえって」が文脈に合う。"},
      {q:"（5）",o:["消極的に","一切","前向きに","否定的に"],a:2,exp:"文脈上、失敗を「前向きに」評価する文化が求められているという結論が自然。"},
      {sec:"問題10　内容理解（短文）",passage:"この自治体では、子育て世帯への支援策として、保育料の無償化を実施した。その結果、若い世帯の転入が増加している。",q:"保育料無償化の結果、何が起きたか。",o:["保育士の不足","税収の減少","若い世帯の転入増加","人口の減少"],a:2,exp:"「若い世帯の転入が増加している」がそのまま答え。"},
      {passage:"この大学では、留学生と日本人学生が共同で生活する寮を新設した。異文化交流を通じた相互理解の促進が狙いだ。",q:"新しい寮の目的は何か。",o:["施設の老朽化対策","異文化交流を通じた相互理解の促進","家賃収入の増加","留学生数の制限"],a:1,exp:"「異文化交流を通じた相互理解の促進が狙い」がそのまま答え。"},
      {passage:"この業界では、人材の流動性が高まっており、転職を経験することが一般的になっている。企業側も中途採用に力を入れざるを得ない状況だ。",q:"企業はなぜ中途採用に力を入れているか。",o:["業績が悪化したから","人材の流動性が高まっているから","新卒採用を廃止したから","法律で義務付けられているから"],a:1,exp:"「人材の流動性が高まっており…中途採用に力を入れざるを得ない」がそのまま答え。"},
      {passage:"インターネット広告市場は急速に拡大しており、従来のテレビや新聞広告の市場規模を上回りつつある。企業側も広告戦略の見直しを迫られている。",q:"企業が迫られていることは何か。",o:["新聞購読の促進","テレビ広告の増加","広告費の削減","広告戦略の見直し"],a:3,exp:"「企業側も広告戦略の見直しを迫られている」がそのまま答え。"},
      {passage:"この病院では、待ち時間の長さが患者の不満の原因となっていた。予約システムを改善した結果、待ち時間が大幅に短縮された。",q:"待ち時間が短縮された理由は何か。",o:["予約システムの改善","診療時間の延長","医師の増員","患者数の減少"],a:0,exp:"「予約システムを改善した結果、待ち時間が大幅に短縮された」がそのまま答え。"},
      {sec:"問題11　内容理解（中文）",passage:"組織における心理的安全性という概念が、近年ますます重視されている。率直な意見や懸念を口にしても、罰せられたり恥をかかされたりしないという確信をメンバーが共有している状態を指す。",q:"筆者が定義する心理的安全性とは何か。",o:["居心地のよいぬるま湯的な環境","対立を一切避ける環境","上司にのみ意見が許される環境","率直な意見を言っても罰せられないという確信の共有"],a:3,exp:"「率直な意見や懸念を口にしても…罰せられたりしない確信を、メンバーが共有している状態」が定義。"},
      {q:"心理的安全性が低い組織で起きることとして述べられているのは何か。",o:["業績が必ず向上すること","給料が必ず上がること","離職率が必ず下がること","問題の早期発見が遅れがちになること"],a:3,exp:"「本音を言わなくなり、結果として問題の早期発見が遅れがちになる」がそのまま答え。"},
      {q:"この文章の要旨として最も適切なものはどれか。",o:["対立は組織にとって常に有害だ","心理的安全性の構築は組織の競争力に直結する","心理的安全性は簡単に構築できる","居心地のよさこそが最も重要だ"],a:1,exp:"「その構築は、組織の長期的な競争力に直結する重要な課題」が結論。"},
      {passage:"効率化ばかりを追求する現代社会において、雑談や余白といった一見無駄に見えるものの中にこそ、新しい発想の種が潜んでいるのではないかという指摘がある。無駄を一律に排除する姿勢は、かえって組織の創造性を損なう危険をはらんでいる。",q:"筆者が指摘する危険は何か。",o:["無駄を一律に排除することが創造性を損なうこと","効率化が全く進まないこと","余白が多すぎること","雑談を推奨しすぎること"],a:0,exp:"「無駄を一律に排除する姿勢は、かえって組織の創造性を損なう危険」がそのまま答え。"},
      {q:"筆者は雑談や余白をどう捉えているか。",o:["業務効率を下げるだけのもの","完全に無駄なもの","新しい発想の種になりうるもの","時間の浪費でしかないもの"],a:2,exp:"「新しい発想の種が潜んでいるのではないか」と肯定的に捉えている。"},
      {q:"この文章全体の趣旨として最も適切なものはどれか。",o:["余白は完全に排除すべきだ","雑談は業務の妨げにしかならない","効率化はすべて推進すべきだ","効率偏重の姿勢が組織の創造性を損なう危険がある"],a:3,exp:"効率偏重への警鐘が文章全体の趣旨。"},
      {passage:"終身雇用制度は、従業員に安定と忠誠心をもたらし、長期的な人材育成を可能にしてきた。しかし、変化の激しい現代のビジネス環境には適していないという指摘もある。",q:"終身雇用制度の利点として挙げられているのは何か。",o:["安定と忠誠心をもたらし長期的な人材育成を可能にすること","若手の挑戦を促進すること","企業の新陳代謝を促すこと","離職率を高めること"],a:0,exp:"「従業員に安定と忠誠心をもたらし、長期的な人材育成を可能にしてきた」がそのまま答え。"},
      {q:"終身雇用制度への指摘として述べられているのは何か。",o:["現代にこそ最も適した制度だ","従業員の不満を増加させる","企業のコストを削減する","変化の激しい現代のビジネス環境には適していない"],a:3,exp:"「変化の激しい現代のビジネス環境には適していないという指摘もある」がそのまま答え。"},
      {q:"この文章全体の趣旨として最も適切なものはどれか。",o:["終身雇用制度は廃止すべきだ","終身雇用制度は完全に時代遅れだ","終身雇用制度に課題は存在しない","終身雇用制度には利点と課題の両面がある"],a:3,exp:"利点と現代における課題の両方を扱っている。"},
      {sec:"問題12　統合理解",passage:"【A】人工知能の発達により、これまで人間にしかできないと思われていた仕事の一部が自動化されつつある。この変化を前向きに捉え、人間はより創造的な業務にシフトしていくべきだという声もある。<br><br>【B】しかし、この楽観的な見方には慎重であるべきだ。新たに生まれる「創造的な仕事」の数が、失われる仕事の数を上回る保証はどこにもない。",q:"Aの筆者が主張していることは何か。",o:["単純作業のみが自動化される","AIの発展はすぐに止めるべきだ","知的業務は自動化されない","人間はより創造的な業務にシフトすべきだ"],a:3,exp:"Aは「人間はより創造的な業務にシフトしていくべき」と前向きに捉えている。"},
      {q:"Bの筆者が懸念していることは何か。",o:["技術革新自体が起きないこと","AIが全く発展しないこと","新しい仕事が失われる仕事を上回る保証がないこと","単純作業が残り続けること"],a:2,exp:"「新たに生まれる…仕事の数が、失われる仕事の数を上回る保証はどこにもない」が懸念。"},
      {sec:"問題13　主張理解（長文）",passage:"組織におけるリーダーシップとは、単に指示を出す能力ではなく、メンバーそれぞれの強みを引き出し、全体としての成果を最大化する力を指すと言えよう。優れたリーダーは、自らが前面に立って主導するだけでなく、時にはあえて一歩引き、メンバーが自律的に判断し行動できる環境を整えることに長けている。<br><br>この考え方に立てば、リーダーシップの評価基準も見直す必要が出てくる。従来は、決断力やカリスマ性が重視されがちであったが、それだけでは組織全体の持続的な成長を支えることは難しい。",q:"筆者が定義するリーダーシップとは何か。",o:["指示を的確に出す能力","失敗を許さない厳格さ","権威を持って統率する力","メンバーの強みを引き出し成果を最大化する力"],a:3,exp:"「メンバーそれぞれの強みを引き出し…最大化する力」が定義。"},
      {q:"優れたリーダーの特徴として述べられていることは何か。",o:["常に前面に立って指示すること","決断力とカリスマ性のみを重視すること","時には一歩引きメンバーの自律性を尊重すること","メンバーに一切任せないこと"],a:2,exp:"「時にはあえて一歩引き、メンバーが自律的に判断し行動できる環境を整える」がそのまま答え。"},
      {q:"筆者が見直す必要があると述べているものは何か。",o:["会議の頻度","メンバーの採用基準","組織の給与体系","リーダーシップの評価基準"],a:3,exp:"「リーダーシップの評価基準も見直す必要が出てくる」がそのまま答え。"},
      {sec:"問題14　情報検索",passage:"【オンライン日本語検定　受験案内】<br>・レベル：初級／中級／上級の3レベル。レベルは事前診断テスト（無料、所要15分）の結果に基づき自動判定。<br>・受験料：初級3,000円、中級4,000円、上級5,000円。学生証提示で全レベル一律1,000円引き。<br>・受験方法：自宅のパソコンから受験可能。カメラでの本人確認とオンライン監督が必須。<br>・結果発表：受験後、即日で仮結果を通知。正式な証明書は2週間後に発行。<br>・注意事項：診断テストで判定されたレベルより下のレベルでの受験は認められない。",q:"学生が診断テストで中級と判定された場合、受験料はいくらか。",o:["3,000円","5,000円","2,000円","4,000円"],a:0,exp:"中級4,000円から学生割引1,000円引きで3,000円。"},
      {q:"この案内から分かることとして正しいものはどれか。",o:["結果は受験当日には一切分からない","診断テストで判定されたレベルより下では受験できない","本人確認は不要である","再受験の受験料は変わらない"],a:1,exp:"「診断テストで判定されたレベルより下のレベルでの受験は認められない」がそのまま該当。"}
    ]},
    {id:"b", title:"聴解", minutes:50, questions:[
      {sec:"問題1　課題理解",audio:"男：来週の 株主総会の 招集通知の 発送は いつですか。　女：来週中に 発送する 予定です。今日中に 最終的な 文面の 確認を お願いできますか。",q:"男の人は このあと、まず 何を しますか。",o:["招集通知を発送する","株主総会を延期する","招集通知の文面を確認する","会場を予約する"],a:2,exp:"「今日中に 最終的な 文面の 確認を お願いできますか」への依頼が答え。"},
      {audio:"女：新製品の 発表会、来賓リストの 確認は 済んでいますか。　男：まだです。今日の 午後、広報部と 一緒に 確認します。",q:"男の人は このあと、まず 何を しますか。",o:["広報部と来賓リストを確認する","発表会を中止する","来賓を追加する","会場を変更する"],a:0,exp:"「今日の 午後、広報部と 一緒に 確認します」がそのまま答え。"},
      {audio:"男：来週の 監査、必要な 書類は そろっていますか。　女：ほとんど そろっていますが、一部の 領収書が まだです。今日中に 経理に 確認します。",q:"女の人は このあと、まず 何を しますか。",o:["監査を延期する","新しい書類を作成する","経理に確認する","書類をすべて破棄する"],a:2,exp:"「今日中に 経理に 確認します」がそのまま答え。"},
      {audio:"女：来月の システム移行、テストの 日程は 決まりましたか。　男：来週の 水曜日に 決まりました。今日中に 関係部署に 連絡します。",q:"男の人は このあと、まず 何を しますか。",o:["日程を再調整する","テストを中止する","システムを移行する","関係部署に連絡する"],a:3,exp:"「今日中に 関係部署に 連絡します」がそのまま答え。"},
      {audio:"女：この 報告書、来週の 役員会議までに 仕上げないといけないんですが。　男：手伝いますよ。どこまで 進んでいますか。　女：本文は できているので、あとは 要約の 部分を お願いできますか。",q:"男の人は このあと、何を しますか。",o:["本文を書き直す","会議の日程を変更する","報告書の要約部分を書く","報告書を印刷する"],a:2,exp:"「要約の 部分を お願いできますか」への流れから、男性は要約部分を担当する。"},
      {sec:"問題2　ポイント理解",audio:"男：この 新サービス、思ったより 契約が 伸びませんね。　女：料金プランが 分かりにくいのが 一番の 原因だと思います。",q:"女の人は、契約が 伸びない 一番の 原因は 何だと 言っていますか。",o:["料金プランが分かりにくいこと","競合が多いこと","広告が少ないこと","サービス自体の質が悪いこと"],a:0,exp:"「料金プランが分かりにくいのが一番の原因」がそのまま答え。"},
      {audio:"女：この チーム、最近 ミスが 増えていますね。　男：確認作業を 一人に 頼りすぎている ことが 一番の 原因だと思います。",q:"男の人は、ミスが 増えた 一番の 原因は 何だと 考えていますか。",o:["確認作業を一人に頼りすぎていること","業務量が増加したこと","締め切りが厳しいこと","メンバーが未熟なこと"],a:0,exp:"「一番の原因は、確認作業を一人に頼りすぎていること」がそのまま答え。"},
      {audio:"男：この 店舗、リピーターが 少ないですね。　女：ポイントカードの 特典が 魅力的でない ことが 一番の 問題だと思います。",q:"女の人は、リピーターが 少ない 一番の 原因は 何だと 考えていますか。",o:["ポイントカードの特典が魅力的でないこと","接客の質が悪いこと","価格が高いこと","立地が悪いこと"],a:0,exp:"「一番の問題は、ポイントカードの特典が魅力的でないこと」がそのまま答え。"},
      {audio:"女：この アプリ、評価が 低いですね。　男：動作が 重く 頻繁に 落ちる ことが 一番の 原因だと思います。",q:"男の人は、評価が 低い 一番の 原因は 何だと 考えていますか。",o:["動作が重く頻繁に落ちること","機能が少ないこと","デザインが悪いこと","価格が高いこと"],a:0,exp:"「一番の原因は、動作が重く頻繁に落ちること」がそのまま答え。"},
      {audio:"男：この 学部、志願者が 減っていますね。　女：就職実績の 情報発信が 弱い ことが 一番大きいと思います。",q:"女の人は、志願者が 減った 一番の 原因は 何だと 考えていますか。",o:["立地が悪いこと","就職実績の情報発信が弱いこと","定員が少ないこと","学費が高いこと"],a:1,exp:"「一番大きいのは、就職実績の情報発信が弱いこと」がそのまま答え。"},
      {audio:"女：この 地域、空き家が 増えていますね。　男：若い 世代の 働き口が 少ない ことが 一番の 原因だと思います。",q:"男の人は、空き家が 増えた 一番の 原因は 何だと 考えていますか。",o:["家賃が高いこと","高齢化が進んでいること","交通の便が悪いこと","若い世代の働き口が少ないこと"],a:3,exp:"「一番の原因は、若い世代の働き口が少ないこと」がそのまま答え。"},
      {sec:"問題3　概要理解",audio:"組織における心理的安全性が注目される中、これは単に居心地のよい環境を意味するのではなく、建設的な対立を歓迎する土壌があってこそ成立するという指摘がある。",q:"この話は、主に何について述べていますか。",o:["人事評価の基準","会議の司会の進め方","心理的安全性の本質についての考え方","給与制度の設計"],a:2,exp:"心理的安全性とは何かについての考察が主題。"},
      {audio:"教育の目的は知識の詰め込みではなく自ら考え判断する力を養うことにあるとされ、正解が一つに定まらない問いに向き合う経験の重要性が指摘されている。",q:"この話は、主に何について述べていますか。",o:["教員採用の基準","学校施設の整備","教育における思考力育成の重要性","入試制度の改革案"],a:2,exp:"教育の目的と思考力育成についての話。"},
      {audio:"終身雇用制度は安定をもたらす一方、変化の激しい現代には適さないという指摘もあり、より流動的な雇用形態への移行が求められるという意見がある。",q:"この話は、主に何について述べていますか。",o:["退職金の計算方法","労働組合の役割","採用面接の進め方","終身雇用制度の課題と今後の展望"],a:3,exp:"終身雇用制度の課題と今後の雇用のあり方についての話。"},
      {audio:"少子高齢化が進む中、外国人労働者の受け入れが議論されているが、言語や文化の違いによる摩擦を懸念する声もあり、企業側の意識改革が求められている。",q:"この話は、主に何について述べていますか。",o:["外国人労働者の給与水準","労働ビザの種類","外国人労働者受け入れに必要な企業の意識改革","入国管理の手続き"],a:2,exp:"受け入れ企業側の意識改革の必要性についての話。"},
      {audio:"効率化ばかりを追求する風潮に対し、雑談や余白の中にこそ新しい発想の種があるのではないかという指摘がなされ、効率と余白の共存が求められている。",q:"この話は、主に何について述べていますか。",o:["効率的な仕事の進め方","効率化の行き過ぎがもたらす弊害への懸念","職場のルール作り","雑談の内容の分析"],a:1,exp:"効率化偏重への懸念と、余白の価値についての話。"},
      {sec:"問題4　即時応答",audio:"この件、少々お時間をいただければと存じます。",q:"最もよい返答はどれですか。",o:["それは残念です。","おめでとうございます。","もう終わりました。","はい、承知しました。"],a:3,exp:"時間の猶予を求める依頼への自然な返答は「はい、承知しました」。"},
      {audio:"恐縮ですが、この日程では対応が難しそうです。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","もう決まったことです。","では、ご都合のよい日をお知らせいただけますか。","それは嬉しいです。"],a:2,exp:"日程が難しいという連絡への自然な返答は、代替日を尋ねる形。"},
      {audio:"この資料、もう少し具体性を持たせたほうがいいと思います。",q:"最もよい返答はどれですか。",o:["もう直しました、以上です。","おめでとうございます。","それはすごいですね。","ありがとうございます。どの部分でしょうか。"],a:3,exp:"修正の指摘への自然な返答は、感謝しつつ詳細を尋ねる形。"},
      {audio:"正直、この案には少し不安があります。",q:"最もよい返答はどれですか。",o:["もう決まりました。","おめでとうございます。","それは嬉しいです。","どのあたりが不安でしょうか、詳しく伺えますか。"],a:3,exp:"不安を打ち明けられた際の自然な返答は、具体的に寄り添う形。"},
      {audio:"急なお願いで恐縮ですが、今週中にお願いできますか。",q:"最もよい返答はどれですか。",o:["それは残念ですね。","おめでとうございます。","もう終わりました。","承知しました。調整してみます。"],a:3,exp:"急な依頼への自然な返答は「承知しました。調整してみます」。"},
      {audio:"念のため確認させてください。この方向性でよろしいでしょうか。",q:"最もよい返答はどれですか。",o:["もう終わった話です。","それはすごいですね。","いいえ、まだ始まっていません。","はい、その方向性で結構です。"],a:3,exp:"方向性の確認への自然な返答は「はい、その方向性で結構です」。"},
      {audio:"この度はこちらの不手際でご迷惑をおかけしました。",q:"最もよい返答はどれですか。",o:["もっとやってください。","それは嬉しいです。","いえ、こちらこそ説明が不十分でした。","おめでとうございます。"],a:2,exp:"謝罪への自然な返答は、相手を責めずに応じる形。"},
      {audio:"この案件、優先的に対応していただけますか。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","それは残念ですね。","承知しました。他の予定と調整します。","もう終わりました。"],a:2,exp:"優先対応の依頼への自然な返答。"},
      {audio:"この度は温かいお言葉をありがとうございます。",q:"最もよい返答はどれですか。",o:["それは残念ですね。","おめでとうございます。","いえ、こちらこそ励みになりました。","もう終わりです。"],a:2,exp:"感謝の言葉への自然な返答。"},
      {audio:"念のため伺いますが、この内容で先方にお送りしてよろしいでしょうか。",q:"最もよい返答はどれですか。",o:["もう送信済みです。","いいえ、まだ始まっていません。","はい、問題ありません。","それはすごいですね。"],a:2,exp:"送信前の最終確認への自然な返答は「はい、問題ありません」。"},
      {sec:"問題5　統合理解",audio:"司会：来年度の新人研修プログラムについて、三つ案があります。<br>男性A：座学中心の研修がいいと思います。基礎をしっかり固めるべきです。<br>女性：私は現場でのOJT中心にすべきだと思います。実践を通じて学ぶことが多いです。<br>男性B：両方を組み合わせて、前半に座学、後半にOJTを行うのはどうでしょうか。<br>司会：それでは、前半座学・後半OJTの組み合わせ案で進めましょう。",q:"最終的にどの案で進めることになりましたか。",o:["案がまとまらなかった","前半座学・後半OJTの組み合わせ案","座学中心の案","OJT中心の案"],a:1,exp:"司会が「前半座学・後半OJTの組み合わせ案で進めましょう」と決定している。"},
      {q:"女性がOJT中心の研修を推した理由は何ですか。",o:["座学が退屈だから","予算が最も安いから","実践を通じて学ぶことが多いから","講師が不足しているから"],a:2,exp:"「実践を通じて学ぶことが多いです」が理由。"},
      {audio:"司会：来年度の顧客対応の改善策について、三つ案があります。<br>男性A：問い合わせ窓口の人員を増やすべきだと思います。<br>女性：私はチャットボットの導入を進めるべきだと思います。24時間対応が可能になります。<br>男性B：両方を組み合わせて、簡単な質問はチャットボット、複雑な質問は人員対応にするのはどうでしょうか。<br>司会：それでは、チャットボットと人員対応を組み合わせる案で進めましょう。",q:"最終的にどの案で進めることになりましたか。",o:["チャットボットと人員対応を組み合わせる案","チャットボット導入のみの案","現状維持の案","人員増強のみの案"],a:0,exp:"司会が「チャットボットと人員対応を組み合わせる案で進めましょう」と決定している。"}
    ]}
  ]
},
{
  id:"o-n2-5", lvl:"N2", title:"Examen oficial N2 · 5", desc:"Simulacro cronometrado con el formato completo del Noken",
  sections:[
    {id:"a", title:"言語知識（文字・語彙・文法）・読解", minutes:105, questions:[
      {sec:"問題1　漢字読み",q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 意見は 示唆に 富んでいる。",o:["じさ","しし","じし","しさ"],a:3,exp:"示唆→しさ「sugerencia」。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は 寡黙な 人だ。",o:["かぼく","がもく","かもく","かもつ"],a:2,exp:"寡黙→かもく「taciturno」。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　その 決定は 拙速だった。",o:["せっそく","せっすみ","せつすみ","せつそく"],a:0,exp:"拙速→せっそく「apresurado」。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は 冷静さを 失わなかった。",o:["うしなわなかった","しつわなかった","しっしなかった","うしないなかった"],a:0,exp:"失わなかった→うしなわなかった「no perdió」。"},
      {q:"＿＿の ことばの 読み方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 態度は 一貫している。",o:["いつかん","いっかんせい","いっかん","いちかん"],a:2,exp:"一貫→いっかん「coherencia」。"},
      {sec:"問題2　表記",q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　しさに とんでいる。",o:["指嗟","指唆","示嗟","示唆"],a:3,exp:"しさ→示唆「sugerencia」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　かもくな ひと。",o:["過黙","寡黙","過默","寡默"],a:1,exp:"かもく→寡黙「taciturno」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　せっそくな はんだん。",o:["接速","切速","説速","拙速"],a:3,exp:"せっそく→拙速「apresurado」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　いっかんしている。",o:["一貫","一環","一慣","一館"],a:0,exp:"いっかん→一貫「coherencia」。"},
      {q:"＿＿の ことばは どう 書きますか。1・2・3・4から 一つ 選びなさい。　うしなわなかった。",o:["矢わなかった","夫わなかった","失うなかった","失わなかった"],a:3,exp:"うしなわなかった→失わなかった「no perdió」。"},
      {sec:"問題3　語形成",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 制度は （　）改正された。",o:["再","超","非","不"],a:0,exp:"「再改正」＝再（接頭語）+改正、再び行うことを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は （　）社員だ。",o:["旧","元","古","前"],a:1,exp:"「元社員」＝元（接頭語）+社員、以前その立場だったことを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この プロジェクトは 進行（　）だ。",o:["中","後","内","前"],a:0,exp:"「進行中」＝進行+中（接尾語）、その最中であることを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は （　）常識な 発言を した。",o:["未","非","超","不"],a:1,exp:"「非常識」＝非（接頭語）+常識、常識に反することを表す。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 案件は 処理（　）だ。",o:["後","済み","中","前"],a:1,exp:"「処理済み」＝処理+済み（接尾語）、すでに処理したことを表す。"},
      {sec:"問題4　文脈規定",q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は 事態を （　）に 受け止めた。",o:["真面目","真剣","本気","深刻"],a:3,exp:"深刻に受け止める「tomarse en serio (una situación grave)」。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 発言は （　）を 招いた。",o:["評判","話題","注目","物議"],a:3,exp:"物議を招く「causar controversia」。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は （　）として 批判に 耐えた。",o:["茫然","漠然","超然","毅然"],a:3,exp:"「毅然として」＝con firmeza。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 問題は （　）を 要する。",o:["慎重検討","慎重に検討","慎重さ検討","慎重な検討"],a:3,exp:"「慎重な検討」が名詞句として自然な形。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 説明には （　）が ある。",o:["説得感","説得質","説得力","説得性"],a:2,exp:"説得力「poder de convicción」が正しい語形。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は （　）として 動じなかった。",o:["漠然","唖然","泰然","超然"],a:2,exp:"泰然としている「permanecer sereno」。"},
      {q:"（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は 難局を （　）乗り切った。",o:["過剰に","強引に","巧みに","急激に"],a:2,exp:"「巧みに」＝hábilmente。"},
      {sec:"問題5　言い換え類義",q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼の 意見は 示唆に 富んでいる。",o:["結論をはっきり述べる","理解しにくい","反論しにくい","ヒントや気づきを与える"],a:3,exp:"示唆に富む≒「rico en sugerencias」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　その 決定は 拙速だった。",o:["慎重すぎた","的確だった","急ぎすぎて不十分だった","遅すぎた"],a:2,exp:"拙速≒「apresurado y descuidado」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼は 寡黙な 人だ。",o:["おしゃべりな","陽気な","感情的な","口数が少ない"],a:3,exp:"寡黙≒「taciturno」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼は 毅然として 批判に 耐えた。",o:["不安そうに","態度を崩さず堂々と","諦めて","焦って"],a:1,exp:"毅然として≒「con firmeza, sin flaquear」。"},
      {q:"　　の ことばに 意味が 最も 近い ものを、1・2・3・4から 一つ 選びなさい。　彼は 執着を 捨てられなかった。",o:["強いこだわり","柔軟さ","冷静さ","無関心"],a:0,exp:"執着≒「apego、obsesión」。"},
      {sec:"問題6　用法",q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「すべからく」",o:["リーダーはすべからく謙虚であるべきだ。","すべからく三時に会議がある。","すべからく明日晴れるだろう。","すべからく早く終わった。"],a:0,exp:"「すべからく〜べきだ」＝por naturaleza / necesariamente se debe。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「いみじくも」",o:["彼はいみじくも真実を言い当てた。","いみじくも早く終わった。","いみじくも明日雨が降る。","いみじくも三時に来た。"],a:0,exp:"「いみじくも」＝acertadamente, con precisión sorprendente。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「あながち」",o:["あながち明日会議がある。","あながち早く終わった。","あながち三時に来た。","彼の意見もあながち間違いとは言えない。"],a:3,exp:"「あながち〜とは言えない」＝no del todo。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「つゆほども」",o:["つゆほども明日雨が降る。","つゆほども三時に来た。","彼は失敗をつゆほども後悔していない。","つゆほども早く終わった。"],a:2,exp:"「つゆほども〜ない」＝en absoluto, ni una pizca。"},
      {q:"次の ことばの 使い方として 最もよい ものを、1・2・3・4から 一つ 選びなさい。「よそに」",o:["よそに三時に会議がある。","よそに明日雨が降る。","周囲の心配をよそに、彼は平然としていた。","よそに早く終わった。"],a:2,exp:"「〜をよそに」＝haciendo caso omiso de。"},
      {sec:"問題7　文法1（文法形式の判断）",q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は 逆境（　）、決して 諦めなかった。",o:["ときたら","はおろか","にひきかえ","にあっても"],a:3,exp:"「〜にあっても」＝incluso en (adversidad)。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 結果は 偶然（　）必然の 産物だ。",o:["といえども","というのに","というより","というもの"],a:2,exp:"「〜というより」＝más que。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 貢献（　）、この 成功は なかっただろう。",o:["にひきかえ","はおろか","ときたら","なくして"],a:3,exp:"「〜なくして（は）」＝sin (algo)。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　規模の 大小（　）、この 問題は 軽視できない。",o:["を問わず","にわたって","にそくして","につき"],a:0,exp:"「〜を問わず」＝independientemente de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は 経験の 乏しさ（　）、見事な 対応を 見せた。",o:["はおろか","をものともせず","にひきかえ","ときたら"],a:1,exp:"「〜をものともせず」＝sin dejarse afectar por。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　社員の 声を 反映する（　）、制度を 見直した。",o:["かねて","べく","がてら","もかまわず"],a:1,exp:"「〜べく」＝con el fin de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　周囲の 反対を （　）、彼は 計画を 実行した。",o:["かねて","もとに","押し切って","めぐって"],a:2,exp:"「〜を押し切って」＝haciendo caso omiso de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　経験の 有無に （　）、誰でも 参加できる。",o:["こたえて","かかわらず","わたって","そって"],a:1,exp:"「〜にかかわらず」＝independientemente de。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　失敗を 重ねた（　）、彼は ようやく 成功を つかんだ。",o:["ところで","なくして","すえに","かたわら"],a:2,exp:"「〜すえに」＝tras un largo proceso。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　規則を 破った（　）、罰せられるのは 当然だ。",o:["上に","うちに","以上","かたわら"],a:2,exp:"「〜以上」＝dado que。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女の 才能（　）、成功は 時間の 問題だった。",o:["をもってすれば","ときたら","はおろか","にひきかえ"],a:0,exp:"「〜をもってすれば」＝con tal capacidad。"},
      {q:"次の文の（　）に 入れるのに 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の 実力（　）、この 結果は 当然だ。",o:["はさておき","からすれば","をものともせず","にひきかえ"],a:1,exp:"「〜からすれば」＝desde el punto de vista de。"},
      {sec:"問題8　文法2（文の組み立て）",q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼は　___　___　★　___　最後までやり通した。（1 周囲の　2 懸念　3 をよそに　4 も）",o:["周囲の","も","をよそに","懸念"],a:3,exp:"正しい順序：1周囲の→2懸念→4も→3をよそに「周囲の懸念をよそに」。★の位置には2「懸念」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼女は　___　___　★　___　見事な 対応を 見せた。（1 経験の　2 も　3 乏しさ　4 をものともせず）",o:["をものともせず","も","乏しさ","経験の"],a:0,exp:"正しい順序：1経験の→3乏しさ→4をものともせず「経験の乏しさをものともせず」。★の位置には4「をものともせず」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　この 結果は　___　___　★　___　産物だ。（1 より　2 偶然　3 必然の　4 という）",o:["より","必然の","という","偶然"],a:0,exp:"正しい順序：2偶然→4という→1より→3必然の「偶然というより必然の」。★の位置には1「より」が入る。"},
      {q:"次の文の　★　に 入る 最もよい ものを、1・2・3・4から 一つ 選びなさい。　彼の　___　___　★　___　この 成功は なかっただろう。（1 貢献　2 は　3 も　4 なくして）",o:["も","貢献","なくして","は"],a:2,exp:"正しい順序：1貢献→4なくして「貢献なくして」。★の位置には4「なくして」が入る。"},
      {sec:"問題9　文章の文法",passage:"効率化ばかりを 追求する 現代社会に おいて、あらゆる 無駄が 排除されるべきだという 風潮が 強まっている。しかし、この 考え方（1）、見落とされている ものが あるのではないか。一見 無駄に 見える 雑談や 余白（2）、新しい アイデアが 生まれる ことも 少なくない。（3）、効率を 追求する あまり、こうした 偶発的な 創造性の 芽まで 摘み取ってしまう 危険が ある。もちろん、無駄を 完全に 肯定する わけでは ない。（4）、適度な 余裕を 持つ ことの 価値を、改めて 見直す 必要が あるという ことだ。効率と 余白、この 両者の（5）こそが、これからの 時代に 求められて いるのだろう。",q:"（1）",o:["とは","でも","なら","には"],a:3,exp:"〜には「en (esta idea)」対象を示す助詞。"},
      {q:"（2）",o:["まで","ばかり","ゆえ","から"],a:3,exp:"〜から「a partir de」原因・出発点を示す。"},
      {q:"（3）",o:["ゆえに","したがって","ところが","つまり"],a:2,exp:"逆接の接続詞「ところが」が文脈に合う。"},
      {q:"（4）",o:["言われてみれば","言いたいのは","言うまでもなく","言われるとおり"],a:1,exp:"「言いたいのは〜ということだ」筆者の主張をまとめる定型表現。"},
      {q:"（5）",o:["対立","バランス","優劣","分離"],a:1,exp:"文脈上、両者の「バランス」が求められているという結論が自然。"},
      {sec:"問題10　内容理解（短文）",passage:"再生可能エネルギーの普及が進む一方、天候に左右される発電量の不安定さが課題として指摘されている。蓄電技術の進歩が解決の鍵とされる。",q:"再生可能エネルギーの課題は何か。",o:["発電量が天候に左右される不安定さ","法律で禁止されていること","コストが高すぎること","設置場所がないこと"],a:0,exp:"「天候に左右される発電量の不安定さが課題」がそのまま答え。"},
      {passage:"この地域は昔から農業が盛んで、特に米作りで知られている。しかし近年、若い世代の農業離れが進み、後継者不足が深刻な問題となっている。",q:"この地域の問題は何か。",o:["観光客が少ないこと","後継者不足","土地が狭いこと","米の生産量が多すぎること"],a:1,exp:"「後継者不足が深刻な問題」がそのまま答え。"},
      {passage:"この病院では、待ち時間の長さが患者の不満の原因となっていた。予約システムを改善した結果、待ち時間が大幅に短縮された。",q:"待ち時間が短縮された理由は何か。",o:["予約システムの改善","医師の増員","患者数の減少","診療時間の延長"],a:0,exp:"「予約システムを改善した結果、待ち時間が大幅に短縮された」がそのまま答え。"},
      {passage:"この会社では、社員の提案から生まれた新商品が好調な売れ行きを見せている。社員のアイデアを大切にする社風が実を結んだ形だ。",q:"新商品の好調な売れ行きは何の結果か。",o:["広告の効果","社員のアイデアを大切にする社風","競合の撤退","値下げ"],a:1,exp:"「社員のアイデアを大切にする社風が実を結んだ」がそのまま答え。"},
      {passage:"この地域では、空き店舗を利用したイベントが定期的に開かれており、地域の活性化につながっている。",q:"空き店舗の利用は何につながっているか。",o:["家賃の上昇","犯罪の増加","地域の活性化","人口の減少"],a:2,exp:"「地域の活性化につながっている」がそのまま答え。"},
      {sec:"問題11　内容理解（中文）",passage:"組織における心理的安全性という概念が、近年注目を集めている。率直な意見を言っても罰せられないという確信をメンバーが共有している状態を指すが、これは単に居心地のよい環境を意味するわけではない。むしろ、建設的な対立を歓迎する土壌があってこそ成立するものである。",q:"筆者が定義する心理的安全性とは何か。",o:["対立を一切避ける環境","居心地のよいぬるま湯的な環境","上司にのみ意見が許される環境","率直な意見を言っても罰せられないという確信の共有"],a:3,exp:"「率直な意見や懸念を口にしても…罰せられたりしない確信を、メンバーが共有している状態」が定義。"},
      {q:"筆者は心理的安全性についてどのような誤解を指摘しているか。",o:["単に居心地のよい環境だという誤解","上司にのみ必要だという誤解","測定不可能だという誤解","効果がないという誤解"],a:0,exp:"「単に居心地の良い、ぬるま湯的な環境を意味するわけではない」がそのまま答え。"},
      {q:"この文章全体の趣旨として最も適切なものはどれか。",o:["心理的安全性は対立を避けることで成立する","心理的安全性は上司だけが持つべきものだ","心理的安全性は不要な概念だ","心理的安全性は建設的な対立があってこそ成立する"],a:3,exp:"「建設的な対立を歓迎する土壌があってこそ、真の心理的安全性は成立する」が趣旨。"},
      {passage:"少子高齢化が進む日本では、労働力不足を補うため、外国人労働者の受け入れ拡大が議論されている。一方で、言語や文化の違いによる職場での摩擦を懸念する声も根強い。",q:"外国人労働者の受け入れに関して懸念されていることは何か。",o:["賃金の高騰","住居不足","治安の悪化","言語や文化の違いによる摩擦"],a:3,exp:"「言語や文化の違いによる職場での摩擦を懸念する声も根強い」がそのまま答え。"},
      {q:"この文章が扱っている論点は何か。",o:["移民法の改正手続き","労働力不足対策としての外国人労働者受け入れとその課題","治安対策の強化","賃金体系の見直し"],a:1,exp:"労働力不足対策とその懸念点の両方を扱っている。"},
      {q:"この文章の要旨として最も適切なものはどれか。",o:["外国人労働者の受け入れは不要である","外国人労働者受け入れには制度と意識の両面の変化が必要だ","言語の違いは全く問題にならない","賃金さえ上げれば全て解決する"],a:1,exp:"制度的な議論と意識改革の両方に言及している。"},
      {passage:"効率化ばかりを追求する現代社会において、雑談や余白といった一見無駄に見えるものの中にこそ、新しい発想の種が潜んでいるのではないかという指摘がある。無駄を一律に排除する姿勢は、かえって組織の創造性を損なう危険をはらんでいる。",q:"筆者が指摘する危険は何か。",o:["雑談を推奨しすぎること","効率化が全く進まないこと","余白が多すぎること","無駄を一律に排除することが創造性を損なうこと"],a:3,exp:"「無駄を一律に排除する姿勢は、かえって組織の創造性を損なう危険」がそのまま答え。"},
      {q:"筆者は雑談や余白をどう捉えているか。",o:["新しい発想の種になりうるもの","時間の浪費でしかないもの","完全に無駄なもの","業務効率を下げるだけのもの"],a:0,exp:"「新しい発想の種が潜んでいるのではないか」と肯定的に捉えている。"},
      {q:"この文章全体の趣旨として最も適切なものはどれか。",o:["雑談は業務の妨げにしかならない","効率化はすべて推進すべきだ","効率偏重の姿勢が組織の創造性を損なう危険がある","余白は完全に排除すべきだ"],a:2,exp:"効率偏重への警鐘が文章全体の趣旨。"},
      {sec:"問題12　統合理解",passage:"【A】終身雇用制度は、従業員に安定と忠誠心をもたらし、長期的な人材育成を可能にしてきた。この制度を安易に手放すべきではないという意見がある。<br><br>【B】しかし、終身雇用制度は、変化の激しい現代のビジネス環境には適していないという指摘もある。年功序列と結びついたこの制度は、若手の意欲的な挑戦を阻害しかねない。",q:"Aの筆者が主張していることは何か。",o:["離職率は高い方がよい","若手の挑戦を阻害すべきだ","終身雇用制度を安易に手放すべきではない","終身雇用制度をすぐに廃止すべきだ"],a:2,exp:"Aは終身雇用制度の維持を支持している。"},
      {q:"Bの筆者が懸念していることは何か。",o:["終身雇用制度が若手の挑戦を阻害すること","離職率が低すぎること","雇用が流動的すぎること","終身雇用制度がすぐになくなること"],a:0,exp:"「若手の意欲的な挑戦を阻害しかねない」が懸念。"},
      {sec:"問題13　主張理解（長文）",passage:"組織における心理的安全性という概念が、近年ますます重視されている。率直な意見や懸念を口にしても、罰せられたり恥をかかされたりしないという確信をメンバーが共有している状態を指す。<br><br>この安全性が低い組織では、メンバーは失敗を恐れるあまり本音を言わなくなり、結果として問題の早期発見が遅れがちになる。<br><br>心理的安全性を高めることは、決して簡単な取り組みではない。しかし、その構築は、組織の長期的な競争力に直結する重要な課題だと言えるだろう。",q:"筆者が定義する心理的安全性とは何か。",o:["率直な意見を言っても罰せられないという確信の共有","対立を一切避ける環境","上司にのみ意見が許される環境","居心地のよいぬるま湯的な環境"],a:0,exp:"「率直な意見や懸念を口にしても…罰せられたりしない確信を、メンバーが共有している状態」が定義。"},
      {q:"心理的安全性が低い組織で起きることとして述べられているのは何か。",o:["問題の早期発見が遅れがちになること","給料が必ず上がること","離職率が必ず下がること","業績が必ず向上すること"],a:0,exp:"「本音を言わなくなり、結果として問題の早期発見が遅れがちになる」がそのまま答え。"},
      {q:"この文章全体を通して筆者が伝えたいことは何か。",o:["対立は組織にとって常に有害である","心理的安全性は簡単に構築できる","心理的安全性の構築が組織の競争力に直結する","居心地のよさこそが最も重要だ"],a:2,exp:"「その構築は、組織の長期的な競争力に直結する重要な課題」が結論。"},
      {sec:"問題14　情報検索",passage:"【地域図書館　貸出サービス案内】<br>・利用登録：市内在住・在勤・在学者は無料。市外在住者は年間登録料1,000円。<br>・貸出冊数：一般書10冊、雑誌・DVD各2点まで、貸出期間は2週間。<br>・延長：予約が入っていない資料に限り、1回だけ2週間延長可能。<br>・予約サービス：他の利用者が借りている資料の予約が可能。準備ができ次第、メールで通知（登録者のみ）。<br>・注意：延滞が続いた場合、新規の貸出および予約サービスの利用が一時停止される。",q:"市外在住のAさんが本を借りたい場合、まず何をする必要があるか。",o:["市内に転居する","年間登録料1,000円を払って利用登録をする","無料で登録する","図書館に問い合わせるだけでよい"],a:1,exp:"「市外在住者は年間登録料1,000円」を払って登録する必要がある。"},
      {q:"この案内から分かることとして正しいものはどれか。",o:["貸出期間は1か月である","延滞が続くと新規貸出が一時停止される","予約は登録者以外も利用できる","延長は何回でもできる"],a:1,exp:"「延滞が続いた場合、新規の貸出および予約サービスの利用が一時停止される」がそのまま該当。"}
    ]},
    {id:"b", title:"聴解", minutes:50, questions:[
      {sec:"問題1　課題理解",audio:"男：来週のセミナー、資料は準備できていますか。　女：ほぼ完成していますが、最後のページの図をもう少し見やすくしたいです。今日中に直します。",q:"女の人は このあと まず 何を しますか。",o:["資料を印刷する","参加者に連絡する","図を見やすく修正する","セミナーを中止する"],a:2,exp:"「今日中に 直します」がそのまま答え。"},
      {audio:"女：新しいロゴのデザイン、三案ありますが、どれがいいと思いますか。　男：正直迷いますね。デザイン部の意見も聞いてから決めませんか。",q:"この後 まず 何を しますか。",o:["三案とも採用する","ロゴをすぐに決める","デザインをやり直す","デザイン部の意見を聞く"],a:3,exp:"「デザイン部の意見も聞いてから決めませんか」がそのまま答え。"},
      {audio:"男：来月の出張の交通手段、まだ決めていませんでした。　女：新幹線の方が早いですが、予算的にはバスの方が安いです。上司に確認してから決めましょう。",q:"この後 まず 何を しますか。",o:["バスを予約する","出張を中止する","上司に確認する","新幹線を予約する"],a:2,exp:"「上司に確認してから決めましょう」がそのまま答え。"},
      {audio:"女：来週の展示会の準備、順調ですか。　男：はい、ほぼ予定通りですが、パンフレットの印刷だけ少し遅れています。",q:"何が 遅れて いますか。",o:["パンフレットの印刷","商品の到着","会場の準備","スタッフの手配"],a:0,exp:"「パンフレットの印刷だけ少し遅れています」がそのまま答え。"},
      {audio:"男：新しいシステムの導入、社員への説明会はいつ行いますか。　女：来週の水曜日に予定しています。今日中に案内メールを送ります。",q:"女の人は このあと まず 何を しますか。",o:["社員を集める","案内メールを送る","システムを変更する","説明会を延期する"],a:1,exp:"「今日中に案内メールを送ります」がそのまま答え。"},
      {sec:"問題2　ポイント理解",audio:"女：この商品、海外での売り上げが伸びませんね。　男：現地の文化に合わせたマーケティングが不足していることが一番の原因だと思います。",q:"男の人は、売り上げが伸びない一番の原因は何だと考えていますか。",o:["競合が多いこと","価格が高すぎること","品質が悪いこと","現地の文化に合わせたマーケティングの不足"],a:3,exp:"「現地の文化に合わせたマーケティングが不足していることが一番の原因」がそのまま答え。"},
      {audio:"男：この部署、残業が多いですね。　女：業務の分担が偏っていることが一番の原因だと思います。",q:"女の人は、残業が多い一番の原因は何だと考えていますか。",o:["業務の分担が偏っていること","人手が足りないこと","効率が悪いこと","仕事の量が多すぎること"],a:0,exp:"「業務の分担が偏っていることが一番の原因」がそのまま答え。"},
      {audio:"女：この店、常連客が減っていますね。　男：接客態度に問題があったことが一番の原因だと聞いています。",q:"男の人は、常連客が減った一番の原因は何だと考えていますか。",o:["接客態度の問題","メニューの変更","価格の値上げ","立地の悪さ"],a:0,exp:"「接客態度に問題があったことが一番の原因」がそのまま答え。"},
      {audio:"男：この大学、留学生が減っていますね。　女：奨学金制度が他大学に比べて少ないことが一番の原因だと思います。",q:"女の人は、留学生が減った一番の原因は何だと考えていますか。",o:["立地が悪いこと","講義が英語で行われないこと","授業料が高いこと","奨学金制度が少ないこと"],a:3,exp:"「奨学金制度が他大学に比べて少ないことが一番の原因」がそのまま答え。"},
      {audio:"女：このプロジェクト、スケジュールが遅れていますね。　男：初期段階での要件定義が不十分だったことが一番の原因だと思います。",q:"男の人は、スケジュールが遅れた一番の原因は何だと考えていますか。",o:["技術的な問題があったこと","予算が少なかったこと","人員が不足していたこと","初期段階での要件定義が不十分だったこと"],a:3,exp:"「初期段階での要件定義が不十分だったことが一番の原因」がそのまま答え。"},
      {audio:"男：この商品、SNSでの評判が悪いですね。　女：発売前の情報公開が不十分だったことが一番の原因だと思います。",q:"女の人は、評判が悪い一番の原因は何だと考えていますか。",o:["デザインが悪いこと","競合が優れていること","発売前の情報公開が不十分だったこと","価格が高すぎること"],a:2,exp:"「発売前の情報公開が不十分だったことが一番の原因」がそのまま答え。"},
      {sec:"問題3　概要理解",audio:"組織における心理的安全性が注目される中、これは単に居心地のよい環境を意味するのではなく、建設的な対立を歓迎する土壌があってこそ成立するという指摘がある。",q:"この話は、主に何について述べていますか。",o:["心理的安全性の本質についての考え方","会議の司会の進め方","給与制度の設計","人事評価の基準"],a:0,exp:"心理的安全性とは何かについての考察が主題。"},
      {audio:"終身雇用制度は安定をもたらす一方、変化の激しい現代には適さないという指摘もあり、より流動的な雇用形態への移行が求められるという意見がある。",q:"この話は、主に何について述べていますか。",o:["採用面接の進め方","労働組合の役割","終身雇用制度の課題と今後の展望","退職金の計算方法"],a:2,exp:"終身雇用制度の課題と今後の雇用のあり方についての話。"},
      {audio:"少子高齢化が進む中、外国人労働者の受け入れが議論されているが、言語や文化の違いによる摩擦を懸念する声もあり、企業側の意識改革が求められている。",q:"この話は、主に何について述べていますか。",o:["外国人労働者受け入れに必要な企業の意識改革","外国人労働者の給与水準","労働ビザの種類","入国管理の手続き"],a:0,exp:"受け入れ企業側の意識改革の必要性についての話。"},
      {audio:"効率化ばかりを追求する風潮に対し、雑談や余白の中にこそ新しい発想の種があるのではないかという指摘がなされ、効率と余白の共存が求められている。",q:"この話は、主に何について述べていますか。",o:["効率的な仕事の進め方","雑談の内容の分析","職場のルール作り","効率化の行き過ぎがもたらす弊害への懸念"],a:3,exp:"効率化偏重への懸念と、余白の価値についての話。"},
      {audio:"再生可能エネルギーの普及に伴い、電力供給の安定性をどう確保するかが新たな課題として浮上している。蓄電技術への投資が急速に進められている。",q:"この話は、主に何について述べていますか。",o:["電気料金の値上げ","停電の原因","発電所の建設計画","再生可能エネルギー普及に伴う課題と対策"],a:3,exp:"再生可能エネルギー普及に伴う電力安定性の課題と対策についての話。"},
      {sec:"問題4　即時応答",audio:"この件、少し検討させていただけますか。",q:"最もよい返答はどれですか。",o:["もう終わりました。","はい、どうぞ。","いいえ、まだです。","それは残念ですね。"],a:1,exp:"確認の申し出に対して自然な返答は「はい、どうぞ」。"},
      {audio:"申し訳ございませんが、本日中の対応は難しい状況です。",q:"最もよい返答はどれですか。",o:["それは良かったです。","はい、すぐやります。","おめでとうございます。","では、いつ頃なら可能でしょうか。"],a:3,exp:"対応が難しいという連絡への自然な返答は、代替案を尋ねる形。"},
      {audio:"この資料、ちょっと目を通していただけますか。",q:"最もよい返答はどれですか。",o:["もう捨てました。","はい、拝見します。","それはおめでとうございます。","いいえ、要りません。"],a:1,exp:"資料を確認してほしいという依頼への自然な返答は「はい、拝見します」。"},
      {audio:"恐れ入りますが、少々お待ちいただけますでしょうか。",q:"最もよい返答はどれですか。",o:["いいえ、待てません。","もう終わりです。","それはすごいですね。","はい、かしこまりました。"],a:3,exp:"待ってほしいという依頼への自然な返答は「はい、かしこまりました」。"},
      {audio:"この度は大変ご迷惑をおかけし、申し訳ございませんでした。",q:"最もよい返答はどれですか。",o:["おめでとうございます。","いえ、こちらこそ確認不足がありました。","それは嬉しいです。","もっとやってください。"],a:1,exp:"謝罪への自然な返答として、相手を責めずに応じる形。"},
      {audio:"来週の予定、変更になる可能性があります。",q:"最もよい返答はどれですか。",o:["分かりました。決まり次第教えてください。","おめでとうございます。","それは羨ましいです。","もう変更しました。"],a:0,exp:"予定変更の可能性を知らされた自然な返答は「決まり次第教えてください」。"},
      {audio:"この企画、正直あまり自信がないんです。",q:"最もよい返答はどれですか。",o:["もうやめましょう。","それはよかったですね。","どの部分が気になりますか。一緒に考えましょう。","おめでとうございます。"],a:2,exp:"不安を打ち明けられた際の自然な返答は、具体的に寄り添う形。"},
      {audio:"この書類、ハンコを押していただけますか。",q:"最もよい返答はどれですか。",o:["それは大変ですね。","はい、こちらに押しますね。","いいえ、書きません。","もう押されています。"],a:1,exp:"押印の依頼への自然な返答は「はい、こちらに押しますね」。"},
      {audio:"すみません、少し声が小さくて聞き取れませんでした。",q:"最もよい返答はどれですか。",o:["失礼しました。もう一度お伝えします。","それは残念ですね。","もう聞こえています。","おめでとうございます。"],a:0,exp:"聞き取れなかったという指摘への自然な返答は「もう一度お伝えします」。"},
      {audio:"この案で進めてもよろしいでしょうか。",q:"最もよい返答はどれですか。",o:["もう終わった話です。","それはすごいですね。","いいえ、まだ始まっていません。","はい、それでお願いします。"],a:3,exp:"承認を求められた際の自然な返答は「はい、それでお願いします」。"},
      {sec:"問題5　統合理解",audio:"司会：新しいオフィスのレイアウトについて、三つの案が出ています。<br>男性A：私はオープンスペース案がいいと思います。部署間のコミュニケーションが活発になりますし、コストも抑えられます。<br>女性：私は個室中心の案を推します。集中して作業したいという社員の声も多いですし、機密情報を扱う部署もありますから。<br>男性B：私はその中間の、半個室のブース形式がいいと思います。<br>司会：それでは、コストと集中力のバランスを重視して、ブース形式で進めることにしましょう。",q:"最終的にどの案で進めることになりましたか。",o:["オープンスペース案","ブース形式の案","個室中心の案","三つの案を組み合わせた新しい案"],a:1,exp:"司会が最後に「ブース形式で進めることにしましょう」と決定している。"},
      {q:"女性が個室中心の案を推した理由は何ですか。",o:["集中したい社員の声や機密情報への配慮","部署間の交流を増やすため","コストが最も安いから","男性Aの意見に賛成だったから"],a:0,exp:"「集中して作業したいという社員の声…機密情報を扱う部署もある」が理由。"},
      {audio:"司会：来年度の新入社員研修について、三つの案があります。<br>男性A：私は座学中心の研修がいいと思います。基礎知識をしっかり身につけさせるべきです。<br>女性：私は実地研修を増やすべきだと思います。現場での経験がないと、座学だけでは実践力が身につきません。<br>男性B：両方を組み合わせて、午前は座学、午後は実地という形にするのはどうでしょうか。<br>司会：それでは、午前座学・午後実地の組み合わせ案で進めましょう。",q:"最終的にどの案で進めることになりましたか。",o:["午前座学・午後実地の組み合わせ案","案がまとまらなかった","実地研修中心の案","座学中心の案"],a:0,exp:"司会が「午前座学・午後実地の組み合わせ案で進めましょう」と決定している。"}
    ]}
  ]
}
];
